import numpy as np
import matplotlib.pyplot as plt
from scipy.interpolate import interp1d
from scipy.signal import find_peaks
import MDAnalysis as mda
from MDAnalysis.analysis.base import AnalysisBase, Results
from MDAnalysis.lib.distances import distance_array
from tqdm import tqdm
import pickle
import os

class ZDirectionalAnalysis(AnalysisBase):
    '''
    Analysis class for studying simulation trajectories as a function of z-direction distance.
    Useful for interfaces, bilayers, membranes, or any system with directional properties.
    
    Features:
    - Density profiles along z-axis (both number density and raw counts)
    - Ion distribution vs z-position
    - Coordination environment changes with z
    - Interface detection and analysis
    - Water orientation at interfaces
    - Layer-specific properties
    - 13+ additional analysis methods
    - Smart caching system
    - Profile symmetrization
    '''
    
    def __init__(self, top=None, traj=None, universe=None,
                z_min=None, z_max=None, n_bins=100,
                water='resname SOL or resname WAT',
                water_oxygen='name OW or name Ow',
                water_hydrogen='name HW1 or name HW2 or name Hw1 or name Hw2',
                cation='resname NA or resname K or resname MG or resname CA',
                anion='resname CL or resname BR or resname F or resname I',
                center_box=True,
                **kwargs):
        '''
        Initialize Z-directional analysis.
        
        Parameters
        ----------
        top : str, optional
            Topology file (e.g., .tpr, .gro, .pdb)
        traj : str or list, optional
            Trajectory file(s) (e.g., .trr, .xtc, .dcd)
        universe : MDAnalysis.Universe, optional
            Pre-existing universe object (alternative to top/traj)
        z_min : float, optional
            Minimum z-coordinate. If None, uses trajectory minimum
        z_max : float, optional  
            Maximum z-coordinate. If None, uses trajectory maximum
        n_bins : int
            Number of bins for z-direction discretization, default=100
        water : str
            Selection string for all water atoms (full residue)
        water_oxygen : str
            Selection string for water oxygen atoms
        water_hydrogen : str
            Selection string for water hydrogen atoms
        cation : str
            Selection string for cations
        anion : str
            Selection string for anions
        center_box : bool
            If True, center the simulation box so z=0 is at box center
        '''
        
        # Create universe object FIRST
        if universe is not None:
            self.universe = universe
        elif top is not None and traj is not None:
            print(f"Loading trajectory from files:")
            print(f"  Topology: {top}")
            print(f"  Trajectory: {traj}")
            self.universe = mda.Universe(top, traj)
        else:
            raise ValueError("Must provide either 'universe' or both 'top' and 'traj' parameters")
        
        # NOW initialize parent class with trajectory
        super().__init__(self.universe.trajectory, **kwargs)
        
        self.n_bins = n_bins
        self.center_box = center_box
        
        # Store selection strings for later use
        self.water_selection = water
        self.water_oxygen_selection = water_oxygen
        self.water_hydrogen_selection = water_hydrogen
        self.cation_selection = cation
        self.anion_selection = anion
        
        # Create atom selections
        self.waters = self.universe.select_atoms(water)  # All water atoms
        self.water_oxygens = self.universe.select_atoms(water_oxygen)  # Only oxygens
        self.water_hydrogens = self.universe.select_atoms(water_hydrogen)  # Only hydrogens
        self.cations = self.universe.select_atoms(cation)
        self.anions = self.universe.select_atoms(anion)
        
        # FIX: Properly identify and store ion types as AtomGroup objects
        self.cation_types = self._identify_ion_types(self.cations)
        self.anion_types = self._identify_ion_types(self.anions)
        
        print(f"Z-directional analysis initialized:")
        print(f"  Total atoms: {self.universe.atoms.n_atoms}")
        print(f"  Total frames: {len(self.universe.trajectory)}")
        print(f"  Water molecules (OW): {len(self.water_oxygens)}")
        print(f"  Water hydrogens (HW): {len(self.water_hydrogens)}")
        print(f"  Total water atoms: {len(self.waters)}")
        print(f"  Cations: {len(self.cations)}")
        print(f"  Anions: {len(self.anions)}")
        
        # Determine z-range and centering
        if z_min is None or z_max is None:
            print("Determining z-range from trajectory...")
            self._determine_z_range_and_center()
        else:
            self.z_min = z_min
            self.z_max = z_max
            if center_box:
                print("Warning: Manual z_min/z_max specified with center_box=True")
                print("Centering will be skipped when z-range is manually specified")
        
        # Create z-bins
        self.z_edges = np.linspace(self.z_min, self.z_max, self.n_bins + 1)
        self.z_centers = (self.z_edges[:-1] + self.z_edges[1:]) / 2
        self.bin_width = (self.z_max - self.z_min) / self.n_bins
        
        print(f"Z-range: {self.z_min:.2f} - {self.z_max:.2f} Å")
        print(f"Box center at z = 0: {abs(self.z_min + self.z_max) < 0.1}")
        print(f"Bin width: {self.bin_width:.3f} Å")
        
        # Initialize results storage
        self.results = Results()

    def _determine_z_range_and_center(self, sample_frames=10):
        '''Determine z-range by sampling trajectory and optionally center the box'''
        
        frame_indices = np.linspace(0, len(self.universe.trajectory)-1, 
                                min(sample_frames, len(self.universe.trajectory)), 
                                dtype=int)
        
        all_z_coords = []
        box_z_sizes = []
        
        for frame_idx in frame_indices:
            self.universe.trajectory[frame_idx]
            all_z_coords.extend(self.universe.atoms.positions[:, 2])
            
            # Also collect box z-dimensions for centering
            if self.universe.dimensions is not None:
                box_z_sizes.append(self.universe.dimensions[2])
        
        all_z_coords = np.array(all_z_coords)
        
        if self.center_box:
            # Center the box around z=0
            print("Centering simulation box around z=0...")
            
            # Get average box size in z-direction
            if box_z_sizes:
                avg_box_z = np.mean(box_z_sizes)
                print(f"Average box z-dimension: {avg_box_z:.2f} Å")
                
                # Set z-range to be symmetric around 0
                half_box = avg_box_z / 2
                padding = half_box * 0.05  # 5% padding
                
                self.z_min = -half_box - padding
                self.z_max = half_box + padding
                
                print(f"Centered z-range: {self.z_min:.2f} to {self.z_max:.2f} Å")
                
            else:
                # Fallback: center based on actual coordinate range
                z_range = all_z_coords.max() - all_z_coords.min()
                z_center = (all_z_coords.max() + all_z_coords.min()) / 2
                
                padding = z_range * 0.05
                half_range = z_range / 2 + padding
                
                self.z_min = -half_range
                self.z_max = half_range
                
                print(f"Centered around coordinate range: {self.z_min:.2f} to {self.z_max:.2f} Å")
                print(f"Original center was at z = {z_center:.2f} Å")
        
        else:
            # Original method: use actual coordinate range
            padding = (all_z_coords.max() - all_z_coords.min()) * 0.05
            self.z_min = all_z_coords.min() - padding
            self.z_max = all_z_coords.max() + padding
            
            print(f"Using actual coordinate range: {self.z_min:.2f} to {self.z_max:.2f} Å")

    def _calculate_density_profiles(self, box_volume):
        '''Calculate density profiles for current frame with coordinate transformation'''
        
        if self.center_box:
            # Apply centering transformation to coordinates
            box_z = self.universe.dimensions[2] if self.universe.dimensions is not None else None
            
            if box_z is not None:
                # Transform coordinates to center the box at z=0
                z_offset = box_z / 2
                
                # Water density (both number density and raw counts)
                if len(self.waters) > 0:
                    water_z = self.waters.positions[:, 2] - z_offset
                    hist, _ = np.histogram(water_z, bins=self.z_edges)
                    self.results.water_density += hist / box_volume  # Number density (molecules/Å³)
                    self.results.water_counts += hist  # Raw counts
                
                # Cation density
                if len(self.cations) > 0:
                    cation_z = self.cations.positions[:, 2] - z_offset
                    hist, _ = np.histogram(cation_z, bins=self.z_edges)
                    self.results.cation_density += hist / box_volume
                    self.results.cation_counts += hist
                
                # Anion density
                if len(self.anions) > 0:
                    anion_z = self.anions.positions[:, 2] - z_offset
                    hist, _ = np.histogram(anion_z, bins=self.z_edges)
                    self.results.anion_density += hist / box_volume
                    self.results.anion_counts += hist
                
                # Ion-specific densities
                for ion_type, ion_group in self.cation_types.items():
                    if len(ion_group) > 0:
                        ion_z = ion_group.positions[:, 2] - z_offset
                        hist, _ = np.histogram(ion_z, bins=self.z_edges)
                        self.results.ion_densities_by_type[ion_type] += hist / box_volume
                        self.results.ion_counts_by_type[ion_type] += hist
                
                for ion_type, ion_group in self.anion_types.items():
                    if len(ion_group) > 0:
                        ion_z = ion_group.positions[:, 2] - z_offset
                        hist, _ = np.histogram(ion_z, bins=self.z_edges)
                        self.results.ion_densities_by_type[ion_type] += hist / box_volume
                        self.results.ion_counts_by_type[ion_type] += hist
                
                # Total density
                total_z = self.universe.atoms.positions[:, 2] - z_offset
                hist, _ = np.histogram(total_z, bins=self.z_edges)
                self.results.total_density += hist / box_volume
                self.results.total_counts += hist
                
            else:
                # Fallback to original method if box dimensions not available
                print("Warning: Box dimensions not available, using original coordinate system")
                self._calculate_density_profiles_original(box_volume)
        
        else:
            # Use original method
            self._calculate_density_profiles_original(box_volume)

    def _calculate_density_profiles_original(self, box_volume):
        '''Original density calculation method without coordinate transformation'''
        
        # Water density (both number density and raw counts)
        if len(self.waters) > 0:
            water_z = self.waters.positions[:, 2]
            hist, _ = np.histogram(water_z, bins=self.z_edges)
            self.results.water_density += hist / box_volume
            self.results.water_counts += hist
        
        # Cation density
        if len(self.cations) > 0:
            cation_z = self.cations.positions[:, 2]
            hist, _ = np.histogram(cation_z, bins=self.z_edges)
            self.results.cation_density += hist / box_volume
            self.results.cation_counts += hist
        
        # Anion density
        if len(self.anions) > 0:
            anion_z = self.anions.positions[:, 2]
            hist, _ = np.histogram(anion_z, bins=self.z_edges)
            self.results.anion_density += hist / box_volume
            self.results.anion_counts += hist
        
        # Ion-specific densities
        for ion_type, ion_group in self.cation_types.items():
            if len(ion_group) > 0:
                ion_z = ion_group.positions[:, 2]
                hist, _ = np.histogram(ion_z, bins=self.z_edges)
                self.results.ion_densities_by_type[ion_type] += hist / box_volume
                self.results.ion_counts_by_type[ion_type] += hist
        
        for ion_type, ion_group in self.anion_types.items():
            if len(ion_group) > 0:
                ion_z = ion_group.positions[:, 2]
                hist, _ = np.histogram(ion_z, bins=self.z_edges)
                self.results.ion_densities_by_type[ion_type] += hist / box_volume
                self.results.ion_counts_by_type[ion_type] += hist
        
        # Total density (atoms per unit volume)
        total_z = self.universe.atoms.positions[:, 2]
        hist, _ = np.histogram(total_z, bins=self.z_edges)
        self.results.total_density += hist / box_volume
        self.results.total_counts += hist

    def _calculate_coordination_vs_z(self, coordination_radius=3.0):
        '''Calculate coordination numbers as function of z with coordinate transformation'''
        
        # Determine z-offset for centering if needed
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # This requires coordination radii - simplified version
        for ion_type, ion_group in {**self.cation_types, **self.anion_types}.items():
            for ion in ion_group:
                ion_z = ion.position[2] - z_offset  # Apply centering offset
                
                # Count coordinating water molecules
                distances = np.linalg.norm(self.waters.positions - ion.position, axis=1)
                coordination_number = np.sum(distances <= coordination_radius)
                
                self.results.coordination_vs_z[ion_type]['z_positions'].append(ion_z)
                self.results.coordination_vs_z[ion_type]['coordination_numbers'].append(coordination_number)

    def _calculate_dipole_vs_z(self):
        '''Calculate water dipole orientation as function of z with coordinate transformation'''
        
        # Determine z-offset for centering if needed
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        for water_oxygen in self.waters:
            try:
                # Get hydrogen atoms bonded to this oxygen
                bonded_hydrogens = water_oxygen.bonded_atoms
                if len(bonded_hydrogens) >= 2:
                    # Calculate dipole vector (O→H direction: from H to O, physical dipole convention)
                    h_positions = bonded_hydrogens.positions
                    dipole_vector = water_oxygen.position - h_positions.mean(axis=0)
                    
                    # Calculate angle with z-axis
                    z_axis = np.array([0, 0, 1])
                    angle = np.arccos(np.dot(dipole_vector, z_axis) / 
                                    (np.linalg.norm(dipole_vector) * np.linalg.norm(z_axis)))
                    angle_degrees = np.degrees(angle)
                    
                    # Apply centering offset to z-coordinate
                    water_z = water_oxygen.position[2] - z_offset
                    
                    self.results.dipole_vs_z['z_positions'].append(water_z)
                    self.results.dipole_vs_z['dipole_angles'].append(angle_degrees)
            except:
                continue  # Skip if bonding information not available

