    def _setup_results_storage(self):
        '''Initialize storage arrays for all analysis results'''
        
        # Basic density profiles (both density and counts)
        self.results.z_centers = self.z_centers
        self.results.z_edges = self.z_edges
        
        # Density profiles (number/Å³)
        self.results.water_density = np.zeros(self.n_bins)
        self.results.cation_density = np.zeros(self.n_bins)
        self.results.anion_density = np.zeros(self.n_bins)
        self.results.total_density = np.zeros(self.n_bins)
        
        # Count profiles (raw counts)
        self.results.water_counts = np.zeros(self.n_bins)
        self.results.cation_counts = np.zeros(self.n_bins)
        self.results.anion_counts = np.zeros(self.n_bins)
        self.results.total_counts = np.zeros(self.n_bins)
        
        # Identify different ion types
        self.cation_types = self._identify_ion_types(self.cations)
        self.anion_types = self._identify_ion_types(self.anions)
        
        # Ion-specific storage - use string keys consistently
        self.results.ion_densities_by_type = {}
        self.results.ion_counts_by_type = {}
        
        # Initialize ion-specific arrays with string keys
        for ion_type in {**self.cation_types, **self.anion_types}:
            # Convert numpy string to regular string for consistent keys
            ion_key = str(ion_type)
            self.results.ion_densities_by_type[ion_key] = np.zeros(self.n_bins)
            self.results.ion_counts_by_type[ion_key] = np.zeros(self.n_bins)
        
        # Coordination analysis storage
        self.results.coordination_vs_z = {}
        for ion_type in {**self.cation_types, **self.anion_types}:
            ion_key = str(ion_type)
            self.results.coordination_vs_z[ion_key] = {
                'z_positions': [],
                'coordination_numbers': []
            }
        
        # Dipole orientation storage
        self.results.dipole_vs_z = {
            'z_positions': [],
            'dipole_angles': []
        }
        
        # Per-frame histogram storage for bootstrap
        self.results.per_frame_histograms = {
            'ion_densities_by_type': {str(ion_type): [] for ion_type in {**self.cation_types, **self.anion_types}},
            'frame_indices': [],
            'n_frames_stored': 0,
            'store_per_frame': False  # Will be enabled when bootstrap is requested
        }

        # Frame counter
        self.n_frames_analyzed = 0
        

    def _identify_ion_types(self, ion_group):
        '''Identify different ion types within a group'''
        
        ion_types = {}
        
        # Group by residue name
        unique_resnames = np.unique([atom.resname for atom in ion_group])
        
        for resname in unique_resnames:
            atoms_of_type = ion_group.select_atoms(f'resname {resname}')
            if len(atoms_of_type) > 0:
                ion_types[resname] = atoms_of_type
        
        return ion_types

    def _single_frame(self):
        '''Analyze single frame - called by MDAnalysis during trajectory iteration'''
        
        # Calculate box volume for this frame
        box_volume = self._calculate_box_volume()
        
        # Calculate density profiles
        self._calculate_density_profiles(box_volume)
        
        # Calculate coordination vs z (sample every few frames to save time)
        if self.n_frames_analyzed % 5 == 0:  # Every 5th frame
            self._calculate_coordination_vs_z()
        
        # Calculate water dipole orientation (sample every few frames)
        if self.n_frames_analyzed % 10 == 0:  # Every 10th frame
            self._calculate_dipole_vs_z()
        
        # Store per-frame histograms if requested (for bootstrap)
        if self.results.per_frame_histograms['store_per_frame']:
            self._store_frame_histograms()

        self.n_frames_analyzed += 1


