    def _store_frame_histograms(self):
        '''Store per-frame histograms for bootstrap analysis'''
        
        # Determine z-offset for centering if needed
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Calculate box volume for this frame
        box_volume = self._calculate_box_volume()
        
        # Store histograms for each ion type
        for ion_type, ion_group in {**self.cation_types, **self.anion_types}.items():
            # Convert to string key for consistency
            ion_key = str(ion_type)
            
            if len(ion_group) > 0:
                # Get ion positions with centering offset
                ion_positions = ion_group.positions.copy()
                ion_z = ion_positions[:, 2] - z_offset
                
                # Create histogram for this frame
                hist, _ = np.histogram(ion_z, bins=self.z_edges)
                
                # Store as density (divide by volume)
                frame_density = hist / box_volume
                
                # Append to per-frame storage
                self.results.per_frame_histograms['ion_densities_by_type'][ion_key].append(frame_density)
            else:
                # Store zeros if no ions of this type
                zero_density = np.zeros(self.n_bins)
                self.results.per_frame_histograms['ion_densities_by_type'][ion_key].append(zero_density)
        
        # Store frame index
        current_frame = self.universe.trajectory.ts.frame
        self.results.per_frame_histograms['frame_indices'].append(current_frame)
        self.results.per_frame_histograms['n_frames_stored'] += 1


    def enable_bootstrap_data_collection(self):
        '''Enable collection of per-frame data for bootstrap analysis'''
        
        if not hasattr(self.results, 'per_frame_histograms'):
            print("❌ Results storage not initialized. Run _setup_results_storage() first.")
            return False
        
        self.results.per_frame_histograms['store_per_frame'] = True
        print("✅ Per-frame histogram collection enabled for bootstrap analysis")
        return True

    def disable_bootstrap_data_collection(self):
        '''Disable per-frame data collection to save memory'''
        if hasattr(self.results, 'per_frame_histograms'):
            self.results.per_frame_histograms['store_per_frame'] = False
            print("⚠️  Per-frame histogram collection disabled")


    def _calculate_box_volume(self):
        '''Calculate volume per bin for density normalization'''
        
        if self.universe.dimensions is not None:
            # Get box dimensions (assume rectangular box)
            box_x, box_y, box_z = self.universe.dimensions[:3]
            
            # Volume of one z-bin
            bin_volume = box_x * box_y * self.bin_width
            
            return bin_volume
        else:
            # Fallback: estimate from coordinate ranges
            print("Warning: Box dimensions not available, using coordinate-based volume estimation")
            
            # Get coordinate ranges
            coords = self.universe.atoms.positions
            x_range = coords[:, 0].max() - coords[:, 0].min()
            y_range = coords[:, 1].max() - coords[:, 1].min()
            
            bin_volume = x_range * y_range * self.bin_width
            return bin_volume

    def _conclude(self):
        '''Finalize analysis after all frames processed'''
        
        print(f"Analysis complete: {self.n_frames_analyzed} frames processed")
        
        # Normalize densities by number of frames
        self.results.water_density /= self.n_frames_analyzed
        self.results.cation_density /= self.n_frames_analyzed
        self.results.anion_density /= self.n_frames_analyzed
        self.results.total_density /= self.n_frames_analyzed
        
        # Normalize counts by number of frames (to get average counts per frame)
        self.results.water_counts /= self.n_frames_analyzed
        self.results.cation_counts /= self.n_frames_analyzed
        self.results.anion_counts /= self.n_frames_analyzed
        self.results.total_counts /= self.n_frames_analyzed
        
        # Normalize ion-specific densities and counts
        for ion_type in self.results.ion_densities_by_type:
            self.results.ion_densities_by_type[ion_type] /= self.n_frames_analyzed
            self.results.ion_counts_by_type[ion_type] /= self.n_frames_analyzed



