    def _get_ion_selection(self, ion_type):
        """
        Helper method to get ion selection for a given ion type.
        
        Parameters
        ----------
        ion_type : str
            Ion type (e.g., 'NA', 'CL', 'MG', etc.)
        
        Returns
        -------
        AtomGroup or None
            MDAnalysis AtomGroup for the requested ion type
        """
        
        # Try to find the ion group from existing cation/anion types
        if hasattr(self, 'cation_types') and ion_type in self.cation_types:
            ion_group = self.cation_types[ion_type]
            if hasattr(ion_group, 'positions'):
                return ion_group
        
        if hasattr(self, 'anion_types') and ion_type in self.anion_types:
            ion_group = self.anion_types[ion_type]
            if hasattr(ion_group, 'positions'):
                return ion_group
        
        # Fallback: Try direct selection
        try:
            if ion_type.upper() == 'NA':
                return self.universe.select_atoms('name NA')
            elif ion_type.upper() == 'CL':
                return self.universe.select_atoms('name CL') 
            elif ion_type.upper() == 'MG':
                return self.universe.select_atoms('name MG')
            elif ion_type.upper() == 'CA':
                return self.universe.select_atoms('name CA')
            elif ion_type.upper() == 'K':
                return self.universe.select_atoms('name K')
            else:
                return self.universe.select_atoms(f'name {ion_type.upper()}')
        except:
            return None


    def calculate_pmf_vs_z_from_ion_density(z_analysis, ion_types=None, target_z_values=None, step=1,
                                                z_slice_width=3.0, xy_grid_size=4.0, 
                                                temperature=298.15, reference_z=0.0,
                                                use_cache=True, cache_filename=None, force_recalculate=False):
        """
        Debug script to count cubes, analyze ion density, and calculate PMF for 3D calculation
        
        Parameters
        ----------
        z_analysis : ZDirectionalAnalysis
            Your analysis object (to get box dimensions and ion data)
        ion_types : list or None
            List of ion types to analyze (e.g., ['NA', 'MG', 'CL']). If None, defaults to ['NA']
        target_z_values : list
            Z-positions for slice centers
        z_slice_width : float
            Thickness of each z-slab (Å)
        xy_grid_size : float
            Size of each cube in XY plane (Å)
        temperature : float
            Temperature in Kelvin for PMF calculation
        reference_z : float, default=0.0
            Z-position to use as reference (bulk) for PMF calculation (Å)
        use_cache : bool, default=True
            Whether to use cached results if available
        cache_filename : str, optional
            Custom filename for cache. If None, auto-generates based on parameters
        force_recalculate : bool, default=False
            Force recalculation even if cache exists
        """
        
        print("🔍 CUBE COUNTING + ION DENSITY + PMF DEBUG SCRIPT")
        print("=" * 70)
        
        # Handle ion_types parameter
        if ion_types is None:
            ion_types = ['NA']  # Default to NA if not specified
        elif isinstance(ion_types, str):
            ion_types = [ion_types]  # Convert single string to list
        
        print(f"🧂 Ion types to analyze: {ion_types}")
        
        # Generate cache filename if not provided
        if cache_filename is None:
            # Create hash from parameters for unique cache filename
            import hashlib
            ions_str = "_".join(sorted(ion_types))
            z_vals_str = "_".join([f"{z:.1f}" for z in sorted(target_z_values)])
            param_str = f"{ions_str}_z{z_vals_str}_w{z_slice_width}_xy{xy_grid_size}_T{temperature}_ref{reference_z}_step{step}"
            param_hash = hashlib.md5(param_str.encode()).hexdigest()[:8]
            cache_filename = f"pmf_density_cache_{param_hash}.npz"
        
        print(f"💾 Cache filename: {cache_filename}")
        
        # Check for existing cache
        if use_cache and not force_recalculate:
            import os
            if os.path.exists(cache_filename):
                print(f"📂 Found existing cache file: {cache_filename}")
                try:
                    print("   Loading cached results...")
                    cached_data = np.load(cache_filename, allow_pickle=True)
                    
                    # Reconstruct results from cache
                    cached_results = {
                        'box_dimensions': tuple(cached_data['box_dimensions']),
                        'xy_grid_size': float(cached_data['xy_grid_size']),
                        'z_slice_width': float(cached_data['z_slice_width']),
                        'n_x_cubes': int(cached_data['n_x_cubes']),
                        'n_y_cubes': int(cached_data['n_y_cubes']),
                        'cubes_per_slab': int(cached_data['cubes_per_slab']),
                        'cube_volume': float(cached_data['cube_volume']),
                        'x_centers': cached_data['x_centers'],
                        'y_centers': cached_data['y_centers'],
                        'x_edges': cached_data['x_edges'],
                        'y_edges': cached_data['y_edges'],
                        'ion_types': list(cached_data['ion_types']),
                        'n_frames_analyzed': int(cached_data['n_frames_analyzed']),
                        'bulk_densities': cached_data['bulk_densities'].item(),
                        'temperature': float(cached_data['temperature']),
                        'kT_kJ_mol': float(cached_data['kT_kJ_mol']),
                        'reference_slab_idx': int(cached_data['reference_slab_idx']) if cached_data['reference_slab_idx'] is not None else None,
                        'reference_z': float(cached_data['reference_z']),
                        'reference_in_original_targets': bool(cached_data['reference_in_original_targets']),
                        'original_target_z_values': list(cached_data['original_target_z_values']),
                        'analysis_z_values': list(cached_data['analysis_z_values']),
                    }
                    
                    # Reconstruct slab_results from flattened structure
                    slab_results = {}
                    
                    # Find all unique slab_idx and ion_type combinations
                    slab_ion_combos = set()
                    for key in cached_data.files:
                        if key.startswith('slab_') and '_target_z' in key:
                            # Extract slab_idx and ion_type from key like "slab_0_NA_target_z"
                            parts = key.replace('_target_z', '').split('_')
                            if len(parts) >= 3:
                                slab_idx = int(parts[1])
                                ion_type = '_'.join(parts[2:])  # Handle ion types with underscores
                                slab_ion_combos.add((slab_idx, ion_type))
                    
                    # Reconstruct each slab's data
                    for slab_idx, ion_type in sorted(slab_ion_combos):
                        if slab_idx not in slab_results:
                            slab_results[slab_idx] = {}
                        
                        key_prefix = f"slab_{slab_idx}_{ion_type}"
                        slab_results[slab_idx][ion_type] = {
                            'target_z': float(cached_data[f"{key_prefix}_target_z"]),
                            'density_grid': cached_data[f"{key_prefix}_density_grid"],
                            'pmf_grid': cached_data[f"{key_prefix}_pmf_grid"],
                            'total_density': float(cached_data[f"{key_prefix}_total_density"]),
                            'mean_density': float(cached_data[f"{key_prefix}_mean_density"]),
                            'max_density': float(cached_data[f"{key_prefix}_max_density"]),
                            'non_zero_cubes': int(cached_data[f"{key_prefix}_non_zero_cubes"]),
                            'pmf_mean': float(cached_data[f"{key_prefix}_pmf_mean"]),
                            'pmf_stats': {
                                'finite_pmfs': cached_data[f"{key_prefix}_pmf_stats_finite_pmfs"],
                                'favorable_cubes': int(cached_data[f"{key_prefix}_pmf_stats_favorable_cubes"]),
                                'neutral_cubes': int(cached_data[f"{key_prefix}_pmf_stats_neutral_cubes"]),
                                'unfavorable_cubes': int(cached_data[f"{key_prefix}_pmf_stats_unfavorable_cubes"])
                            },
                            'x_centers': cached_data[f"{key_prefix}_x_centers"],
                            'y_centers': cached_data[f"{key_prefix}_y_centers"],
                            'bulk_density': float(cached_data[f"{key_prefix}_bulk_density"])
                        }
                    
                    cached_results['slab_results'] = slab_results
                    
                    # Reconstruct slab_total_densities from flattened structure
                    slab_total_densities = {}
                    for key in cached_data.files:
                        if key.startswith('slab_total_'):
                            # Extract slab_idx and ion_type from key like "slab_total_0_NA"
                            parts = key.replace('slab_total_', '').split('_', 1)
                            if len(parts) == 2:
                                slab_idx = int(parts[0])
                                ion_type = parts[1]
                                
                                if slab_idx not in slab_total_densities:
                                    slab_total_densities[slab_idx] = {}
                                
                                slab_total_densities[slab_idx][ion_type] = float(cached_data[key])
                    
                    cached_results['slab_total_densities'] = slab_total_densities
                    
                    # Note: ion_atoms cannot be cached (they're MDAnalysis objects)
                    # We'll set to None - user should not rely on this field from cached data
                    cached_results['ion_atoms'] = None
                    
                    print("   ✅ Cache loaded successfully!")
                    print(f"   📊 Cached data contains {len(slab_results)} slabs for {len(ion_types)} ion types")
                    print("=" * 70)
                    return cached_results
                    
                except Exception as e:
                    print(f"   ⚠️ Failed to load cache: {e}")
                    print("   Proceeding with fresh calculation...")
            else:
                print(f"   No cache file found, will calculate and save to cache")
        elif force_recalculate:
            print(f"   🔄 Force recalculate enabled, ignoring any existing cache")
        
        # Handle reference_z inclusion - automatically add if not in target range
        original_target_z_values = list(target_z_values)  # Store original targets
        reference_in_targets = any(abs(z - reference_z) < 0.01 for z in target_z_values)
        
        if not reference_in_targets:
            # Add reference_z to analysis but keep track of original targets
            extended_z_values = sorted(list(target_z_values) + [reference_z])
            print(f"🎯 Reference z = {reference_z:.1f} Å not in target range")
            print(f"   Automatically adding reference slice for bulk density calculation")
            print(f"   Extended analysis range: {len(extended_z_values)} slices (including reference)")
            analysis_z_values = extended_z_values
        else:
            print(f"🎯 Reference z = {reference_z:.1f} Å found in target range")
            analysis_z_values = target_z_values
        
        print(f"   Analysis will process: {len(analysis_z_values)} z-slices")
        print(f"   Results will be returned for: {len(original_target_z_values)} original target slices")
        
        # Physical constants
        kB = 1.380649e-23  # J/K
        kT_J = kB * temperature  # J
        kT_kJ_mol = kT_J * 6.02214076e23 / 1000  # kJ/mol
        
        print(f"🌡️  Temperature: {temperature:.2f} K")
        print(f"   kT = {kT_kJ_mol:.4f} kJ/mol")
        
        # Get simulation box dimensions
        box_dims = z_analysis.universe.dimensions
        box_x, box_y, box_z = box_dims[0], box_dims[1], box_dims[2]
        
        print(f"\n📦 Simulation Box Dimensions:")
        print(f"   X: {box_x:.2f} Å")
        print(f"   Y: {box_y:.2f} Å") 
        print(f"   Z: {box_z:.2f} Å")
        print(f"   Total volume: {box_x * box_y * box_z:.2f} Å³")
        
        # Calculate XY grid
        n_x_cubes = int(np.ceil(box_x / xy_grid_size))
        n_y_cubes = int(np.ceil(box_y / xy_grid_size))
        
        print(f"\n🔲 XY Grid Calculation:")
        print(f"   XY grid size: {xy_grid_size:.1f} Å")
        print(f"   X cubes: {box_x:.1f} Å ÷ {xy_grid_size:.1f} Å = {n_x_cubes} cubes")
        print(f"   Y cubes: {box_y:.1f} Å ÷ {xy_grid_size:.1f} Å = {n_y_cubes} cubes")
        print(f"   Total XY cubes per z-slice: {n_x_cubes} × {n_y_cubes} = {n_x_cubes * n_y_cubes} cubes")
        
        # Calculate cube volume
        cube_volume = xy_grid_size * xy_grid_size * z_slice_width
        print(f"\n📏 Individual Cube Properties:")
        print(f"   Cube dimensions: {xy_grid_size:.1f} × {xy_grid_size:.1f} × {z_slice_width:.1f} Å")
        print(f"   Cube volume: {cube_volume:.2f} Å³")
        
        # Create grid coordinates
        x_edges = np.linspace(0, box_x, n_x_cubes + 1)
        y_edges = np.linspace(0, box_y, n_y_cubes + 1)
        x_centers = (x_edges[:-1] + x_edges[1:]) / 2
        y_centers = (y_edges[:-1] + y_edges[1:]) / 2
        
        # Get ion atoms for all requested ion types
        ion_atoms = {}
        for ion_type in ion_types:
            try:
                atoms = z_analysis.universe.select_atoms(f"name {ion_type}")
                ion_atoms[ion_type] = atoms
                print(f"\n🧂 Found {len(atoms)} {ion_type} atoms in system")
            except:
                print(f"\n❌ No {ion_type} atoms found in system!")
                ion_atoms[ion_type] = None
        
        # Get z-offset for centering
        z_offset = 0
        if z_analysis.center_box and z_analysis.universe.dimensions is not None:
            z_offset = z_analysis.universe.dimensions[2] / 2
        
        print(f"\n   Z-offset for centering: {z_offset:.2f} Å")
        
        # Initialize storage for density analysis
        slab_results = {}
        slab_total_densities = {}
        
        print(f"\n🎯 Z-SLAB ANALYSIS WITH ION DENSITY + PMF:")
        print(f"   Analysis z-values: {analysis_z_values}")
        print(f"   Original target z-values: {original_target_z_values}")
        print(f"   Z-slice width: {z_slice_width:.1f} Å")
        print(f"   Reference position: z = {reference_z:.1f} Å (bulk)")
        print()
        
        # Process each frame to get average ion density
        frame_indices = range(0, len(z_analysis.universe.trajectory), step)
        print(f"📊 Sampling {len(frame_indices)} frames (every {step} frames) for ion density calculation...")
        
        # Initialize density grids for each slab and ion type
        slab_density_grids = {}
        for i, target_z in enumerate(analysis_z_values):
            slab_density_grids[i] = {}
            for ion_type in ion_types:
                if ion_atoms[ion_type] is not None:
                    slab_density_grids[i][ion_type] = np.zeros((n_y_cubes, n_x_cubes))
        
        # Process frames
        for frame_idx in frame_indices:
            z_analysis.universe.trajectory[frame_idx]
            
            # Process each z-slab
            for i, target_z in enumerate(analysis_z_values):
                z_min = target_z - z_slice_width / 2
                z_max = target_z + z_slice_width / 2
                
                # Process each ion type
                for ion_type in ion_types:
                    if ion_atoms[ion_type] is None:
                        continue
                    
                    # Get ion positions
                    ion_positions = ion_atoms[ion_type].positions.copy()
                    if z_analysis.center_box:
                        ion_positions[:, 2] -= z_offset
                    
                    # Select atoms in this z-slab
                    z_mask = (ion_positions[:, 2] >= z_min) & (ion_positions[:, 2] <= z_max)
                    ions_in_slab = ion_positions[z_mask]
                    
                    if len(ions_in_slab) > 0:
                        # Apply periodic boundary conditions
                        ions_in_slab[:, 0] = ions_in_slab[:, 0] % box_x
                        ions_in_slab[:, 1] = ions_in_slab[:, 1] % box_y
                        
                        # Create 2D histogram for this slab
                        H, _, _ = np.histogram2d(ions_in_slab[:, 1], ions_in_slab[:, 0], 
                                            bins=[y_edges, x_edges])
                        slab_density_grids[i][ion_type] += H
        
        # Average over frames and convert to density
        for i in range(len(analysis_z_values)):
            for ion_type in ion_types:
                if ion_type in slab_density_grids[i]:
                    slab_density_grids[i][ion_type] /= len(frame_indices)  # Average over frames
                    slab_density_grids[i][ion_type] /= cube_volume  # Convert to density (ions/Å³)
        
        # Find reference density (z = reference_z Å)
        reference_slab_idx = None
        for i, target_z in enumerate(analysis_z_values):
            if abs(target_z - reference_z) < 0.1:  # Find z ≈ reference_z
                reference_slab_idx = i
                break
        
        # Calculate bulk densities for each ion type
        bulk_densities = {}
        for ion_type in ion_types:
            if reference_slab_idx is not None and ion_type in slab_density_grids[reference_slab_idx]:
                bulk_densities[ion_type] = np.mean(slab_density_grids[reference_slab_idx][ion_type])
                print(f"📍 Reference bulk density for {ion_type} (z = {reference_z:.1f} Å): {bulk_densities[ion_type]:.8f} ions/Å³")
            else:
                # Fallback: use overall average for this ion type
                all_densities = []
                for i in range(len(analysis_z_values)):
                    if ion_type in slab_density_grids[i]:
                        all_densities.extend(slab_density_grids[i][ion_type].flatten())
                bulk_densities[ion_type] = np.mean(all_densities) if all_densities else 0.0
                print(f"📍 Fallback bulk density for {ion_type} (overall average): {bulk_densities[ion_type]:.8f} ions/Å³")
        
        print()
        
        # Analyze each z-slab
        for i, target_z in enumerate(analysis_z_values):
            # Check if this is an original target or added reference
            is_original_target = target_z in original_target_z_values
            is_reference_slice = abs(target_z - reference_z) < 0.01
            
            slab_label = f"Z-SLAB {i+1}"
            if is_reference_slice and not is_original_target:
                slab_label += " (REFERENCE - auto-added)"
            elif is_reference_slice:
                slab_label += " (REFERENCE)"
            
            print(f"📍 {slab_label}: z = {target_z:.1f} Å")
            
            # Calculate z-slab boundaries
            z_min = target_z - z_slice_width / 2
            z_max = target_z + z_slice_width / 2
            
            print(f"   Z boundaries: {z_min:.1f} to {z_max:.1f} Å")
            print(f"   Z thickness: {z_max - z_min:.1f} Å")
            
            # Check if z-slab is within simulation box
            if z_analysis.center_box:
                sim_z_min = -box_z / 2
                sim_z_max = box_z / 2
            else:
                sim_z_min = 0
                sim_z_max = box_z
            
            print(f"   Simulation Z-range: {sim_z_min:.1f} to {sim_z_max:.1f} Å")
            
            # Check overlap
            overlap_min = max(z_min, sim_z_min)
            overlap_max = min(z_max, sim_z_max)
            
            if overlap_max > overlap_min:
                overlap_thickness = overlap_max - overlap_min
                overlap_fraction = overlap_thickness / z_slice_width
                
                print(f"   ✅ Z-slab overlaps with simulation box")
                print(f"   Overlap region: {overlap_min:.1f} to {overlap_max:.1f} Å")
                print(f"   Overlap thickness: {overlap_thickness:.1f} Å ({overlap_fraction*100:.1f}% of slab)")
                
                # Analyze each ion type in this slab
                slab_ion_results = {}
                
                for ion_type in ion_types:
                    if ion_type not in slab_density_grids[i] or ion_atoms[ion_type] is None:
                        continue
                    
                    print(f"\n   🧂 {ion_type} DENSITY ANALYSIS:")
                    
                    # Get density grid for this ion type
                    density_grid = slab_density_grids[i][ion_type]
                    
                    # Calculate statistics
                    total_density = np.sum(density_grid)
                    mean_density = np.mean(density_grid)
                    max_density = np.max(density_grid)
                    min_density = np.min(density_grid)
                    non_zero_cubes = np.sum(density_grid > 0)
                    
                    # Store total density for comparison
                    if i not in slab_total_densities:
                        slab_total_densities[i] = {}
                    slab_total_densities[i][ion_type] = total_density
                    
                    print(f"     Total cubes: {n_x_cubes * n_y_cubes}")
                    print(f"     Cubes with {ion_type}: {non_zero_cubes}")
                    print(f"     Empty cubes: {n_x_cubes * n_y_cubes - non_zero_cubes}")
                    print(f"     Total density: {total_density:.6f} ions/Å³")
                    print(f"     Mean density per cube: {mean_density:.6f} ions/Å³")
                    print(f"     Max density in any cube: {max_density:.6f} ions/Å³")
                    print(f"     Min density: {min_density:.6f} ions/Å³")
                    
                    # Calculate PMF for this ion type
                    print(f"   ⚡ {ion_type} PMF ANALYSIS:")
                    
                    bulk_density = bulk_densities[ion_type]
                    
                    # Calculate PMF for mean density of this slab
                    if bulk_density > 0 and mean_density > 0:
                        pmf_mean = -kT_kJ_mol * np.log(mean_density / bulk_density)
                        print(f"     PMF (slab average): {pmf_mean:.3f} kJ/mol")
                    else:
                        pmf_mean = float('inf')
                        print(f"     PMF (slab average): ∞ (zero density)")
                    
                    # Calculate PMF statistics for all cubes
                    pmf_grid = np.full_like(density_grid, float('inf'))
                    valid_mask = density_grid > 0
                    
                    if np.any(valid_mask) and bulk_density > 0:
                        pmf_grid[valid_mask] = -kT_kJ_mol * np.log(density_grid[valid_mask] / bulk_density)
                        
                        finite_pmfs = pmf_grid[np.isfinite(pmf_grid)]
                        if len(finite_pmfs) > 0:
                            print(f"     PMF statistics (cube-by-cube):")
                            print(f"       Mean PMF: {np.mean(finite_pmfs):.3f} kJ/mol")
                            print(f"       Min PMF:  {np.min(finite_pmfs):.3f} kJ/mol")
                            print(f"       Max PMF:  {np.max(finite_pmfs):.3f} kJ/mol")
                            print(f"       Std PMF:  {np.std(finite_pmfs):.3f} kJ/mol")
                            print(f"       Cubes with finite PMF: {len(finite_pmfs)}")
                            
                            # PMF ranges classification
                            favorable_cubes = np.sum(finite_pmfs < -1.0)  # > 1 kJ/mol favorable
                            neutral_cubes = np.sum(np.abs(finite_pmfs) <= 1.0)  # ±1 kJ/mol neutral
                            unfavorable_cubes = np.sum(finite_pmfs > 1.0)  # > 1 kJ/mol unfavorable
                            
                            print(f"     PMF distribution:")
                            print(f"       Favorable (< -1 kJ/mol): {favorable_cubes} cubes")
                            print(f"       Neutral (±1 kJ/mol): {neutral_cubes} cubes")
                            print(f"       Unfavorable (> +1 kJ/mol): {unfavorable_cubes} cubes")
                        else:
                            print(f"     No finite PMF values calculated")
                            finite_pmfs = np.array([])
                            favorable_cubes = neutral_cubes = unfavorable_cubes = 0
                    else:
                        print(f"     No valid density data for PMF calculation")
                        finite_pmfs = np.array([])
                        favorable_cubes = neutral_cubes = unfavorable_cubes = 0
                    
                    # Reference comparison
                    if i == reference_slab_idx:
                        print(f"     🎯 REFERENCE SLAB (bulk)")
                        print(f"       This slab defines bulk density: {bulk_density:.8f} ions/Å³")
                        print(f"       PMF should be ~0 kJ/mol: {pmf_mean:.3f} kJ/mol")
                    else:
                        relative_density = mean_density / bulk_density if bulk_density > 0 else 0
                        print(f"     Relative to bulk:")
                        print(f"       Density ratio: {relative_density:.3f}")
                        if relative_density > 1.1:
                            print(f"       → Enhanced accumulation (+{(relative_density-1)*100:.1f}%)")
                        elif relative_density < 0.9:
                            print(f"       → Depletion ({(1-relative_density)*100:.1f}% less)")
                        else:
                            print(f"       → Similar to bulk")
                    
                    # Find highest and lowest PMF cubes
                    if np.any(np.isfinite(pmf_grid)):
                        finite_mask = np.isfinite(pmf_grid)
                        
                        # Lowest PMF (most favorable)
                        min_pmf_idx = np.unravel_index(np.nanargmin(pmf_grid), pmf_grid.shape)
                        min_pmf_val = pmf_grid[min_pmf_idx]
                        min_x_center = x_centers[min_pmf_idx[1]]
                        min_y_center = y_centers[min_pmf_idx[0]]
                        
                        # Highest PMF (least favorable)
                        max_pmf_idx = np.unravel_index(np.nanargmax(pmf_grid[finite_mask]), pmf_grid.shape)
                        max_pmf_val = pmf_grid[max_pmf_idx]
                        max_x_center = x_centers[max_pmf_idx[1]]
                        max_y_center = y_centers[max_pmf_idx[0]]
                        
                        print(f"     Extreme PMF locations:")
                        print(f"       Most favorable: PMF = {min_pmf_val:.3f} kJ/mol at ({min_x_center:.1f}, {min_y_center:.1f}) Å")
                        print(f"       Least favorable: PMF = {max_pmf_val:.3f} kJ/mol at ({max_x_center:.1f}, {max_y_center:.1f}) Å")
                    
                    # Find highest density cubes
                    flat_indices = np.argsort(density_grid.flatten())[-5:]  # Top 5 cubes
                    top_densities = density_grid.flatten()[flat_indices][::-1]  # Reverse for descending order
                    
                    print(f"     TOP 5 HIGHEST DENSITY CUBES for {ion_type}:")
                    for rank, (flat_idx, density_val) in enumerate(zip(flat_indices[::-1], top_densities)):
                        if density_val > 0:
                            y_idx, x_idx = np.unravel_index(flat_idx, density_grid.shape)
                            x_center = x_centers[x_idx]
                            y_center = y_centers[y_idx]
                            
                            # Calculate PMF for this cube
                            if bulk_density > 0:
                                cube_pmf = -kT_kJ_mol * np.log(density_val / bulk_density)
                                print(f"       #{rank+1}: Cube ({x_idx:2d},{y_idx:2d}) at XY=({x_center:5.1f},{y_center:5.1f}) Å")
                                print(f"             density={density_val:.6f} ions/Å³, PMF={cube_pmf:.3f} kJ/mol")
                            else:
                                print(f"       #{rank+1}: Cube ({x_idx:2d},{y_idx:2d}) at XY=({x_center:5.1f},{y_center:5.1f}) Å")
                                print(f"             density={density_val:.6f} ions/Å³, PMF=∞")
                    
                    # Store detailed results including PMF for this ion type
                    slab_ion_results[ion_type] = {
                        'target_z': target_z,
                        'density_grid': density_grid,
                        'pmf_grid': pmf_grid,
                        'total_density': total_density,
                        'mean_density': mean_density,
                        'max_density': max_density,
                        'non_zero_cubes': non_zero_cubes,
                        'pmf_mean': pmf_mean,
                        'pmf_stats': {
                            'finite_pmfs': finite_pmfs,
                            'favorable_cubes': favorable_cubes,
                            'neutral_cubes': neutral_cubes,
                            'unfavorable_cubes': unfavorable_cubes
                        },
                        'x_centers': x_centers,
                        'y_centers': y_centers,
                        'bulk_density': bulk_density
                    }
                
                # Store results for this slab
                if i not in slab_results:
                    slab_results[i] = {}
                slab_results[i] = slab_ion_results
                
            else:
                print(f"   ❌ Z-slab is OUTSIDE simulation box!")
                for ion_type in ion_types:
                    if i not in slab_total_densities:
                        slab_total_densities[i] = {}
                    slab_total_densities[i][ion_type] = 0.0
                
            print()
        
        # Find slab with highest total density for each ion type
        for ion_type in ion_types:
            if ion_atoms[ion_type] is None:
                continue
            
            # Get total densities for this ion type across all slabs
            ion_slab_densities = {}
            for slab_idx, slab_data in slab_total_densities.items():
                if ion_type in slab_data:
                    ion_slab_densities[slab_idx] = slab_data[ion_type]
            
            if ion_slab_densities:
                max_density_slab = max(ion_slab_densities, key=ion_slab_densities.get)
                max_density_value = ion_slab_densities[max_density_slab]
                max_density_z = analysis_z_values[max_density_slab]
                
                print(f"🏆 HIGHEST TOTAL {ion_type} DENSITY:")
                print(f"   Z-SLAB {max_density_slab + 1} (z = {max_density_z:.1f} Å)")
                print(f"   Total density: {max_density_value:.6f} ions/Å³")
                print(f"   This represents the z-position with highest {ion_type} accumulation")
                
                # Calculate PMF for this high-density region
                if max_density_slab in slab_results and ion_type in slab_results[max_density_slab]:
                    max_slab_result = slab_results[max_density_slab][ion_type]
                    max_slab_pmf = max_slab_result['pmf_mean']
                    print(f"   PMF at highest density slab: {max_slab_pmf:.3f} kJ/mol")
        
        # Show comparison between ion types
        print(f"\n📊 DENSITY AND PMF COMPARISON BETWEEN ION TYPES:")
        for i, target_z in enumerate(analysis_z_values):
            is_reference_slice = abs(target_z - reference_z) < 0.01
            is_original_target = target_z in original_target_z_values
            
            slab_info = f"Z-SLAB {i + 1} (z={target_z:5.1f} Å)"
            if is_reference_slice and not is_original_target:
                slab_info += " [AUTO-ADDED REF]"
            
            print(f"\n   {slab_info}:")
            for ion_type in ion_types:
                if i in slab_total_densities and ion_type in slab_total_densities[i]:
                    total_dens = slab_total_densities[i][ion_type]
                    
                    pmf_info = ""
                    if i in slab_results and ion_type in slab_results[i]:
                        pmf_val = slab_results[i][ion_type]['pmf_mean']
                        if np.isfinite(pmf_val):
                            pmf_info = f", PMF={pmf_val:+.3f} kJ/mol"
                        else:
                            pmf_info = ", PMF=∞"
                    
                    ref_marker = " (REFERENCE)" if abs(target_z - reference_z) < 0.1 else ""
                    
                    print(f"     {ion_type}: {total_dens:.6f} ions/Å³{pmf_info}{ref_marker}")
        
        print("=" * 70)
        
        # PMF Summary
        print(f"\n⚡ PMF SUMMARY:")
        print(f"   Reference conditions:")
        print(f"     Temperature: {temperature:.2f} K")
        print(f"     kT: {kT_kJ_mol:.4f} kJ/mol")
        
        for ion_type in ion_types:
            if ion_type in bulk_densities:
                print(f"     Bulk density {ion_type} (z={reference_z:.1f}): {bulk_densities[ion_type]:.8f} ions/Å³")
        print()
        
        print(f"   PMF by slab and ion type:")
        for i, target_z in enumerate(analysis_z_values):
            if i in slab_results:
                is_reference_slice = abs(target_z - reference_z) < 0.01
                is_original_target = target_z in original_target_z_values
                
                z_info = f"z = {target_z:5.1f} Å"
                if is_reference_slice and not is_original_target:
                    z_info += " [REF]"
                    
                print(f"     {z_info}:")
                for ion_type in ion_types:
                    if ion_type in slab_results[i]:
                        result = slab_results[i][ion_type]
                        pmf_val = result['pmf_mean']
                        bulk_density = bulk_densities[ion_type]
                        rel_density = result['mean_density'] / bulk_density if bulk_density > 0 else 0
                        
                        if np.isfinite(pmf_val):
                            print(f"       {ion_type}: PMF = {pmf_val:+7.3f} kJ/mol (ρ/ρ₀ = {rel_density:.3f})")
                        else:
                            print(f"       {ion_type}: PMF = ∞ (ρ/ρ₀ = {rel_density:.3f})")
        
        print()
        print(f"   Interpretation:")
        print(f"     PMF < 0: Favorable for ion accumulation")
        print(f"     PMF = 0: Bulk-like behavior") 
        print(f"     PMF > 0: Unfavorable for ion accumulation")
        print(f"     |PMF| > 2.5 kJ/mol (~kT): Strong preference/avoidance")
        
        # Filter results to only include original target slices (not auto-added reference)
        filtered_slab_results = {}
        filtered_slab_total_densities = {}
        
        # Map original target indices
        original_target_indices = []
        for orig_z in original_target_z_values:
            for i, analysis_z in enumerate(analysis_z_values):
                if abs(orig_z - analysis_z) < 0.01:
                    original_target_indices.append(i)
                    break
        
        # Filter results to original targets only
        for new_idx, old_idx in enumerate(original_target_indices):
            if old_idx in slab_results:
                filtered_slab_results[new_idx] = slab_results[old_idx]
            if old_idx in slab_total_densities:
                filtered_slab_total_densities[new_idx] = slab_total_densities[old_idx]
        
        # Update reference_slab_idx for filtered results
        filtered_reference_slab_idx = None
        if reference_slab_idx is not None:
            try:
                filtered_reference_slab_idx = original_target_indices.index(reference_slab_idx)
            except ValueError:
                # Reference was auto-added, not in original targets
                filtered_reference_slab_idx = None
        
        print(f"\n📋 RESULTS SUMMARY:")
        print(f"   Total slices analyzed: {len(analysis_z_values)} (including auto-added reference if needed)")
        print(f"   Results returned for: {len(original_target_z_values)} original target slices")
        if not reference_in_targets:
            print(f"   Reference slice z={reference_z:.1f} was auto-added for bulk density calculation")
            print(f"   Bulk density successfully calculated from reference slice")
        
        # Return comprehensive results
        results = {
            'box_dimensions': (box_x, box_y, box_z),
            'xy_grid_size': xy_grid_size,
            'z_slice_width': z_slice_width,
            'n_x_cubes': n_x_cubes,
            'n_y_cubes': n_y_cubes,
            'cubes_per_slab': n_x_cubes * n_y_cubes,
            'cube_volume': cube_volume,
            'x_centers': x_centers,
            'y_centers': y_centers,
            'x_edges': x_edges,
            'y_edges': y_edges,
            'ion_types': ion_types,
            'slab_results': filtered_slab_results,  # Only original targets
            'slab_total_densities': filtered_slab_total_densities,  # Only original targets
            'n_frames_analyzed': len(frame_indices),
            'bulk_densities': bulk_densities,  # Available for all ion types
            'temperature': temperature,
            'kT_kJ_mol': kT_kJ_mol,
            'reference_slab_idx': filtered_reference_slab_idx,  # Adjusted for filtered results
            'reference_z': reference_z,
            'reference_in_original_targets': reference_in_targets,  # Track if reference was in original targets
            'original_target_z_values': original_target_z_values,  # Store original targets
            'analysis_z_values': analysis_z_values,  # Store full analysis range
            'ion_atoms': ion_atoms
        }
        
        # Save results to cache if requested
        if use_cache:
            print(f"\n💾 Saving results to cache: {cache_filename}")
            try:
                # Prepare data for caching (flatten nested dictionaries)
                cache_dict = {
                    'box_dimensions': np.array(results['box_dimensions']),
                    'xy_grid_size': results['xy_grid_size'],
                    'z_slice_width': results['z_slice_width'],
                    'n_x_cubes': results['n_x_cubes'],
                    'n_y_cubes': results['n_y_cubes'],
                    'cubes_per_slab': results['cubes_per_slab'],
                    'cube_volume': results['cube_volume'],
                    'x_centers': results['x_centers'],
                    'y_centers': results['y_centers'],
                    'x_edges': results['x_edges'],
                    'y_edges': results['y_edges'],
                    'ion_types': np.array(results['ion_types']),
                    'n_frames_analyzed': results['n_frames_analyzed'],
                    'bulk_densities': results['bulk_densities'],
                    'temperature': results['temperature'],
                    'kT_kJ_mol': results['kT_kJ_mol'],
                    'reference_slab_idx': results['reference_slab_idx'] if results['reference_slab_idx'] is not None else -1,
                    'reference_z': results['reference_z'],
                    'reference_in_original_targets': results['reference_in_original_targets'],
                    'original_target_z_values': np.array(results['original_target_z_values']),
                    'analysis_z_values': np.array(results['analysis_z_values'])
                }
                
                # Flatten slab_results for caching
                slab_results_flat = {}
                for slab_idx, slab_data in filtered_slab_results.items():
                    for ion_type, ion_data in slab_data.items():
                        key_prefix = f"slab_{slab_idx}_{ion_type}"
                        slab_results_flat[f"{key_prefix}_target_z"] = ion_data['target_z']
                        slab_results_flat[f"{key_prefix}_density_grid"] = ion_data['density_grid']
                        slab_results_flat[f"{key_prefix}_pmf_grid"] = ion_data['pmf_grid']
                        slab_results_flat[f"{key_prefix}_total_density"] = ion_data['total_density']
                        slab_results_flat[f"{key_prefix}_mean_density"] = ion_data['mean_density']
                        slab_results_flat[f"{key_prefix}_max_density"] = ion_data['max_density']
                        slab_results_flat[f"{key_prefix}_non_zero_cubes"] = ion_data['non_zero_cubes']
                        slab_results_flat[f"{key_prefix}_pmf_mean"] = ion_data['pmf_mean']
                        slab_results_flat[f"{key_prefix}_pmf_stats_finite_pmfs"] = ion_data['pmf_stats']['finite_pmfs']
                        slab_results_flat[f"{key_prefix}_pmf_stats_favorable_cubes"] = ion_data['pmf_stats']['favorable_cubes']
                        slab_results_flat[f"{key_prefix}_pmf_stats_neutral_cubes"] = ion_data['pmf_stats']['neutral_cubes']
                        slab_results_flat[f"{key_prefix}_pmf_stats_unfavorable_cubes"] = ion_data['pmf_stats']['unfavorable_cubes']
                        slab_results_flat[f"{key_prefix}_x_centers"] = ion_data['x_centers']
                        slab_results_flat[f"{key_prefix}_y_centers"] = ion_data['y_centers']
                        slab_results_flat[f"{key_prefix}_bulk_density"] = ion_data['bulk_density']
                
                # Flatten slab_total_densities for caching
                slab_total_flat = {}
                for slab_idx, density_dict in filtered_slab_total_densities.items():
                    for ion_type, density_value in density_dict.items():
                        slab_total_flat[f"slab_total_{slab_idx}_{ion_type}"] = density_value
                
                # Save to npz file
                np.savez(cache_filename, **cache_dict, **slab_results_flat, **slab_total_flat)
                print(f"   ✅ Cache saved successfully!")
                print(f"   📁 File: {cache_filename}")
                
            except Exception as e:
                print(f"   ⚠️ Failed to save cache: {e}")
                print(f"   Continuing without cache...")
        
        return results


    def create_adaptive_stacked_isosurfaces(self, debug_results, ion_types=None, 
                                        n_energy_levels=10, 
                                        percentile_range=(5, 95),
                                        target_z_values=None,
                                        z_spacing=2.0,
                                        colors=None, 
                                        alphas=None,
                                        energy_tolerance=None,
                                        isosurface_method='marching_cubes',
                                        smoothing=True,
                                        smoothing_sigma=0.5):
        """
        Create adaptive stacked isosurfaces using data-driven energy levels from calculate_pmf_vs_z_from_ion_density()
        
        This method extracts actual PMF values from the debug cube analysis and creates
        meaningful energy isosurfaces stacked vertically to show the 3D energy landscape.
        
        Parameters
        ----------
        debug_results : dict
            Results from calculate_pmf_vs_z_from_ion_density()
        ion_types : list, optional
            Ion types to analyze. If None, uses all available from debug_results
        n_energy_levels : int, default=10
            Number of energy levels to create per ion type
        percentile_range : tuple, default=(5, 95)
            Percentile range to use for energy level bounds (avoids extreme outliers)
        target_z_values : array-like, optional
            Specific Z-values to use. If None, uses fine sampling based on bin_width
        z_spacing : float, default=2.0
            Vertical spacing between energy level surfaces (Å)
        colors : list, optional
            Colors for energy levels. If None, uses adaptive colormap
        alphas : list, optional  
            Alpha values for energy levels. If None, uses adaptive transparency
        energy_tolerance : float, optional
            Tolerance for matching energy levels. If None, auto-calculated
        isosurface_method : str, default='marching_cubes'
            Method for isosurface extraction
        smoothing : bool, default=True
            Apply smoothing to PMF grids before isosurface extraction
        smoothing_sigma : float, default=0.5
            Gaussian smoothing parameter
            
        Returns
        -------
        dict
            Stacked isosurface results with adaptive energy levels
        """
        
        # Import required modules
        import matplotlib.pyplot as plt
        from scipy.ndimage import gaussian_filter
        
        # Try to import skimage for marching cubes, fallback if not available
        try:
            from skimage import measure
            SKIMAGE_AVAILABLE = True
        except ImportError:
            print("⚠️ scikit-image not available, using point_mask method only")
            SKIMAGE_AVAILABLE = False
            if isosurface_method == 'marching_cubes':
                print("→ Switching to point_mask method")
                isosurface_method = 'point_mask'
        
        print(f"\n🎯 CREATING ADAPTIVE STACKED ISOSURFACES")
        print(f"{'='*60}")
        print(f"Data-driven energy levels: {n_energy_levels} levels per ion")
        print(f"Percentile range: {percentile_range[0]}-{percentile_range[1]}%")
        print(f"Isosurface method: {isosurface_method}")
        
        # Validate debug results structure
        if not debug_results or 'slab_results' not in debug_results:
            raise ValueError("Invalid debug_results. Must contain 'slab_results' from calculate_pmf_vs_z_from_ion_density()")
        
        slab_results = debug_results['slab_results']
        
        # Extract coordinate arrays
        x_centers = debug_results.get('x_centers')
        y_centers = debug_results.get('y_centers')
        
        if x_centers is None or y_centers is None:
            raise ValueError("Missing coordinate data in debug_results")
        
        print(f"✓ Found {len(slab_results)} z-slabs in debug results")
        print(f"✓ Grid dimensions: {len(x_centers)} × {len(y_centers)}")
        
        # Get available ion types from debug results
        available_ions = set()
        z_values = []
        
        for slab_idx, slab_data in slab_results.items():
            if slab_data:  # Check if slab_data is not empty
                # Get z-value from first available ion in this slab
                first_ion_key = next(iter(slab_data.keys()))
                if 'target_z' in slab_data[first_ion_key]:
                    z_values.append(slab_data[first_ion_key]['target_z'])
                
                # Collect all ion types
                for ion_type in slab_data.keys():
                    available_ions.add(ion_type)
        
        available_ions = list(available_ions)
        z_values = sorted(set(z_values))
        
        # Apply target_z_values filter if provided
        if target_z_values is not None:
            if isinstance(target_z_values, (int, float)):
                target_z_values = [target_z_values]
            # Filter z_values to only include those close to target values
            filtered_z = []
            for target_z in target_z_values:
                closest_z = min(z_values, key=lambda z: abs(z - target_z))
                if abs(closest_z - target_z) <= z_spacing:  # Within reasonable tolerance
                    filtered_z.append(closest_z)
            z_values = sorted(set(filtered_z))
            print(f"✓ Filtered to target z-values: {z_values}")
        
        if not available_ions:
            raise ValueError("No ion types found in debug results")
        
        # Handle ion_types parameter
        if ion_types is None:
            ion_types = available_ions
        elif isinstance(ion_types, str):
            ion_types = [ion_types]
        
        # Validate requested ion types
        invalid_ions = [ion for ion in ion_types if ion not in available_ions]
        if invalid_ions:
            print(f"⚠ Warning: Ion types {invalid_ions} not found in debug results")
            print(f"  Available: {available_ions}")
        
        ion_types = [ion for ion in ion_types if ion in available_ions]
        
        if not ion_types:
            raise ValueError("No valid ion types to process")
        
        print(f"Processing ion types: {ion_types}")
        print(f"Available z-values: {z_values}")
        
        # Initialize results
        results = {
            'ion_types': ion_types,
            'z_values': z_values,
            'x_centers': x_centers,
            'y_centers': y_centers,
            'n_energy_levels': n_energy_levels,
            'percentile_range': percentile_range,
            'z_spacing': z_spacing,
            'isosurface_method': isosurface_method,
            'ion_isosurfaces': {},
            'parameters': {
                'energy_tolerance': energy_tolerance,
                'smoothing': smoothing,
                'smoothing_sigma': smoothing_sigma,
                'temperature': debug_results.get('temperature', 298.15),
                'kT_kJ_mol': debug_results.get('kT_kJ_mol', 2.48)
            }
        }
        
        # Process each ion type
        for ion_type in ion_types:
            print(f"\n🔍 Processing {ion_type}...")
            
            # Collect PMF statistics and grids for this ion across all z-slices
            pmf_values_for_histogram = []  # Only for histogram calculation
            pmf_grids_by_z = {}  # Store PMF grids by z-value for isosurface creation
            pmf_min_global = float('inf')
            pmf_max_global = float('-inf')
            total_finite_count = 0
            
            for slab_idx, slab_data in slab_results.items():
                if ion_type in slab_data:
                    ion_result = slab_data[ion_type]
                    
                    if 'pmf_grid' in ion_result and 'target_z' in ion_result:
                        pmf_grid = ion_result['pmf_grid']
                        target_z = ion_result['target_z']
                        
                        # Store grid for later use
                        pmf_grids_by_z[target_z] = {
                            'pmf_grid': pmf_grid,
                            'slab_idx': slab_idx,
                            'ion_result': ion_result
                        }
                        
                        # Collect finite PMF values for statistics (memory efficient)
                        if pmf_grid is not None and pmf_grid.size > 0:
                            finite_pmf = pmf_grid[np.isfinite(pmf_grid)]
                            if len(finite_pmf) > 0:
                                pmf_min_global = min(pmf_min_global, np.min(finite_pmf))
                                pmf_max_global = max(pmf_max_global, np.max(finite_pmf))
                                total_finite_count += len(finite_pmf)
                                # Sample for histogram (to avoid memory issues)
                                if len(pmf_values_for_histogram) < 100000:  # Limit samples
                                    pmf_values_for_histogram.extend(finite_pmf)
                                else:
                                    # Random sampling for large datasets
                                    sample_indices = np.random.choice(len(finite_pmf), 
                                                                     min(1000, len(finite_pmf)), 
                                                                     replace=False)
                                    pmf_values_for_histogram.extend(finite_pmf[sample_indices])
            
            if not pmf_values_for_histogram or total_finite_count == 0:
                print(f"  ❌ No finite PMF values found for {ion_type}")
                continue
            
            pmf_values_for_histogram = np.array(pmf_values_for_histogram)
            print(f"  ✓ Collected {total_finite_count} finite PMF values ({len(pmf_values_for_histogram)} sampled for analysis)")
            print(f"  ✓ PMF range: {pmf_min_global:.2f} to {pmf_max_global:.2f} kJ/mol")
            
            # Create adaptive energy levels based on data distribution
            pmf_min = np.percentile(pmf_values_for_histogram, percentile_range[0])
            pmf_max = np.percentile(pmf_values_for_histogram, percentile_range[1])
            
            print(f"  📊 Using percentile range {percentile_range[0]}-{percentile_range[1]}%:")
            print(f"    Energy range: {pmf_min:.2f} to {pmf_max:.2f} kJ/mol")
            
            # Create energy levels with higher density where data is more common
            hist, bin_edges = np.histogram(pmf_values_for_histogram, bins=50)
            
            # Method: Density-weighted energy levels
            # Place more levels where there's more data
            cumulative_hist = np.cumsum(hist)
            cumulative_hist = cumulative_hist / cumulative_hist[-1]  # normalize to [0,1]
            
            # Generate evenly spaced quantiles for adaptive levels
            quantiles = np.linspace(0, 1, n_energy_levels)
            energy_levels = np.interp(quantiles, cumulative_hist, bin_edges[1:])
            
            # Ensure energy levels are within the percentile range
            energy_levels = np.clip(energy_levels, pmf_min, pmf_max)
            energy_levels = np.unique(energy_levels)  # Remove duplicates
            
            print(f"  🎨 Created {len(energy_levels)} adaptive energy levels:")
            for i, level in enumerate(energy_levels):
                print(f"    Level {i+1}: {level:.2f} kJ/mol")
            
            # Set up colors and alphas
            if colors is None:
                # Use colormap from deep (favorable) to light (unfavorable)
                cmap = plt.cm.get_cmap('RdYlBu_r')  # Red-Yellow-Blue reversed
                colors_ion = [cmap(i / len(energy_levels)) for i in range(len(energy_levels))]
            else:
                colors_ion = colors[:len(energy_levels)]
            
            if alphas is None:
                # Higher alpha for more favorable (lower energy) levels
                alphas_ion = np.linspace(0.9, 0.3, len(energy_levels))
            else:
                alphas_ion = alphas[:len(energy_levels)]
            
            # Calculate energy tolerance if not provided
            if energy_tolerance is None:
                energy_tolerance_ion = (pmf_max - pmf_min) / (len(energy_levels) * 2)
            else:
                energy_tolerance_ion = energy_tolerance
            
            print(f"  🔧 Energy tolerance: ±{energy_tolerance_ion:.3f} kJ/mol")
            
            # Create isosurfaces for each energy level
            isosurfaces = {}
            
            for level_idx, (energy, color, alpha) in enumerate(zip(energy_levels, colors_ion, alphas_ion)):
                print(f"    Creating isosurface {level_idx+1}: {energy:.2f} kJ/mol (α={alpha:.2f})")
                
                level_surfaces = []
                
                # Process each z-slice for this energy level
                for target_z in sorted(pmf_grids_by_z.keys()):
                    pmf_data = pmf_grids_by_z[target_z]
                    pmf_grid = pmf_data['pmf_grid']
                    
                    if pmf_grid is None or pmf_grid.size == 0:
                        continue
                    
                    # Apply smoothing if requested
                    if smoothing:
                        pmf_grid_smooth = gaussian_filter(pmf_grid, sigma=smoothing_sigma)
                    else:
                        pmf_grid_smooth = pmf_grid.copy()
                    
                    # Calculate stack height for this energy level
                    stack_z = target_z + level_idx * z_spacing
                    
                    # Create proper isosurface based on method
                    surface = None
                    
                    if isosurface_method == 'marching_cubes' and SKIMAGE_AVAILABLE:
                        try:
                            # Use marching cubes for proper 3D isosurface
                            verts, faces, normals, values = measure.marching_cubes(
                                pmf_grid_smooth, level=energy, spacing=(x_centers[1]-x_centers[0], 
                                                                        y_centers[1]-y_centers[0], 1.0))
                            
                            # Transform vertices to actual coordinates
                            verts_transformed = verts.copy()
                            verts_transformed[:, 0] = verts[:, 0] + x_centers[0]
                            verts_transformed[:, 1] = verts[:, 1] + y_centers[0]
                            verts_transformed[:, 2] = stack_z  # Stack at designated height
                            
                            surface = {
                                'original_z': target_z,
                                'stack_z': stack_z,
                                'energy_level': energy,
                                'level_index': level_idx,
                                'vertices': verts_transformed,
                                'faces': faces,
                                'normals': normals,
                                'values': values,
                                'color': color,
                                'alpha': alpha,
                                'n_points': len(verts_transformed),
                                'energy_tolerance': energy_tolerance_ion,
                                'method': 'marching_cubes'
                            }
                            
                        except (ValueError, RuntimeError) as e:
                            # Fallback to point mask method if marching cubes fails
                            print(f"      ⚠️ Marching cubes failed for energy {energy:.2f}: {e}")
                            print(f"      → Falling back to point mask method")
                            isosurface_method = 'point_mask'
                    elif isosurface_method == 'marching_cubes' and not SKIMAGE_AVAILABLE:
                        # Force fallback if scikit-image is not available
                        print(f"      ⚠️ scikit-image not available, using point_mask method")
                        isosurface_method = 'point_mask'
                    
                    if isosurface_method == 'point_mask' or surface is None:
                        # Fallback: Find regions matching this energy level (±tolerance)
                        energy_mask = np.abs(pmf_grid_smooth - energy) <= energy_tolerance_ion
                        
                        if np.any(energy_mask):
                            # Get coordinate grids
                            X, Y = np.meshgrid(x_centers, y_centers)
                            
                            # Create point cloud surface data
                            surface = {
                                'original_z': target_z,
                                'stack_z': stack_z,
                                'energy_level': energy,
                                'level_index': level_idx,
                                'x_coords': X[energy_mask],
                                'y_coords': Y[energy_mask], 
                                'z_coords': np.full(np.sum(energy_mask), stack_z),
                                'pmf_values': pmf_grid_smooth[energy_mask],
                                'color': color,
                                'alpha': alpha,
                                'n_points': np.sum(energy_mask),
                                'energy_tolerance': energy_tolerance_ion,
                                'method': 'point_mask'
                            }
                    
                    if surface is not None:
                        
                        level_surfaces.append(surface)
                
                # Store isosurface data for this energy level
                isosurfaces[energy] = {
                    'energy_level': energy,
                    'level_index': level_idx,
                    'color': color,
                    'alpha': alpha,
                    'surfaces': level_surfaces,
                    'total_points': sum(s['n_points'] for s in level_surfaces),
                    'z_range': (min(s['original_z'] for s in level_surfaces), 
                            max(s['original_z'] for s in level_surfaces)) if level_surfaces else None,
                    'stack_z_range': (min(s['stack_z'] for s in level_surfaces),
                                    max(s['stack_z'] for s in level_surfaces)) if level_surfaces else None
                }
                
                print(f"      → {len(level_surfaces)} surfaces, {isosurfaces[energy]['total_points']} total points")
            
            # Store results for this ion
            results['ion_isosurfaces'][ion_type] = {
                'energy_levels': energy_levels.tolist(),
                'isosurfaces': isosurfaces,
                'colors': [c if isinstance(c, str) else tuple(c[:3]) if len(c) >= 3 else tuple(c) for c in colors_ion],  # Serialize RGBA to RGB
                'alphas': alphas_ion.tolist(),
                'pmf_statistics': {
                    'min': pmf_min,
                    'max': pmf_max,
                    'global_min': pmf_min_global,
                    'global_max': pmf_max_global,
                    'mean': np.mean(pmf_values_for_histogram),
                    'std': np.std(pmf_values_for_histogram),
                    'total_points': total_finite_count,
                    'sampled_points': len(pmf_values_for_histogram)
                },
                'adaptive_parameters': {
                    'n_energy_levels': len(energy_levels),
                    'energy_tolerance': energy_tolerance_ion,
                    'percentile_range': percentile_range,
                    'z_spacing': z_spacing
                }
            }
            
            print(f"  ✅ Created {len(isosurfaces)} adaptive isosurfaces for {ion_type}")
            total_surfaces = sum(len(iso['surfaces']) for iso in isosurfaces.values())
            total_points = sum(iso['total_points'] for iso in isosurfaces.values())
            print(f"    Total surfaces: {total_surfaces}")
            print(f"    Total points: {total_points}")
        
        print(f"\n✅ ADAPTIVE STACKED ISOSURFACES COMPLETE!")
        print(f"{'='*60}")
        
        total_ion_surfaces = sum(len(data['isosurfaces']) for data in results['ion_isosurfaces'].values())
        print(f"📊 Summary:")
        print(f"  Ion types processed: {len(results['ion_isosurfaces'])}")
        print(f"  Total energy levels: {total_ion_surfaces}")
        print(f"  Isosurface method: {isosurface_method}")
        print(f"  Adaptive energy levels: DATA-DRIVEN (no manual thresholds)")
        
        print(f"\n💡 Visualization interpretation:")
        print(f"  → Lower surfaces (darker colors): More favorable binding (lower PMF)")
        print(f"  → Higher surfaces (lighter colors): Less favorable binding (higher PMF)")
        print(f"  → Surface extent: Spatial distribution of that energy level")
        print(f"  → Vertical stacking: Energy landscape hierarchy")
        
        return results


    def create_pmf_height_surfaces(self, debug_results, ion_types=None,
                                 z_surface_values=None,
                                 colors=None,
                                 alphas=None,
                                 smoothing=True,
                                 smoothing_sigma=1.0,
                                 z_scale_factor=None,
                                 pmf_threshold_range=None,
                                 surface_interpolation='cubic',
                                 grid_upsampling_factor=1,
                                 nan_handling='interpolate',
                                 reference_level='bulk'):
        """
        Create smooth continuous height-based surfaces from PMF data.
        
        This method creates surfaces where PMF values are represented as height (Z-coordinate)
        instead of isosurfaces at fixed energy levels. Similar to electrostatic potential 
        surface plotting but using PMF data.
        
        Parameters
        ----------
        debug_results : dict
            Results from calculate_pmf_vs_z_from_ion_density() method
        ion_types : list, optional
            Ion types to process. If None, uses all available from debug_results
        z_surface_values : list, optional
            Z-slice values to create surfaces for. If None, uses all available slices.
            Surfaces will be centered at these z-positions with PMF variations as height deviations.
        colors : list, optional
            Colors for each ion type. If None, auto-generates colors
        alphas : list, optional
            Transparency values for each ion type. If None, auto-generates
        smoothing : bool, default=True
            Apply Gaussian smoothing to surfaces for continuity
        smoothing_sigma : float, default=1.0
            Gaussian smoothing parameter (higher = more smoothing)
        z_scale_factor : float, optional
            Scale factor for PMF height representation. If None, auto-calculates
        pmf_threshold_range : tuple, optional
            (min_pmf, max_pmf) range to display. Values outside are clipped
        surface_interpolation : str, default='cubic'
            Interpolation method for smooth surfaces: 'linear', 'cubic', 'quintic'
        grid_upsampling_factor : int, default=1
            Factor to increase grid resolution through interpolation
        nan_handling : str, default='interpolate'
            How to handle NaN values: 'interpolate', 'mask', 'zero'
        reference_level : str, default='bulk'
            Reference level for PMF heights: 'bulk' (PMF=0), 'minimum', 'custom'
        
        Returns
        -------
        dict
            Dictionary containing height surface data for plotting
        """
        
        print(f"\n🏔️ CREATING PMF HEIGHT SURFACES")
        print(f"{'='*60}")
        print(f"Surface type: Height-based (PMF as Z-coordinate)")
        print(f"Smoothing: {'Enabled' if smoothing else 'Disabled'}")
        print(f"Reference level: {reference_level}")
        
        # Import required modules
        import matplotlib.pyplot as plt
        from scipy.ndimage import gaussian_filter
        from scipy.interpolate import interp2d, griddata
        
        # Validate debug results structure
        if not debug_results or 'slab_results' not in debug_results:
            raise ValueError("Invalid debug_results. Must contain 'slab_results' from calculate_pmf_vs_z_from_ion_density()")
        
        slab_results = debug_results['slab_results']
        
        # Extract coordinate arrays
        x_centers = debug_results.get('x_centers')
        y_centers = debug_results.get('y_centers')
        
        if x_centers is None or y_centers is None:
            raise ValueError("Missing coordinate data in debug_results")
        
        print(f"✓ Found {len(slab_results)} z-slabs in debug results")
        print(f"✓ Grid dimensions: {len(x_centers)} × {len(y_centers)}")
        
        # Get available ion types and z-values
        available_ions = set()
        z_values = []
        
        for slab_idx, slab_data in slab_results.items():
            if slab_data:  # Check if slab_data is not empty
                # Get z-value from first available ion in this slab
                first_ion_key = next(iter(slab_data.keys()))
                if 'target_z' in slab_data[first_ion_key]:
                    z_values.append(slab_data[first_ion_key]['target_z'])
                
                # Collect all ion types
                for ion_type in slab_data.keys():
                    available_ions.add(ion_type)
        
        available_ions = list(available_ions)
        z_values = sorted(set(z_values))
        
        if not available_ions:
            raise ValueError("No ion types found in debug results")
        
        # Process ion types parameter
        if ion_types is None:
            ion_types = available_ions
        elif isinstance(ion_types, str):
            ion_types = [ion_types]
        
        # Validate ion types
        invalid_ions = [ion for ion in ion_types if ion not in available_ions]
        if invalid_ions:
            print(f"⚠️ Warning: Ion types {invalid_ions} not found in results")
        ion_types = [ion for ion in ion_types if ion in available_ions]
        
        if not ion_types:
            raise ValueError("No valid ion types to process")
        
        print(f"Processing ion types: {ion_types}")
        
        # Process z-surface values parameter
        if z_surface_values is None:
            z_surface_values = z_values
        else:
            # Find closest matching z-values
            matched_z_values = []
            for target_z in z_surface_values:
                closest_z = min(z_values, key=lambda z: abs(z - target_z))
                matched_z_values.append(closest_z)
            z_surface_values = matched_z_values
        
        print(f"Creating surfaces for z-values: {z_surface_values}")
        
        # Generate colors and alphas if not provided
        if colors is None:
            # Use same color scheme as other methods
            color_cycle = plt.cm.Set1(np.linspace(0, 1, max(8, len(ion_types))))
            colors = {ion_type: color_cycle[i % len(color_cycle)] 
                     for i, ion_type in enumerate(ion_types)}
        elif isinstance(colors, (list, tuple)):
            colors = {ion_type: colors[i % len(colors)] 
                     for i, ion_type in enumerate(ion_types)}
        
        if alphas is None:
            # Use gradual transparency based on number of surfaces
            base_alpha = 0.8
            alphas = {ion_type: base_alpha - 0.1 * i 
                     for i, ion_type in enumerate(ion_types)}
        elif isinstance(alphas, (list, tuple)):
            alphas = {ion_type: alphas[i % len(alphas)] 
                     for i, ion_type in enumerate(ion_types)}
        
        # Initialize results storage
        results = {
            'height_surfaces': {},
            'ion_types': ion_types,
            'z_surface_values': z_surface_values,
            'x_centers': x_centers,
            'y_centers': y_centers,
            'colors': colors,
            'alphas': alphas,
            'smoothing_applied': smoothing,
            'smoothing_sigma': smoothing_sigma if smoothing else None,
            'z_scale_factor': z_scale_factor,
            'reference_level': reference_level,
            'surface_type': 'height_based',
            'creation_timestamp': debug_results.get('timestamp', 'unknown')
        }
        
        # Transform coordinates to start from 0 (same as electrostatic method)
        x_display = x_centers - x_centers.min()
        y_display = y_centers - y_centers.min()
        
        # Create meshgrids for surface creation
        X, Y = np.meshgrid(x_display, y_display)
        
        # Determine PMF scaling
        if z_scale_factor is None:
            # Auto-calculate scale factor based on PMF range
            all_pmfs = []
            for slab_idx, slab_data in slab_results.items():
                for ion_type in ion_types:
                    if ion_type in slab_data and 'pmf_grid' in slab_data[ion_type]:
                        pmf_grid = slab_data[ion_type]['pmf_grid']
                        if pmf_grid is not None:
                            finite_pmfs = pmf_grid[np.isfinite(pmf_grid)]
                            all_pmfs.extend(finite_pmfs)
            
            if all_pmfs:
                pmf_range = np.max(all_pmfs) - np.min(all_pmfs)
                # Scale to reasonable height range (e.g., 10-20 Å)
                target_height_range = 15.0  # Å
                z_scale_factor = target_height_range / pmf_range if pmf_range > 0 else 1.0
            else:
                z_scale_factor = 1.0
        
        results['z_scale_factor'] = z_scale_factor
        print(f"✓ Z-scale factor: {z_scale_factor:.3f} (Å per kJ/mol)")
        
        # Process each ion type
        for ion_idx, ion_type in enumerate(ion_types):
            print(f"\n🔹 Processing {ion_type}:")
            
            ion_surfaces = {}
            ion_color = colors[ion_type]
            ion_alpha = alphas[ion_type]
            
            # Process each z-surface
            for surf_idx, target_z in enumerate(z_surface_values):
                # Find corresponding slab
                slab_idx = None
                for s_idx, slab_data in slab_results.items():
                    if ion_type in slab_data:
                        slab_target_z = slab_data[ion_type].get('target_z')
                        if slab_target_z is not None and abs(slab_target_z - target_z) < 0.1:
                            slab_idx = s_idx
                            break
                
                if slab_idx is None:
                    print(f"  ⚠️ No data found for z = {target_z:.1f} Å")
                    continue
                
                ion_result = slab_results[slab_idx][ion_type]
                pmf_grid = ion_result.get('pmf_grid')  # Fixed: singular 'pmf_grid' not 'pmf_grids'
                
                if pmf_grid is None or pmf_grid.size == 0:
                    print(f"  ⚠️ No PMF grid data for z = {target_z:.1f} Å")
                    continue
                
                # Handle NaN values based on method
                if nan_handling == 'interpolate' and np.any(np.isnan(pmf_grid)):
                    # Interpolate NaN values
                    valid_mask = ~np.isnan(pmf_grid)
                    if np.any(valid_mask):
                        valid_coords = np.column_stack(np.where(valid_mask))
                        valid_values = pmf_grid[valid_mask]
                        
                        # Create coordinate grid for interpolation
                        yi, xi = np.mgrid[0:pmf_grid.shape[0], 0:pmf_grid.shape[1]]
                        
                        try:
                            pmf_grid = griddata(valid_coords, valid_values, (yi, xi), 
                                              method='nearest', fill_value=0.0)
                        except Exception as e:
                            print(f"    ⚠️ Interpolation failed: {e}, using original grid")
                elif nan_handling == 'zero':
                    pmf_grid = np.nan_to_num(pmf_grid, nan=0.0)
                elif nan_handling == 'mask':
                    # Keep NaN values as is (will be handled during plotting)
                    pass
                
                # Apply smoothing if requested
                if smoothing:
                    # Only smooth finite values
                    finite_mask = np.isfinite(pmf_grid)
                    if np.any(finite_mask):
                        pmf_grid_smooth = gaussian_filter(pmf_grid, sigma=smoothing_sigma)
                        # Restore NaN values if nan_handling is 'mask'
                        if nan_handling == 'mask':
                            pmf_grid_smooth[~finite_mask] = np.nan
                        pmf_grid = pmf_grid_smooth
                    else:
                        print(f"    ⚠️ No finite values to smooth for z = {target_z:.1f} Å")
                
                # Apply PMF threshold range if specified
                if pmf_threshold_range is not None:
                    min_thresh, max_thresh = pmf_threshold_range
                    pmf_grid = np.clip(pmf_grid, min_thresh, max_thresh)
                
                # Calculate surface height centered at target_z
                # Remove DC offset from PMF to center surface at target z-position
                pmf_mean = np.nanmean(pmf_grid)
                pmf_centered = pmf_grid - pmf_mean
                
                # Base z is the target position (no stacking offset needed)
                base_z = target_z
                height_surface = base_z + pmf_centered * z_scale_factor
                
                # Apply grid upsampling if requested
                if grid_upsampling_factor > 1:
                    try:
                        # Use RegularGridInterpolator instead of deprecated interp2d
                        from scipy.interpolate import RegularGridInterpolator
                        
                        # Create interpolator
                        interpolator = RegularGridInterpolator(
                            (y_display, x_display), height_surface,
                            method='cubic' if surface_interpolation == 'cubic' else 'linear',
                            bounds_error=False, fill_value=np.nan
                        )
                        
                        # Create higher resolution grids
                        x_hr = np.linspace(x_display.min(), x_display.max(), 
                                         len(x_display) * grid_upsampling_factor)
                        y_hr = np.linspace(y_display.min(), y_display.max(),
                                         len(y_display) * grid_upsampling_factor)
                        
                        X_hr, Y_hr = np.meshgrid(x_hr, y_hr)
                        
                        # Create coordinate pairs for interpolation
                        coords = np.column_stack([Y_hr.ravel(), X_hr.ravel()])
                        height_surface_hr = interpolator(coords).reshape(Y_hr.shape)
                        
                        surface_data = {
                            'X': X_hr, 'Y': Y_hr, 'Z': height_surface_hr,
                            'upsampled': True
                        }
                    except Exception as e:
                        print(f"    ⚠️ Upsampling failed: {e}, using original resolution")
                        surface_data = {
                            'X': X, 'Y': Y, 'Z': height_surface,
                            'upsampled': False
                        }
                else:
                    surface_data = {
                        'X': X, 'Y': Y, 'Z': height_surface,
                        'upsampled': False
                    }
                
                # Store surface information
                surface_info = {
                    'original_z': target_z,
                    'base_z': base_z,
                    'surface_data': surface_data,
                    'pmf_grid': pmf_grid,
                    'color': ion_color,
                    'alpha': ion_alpha,
                    'pmf_stats': {
                        'min': np.nanmin(pmf_grid) if np.any(np.isfinite(pmf_grid)) else np.nan,
                        'max': np.nanmax(pmf_grid) if np.any(np.isfinite(pmf_grid)) else np.nan,
                        'mean': np.nanmean(pmf_grid) if np.any(np.isfinite(pmf_grid)) else np.nan,
                        'finite_count': np.sum(np.isfinite(pmf_grid))
                    },
                    'height_stats': {
                        'min': np.nanmin(height_surface) if np.any(np.isfinite(height_surface)) else np.nan,
                        'max': np.nanmax(height_surface) if np.any(np.isfinite(height_surface)) else np.nan,
                        'range': (np.nanmax(height_surface) - np.nanmin(height_surface)) if np.any(np.isfinite(height_surface)) else 0.0
                    }
                }
                
                ion_surfaces[target_z] = surface_info
                
                finite_points = surface_info['pmf_stats']['finite_count']
                pmf_range = surface_info['pmf_stats']['max'] - surface_info['pmf_stats']['min']
                height_range = surface_info['height_stats']['range']
                
                print(f"  ✓ z = {target_z:5.1f} Å: {finite_points} points, "
                      f"PMF range = {pmf_range:.2f} kJ/mol, height range = {height_range:.2f} Å")
            
            # Store results for this ion type
            results['height_surfaces'][ion_type] = {
                'surfaces': ion_surfaces,
                'color': ion_color,
                'alpha': ion_alpha,
                'n_surfaces': len(ion_surfaces),
                'z_range': (min(ion_surfaces.keys()), max(ion_surfaces.keys())) if ion_surfaces else (0, 0)
            }
            
            print(f"  ✅ Created {len(ion_surfaces)} height surfaces for {ion_type}")
        
        print(f"\n✅ PMF HEIGHT SURFACES COMPLETE!")
        print(f"{'='*60}")
        
        total_surfaces = sum(len(data['surfaces']) for data in results['height_surfaces'].values())
        print(f"📊 Summary:")
        print(f"  Ion types processed: {len(ion_types)}")
        print(f"  Total height surfaces: {total_surfaces}")
        print(f"  Smoothing applied: {'Yes' if smoothing else 'No'}")
        print(f"  Grid upsampling: {grid_upsampling_factor}x")
        print(f"  Z-scale factor: {z_scale_factor:.3f} Å/(kJ/mol)")
        
        print(f"\n💡 Height Surface Interpretation:")
        print(f"  → Surface height = Target Z + (Centered PMF × scale_factor)")
        print(f"  → Surfaces are centered at their target z-positions")
        print(f"  → PMF mean removed to center variations around target_z")
        print(f"  → Higher peaks: Less favorable binding (higher relative PMF)")
        print(f"  → Lower valleys: More favorable binding (lower relative PMF)")
        print(f"  → Continuous surface: Smooth spatial variation of binding affinity")
        
        return results


    def create_coordination_height_surfaces(self, coordination_results=None, ion_types=None,
                                          z_surface_values=None,
                                          plot_mode='shells',  # 'shells' or 'z_slices'
                                          shell_selection=None,
                                          z_spacing=2.0,
                                          colors=None,
                                          alphas=None,
                                          smoothing=True,
                                          smoothing_sigma=1.0,
                                          z_scale_factor=1.0,
                                          coordination_threshold_range=None,
                                          surface_interpolation='cubic',
                                          grid_upsampling_factor=1,
                                          nan_handling='interpolate',
                                          reference_level='zero'):
        """
        Create smooth continuous height-based surfaces from coordination data.
        
        This method creates surfaces where coordination numbers are represented as height (Z-coordinate)
        instead of traditional 2D heatmaps. Similar to PMF height surfaces but using coordination data.
        
        Parameters
        ----------
        coordination_results : dict, optional
            Results from calculate_solvation_shells_vs_z_detailed() method.
            If None, uses self.results.spatial_analysis_detailed
        ion_types : list, optional
            Ion types to process. If None, uses all available from coordination_results
        z_surface_values : list, optional
            Z-slice values to create surfaces for. If None, uses all available slices
        plot_mode : str, default='shells'
            Surface creation mode:
            - 'shells': Create surfaces for different coordination shells
            - 'z_slices': Create surfaces for different Z-layers
        shell_selection : list, optional
            Which shells to include (['first_shell', 'second_shell', 'third_shell']).
            If None, uses all available shells
        z_spacing : float, default=2.0
            Vertical spacing between surface layers (Å)
        colors : list or dict, optional
            Colors for each ion type. If None, auto-generates colors
        alphas : list or dict, optional
            Transparency values for each ion type. If None, auto-generates
        smoothing : bool, default=True
            Apply Gaussian smoothing to surfaces for continuity
        smoothing_sigma : float, default=1.0
            Gaussian smoothing parameter (higher = more smoothing)
        z_scale_factor : float, default=1.0
            Scale factor for coordination height representation
        coordination_threshold_range : tuple, optional
            (min_coord, max_coord) range to display. Values outside are clipped
        surface_interpolation : str, default='cubic'
            Interpolation method for smooth surfaces: 'linear', 'cubic', 'quintic'
        grid_upsampling_factor : int, default=1
            Factor to increase grid resolution through interpolation
        nan_handling : str, default='interpolate'
            How to handle NaN values: 'interpolate', 'mask', 'zero'
        reference_level : str, default='zero'
            Reference level for coordination heights: 'zero' (coord=0), 'minimum', 'custom'
        
        Returns
        -------
        dict
            Dictionary containing coordination height surface data for plotting
        """
        
        print(f"\n🧭 CREATING COORDINATION HEIGHT SURFACES")
        print(f"{'='*60}")
        print(f"Surface type: Height-based (Coordination as Z-coordinate)")
        print(f"Plot mode: {plot_mode}")
        print(f"Smoothing: {'Enabled' if smoothing else 'Disabled'}")
        print(f"Reference level: {reference_level}")
        
        # Import required modules
        import matplotlib.pyplot as plt
        from scipy.ndimage import gaussian_filter
        from scipy.interpolate import interp2d, griddata
        
        # Get coordination data
        if coordination_results is None:
            # Try to get spatial coordination data from calculate_solvation_shells_vs_z_detailed()
            if (hasattr(self.results, 'solvation_shells_xy_spatial') and 
                self.results.solvation_shells_xy_spatial is not None):
                coordination_results = self.results.solvation_shells_xy_spatial
                print(f"✓ Found coordination data in: results.solvation_shells_xy_spatial")
            else:
                raise ValueError("No coordination results found. Run calculate_solvation_shells_vs_z_detailed() with enable_spatial_analysis=True first.")
        
        # Validate coordination results structure and convert to expected format
        if not coordination_results or 'z_slices' not in coordination_results:
            raise ValueError("Invalid coordination_results. Must contain 'z_slices' from calculate_solvation_shells_vs_z_detailed() with enable_spatial_analysis=True")
        
        # Convert z_slices list to layer_data dict (z_value -> layer_data mapping)
        layer_data = {}
        for layer in coordination_results['z_slices']:
            z_center = layer['z_center']
            layer_data[z_center] = layer
        
        print(f"✓ Converted {len(coordination_results['z_slices'])} z_slices to layer_data dict")
        
        # Get coordinate arrays from first layer
        first_layer = list(layer_data.values())[0]
        if 'x_centers' not in first_layer or 'y_centers' not in first_layer:
            raise ValueError("Missing coordinate data (x_centers, y_centers) in layer data")
        
        x_centers = first_layer['x_centers']
        y_centers = first_layer['y_centers']
        
        print(f"✓ Found {len(layer_data)} z-layers in coordination results")
        print(f"✓ Grid dimensions: {len(x_centers)} × {len(y_centers)}")
        
        # Get available data structure
        available_ions = set()
        available_shells = set()
        z_values = list(layer_data.keys())
        shell_names = ['first_shell', 'second_shell', 'third_shell']
        
        for z_layer, z_data in layer_data.items():
            if 'coordination_grids' in z_data:
                coord_grids = z_data['coordination_grids']
                for shell_type in shell_names:
                    if shell_type in coord_grids:
                        available_shells.add(shell_type)
                        for ion_type in coord_grids[shell_type]:
                            available_ions.add(ion_type)
        
        available_ions = list(available_ions)
        available_shells = list(available_shells)
        z_values = sorted(z_values)
        
        if not available_ions:
            raise ValueError("No coordination data found in results")
        
        print(f"Available ion types: {available_ions}")
        print(f"Available shells: {available_shells}")
        print(f"Available z-layers: {z_values}")
        
        # Process ion types parameter
        if ion_types is None:
            ion_types = available_ions
        elif isinstance(ion_types, str):
            ion_types = [ion_types]
        
        # Validate ion types
        invalid_ions = [ion for ion in ion_types if ion not in available_ions]
        if invalid_ions:
            print(f"⚠️ Warning: Ion types {invalid_ions} not found in results")
        ion_types = [ion for ion in ion_types if ion in available_ions]
        
        if not ion_types:
            raise ValueError("No valid ion types to process")
        
        print(f"Processing ion types: {ion_types}")
        
        # Process shell selection
        if shell_selection is None:
            shell_selection = available_shells
        else:
            shell_selection = [shell for shell in shell_selection if shell in available_shells]
        
        print(f"Selected shells: {shell_selection}")
        
        # Process z-surface values parameter
        if z_surface_values is None:
            z_surface_values = z_values
        else:
            # Find closest matching z-values
            matched_z_values = []
            for target_z in z_surface_values:
                closest_z = min(z_values, key=lambda z: abs(z - target_z))
                matched_z_values.append(closest_z)
            z_surface_values = matched_z_values
        
        print(f"Creating surfaces for z-values: {z_surface_values}")
        
        # Generate colors and alphas if not provided
        if colors is None:
            # Use same color scheme as other methods
            color_cycle = plt.cm.Set1(np.linspace(0, 1, max(8, len(ion_types))))
            colors = {ion_type: color_cycle[i % len(color_cycle)] 
                     for i, ion_type in enumerate(ion_types)}
        elif isinstance(colors, (list, tuple)):
            colors = {ion_type: colors[i % len(colors)] 
                     for i, ion_type in enumerate(ion_types)}
        
        if alphas is None:
            # Use gradual transparency based on number of surfaces
            base_alpha = 0.8
            alphas = {ion_type: base_alpha - 0.1 * i 
                     for i, ion_type in enumerate(ion_types)}
        elif isinstance(alphas, (list, tuple)):
            alphas = {ion_type: alphas[i % len(alphas)] 
                     for i, ion_type in enumerate(ion_types)}
        
        # Transform coordinates to start from 0 (same as PMF method)
        x_display = x_centers - x_centers.min()
        y_display = y_centers - y_centers.min()
        
        # Create meshgrids for surface creation
        X, Y = np.meshgrid(x_display, y_display)
        
        # Initialize results storage
        results = {
            'height_surfaces': {},
            'ion_types': ion_types,
            'surface_metadata': {},
            'x_centers': x_centers,
            'y_centers': y_centers,
            'colors': colors,
            'alphas': alphas,
            'smoothing_applied': smoothing,
            'smoothing_sigma': smoothing_sigma if smoothing else None,
            'z_scale_factor': z_scale_factor,
            'reference_level': reference_level,
            'surface_type': 'coordination_height_based',
            'plot_mode': plot_mode,
            'creation_timestamp': coordination_results.get('timestamp', 'unknown')
        }
        
        # Create surfaces for each ion type
        print(f"\n📊 Creating height surfaces...")
        
        for ion_type in ion_types:
            print(f"\n🔹 Processing {ion_type}:")
            
            ion_surfaces = {}
            
            if plot_mode == 'shells':
                # Create surfaces for different shells (aggregated across Z-layers)
                print(f"  Creating shell-based surfaces...")
                
                for shell_type in shell_selection:
                    print(f"    Processing {shell_type}...")
                    
                    # Collect coordination data for this shell across all Z-layers
                    coord_values = []
                    for z_layer in z_surface_values:
                        z_data = layer_data[z_layer]
                        if ('coordination_grids' in z_data and 
                            shell_type in z_data['coordination_grids'] and
                            ion_type in z_data['coordination_grids'][shell_type]):
                            
                            shell_grid = z_data['coordination_grids'][shell_type][ion_type]
                            coord_values.append(shell_grid)
                    
                    if coord_values:
                        # Average across Z-layers (could also use max, median, etc.)
                        coord_surface = np.mean(coord_values, axis=0)
                        
                        # Handle NaN values
                        if nan_handling == 'interpolate':
                            # Simple interpolation of NaN values
                            mask = np.isfinite(coord_surface)
                            if np.any(mask):
                                coord_surface = self._interpolate_nans(coord_surface)
                        elif nan_handling == 'zero':
                            coord_surface = np.nan_to_num(coord_surface, nan=0.0)
                        # 'mask' option keeps NaNs for later handling
                        
                        # Apply smoothing if requested
                        if smoothing and smoothing_sigma > 0:
                            coord_surface = gaussian_filter(coord_surface, sigma=smoothing_sigma)
                        
                        # Apply grid upsampling if requested
                        if grid_upsampling_factor > 1:
                            coord_surface = self._upsample_grid(coord_surface, X, Y, 
                                                              grid_upsampling_factor, surface_interpolation)
                            # Update meshgrids for upsampled data
                            X_up, Y_up = self._create_upsampled_meshgrids(X, Y, grid_upsampling_factor)
                        else:
                            X_up, Y_up = X, Y
                        
                        # Apply coordination threshold if specified
                        if coordination_threshold_range:
                            min_coord, max_coord = coordination_threshold_range
                            coord_surface = np.clip(coord_surface, min_coord, max_coord)
                        
                        # Convert coordination to height
                        if reference_level == 'zero':
                            base_height = 0.0
                        elif reference_level == 'minimum':
                            base_height = np.nanmin(coord_surface)
                        else:
                            base_height = 0.0  # Default
                        
                        height_surface = base_height + coord_surface * z_scale_factor
                        
                        # Store surface data
                        surface_key = shell_type
                        ion_surfaces[surface_key] = {
                            'surface_data': {
                                'X': X_up,
                                'Y': Y_up,
                                'Z': height_surface
                            },
                            'coordination_grid': coord_surface,  # Store original coordination data
                            'base_z': base_height,
                            'original_z': surface_key,
                            'surface_type': shell_type,
                            'coord_range': (np.nanmin(coord_surface), np.nanmax(coord_surface)),
                            'height_range': (np.nanmin(height_surface), np.nanmax(height_surface))
                        }
                        
                        print(f"      ✓ {shell_type}: coord range = {np.nanmin(coord_surface):.2f} to {np.nanmax(coord_surface):.2f}")
                    
                    else:
                        print(f"      ⚠️ No data found for {ion_type} {shell_type}")
            
            elif plot_mode == 'z_slices':
                # Create surfaces for different Z-layers (aggregated across shells)
                print(f"  Creating Z-slice-based surfaces...")
                
                for z_layer in z_surface_values:
                    print(f"    Processing z = {z_layer:.1f} Å...")
                    
                    z_data = layer_data[z_layer]
                    if 'coordination_grids' in z_data:
                        coord_grids = z_data['coordination_grids']
                        
                        # Sum coordination across all selected shells
                        coord_values = []
                        for shell_type in shell_selection:
                            if (shell_type in coord_grids and 
                                ion_type in coord_grids[shell_type]):
                                
                                shell_grid = coord_grids[shell_type][ion_type]
                                coord_values.append(shell_grid)
                        
                        if coord_values:
                            # Sum across shells for total coordination
                            coord_surface = np.sum(coord_values, axis=0)
                            
                            # Apply same processing as shell mode
                            if nan_handling == 'interpolate':
                                mask = np.isfinite(coord_surface)
                                if np.any(mask):
                                    coord_surface = self._interpolate_nans(coord_surface)
                            elif nan_handling == 'zero':
                                coord_surface = np.nan_to_num(coord_surface, nan=0.0)
                            
                            if smoothing and smoothing_sigma > 0:
                                coord_surface = gaussian_filter(coord_surface, sigma=smoothing_sigma)
                            
                            if grid_upsampling_factor > 1:
                                coord_surface = self._upsample_grid(coord_surface, X, Y, 
                                                                  grid_upsampling_factor, surface_interpolation)
                                X_up, Y_up = self._create_upsampled_meshgrids(X, Y, grid_upsampling_factor)
                            else:
                                X_up, Y_up = X, Y
                            
                            if coordination_threshold_range:
                                min_coord, max_coord = coordination_threshold_range
                                coord_surface = np.clip(coord_surface, min_coord, max_coord)
                            
                            # Convert coordination to height
                            if reference_level == 'zero':
                                base_height = 0.0
                            elif reference_level == 'minimum':
                                base_height = np.nanmin(coord_surface)
                            else:
                                base_height = 0.0
                            
                            height_surface = base_height + coord_surface * z_scale_factor
                            
                            # Store surface data
                            surface_key = z_layer
                            ion_surfaces[surface_key] = {
                                'surface_data': {
                                    'X': X_up,
                                    'Y': Y_up,
                                    'Z': height_surface
                                },
                                'coordination_grid': coord_surface,  # Store original coordination data
                                'base_z': base_height,
                                'original_z': z_layer,
                                'surface_type': f'z_slice_{z_layer}',
                                'coord_range': (np.nanmin(coord_surface), np.nanmax(coord_surface)),
                                'height_range': (np.nanmin(height_surface), np.nanmax(height_surface))
                            }
                            
                            print(f"      ✓ z = {z_layer:.1f}: coord range = {np.nanmin(coord_surface):.2f} to {np.nanmax(coord_surface):.2f}")
                        else:
                            print(f"      ⚠️ No data found for {ion_type} at z = {z_layer}")
                    else:
                        print(f"      ⚠️ No coordination_grids found for z = {z_layer}")
            
            # Store ion data in results
            results['height_surfaces'][ion_type] = {
                'surfaces': ion_surfaces,
                'color': colors[ion_type],
                'alpha': alphas[ion_type]
            }
            
            print(f"  ✓ {ion_type}: {len(ion_surfaces)} surfaces created")
        
        # Store the results in analysis object
        self.results.coordination_height_surfaces = results
        
        # Print summary
        total_surfaces = sum(len(ion_data['surfaces']) for ion_data in results['height_surfaces'].values())
        print(f"\n✅ COORDINATION HEIGHT SURFACES CREATED")
        print(f"{'='*60}")
        print(f"Ion types: {len(ion_types)} ({ion_types})")
        print(f"Plot mode: {plot_mode}")
        print(f"Total surfaces: {total_surfaces}")
        print(f"Smoothing applied: {smoothing}")
        if smoothing:
            print(f"Smoothing sigma: {smoothing_sigma}")
        print(f"Grid upsampling: {grid_upsampling_factor}x")
        print(f"Z-scale factor: {z_scale_factor}")
        
        print(f"\n💡 Coordination Height Surface Interpretation:")
        print(f"  → Surface height = Base height + (Coordination × scale_factor)")
        print(f"  → Higher peaks: More coordinated sites (higher coordination number)")
        print(f"  → Lower valleys: Less coordinated sites (lower coordination number)")
        if plot_mode == 'shells':
            print(f"  → Each surface: Different coordination shell (first/second/third)")
        else:
            print(f"  → Each surface: Different Z-layer (total coordination)")
        
        # Store results in self.results for plotting method to find
        self.results.coordination_height_surfaces = results
        print(f"💾 Height surface data stored in results.coordination_height_surfaces")
        
        return results


    def _interpolate_nans(self, data):
        """Helper method to interpolate NaN values in 2D array"""
        from scipy.interpolate import griddata
        
        # Get valid data points
        valid_mask = np.isfinite(data)
        if not np.any(valid_mask):
            return data  # All NaN, can't interpolate
        
        # Create coordinate arrays
        y, x = np.mgrid[0:data.shape[0], 0:data.shape[1]]
        
        # Get valid points and values
        valid_points = np.column_stack((y[valid_mask], x[valid_mask]))
        valid_values = data[valid_mask]
        
        # Get all grid points
        all_points = np.column_stack((y.ravel(), x.ravel()))
        
        # Interpolate
        interpolated = griddata(valid_points, valid_values, all_points, method='cubic', fill_value=np.nan)
        
        # If cubic fails, try linear
        if np.all(np.isnan(interpolated)):
            interpolated = griddata(valid_points, valid_values, all_points, method='linear', fill_value=np.nan)
        
        # If still fails, try nearest
        if np.all(np.isnan(interpolated)):
            interpolated = griddata(valid_points, valid_values, all_points, method='nearest')
        
        return interpolated.reshape(data.shape)


    def _upsample_grid(self, data, X, Y, factor, method):
        """Helper method to upsample grid data"""
        from scipy.interpolate import interp2d
        
        # Create new higher resolution grids
        x_orig = X[0, :]
        y_orig = Y[:, 0]
        
        new_nx = (len(x_orig) - 1) * factor + 1
        new_ny = (len(y_orig) - 1) * factor + 1
        
        x_new = np.linspace(x_orig.min(), x_orig.max(), new_nx)
        y_new = np.linspace(y_orig.min(), y_orig.max(), new_ny)
        
        # Interpolate
        interp_func = interp2d(x_orig, y_orig, data, kind=method, fill_value=np.nan)
        data_upsampled = interp_func(x_new, y_new)
        
        return data_upsampled


    def _create_upsampled_meshgrids(self, X, Y, factor):
        """Helper method to create upsampled coordinate meshgrids"""
        x_orig = X[0, :]
        y_orig = Y[:, 0]
        
        new_nx = (len(x_orig) - 1) * factor + 1
        new_ny = (len(y_orig) - 1) * factor + 1
        
        x_new = np.linspace(x_orig.min(), x_orig.max(), new_nx)
        y_new = np.linspace(y_orig.min(), y_orig.max(), new_ny)
        
        return np.meshgrid(x_new, y_new)


