    def calculate_pmf_volume_from_ion_density(self, debug_results, ion_types=None,
                                              target_z_values=None, step=1,
                                              z_slice_width=2.0, temperature=300.0,
                                              bulk_density_method='reference_slab',
                                              reference_z=0.0, smooth_pmf=True,
                                              smooth_sigma=0.5, use_parallel=True,
                                              max_workers=None, cube_size=1.0,
                                              x_range=None, y_range=None, z_range=None,
                                              verbose=True):
        """
        Calculate 3D volumetric PMF from ion density across multiple Z-slices.
        
        This method extends the 2D PMF height surface calculation to create a complete
        3D PMF volume covering the entire simulation box. Each Z-slice is processed
        to generate local PMF surfaces, which are then combined into a volumetric
        representation suitable for 3D visualization and analysis.
        
        Parameters
        ----------
        debug_results : dict
            Debug results containing ion position data from trajectory analysis.
        ion_types : list of str, optional
            List of ion types to analyze. If None, all ion types found in debug_results.
        target_z_values : array-like, optional
            Z-coordinates for PMF calculation slices. If None, auto-generated.
        step : int, default=1
            Frame sampling step for trajectory analysis.
        z_slice_width : float, default=2.0
            Thickness of each Z-slice for local PMF calculation (Å).
        temperature : float, default=300.0
            System temperature for PMF calculation (K).
        bulk_density_method : str, default='reference_slab'
            Method for bulk density estimation ('reference_slab', 'average', 'bulk_region').
        reference_z : float, default=0.0
            Reference Z-coordinate for bulk density (Å).
        smooth_pmf : bool, default=True
            Apply Gaussian smoothing to PMF surfaces.
        smooth_sigma : float, default=0.5
            Standard deviation for Gaussian smoothing.
        use_parallel : bool, default=True
            Use parallel processing for Z-slice calculations.
        max_workers : int, optional
            Maximum number of worker processes. If None, uses CPU count.
        cube_size : float, default=1.0
            Size of spatial cubes for density calculation (Å).
        x_range : tuple, optional
            X-axis range (x_min, x_max) in Å. If None, uses full box.
        y_range : tuple, optional
            Y-axis range (y_min, y_max) in Å. If None, uses full box.
        z_range : tuple, optional
            Z-axis range (z_min, z_max) in Å. If None, uses full box.
        verbose : bool, default=True
            Print detailed progress information.
            
        Returns
        -------
        dict
            Dictionary containing volumetric PMF results with keys:
            - 'pmf_volumes': Dict with PMF volumes for each ion type
            - 'x_coords': X-coordinates for volume grid
            - 'y_coords': Y-coordinates for volume grid  
            - 'z_coords': Z-coordinates for volume grid
            - 'metadata': Analysis parameters and statistics
        """
        
        if verbose:
            print("\n" + "="*80)
            print("🧊 3D VOLUMETRIC PMF CALCULATION")
            print("="*80)
            
        # Validate inputs and set defaults
        # Handle the correct data structure from calculate_pmf_vs_z_from_ion_density()
        if 'box_dimensions' in debug_results:
            # Direct format from calculate_pmf_vs_z_from_ion_density()
            box_dims = debug_results['box_dimensions']
            if ion_types is None:
                ion_types = debug_results['ion_types']
        else:
            raise ValueError("Box dimensions not found in debug_results. Make sure debug_results comes from calculate_pmf_vs_z_from_ion_density()")
            
        if not ion_types:
            raise ValueError("No ion types found in debug_results")
            
        if verbose:
            print(f"📋 Ion types to analyze: {ion_types}")
            
        # Get box dimensions - now it's a tuple (x, y, z)
        if isinstance(box_dims, tuple) and len(box_dims) == 3:
            box_x, box_y, box_z = box_dims
        else:
            raise ValueError("Invalid box dimensions format in debug_results")
        
        if verbose:
            print(f"📦 Simulation box: {box_x:.1f} × {box_y:.1f} × {box_z:.1f} Å³")
            
        # Set coordinate ranges
        if self.center_box:
            if x_range is None:
                x_range = (-box_x/2, box_x/2)
            if y_range is None:
                y_range = (-box_y/2, box_y/2)
            if z_range is None:
                z_range = (-box_z/2, box_z/2)
        else:
            if x_range is None:
                x_range = (0, box_x)
            if y_range is None:
                y_range = (0, box_y)
            if z_range is None:
                z_range = (0, box_z)
                
        if verbose:
            print(f"📍 Analysis ranges:")
            print(f"   X: {x_range[0]:.1f} to {x_range[1]:.1f} Å")
            print(f"   Y: {y_range[0]:.1f} to {y_range[1]:.1f} Å") 
            print(f"   Z: {z_range[0]:.1f} to {z_range[1]:.1f} Å")
            
        # Generate Z-slice coordinates if not provided
        if target_z_values is None:
            n_slices = int((z_range[1] - z_range[0]) / z_slice_width)
            target_z_values = np.linspace(z_range[0] + z_slice_width/2,
                                        z_range[1] - z_slice_width/2, n_slices)
            
        if verbose:
            print(f"🔬 Z-slice analysis:")
            print(f"   Number of slices: {len(target_z_values)}")
            print(f"   Slice width: {z_slice_width:.1f} Å")
            print(f"   Z-coordinates: {target_z_values[0]:.1f} to {target_z_values[-1]:.1f} Å")
            
        # Create spatial grids
        n_x = int((x_range[1] - x_range[0]) / cube_size)
        n_y = int((y_range[1] - y_range[0]) / cube_size)
        n_z = len(target_z_values)
        
        x_coords = np.linspace(x_range[0], x_range[1], n_x)
        y_coords = np.linspace(y_range[0], y_range[1], n_y)
        z_coords = target_z_values.copy()
        
        if verbose:
            print(f"📐 Volume grid dimensions: {n_x} × {n_y} × {n_z}")
            print(f"   Cube size: {cube_size:.1f} Å")
            
        # Initialize results storage
        pmf_volumes = {}
        volume_metadata = {
            'ion_types': ion_types,
            'target_z_values': target_z_values,
            'z_slice_width': z_slice_width,
            'temperature': temperature,
            'cube_size': cube_size,
            'x_range': x_range,
            'y_range': y_range,
            'z_range': z_range,
            'smooth_pmf': smooth_pmf,
            'smooth_sigma': smooth_sigma,
            'bulk_density_method': bulk_density_method,
            'reference_z': reference_z,
            'box_dimensions': box_dims,
            'grid_dimensions': (n_x, n_y, n_z)
        }
        
        # Process each ion type
        for ion_idx, ion_type in enumerate(ion_types):
            if verbose:
                print(f"\n🧊 Processing ion type {ion_idx+1}/{len(ion_types)}: {ion_type}")
                
            # Check if ion type exists in the slab_results data
            ion_found = False
            if 'slab_results' in debug_results and debug_results['slab_results']:
                # Check if any slab has this ion type
                for slab_data in debug_results['slab_results'].values():
                    if slab_data and ion_type in slab_data:
                        ion_found = True
                        break
                        
            if not ion_found:
                if verbose:
                    print(f"⚠️  Ion type {ion_type} not found in debug_results slab data, skipping...")
                continue
                
            # Calculate PMF height surfaces for this ion type
            if verbose:
                print(f"📊 Calculating PMF height surfaces...")
                
            surface_results = self.create_pmf_height_surfaces(
                debug_results, 
                ion_types=[ion_type],
                z_surface_values=target_z_values,
                z_spacing=z_slice_width,
                smoothing=smooth_pmf,
                smoothing_sigma=smooth_sigma
            )
            
            # Extract height surface data
            if ion_type in surface_results.get('height_surfaces', {}):
                height_data = surface_results['height_surfaces'][ion_type]
                surface_x = surface_results['x_centers']
                surface_y = surface_results['y_centers']
                
                if verbose:
                    print(f"✅ Height surfaces calculated: {len(height_data)} Z-slices")
                    print(f"   Surface grid: {len(surface_x)} × {len(surface_y)}")
                
                # Interpolate height surfaces to volume grid
                if verbose:
                    print(f"🔄 Interpolating to volume grid...")
                    
                # Initialize 3D PMF volume
                pmf_volume = np.zeros((n_x, n_y, n_z))
                
                # Process each Z-slice
                surfaces_data = height_data['surfaces']  # Get the surfaces dictionary
                for z_idx, target_z in enumerate(target_z_values):
                    if target_z in surfaces_data:
                        # Get PMF grid data for this Z-slice
                        pmf_surface = surfaces_data[target_z]['pmf_grid']
                        
                        # Get the actual coordinates from debug_results for this PMF grid
                        # Use the original coordinate arrays that match the PMF grid dimensions
                        pmf_x_centers = debug_results['x_centers']
                        pmf_y_centers = debug_results['y_centers']
                        
                        # Handle dimension mismatch by transposing if needed
                        if pmf_surface.shape != (len(pmf_x_centers), len(pmf_y_centers)):
                            if pmf_surface.shape == (len(pmf_y_centers), len(pmf_x_centers)):
                                # Transpose the PMF surface to match coordinate order
                                pmf_surface = pmf_surface.T
                                if verbose:
                                    print(f"    🔄 Transposed PMF grid for z={target_z} to match coordinates")
                            else:
                                if verbose:
                                    print(f"    ⚠️ Cannot fix dimension mismatch for z={target_z}: PMF shape {pmf_surface.shape}, coords ({len(pmf_x_centers)}, {len(pmf_y_centers)})")
                                continue
                        
                        # Clean infinite and extreme values for interpolation
                        finite_mask = np.isfinite(pmf_surface)
                        n_finite = np.sum(finite_mask)
                        n_total = pmf_surface.size
                        
                        if verbose:
                            print(f"    📊 z={target_z}: {n_finite}/{n_total} finite PMF values ({100*n_finite/n_total:.1f}%)")
                        
                        if n_finite == 0:
                            if verbose:
                                print(f"    ⚠️ No finite PMF values for z={target_z}, skipping slice")
                            continue
                        
                        # Replace infinite values with reasonable bounds
                        pmf_cleaned = pmf_surface.copy()
                        finite_vals = pmf_surface[finite_mask]
                        pmf_min, pmf_max = np.percentile(finite_vals, [5, 95])
                        
                        # Cap extreme values to reasonable range
                        pmf_cleaned[pmf_surface == np.inf] = pmf_max + 5.0  # +5 kJ/mol above 95th percentile
                        pmf_cleaned[pmf_surface == -np.inf] = pmf_min - 5.0  # -5 kJ/mol below 5th percentile
                        pmf_cleaned[np.isnan(pmf_surface)] = 0.0  # Set NaN to bulk-like (0 kJ/mol)
                        
                        if verbose and not np.array_equal(pmf_surface, pmf_cleaned):
                            print(f"    🧹 Cleaned infinite values, range: {pmf_min:.1f} to {pmf_max:.1f} kJ/mol")
                            
                        # Interpolate surface to volume grid
                        from scipy.interpolate import RegularGridInterpolator
                        
                        # Create interpolator for this surface using cleaned data
                        interp_func = RegularGridInterpolator(
                            (pmf_x_centers, pmf_y_centers),
                            pmf_cleaned,  # Use cleaned data instead of raw pmf_surface
                            bounds_error=False,
                            fill_value=0.0  # Use 0.0 (bulk-like) instead of NaN for extrapolation
                        )
                        
                        # Generate grid points for interpolation
                        X_vol, Y_vol = np.meshgrid(x_coords, y_coords, indexing='ij')
                        grid_points = np.column_stack([X_vol.ravel(), Y_vol.ravel()])
                        
                        # Interpolate and reshape
                        interp_values = interp_func(grid_points).reshape(n_x, n_y)
                        pmf_volume[:, :, z_idx] = interp_values
                        
                # Handle NaN values by forward/backward filling
                for i in range(n_x):
                    for j in range(n_y):
                        z_profile = pmf_volume[i, j, :]
                        
                        # Forward fill
                        mask = ~np.isnan(z_profile)
                        if mask.any():
                            first_valid = np.where(mask)[0][0]
                            last_valid = np.where(mask)[0][-1]
                            
                            # Fill before first valid
                            if first_valid > 0:
                                z_profile[:first_valid] = z_profile[first_valid]
                                
                            # Fill after last valid  
                            if last_valid < len(z_profile) - 1:
                                z_profile[last_valid+1:] = z_profile[last_valid]
                                
                            # Interpolate internal gaps
                            if np.isnan(z_profile).any():
                                valid_indices = np.where(~np.isnan(z_profile))[0]
                                z_profile = np.interp(
                                    np.arange(len(z_profile)),
                                    valid_indices,
                                    z_profile[valid_indices]
                                )
                                
                        pmf_volume[i, j, :] = z_profile
                
                # Store volume data
                pmf_volumes[ion_type] = {
                    'pmf_volume': pmf_volume,
                    'volume_statistics': {
                        'min_pmf': np.nanmin(pmf_volume),
                        'max_pmf': np.nanmax(pmf_volume),
                        'mean_pmf': np.nanmean(pmf_volume),
                        'std_pmf': np.nanstd(pmf_volume),
                        'valid_points': np.sum(~np.isnan(pmf_volume)),
                        'total_points': pmf_volume.size
                    },
                    'source_surfaces': surface_results['height_surfaces'][ion_type]
                }
                
                if verbose:
                    stats = pmf_volumes[ion_type]['volume_statistics']
                    print(f"📈 Volume statistics:")
                    print(f"   PMF range: {stats['min_pmf']:.2f} to {stats['max_pmf']:.2f} kJ/mol")
                    print(f"   Mean ± std: {stats['mean_pmf']:.2f} ± {stats['std_pmf']:.2f} kJ/mol")
                    print(f"   Valid points: {stats['valid_points']:,} / {stats['total_points']:,}")
                    
            else:
                if verbose:
                    print(f"⚠️  No height surface data found for {ion_type}")
                    
        # Compile final results
        results = {
            'pmf_volumes': pmf_volumes,
            'x_coords': x_coords,
            'y_coords': y_coords,
            'z_coords': z_coords,
            'metadata': volume_metadata
        }
        
        if verbose:
            print(f"\n✅ 3D volumetric PMF calculation complete!")
            print(f"📊 Generated volumes for {len(pmf_volumes)} ion types")
            print(f"🧊 Volume grid: {n_x} × {n_y} × {n_z} points")
            print("="*80)
            
        return results


    def calculate_pmf_3d_spatial_distribution(self, 
                                            ion_types=None,
                                            target_z_values=None,
                                            z_slice_width=3.0,
                                            xy_grid_size=0.25, 
                                            temperature=298.15,
                                            units='kJ/mol',
                                            reference_method='center_zero',
                                            reference_region=(-3, 3),
                                            return_format='full_grid',
                                            limit_pmf_range=True,
                                            max_pmf_value=2.0,
                                            density_cutoff_value=1.0,
                                            use_cache=False,
                                            step=1,
                                            **kwargs):
        """
        Calculate 3D potential of mean force with CORRECTED bulk region understanding.
        
        CRITICAL FIX: For clay-water systems, bulk is at CENTER (reference_region),
        NOT at the edges. PMF should be: PMF(z) = -kT ln(ρ(z) / ρ_bulk)
        where ρ_bulk is density in reference_region (-3,3).
        """
        
        print(f"\n🔧 3D PMF CALCULATION - CORRECTED BULK REGION")
        print(f"CRITICAL FIX: Bulk region is CENTER ({reference_region}), not edges!")
        
        # Unit conversion
        from scipy import constants
        kT_joules = constants.k * temperature
        kT_kJ_mol = kT_joules * constants.N_A / 1000
        
        conversion_factors = {
            'kT': 1.0,
            'kJ/mol': kT_kJ_mol,
            'kcal/mol': kT_kJ_mol / 4.184,
            'eV': kT_kJ_mol / 96.485
        }
        
        if units not in conversion_factors:
            raise ValueError(f"Unknown units: {units}")
        
        unit_factor = conversion_factors[units]
        print(f"✓ Unit factor: {unit_factor:.6f}")
        
        # Get ion types
        if ion_types is None:
            ion_types = list(self.cation_types.keys()) + list(self.anion_types.keys())
        
        if isinstance(ion_types, str):
            ion_types = [ion_types]
        
        # Use existing z-grid from 1D analysis for perfect alignment
        if not hasattr(self, 'z_edges') or not hasattr(self, 'z_centers'):
            raise ValueError("Run 1D analysis first to establish z-grid")
        
        z_edges = self.z_edges.copy()
        z_centers = self.z_centers.copy()
        
        print(f"✓ Using 1D z-grid: {len(z_centers)} points")
        print(f"✓ Reference region (BULK): {reference_region} Å")
        
        # Create XY grid
        box_x = self.universe.dimensions[0]
        box_y = self.universe.dimensions[1]
        
        n_x_bins = int(np.ceil(box_x / xy_grid_size))
        n_y_bins = int(np.ceil(box_y / xy_grid_size))
        
        x_edges = np.linspace(0, box_x, n_x_bins + 1)
        y_edges = np.linspace(0, box_y, n_y_bins + 1)
        x_centers = (x_edges[:-1] + x_edges[1:]) / 2
        y_centers = (y_edges[:-1] + y_edges[1:]) / 2
        
        print(f"XY grid: {n_x_bins} × {n_y_bins}")
        
        # Initialize results
        results = {
            'x_centers': x_centers,
            'y_centers': y_centers, 
            'z_centers': z_centers,
            'x_edges': x_edges,
            'y_edges': y_edges,
            'z_edges': z_edges,
            'temperature': temperature,
            'units': units,
            'unit_factor': unit_factor,
            'z_slice_width': z_slice_width,
            'reference_method': reference_method,
            'reference_region': reference_region,
            'return_format': return_format,
            'ion_pmf_data': {}
        }
        
        # Process each ion type
        for ion_type in ion_types:
            print(f"\n🔍 Processing {ion_type} (CORRECTED BULK CALCULATION)...")
            
            ion_selection = self._get_ion_selection(ion_type)
            if ion_selection is None or len(ion_selection) == 0:
                continue
            
            print(f"  Found {len(ion_selection)} {ion_type} ions")
            
            # ✅ CRITICAL FIX: Use 1D density for bulk calculation
            print(f"  📊 Calculating bulk density from 1D analysis (CORRECTED)...")
            
            # Get 1D density profile for this ion
            if ion_type not in self.results.ion_densities_by_type:
                print(f"    ❌ No 1D density data for {ion_type}")
                continue
                
            density_1d = self.results.ion_densities_by_type[ion_type]
            
            # ✅ CORRECT BULK CALCULATION: Use reference region as bulk
            bulk_z_min, bulk_z_max = reference_region
            bulk_z_mask = (z_centers >= bulk_z_min) & (z_centers <= bulk_z_max)
            
            if not np.any(bulk_z_mask):
                print(f"    ❌ No z-bins in reference region {reference_region}")
                continue
                
            # Calculate bulk density from 1D profile in reference region
            bulk_density = np.mean(density_1d[bulk_z_mask])
            n_bulk_points = np.sum(bulk_z_mask)
            
            print(f"    ✅ CORRECTED bulk density calculation:")
            print(f"      Reference region: {bulk_z_min:.1f} to {bulk_z_max:.1f} Å")
            print(f"      Z-bins used: {n_bulk_points}")
            print(f"      Bulk density (ρ_bulk): {bulk_density:.8f} ions/Å³")
            
            # Verify this matches expected bulk behavior
            if bulk_density <= 0:
                print(f"    ❌ Invalid bulk density: {bulk_density}")
                continue
            
            # Calculate 3D density for target z-slices
            print(f"  🔄 Calculating 3D density distribution...")
            
            if target_z_values is not None:
                z_slice_results = {}
                
                for target_z in target_z_values:
                    print(f"    Processing z-slice at {target_z} ± {z_slice_width/2} Å")
                    
                    # Define z-slice bounds
                    z_min_slice = target_z - z_slice_width/2
                    z_max_slice = target_z + z_slice_width/2
                    
                    # Initialize 2D grid for this z-slice
                    density_2d = np.zeros((len(y_centers), len(x_centers)))
                    frame_count = 0
                    ions_in_slice_count = 0
                    
                    # Loop through trajectory
                    for ts in self.universe.trajectory[::step]:
                        # Get ion positions
                        positions = ion_selection.positions.copy()
                        
                        # Apply same centering as 1D analysis
                        if self.center_box:
                            box_center = self.universe.dimensions[2] / 2
                            positions[:, 2] -= box_center
                        
                        # Filter: Only ions within z-slice
                        z_mask = (positions[:, 2] >= z_min_slice) & (positions[:, 2] <= z_max_slice)
                        slice_positions = positions[z_mask]
                        
                        ions_in_slice_count += len(slice_positions)
                        
                        if len(slice_positions) > 0:
                            # Bin XY positions only
                            hist_2d, _ = np.histogramdd(slice_positions[:, :2], bins=[y_edges, x_edges])
                            density_2d += hist_2d
                        
                        frame_count += 1
                    
                    # Normalization: Account for z-slice thickness
                    xy_area = (x_edges[1] - x_edges[0]) * (y_edges[1] - y_edges[0])
                    slice_volume = xy_area * z_slice_width
                    density_2d = density_2d / (frame_count * slice_volume)
                    
                    print(f"      ✓ Z-slice processed:")
                    print(f"        Total ions in slice: {ions_in_slice_count}")
                    print(f"        Density range: {np.min(density_2d):.8f} to {np.max(density_2d):.8f} ions/Å³")
                    
                    # ✅ CORRECTED PMF CALCULATION
                    print(f"      🧮 Calculating PMF using CORRECTED formula...")
                    print(f"        PMF(z) = -kT ln(ρ(z) / ρ_bulk)")
                    print(f"        ρ_bulk = {bulk_density:.8f} ions/Å³ (from reference region)")
                    
                    # Apply density cutoff
                    min_density = bulk_density * (density_cutoff_value / 100.0)
                    density_2d_safe = np.maximum(density_2d, min_density)
                    
                    # ✅ CORRECT PMF CALCULATION using bulk from reference region
                    pmf_2d = -unit_factor * np.log(density_2d_safe / bulk_density)
                    
                    # Apply range limiting
                    if limit_pmf_range:
                        pmf_2d = np.where(pmf_2d > max_pmf_value, max_pmf_value, pmf_2d)
                    
                    print(f"        PMF range: {np.min(pmf_2d):.3f} to {np.max(pmf_2d):.3f} {units}")
                    
                    # ✅ CORRECTED SHIFTING: Set reference region to zero
                    if target_z >= bulk_z_min and target_z <= bulk_z_max:
                        # This z-slice is in the reference region, it should be ~0 after shifting
                        print(f"        🎯 This z-slice is in reference region - PMF should be ~0")
                        
                        # Calculate average PMF in this reference slice
                        avg_pmf_in_ref = np.mean(pmf_2d)
                        
                        # Shift to make reference region average = 0
                        pmf_2d_shifted = pmf_2d - avg_pmf_in_ref
                        
                        print(f"        Original avg PMF: {avg_pmf_in_ref:.3f} {units}")
                        print(f"        After shifting: {np.mean(pmf_2d_shifted):.3f} {units} (should be ~0)")
                        
                        pmf_2d = pmf_2d_shifted
                    
                    # Store results for this z-slice
                    z_slice_results[target_z] = {
                        'target_z': target_z,
                        'z_min': z_min_slice,
                        'z_max': z_max_slice,
                        'z_width': z_slice_width,
                        'pmf_surface': pmf_2d,
                        'density_surface': density_2d,
                        'bulk_density': bulk_density,
                        'bulk_calculation_method': 'reference_region_from_1D',
                        'reference_region_used': reference_region,
                        'ions_in_slice': ions_in_slice_count,
                        'frames_processed': frame_count
                    }
            
            # Store in results
            ion_results = {
                'z_slice_surfaces': z_slice_results,
                'bulk_density': bulk_density,
                'bulk_calculation_method': 'reference_region_corrected',
                'reference_region': reference_region,
                'x_centers': x_centers,
                'y_centers': y_centers,
                'xy_grid_size': xy_grid_size,
                'z_slice_width': z_slice_width,
                'target_z_values': target_z_values
            }
            
            results['ion_pmf_data'][ion_type] = ion_results
            
            print(f"  ✅ {ion_type} completed with CORRECTED bulk calculation")
            print(f"      Bulk density (ρ_bulk): {bulk_density:.8f} ions/Å³")
            print(f"      Reference region: {reference_region} Å")
        
        # Store results
        self.results.pmf_3d_spatial_distribution = results
        
        print(f"\n✅ 3D PMF CALCULATION COMPLETE (CORRECTED)")
        print(f"Key corrections applied:")
        print(f"  ✓ Bulk region correctly identified as reference region {reference_region}")
        print(f"  ✓ PMF formula: PMF(z) = -kT ln(ρ(z) / ρ_bulk)")
        print(f"  ✓ ρ_bulk calculated from 1D density in reference region")
        print(f"  ✓ Shifting makes reference region PMF ≈ 0")
        
        return results



