    def plot_density_profiles(self, ion_types=None, save_plots=True, figsize=(15, 12),
                             show_counts=True, show_density=True):
        '''
        Plot density profiles and count profiles vs z-position
        
        Parameters
        ----------
        ion_types : list, optional
            Specific ion types to plot. If None, plots all
        save_plots : bool
            Save plots to files
        figsize : tuple
            Figure size (width, height)
        show_counts : bool
            Show count profiles (raw counts)
        show_density : bool  
            Show density profiles (number/Å³)
        '''
        
        if not show_counts and not show_density:
            print("Error: At least one of show_counts or show_density must be True")
            return
        
        # Determine number of subplots needed
        n_plots = 0
        if show_density:
            n_plots += 1
        if show_counts:
            n_plots += 1
        
        fig, axes = plt.subplots(n_plots, 2, figsize=figsize)
        if n_plots == 1:
            axes = axes.reshape(1, -1)
        
        plot_idx = 0
        
        # DENSITY PROFILES
        if show_density:
            # Plot 1: All species density profiles
            ax1 = axes[plot_idx, 0]
            
            ax1.plot(self.z_centers, self.results.water_density, 'b-', linewidth=2, label='Water')
            ax1.plot(self.z_centers, self.results.cation_density, 'r-', linewidth=2, label='Cations')
            ax1.plot(self.z_centers, self.results.anion_density, 'g-', linewidth=2, label='Anions')
            
            ax1.set_xlabel('z (Å)')
            ax1.set_ylabel('Number Density (molecules/Å³)')
            ax1.set_title('Density Profiles vs Z-Position', fontweight='bold')
            ax1.legend()
            ax1.grid(True, alpha=0.3)
            ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            # Plot 2: Ion-specific density profiles
            ax2 = axes[plot_idx, 1]
            
            colors = ['red', 'orange', 'purple', 'brown', 'pink', 'gray']
            color_idx = 0
            
            for ion_type, density in self.results.ion_densities_by_type.items():
                if ion_types is None or ion_type in ion_types:
                    color = colors[color_idx % len(colors)]
                    ax2.plot(self.z_centers, density, color=color, linewidth=2, 
                            label=f'{ion_type}', linestyle='-' if ion_type in self.cation_types else '--')
                    color_idx += 1
            
            ax2.set_xlabel('z (Å)')
            ax2.set_ylabel('Number Density (ions/Å³)')
            ax2.set_title('Ion-Specific Density Profiles', fontweight='bold')
            ax2.legend()
            ax2.grid(True, alpha=0.3)
            ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            plot_idx += 1
        
        # COUNT PROFILES
        if show_counts:
            # Plot 3: All species count profiles
            ax3 = axes[plot_idx, 0]
            
            ax3.plot(self.z_centers, self.results.water_counts, 'b-', linewidth=2, label='Water')
            ax3.plot(self.z_centers, self.results.cation_counts, 'r-', linewidth=2, label='Cations')
            ax3.plot(self.z_centers, self.results.anion_counts, 'g-', linewidth=2, label='Anions')
            
            ax3.set_xlabel('z (Å)')
            ax3.set_ylabel('Average Count per Frame')
            ax3.set_title('Count Profiles vs Z-Position', fontweight='bold')
            ax3.legend()
            ax3.grid(True, alpha=0.3)
            ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            # Plot 4: Ion-specific count profiles
            ax4 = axes[plot_idx, 1]
            
            colors = ['red', 'orange', 'purple', 'brown', 'pink', 'gray']
            color_idx = 0
            
            for ion_type, counts in self.results.ion_counts_by_type.items():
                if ion_types is None or ion_type in ion_types:
                    color = colors[color_idx % len(colors)]
                    ax4.plot(self.z_centers, counts, color=color, linewidth=2, 
                            label=f'{ion_type}', linestyle='-' if ion_type in self.cation_types else '--')
                    color_idx += 1
            
            ax4.set_xlabel('z (Å)')
            ax4.set_ylabel('Average Count per Frame')
            ax4.set_title('Ion-Specific Count Profiles', fontweight='bold')
            ax4.legend()
            ax4.grid(True, alpha=0.3)
            ax4.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            filename = 'z_density_and_count_profiles.png'
            plt.savefig(filename, dpi=300, bbox_inches='tight')
            print(f"Density and count profiles plot saved as: {filename}")
        
        plt.show()
        
        # Print summary statistics
        print(f"\nDensity Profile Summary:")
        print(f"  Water density range: {np.min(self.results.water_density):.3f} - {np.max(self.results.water_density):.3f} molecules/Å³")
        print(f"  Water count range: {np.min(self.results.water_counts):.1f} - {np.max(self.results.water_counts):.1f} molecules/bin")
        print(f"  Total analyzed frames: {self.n_frames_analyzed}")

    def plot_coordination_vs_z(self, ion_types=None, bin_size=2.0, save_plots=True, figsize=(12, 8)):
        '''Plot coordination numbers vs z-position'''
        
        if not self.results.coordination_vs_z:
            print("No coordination data available. Run analysis first.")
            return
        
        fig, axes = plt.subplots(1, 2, figsize=figsize)
        
        colors = ['red', 'blue', 'green', 'orange', 'purple', 'brown']
        color_idx = 0
        
        # Plot 1: Raw coordination data (scatter)
        ax1 = axes[0]
        
        for ion_type, data in self.results.coordination_vs_z.items():
            if (ion_types is None or ion_type in ion_types) and data['z_positions']:
                color = colors[color_idx % len(colors)]
                ax1.scatter(data['z_positions'], data['coordination_numbers'], 
                           alpha=0.6, s=20, color=color, label=ion_type)
                color_idx += 1
        
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Coordination Number')
        ax1.set_title('Ion Coordination vs Z-Position (Raw Data)', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Binned coordination data (smooth curves)
        ax2 = axes[1]
        color_idx = 0
        
        for ion_type, data in self.results.coordination_vs_z.items():
            if (ion_types is None or ion_type in ion_types) and data['z_positions']:
                z_pos = np.array(data['z_positions'])
                coord_nums = np.array(data['coordination_numbers'])
                
                # Bin the data
                z_bins = np.arange(self.z_min, self.z_max + bin_size, bin_size)
                z_bin_centers = (z_bins[:-1] + z_bins[1:]) / 2
                
                binned_coord = []
                for i in range(len(z_bins)-1):
                    mask = (z_pos >= z_bins[i]) & (z_pos < z_bins[i+1])
                    if np.any(mask):
                        binned_coord.append(np.mean(coord_nums[mask]))
                    else:
                        binned_coord.append(0)
                
                color = colors[color_idx % len(colors)]
                ax2.plot(z_bin_centers, binned_coord, color=color, linewidth=2, 
                        marker='o', markersize=4, label=ion_type)
                color_idx += 1
        
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Average Coordination Number')
        ax2.set_title(f'Average Ion Coordination vs Z (bin size: {bin_size} Å)', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            plt.savefig('coordination_vs_z.png', dpi=300, bbox_inches='tight')
            print("Coordination vs z plot saved as: coordination_vs_z.png")
        
        plt.show()

