    def calculate_clay_interface_boundaries(self, n_frames_average=50):
        """Calculate clay interface boundaries with configurable frame averaging for cleaved clay systems"""
        
        print("🧱 CALCULATING CLAY INTERFACE BOUNDARIES...")
        print("="*50)
        
        original_frame = self.universe.trajectory.ts.frame
        
        try:
            # ✅ COLLECT BOTH SI AND MG POSITIONS FROM MULTIPLE FRAMES
            all_si_positions = []
            all_mg_positions = []
            
            # Use frames around frame 100 (centered on frame 100)
            center_frame = min(100, len(self.universe.trajectory) - 1)
            start_frame = max(0, center_frame - n_frames_average//2)
            end_frame = min(len(self.universe.trajectory), center_frame + n_frames_average//2)
            
            # Ensure we have the requested number of frames (or close to it)
            actual_frames = end_frame - start_frame
            
            print(f"📊 Frame averaging configuration:")
            print(f"   Requested frames: {n_frames_average}")
            print(f"   Center frame: {center_frame}")
            print(f"   Frame range: {start_frame} to {end_frame-1}")
            print(f"   Actual frames: {actual_frames}")
            
            for frame_idx in range(start_frame, end_frame):
                self.universe.trajectory[frame_idx]
                
                # Get Si atoms (always split between upper/lower in cleaved systems)
                si_atoms = self.universe.select_atoms("resname MMT and (name Si or name SI or name Sio or name SIO)")
                
                # Get Mg atoms (variable distribution between frames)
                mg_atoms = self.universe.select_atoms("resname MMT and (name Mgo or name MGO)")
                
                if len(si_atoms) > 0:
                    si_z = si_atoms.positions[:, 2].copy()
                    
                    # Apply centering if enabled
                    if self.center_box:
                        si_z -= self.universe.dimensions[2] / 2.0
                    
                    all_si_positions.extend(si_z)
                
                if len(mg_atoms) > 0:
                    mg_z = mg_atoms.positions[:, 2].copy()
                    
                    # Apply centering if enabled
                    if self.center_box:
                        mg_z -= self.universe.dimensions[2] / 2.0
                    
                    all_mg_positions.extend(mg_z)
            
            # Convert to arrays
            si_positions = np.array(all_si_positions) if all_si_positions else np.array([])
            mg_positions = np.array(all_mg_positions) if all_mg_positions else np.array([])
            
            # ✅ CHECK FOR CLAY DETECTION FAILURE
            if len(si_positions) == 0 and len(mg_positions) == 0:
                print("❌ CLAY DETECTION FAILED: No Si or Mg atoms found")
                print("   Checked atom selections:")
                print("   - Si: 'resname MMT and (name Si or name SI or name Sio or name SIO)'")
                print("   - Mg: 'resname MMT and (name Mgo or name MGO)'")
                return None
            
            print(f"✅ Found clay atoms:")
            print(f"   Si positions analyzed: {len(si_positions)} (from {actual_frames} frames)")
            print(f"   Mg positions analyzed: {len(mg_positions)} (from {actual_frames} frames)")
            
            # ✅ ANALYZE SI ATOMS (PRIMARY REFERENCE - ALWAYS SPLIT)
            si_upper = si_positions[si_positions >= 0] if len(si_positions) > 0 else np.array([])
            si_lower = si_positions[si_positions < 0] if len(si_positions) > 0 else np.array([])
            
            # ✅ ANALYZE MG ATOMS (VARIABLE DISTRIBUTION)
            mg_upper = mg_positions[mg_positions >= 0] if len(mg_positions) > 0 else np.array([])
            mg_lower = mg_positions[mg_positions < 0] if len(mg_positions) > 0 else np.array([])
            
            # Print distribution analysis
            print(f"\n📊 Cleaved clay distribution analysis:")
            print(f"   Si atoms (always split):")
            print(f"     Upper region: {len(si_upper)} atoms")
            print(f"     Lower region: {len(si_lower)} atoms")
            print(f"   Mg atoms (variable):")
            print(f"     Upper region: {len(mg_upper)} atoms")
            print(f"     Lower region: {len(mg_lower)} atoms")
            
            # ✅ ADDITIONAL VALIDATION: Check if we have reasonable clay distribution
            if len(si_positions) > 0:
                # For cleaved clay, we should have Si in both regions
                if len(si_upper) == 0 or len(si_lower) == 0:
                    print("⚠️  WARNING: Si atoms found only in one region")
                    print("   This might indicate:")
                    print("   1. Non-cleaved clay system")
                    print("   2. Unusual clay orientation")
                    print("   3. Insufficient sampling frames")
            
            # ✅ CALCULATE BOUNDARIES USING KEYS EXPECTED BY PLOTTING METHOD
            boundaries = {
                'system_type': 'cleaved_clay',
                'si_distribution': 'always_split',
                'mg_distribution': 'variable'
            }
            
            # Overall clay boundaries (using Si as primary reference)
            boundaries['clay_average_z_positive'] = np.mean(si_upper) if len(si_upper) > 0 else None
            boundaries['clay_average_z_negative'] = np.mean(si_lower) if len(si_lower) > 0 else None
            
            # Si layer boundaries (same as clay for cleaved systems)
            boundaries['si_average_z_positive'] = boundaries['clay_average_z_positive']
            boundaries['si_average_z_negative'] = boundaries['clay_average_z_negative']
            
            # Mg layer boundaries (supplementary information)
            boundaries['mgo_average_z_positive'] = np.mean(mg_upper) if len(mg_upper) > 0 else None
            boundaries['mgo_average_z_negative'] = np.mean(mg_lower) if len(mg_lower) > 0 else None
            
            # Additional boundaries for compatibility with plotting method
            boundaries['upper_clay_avg'] = boundaries['clay_average_z_positive']  # Alias
            boundaries['lower_clay_avg'] = boundaries['clay_average_z_negative']  # Alias
            boundaries['upper_si_above'] = boundaries['si_average_z_positive']    # Alias
            boundaries['lower_si_below'] = boundaries['si_average_z_negative']    # Alias
            boundaries['upper_mgo'] = boundaries['mgo_average_z_positive']        # Alias
            boundaries['lower_mgo'] = boundaries['mgo_average_z_negative']        # Alias
            
            # Min/max boundaries for each region
            boundaries['clay_min_z_positive'] = np.min(si_upper) if len(si_upper) > 0 else None
            boundaries['clay_max_z_positive'] = np.max(si_upper) if len(si_upper) > 0 else None
            boundaries['clay_min_z_negative'] = np.min(si_lower) if len(si_lower) > 0 else None
            boundaries['clay_max_z_negative'] = np.max(si_lower) if len(si_lower) > 0 else None
            
            # Mg distribution characterization
            if len(mg_upper) > 0 and len(mg_lower) > 0:
                boundaries['mg_distribution'] = 'split'
            elif len(mg_upper) > 0:
                boundaries['mg_distribution'] = 'upper_only'
            elif len(mg_lower) > 0:
                boundaries['mg_distribution'] = 'lower_only'
            else:
                boundaries['mg_distribution'] = 'none_found'
            
            # Store additional statistics
            boundaries['n_si_upper'] = len(si_upper)
            boundaries['n_si_lower'] = len(si_lower)
            boundaries['n_mg_upper'] = len(mg_upper)
            boundaries['n_mg_lower'] = len(mg_lower)
            boundaries['n_si_atoms'] = len(si_positions)
            boundaries['n_mgo_atoms'] = len(mg_positions)
            boundaries['n_total_clay_atoms'] = len(si_positions) + len(mg_positions)
            boundaries['frames_averaged'] = actual_frames
            boundaries['n_frames_requested'] = n_frames_average
            boundaries['center_frame'] = center_frame
            
            # Store in results
            if not hasattr(self.results, 'clay_interface_boundaries'):
                self.results.clay_interface_boundaries = boundaries
            
            # Print summary with proper handling of None values
            print(f"\n📊 CLAY INTERFACE BOUNDARIES SUMMARY:")
            print(f"   System type: Cleaved clay (Si always split)")
            print(f"   Upper region (z > 0):")
            print(f"     Si layer average:     {boundaries['si_average_z_positive']:.2f} Å" if boundaries['si_average_z_positive'] is not None else "     Si layer average:     No Si atoms found")
            print(f"     Mg layer average:     {boundaries['mgo_average_z_positive']:.2f} Å" if boundaries['mgo_average_z_positive'] is not None else "     Mg layer average:     No Mg atoms found")
            print(f"     Overall clay average: {boundaries['clay_average_z_positive']:.2f} Å" if boundaries['clay_average_z_positive'] is not None else "     Overall clay average: No atoms found")
            print(f"   Lower region (z < 0):")
            print(f"     Si layer average:     {boundaries['si_average_z_negative']:.2f} Å" if boundaries['si_average_z_negative'] is not None else "     Si layer average:     No Si atoms found")
            print(f"     Mg layer average:     {boundaries['mgo_average_z_negative']:.2f} Å" if boundaries['mgo_average_z_negative'] is not None else "     Mg layer average:     No Mg atoms found")
            print(f"     Overall clay average: {boundaries['clay_average_z_negative']:.2f} Å" if boundaries['clay_average_z_negative'] is not None else "     Overall clay average: No atoms found")
            print(f"   Mg distribution: {boundaries['mg_distribution']}")
            print(f"   Frame averaging: {actual_frames} frames (requested: {n_frames_average})")
            print(f"✅ Clay interface boundaries calculation completed!")
            
            return boundaries
            
        except Exception as e:
            print(f"❌ CLAY DETECTION FAILED: {e}")
            print("   Error occurred during clay boundary calculation")
            import traceback
            traceback.print_exc()
            return None
            
        finally:
            # Restore original frame
            self.universe.trajectory[original_frame]


    def plot_dipole_orientation_vs_z(self, save_plots=True, figsize=None, 
                                    bin_size=2.0, filename=None):
        '''Plot water dipole orientation vs z-position with heatmap'''
        
        self._validate_analysis()
        
        if not self.analysis.results.dipole_vs_z['z_positions']:
            print("No dipole orientation data available. This is collected during run() analysis.")
            return
        
        figsize = figsize or (18, 6)
        fig, axes = plt.subplots(1, 3, figsize=figsize)
        
        z_pos = np.array(self.analysis.results.dipole_vs_z['z_positions'])
        angles = np.array(self.analysis.results.dipole_vs_z['dipole_angles'])
        
        # Plot 1: Raw scatter plot
        ax1 = axes[0]
        ax1.scatter(z_pos, angles, alpha=0.3, s=5, color='blue')
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Dipole Angle (degrees)')
        ax1.set_title('Water Dipole Orientation vs Z (Raw Data)', fontweight='bold')
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        ax1.axhline(90, color='r', linestyle='--', alpha=0.5, label='Random orientation')
        ax1.legend()
        
        # Plot 2: 2D Histogram Heatmap
        ax2 = axes[1]
        
        # Create 2D histogram
        z_bins = np.arange(self.analysis.z_min, self.analysis.z_max + bin_size, bin_size)
        angle_bins = np.arange(0, 181, 5)  # 5-degree bins for angles
        
        H, xedges, yedges = np.histogram2d(z_pos, angles, bins=[z_bins, angle_bins])
        
        # Plot as heatmap
        im = ax2.imshow(H.T, origin='lower', aspect='auto', cmap='hot',
                        extent=[z_bins[0], z_bins[-1], angle_bins[0], angle_bins[-1]],
                        interpolation='gaussian')
        
        ax2.axhline(90, color='cyan', linestyle='--', linewidth=2, 
                alpha=0.7, label='Random (90°)')
        ax2.axvline(0, color='white', linestyle='--', linewidth=1, alpha=0.5)
        
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Dipole Angle (degrees)')
        ax2.set_title('Dipole Orientation Density Map', fontweight='bold')
        
        # Add colorbar
        cbar = plt.colorbar(im, ax=ax2)
        cbar.set_label('Count Density')
        ax2.legend(loc='upper right')
        
        # Plot 3: Binned averages with standard deviation
        ax3 = axes[2]
        
        z_bin_centers = (z_bins[:-1] + z_bins[1:]) / 2
        
        binned_angles = []
        binned_stds = []
        for i in range(len(z_bins)-1):
            mask = (z_pos >= z_bins[i]) & (z_pos < z_bins[i+1])
            if np.any(mask):
                binned_angles.append(np.mean(angles[mask]))
                binned_stds.append(np.std(angles[mask]))
            else:
                binned_angles.append(np.nan)
                binned_stds.append(np.nan)
        
        binned_angles = np.array(binned_angles)
        binned_stds = np.array(binned_stds)
        
        # Remove NaN values
        valid = ~np.isnan(binned_angles)
        
        ax3.plot(z_bin_centers[valid], binned_angles[valid], 'b-', 
                linewidth=2, marker='o', markersize=4, label='Mean angle')
        ax3.fill_between(z_bin_centers[valid], 
                        binned_angles[valid] - binned_stds[valid],
                        binned_angles[valid] + binned_stds[valid],
                        alpha=0.3, color='blue', label='±1 std')
        
        ax3.set_xlabel('z (Å)')
        ax3.set_ylabel('Average Dipole Angle (degrees)')
        ax3.set_title(f'Average Orientation (bin: {bin_size} Å)', fontweight='bold')
        ax3.grid(True, alpha=0.3)
        ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
        ax3.axhline(90, color='r', linestyle='--', alpha=0.5, label='Random (90°)')
        ax3.legend()
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'dipole_orientation_vs_z_with_heatmap.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Dipole orientation heatmap plot saved as: {filename}")
        
        plt.show()
        
        # Print summary
        print(f"\nDipole Orientation Analysis Summary:")
        print(f"  Total water molecules analyzed: {len(angles)}")
        print(f"  Mean dipole angle: {np.mean(angles):.1f}°")
        print(f"  Standard deviation: {np.std(angles):.1f}°")
        print(f"  Median dipole angle: {np.median(angles):.1f}°")
        print(f"  Note: 90° indicates random orientation")
        print(f"        <90° indicates preferential alignment")
        print(f"        >90° indicates preferential anti-alignment")



    def analyze_layer_properties(self, layer_boundaries, layer_names=None):
        '''
        Analyze properties within defined layers
        
        Parameters
        ----------
        layer_boundaries : list
            Z-coordinates defining layer boundaries
        layer_names : list, optional
            Names for each layer region
        
        Returns
        -------
        layer_analysis : dict
            Analysis results for each layer
        '''
        
        if layer_names is None:
            layer_names = [f'Layer_{i+1}' for i in range(len(layer_boundaries)-1)]
        
        print(f"Analyzing layer properties with {len(layer_names)} layers:")
        for i, name in enumerate(layer_names):
            print(f"  {name}: {layer_boundaries[i]:.2f} to {layer_boundaries[i+1]:.2f} Å")
        
        layer_analysis = {}
        
        for i, layer_name in enumerate(layer_names):
            z_start = layer_boundaries[i]
            z_end = layer_boundaries[i+1]
            
            # Find bins within this layer
            layer_mask = (self.z_centers >= z_start) & (self.z_centers <= z_end)
            
            if not np.any(layer_mask):
                print(f"Warning: No bins found in layer {layer_name}")
                continue
            
            layer_results = {
                'z_range': (z_start, z_end),
                'z_center': (z_start + z_end) / 2,
                'thickness': z_end - z_start,
                'n_bins': np.sum(layer_mask)
            }
            
            # Average densities in this layer
            layer_results['water_density'] = np.mean(self.results.water_density[layer_mask])
            layer_results['cation_density'] = np.mean(self.results.cation_density[layer_mask])
            layer_results['anion_density'] = np.mean(self.results.anion_density[layer_mask])
            layer_results['total_density'] = np.mean(self.results.total_density[layer_mask])
            
            # Average counts in this layer
            layer_results['water_counts'] = np.mean(self.results.water_counts[layer_mask])
            layer_results['cation_counts'] = np.mean(self.results.cation_counts[layer_mask])
            layer_results['anion_counts'] = np.mean(self.results.anion_counts[layer_mask])
            layer_results['total_counts'] = np.mean(self.results.total_counts[layer_mask])
            
            # Ion-specific densities
            layer_results['ion_densities'] = {}
            layer_results['ion_counts'] = {}
            for ion_type, density in self.results.ion_densities_by_type.items():
                layer_results['ion_densities'][ion_type] = np.mean(density[layer_mask])
                layer_results['ion_counts'][ion_type] = np.mean(self.results.ion_counts_by_type[ion_type][layer_mask])
            
            layer_analysis[layer_name] = layer_results
        
        # Store layer analysis in results
        self.results.layer_analysis = layer_analysis
        
        # Print summary
        print(f"\nLayer Analysis Summary:")
        for layer_name, data in layer_analysis.items():
            print(f"  {layer_name}:")
            print(f"    Water density: {data['water_density']:.3f} molecules/Å³")
            print(f"    Water counts: {data['water_counts']:.1f} molecules/bin")
            print(f"    Total density: {data['total_density']:.3f} atoms/Å³")
        
        return layer_analysis         

    def export_results(self, filename='z_directional_analysis.pkl'):
        '''Export analysis results to file'''
        
        # Create export data dictionary
        export_data = {
            # Basic analysis parameters
            'analysis_parameters': {
                'z_min': self.z_min,
                'z_max': self.z_max,
                'n_bins': self.n_bins,
                'bin_width': self.bin_width,
                'center_box': self.center_box
            },
            
            # Basic density and count profiles
            'z_centers': self.results.z_centers,
            'z_edges': self.results.z_edges,
            'water_density': self.results.water_density,
            'cation_density': self.results.cation_density,
            'anion_density': self.results.anion_density,
            'total_density': self.results.total_density,
            'water_counts': self.results.water_counts,
            'cation_counts': self.results.cation_counts,
            'anion_counts': self.results.anion_counts,
            'total_counts': self.results.total_counts,
            'ion_densities_by_type': self.results.ion_densities_by_type,
            'ion_counts_by_type': self.results.ion_counts_by_type,
            'coordination_vs_z': self.results.coordination_vs_z,
            'dipole_vs_z': self.results.dipole_vs_z,
            'n_frames_analyzed': self.n_frames_analyzed,
        }
        
        # Add optional advanced analysis results if they exist
        optional_results = [
            'interfaces', 'layer_analysis', 'symmetric_profiles',
            'electrostatic_potential', 'charge_density', 'local_temperature',
            'atom_count_profile', 'rdf_vs_z', 'water_structure', 'mobility_vs_z',
            'solvation_shells', 'surface_tension', 'interfacial_thickness',
            'pressure_components', 'chemical_potential', 'ion_clustering',
            'dielectric_profile', 'ion_pairing'
        ]
        
        for result_key in optional_results:
            if hasattr(self.results, result_key):
                export_data[result_key] = getattr(self.results, result_key)
        
        # Save to pickle file
        with open(filename, 'wb') as f:
            pickle.dump(export_data, f)
        
        print(f"Z-directional analysis results exported to: {filename}")
        return filename

    def _get_cache_filename(self):
        """Generate cache filename based on analysis parameters"""
        step_str = f"_step{getattr(self, 'step_frame', 1)}" if hasattr(self, 'step_frame') and self.step_frame > 1 else ""
        center_str = "_centered" if self.center_box else ""
        cache_filename = f'z_analysis_cache_{self.n_bins}bins{step_str}{center_str}.pkl'
        return cache_filename

    def _save_cache(self, cache_filename):
        """Save analysis results to cache file, including per-frame data"""
        cache_data = {
            'results': self.results,
            'z_centers': self.z_centers,
            'bin_width': self.bin_width,
            'n_frames_analyzed': self.n_frames_analyzed,
            'cation_types': self.cation_types,
            'anion_types': self.anion_types,
            'system_info': {
                'start_frame': 0,  # Default values since these attributes don't exist
                'end_frame': len(self.universe.trajectory),
                'step_frame': getattr(self, 'step_frame', 1)
            }
        }
        
        # IMPORTANT: Save per_frame_histograms if it exists
        if hasattr(self.results, 'per_frame_histograms'):
            cache_data['per_frame_histograms'] = self.results.per_frame_histograms
            print(f"💾 Saving per-frame histogram data to cache...")
        
        try:
            with open(cache_filename, 'wb') as f:
                pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
            
            # Get file size for reporting
            file_size = os.path.getsize(cache_filename) / (1024*1024)  # MB
            print(f"✓ Cache saved: {cache_filename}")
            print(f"✓ Cache file size: {file_size:.2f} MB")
            
        except Exception as e:
            print(f"❌ Error saving cache: {e}")

    def _load_cache(self, cache_filename):
        """Load analysis results from cache file, including per-frame data"""
        try:
            with open(cache_filename, 'rb') as f:
                cache_data = pickle.load(f)
            
            # Load main results
            self.results = cache_data['results']
            self.z_centers = cache_data['z_centers']
            self.bin_width = cache_data['bin_width']
            self.n_frames_analyzed = cache_data['n_frames_analyzed']
            self.cation_types = cache_data['cation_types']
            self.anion_types = cache_data['anion_types']
            
            # Load system info if available
            if 'system_info' in cache_data:
                system_info = cache_data['system_info']
                # Store step_frame if it exists
                if 'step_frame' in system_info:
                    self.step_frame = system_info['step_frame']
            
            # IMPORTANT: Restore per_frame_histograms if it exists in cache
            if 'per_frame_histograms' in cache_data:
                self.results.per_frame_histograms = cache_data['per_frame_histograms']
                print(f"✓ Restored per-frame histogram data from cache")
                print(f"✓ Per-frame data keys: {list(self.results.per_frame_histograms.keys())}")
            else:
                print(f"⚠ No per-frame histogram data found in cache")
            
            # Get file size for reporting
            file_size = os.path.getsize(cache_filename) / (1024*1024)  # MB
            print(f"✓ Successfully loaded cached results ({self.n_frames_analyzed} frames)")
            print(f"✓ Cache file size: {file_size:.2f} MB")
            
            return True
            
        except Exception as e:
            print(f"❌ Error loading cache: {e}")
            return False


    def run(self, start=None, stop=None, step=1, collect_bootstrap_data=False, 
            force_rerun=False, use_cache=True):
        """
        Run the z-directional analysis
        
        Parameters:
        -----------
        start : int, optional
            Starting frame (default: 0)
        stop : int, optional
            Ending frame (default: all frames)
        step : int, optional
            Frame step size (default: 1)
        collect_bootstrap_data : bool, optional
            Whether to collect per-frame data for bootstrap uncertainty analysis (default: False)
        force_rerun : bool, optional
            Whether to force reanalysis even if cache exists (default: False)
        use_cache : bool, optional
            Whether to use caching (default: True)
        """
        
        # Set default values
        if start is None:
            start = 0
        if stop is None:
            stop = len(self.universe.trajectory)
        
        # Update step_frame for this run
        self.step_frame = step
        
        # Check for existing cache
        if use_cache and not force_rerun:
            cache_filename = self._get_cache_filename()
            if os.path.exists(cache_filename):
                print(f"Found existing cache: {cache_filename}")
                if self._load_cache(cache_filename):
                    # Check if we have per_frame_data when bootstrap is requested
                    if collect_bootstrap_data and not hasattr(self.results, 'per_frame_histograms'):
                        print(f"⚠ Cache doesn't contain per-frame data needed for bootstrap analysis")
                        print(f"⚠ Forcing rerun to collect per-frame data...")
                        # Continue to rerun analysis below
                    else:
                        print("Loading cached results...")
                        return  # Use cached results
        
        # Continue with analysis if not using cache or if forced rerun
        print(f"Running z-directional analysis...")
        print(f"Analyzing frames {start} to {stop} with step {step}")
        
        # Initialize storage
        self.results = Results()
        
        # CRITICAL FIX: Preserve original AtomGroup objects
        # Store the original AtomGroup objects separately before any modifications
        original_cation_atomgroups = {}
        original_anion_atomgroups = {}
        
        # Get the original AtomGroup objects from the __init__ method's _identify_ion_types
        for ion_type, ion_group in self.cation_types.items():
            if hasattr(ion_group, 'positions'):
                original_cation_atomgroups[ion_type] = ion_group
        
        for ion_type, ion_group in self.anion_types.items():
            if hasattr(ion_group, 'positions'):
                original_anion_atomgroups[ion_type] = ion_group
        
        # Initialize per-frame storage if bootstrap data is requested
        if collect_bootstrap_data:
            self.results.per_frame_histograms = {}
            print(f"📊 Collecting per-frame data for bootstrap analysis...")
        
        # Initialize counters and accumulators
        frame_count = 0
        water_density_sum = np.zeros(len(self.z_centers))
        ion_density_sums = {}
        ion_count_sums = {}
        
        # Initialize ion-specific storage using original AtomGroup keys
        for ion_type in original_cation_atomgroups.keys():
            ion_density_sums[ion_type] = np.zeros(len(self.z_centers))
            ion_count_sums[ion_type] = np.zeros(len(self.z_centers))
        
        for ion_type in original_anion_atomgroups.keys():
            ion_density_sums[ion_type] = np.zeros(len(self.z_centers))
            ion_count_sums[ion_type] = np.zeros(len(self.z_centers))
        
        # Add any additional ion types that might exist
        for ion_type in ['NA', 'MG', 'CL', 'CA', 'K', 'Li', 'Rb', 'Cs', 'Br', 'I', 'F', 'SO4', 'S']:
            if ion_type not in ion_density_sums:
                ion_density_sums[ion_type] = np.zeros(len(self.z_centers))
                ion_count_sums[ion_type] = np.zeros(len(self.z_centers))
        
        # Initialize dipole data storage
        dipole_positions = []
        dipole_angles = []
        
        # Progress tracking
        total_frames = len(range(start, stop, step))
        print(f"Processing {total_frames} frames...")
        
        # Main analysis loop
        for frame_idx, ts in enumerate(self.universe.trajectory[start:stop:step]):
            if frame_idx % 100 == 0:
                print(f"Processing frame {frame_idx + 1}/{total_frames}")
            
            frame_number = ts.frame
            
            # Get box dimensions
            box_z = self.universe.dimensions[2]
            
            # Center molecules if requested
            if self.center_box:
                # Center water molecules at z=0
                water_positions = self.waters.positions
                water_com_z = np.mean(water_positions[:, 2])
                shift_z = box_z / 2 - water_com_z
                
                # Apply shift to all molecules
                self.waters.positions[:, 2] += shift_z
                if len(self.cations) > 0:
                    self.cations.positions[:, 2] += shift_z
                if len(self.anions) > 0:
                    self.anions.positions[:, 2] += shift_z
            
            # Water density calculation
            water_z = self.waters.positions[:, 2]
            if self.center_box:
                water_z = water_z - box_z / 2  # Center around z=0
            
            # FIXED: Use self.z_edges instead of calculating new bins
            water_hist, _ = np.histogram(water_z, bins=self.z_edges)
            water_density_frame = water_hist / (self.bin_width * self.universe.dimensions[0] * self.universe.dimensions[1])
            water_density_sum += water_density_frame
            
            # Ion density calculations using ORIGINAL AtomGroup objects
            frame_ion_densities = {}
            frame_ion_counts = {}
            
            # Process cations using original AtomGroups
            for ion_type, ion_group in original_cation_atomgroups.items():
                if len(ion_group) > 0:
                    cation_z = ion_group.positions[:, 2]
                    if self.center_box:
                        cation_z = cation_z - box_z / 2
                    
                    # FIXED: Use self.z_edges
                    ion_hist, _ = np.histogram(cation_z, bins=self.z_edges)
                    ion_density = ion_hist / (self.bin_width * self.universe.dimensions[0] * self.universe.dimensions[1])
                    ion_density_sums[ion_type] += ion_density
                    ion_count_sums[ion_type] += ion_hist
                    
                    frame_ion_densities[ion_type] = ion_density
                    frame_ion_counts[ion_type] = ion_hist
            
            # Process anions using original AtomGroups
            for ion_type, ion_group in original_anion_atomgroups.items():
                if len(ion_group) > 0:
                    anion_z = ion_group.positions[:, 2]
                    if self.center_box:
                        anion_z = anion_z - box_z / 2
                    
                    # FIXED: Use self.z_edges
                    ion_hist, _ = np.histogram(anion_z, bins=self.z_edges)
                    ion_density = ion_hist / (self.bin_width * self.universe.dimensions[0] * self.universe.dimensions[1])
                    ion_density_sums[ion_type] += ion_density
                    ion_count_sums[ion_type] += ion_hist
                    
                    frame_ion_densities[ion_type] = ion_density
                    frame_ion_counts[ion_type] = ion_hist
            
            # Also process by name for any remaining ions (fallback)
            if len(self.cations) > 0:
                cation_z = self.cations.positions[:, 2]
                if self.center_box:
                    cation_z = cation_z - box_z / 2
                
                # Identify cation types by name
                cation_names = self.cations.names
                for ion_type in ion_density_sums.keys():
                    if ion_type not in original_cation_atomgroups:  # Only process if not already done
                        ion_mask = np.char.upper(cation_names.astype(str)) == ion_type
                        if np.any(ion_mask):
                            ion_z_positions = cation_z[ion_mask]
                            # FIXED: Use self.z_edges
                            ion_hist, _ = np.histogram(ion_z_positions, bins=self.z_edges)
                            ion_density = ion_hist / (self.bin_width * self.universe.dimensions[0] * self.universe.dimensions[1])
                            ion_density_sums[ion_type] += ion_density
                            ion_count_sums[ion_type] += ion_hist
                            
                            frame_ion_densities[ion_type] = ion_density
                            frame_ion_counts[ion_type] = ion_hist
            
            # Process anions by name (fallback)
            if len(self.anions) > 0:
                anion_z = self.anions.positions[:, 2]
                if self.center_box:
                    anion_z = anion_z - box_z / 2
                
                anion_names = self.anions.names
                for ion_type in ion_density_sums.keys():
                    if ion_type not in original_anion_atomgroups:  # Only process if not already done
                        ion_mask = np.char.upper(anion_names.astype(str)) == ion_type
                        if np.any(ion_mask):
                            ion_z_positions = anion_z[ion_mask]
                            # FIXED: Use self.z_edges
                            ion_hist, _ = np.histogram(ion_z_positions, bins=self.z_edges)
                            ion_density = ion_hist / (self.bin_width * self.universe.dimensions[0] * self.universe.dimensions[1])
                            ion_density_sums[ion_type] += ion_density
                            ion_count_sums[ion_type] += ion_hist
                            
                            frame_ion_densities[ion_type] = ion_density
                            frame_ion_counts[ion_type] = ion_hist
            
            # Water dipole orientation calculation
            if hasattr(self, 'water_oxygens') and hasattr(self, 'water_hydrogens'):
                try:
                    # Calculate dipole vectors and angles
                    oxygen_pos = self.water_oxygens.positions
                    hydrogen_pos = self.water_hydrogens.positions
                    
                    # Assuming 2 hydrogens per oxygen (SPC/E, TIP3P, etc.)
                    n_waters = len(oxygen_pos)
                    h1_pos = hydrogen_pos[::2]  # First hydrogen
                    h2_pos = hydrogen_pos[1::2]  # Second hydrogen
                    
                    if len(h1_pos) == n_waters and len(h2_pos) == n_waters:
                        # Calculate water dipole vectors (pointing from O to midpoint of H atoms)
                        h_midpoint = (h1_pos + h2_pos) / 2
                        # dipole_vectors = h_midpoint - oxygen_pos
                        dipole_vectors = oxygen_pos - h_midpoint
                        
                        # Calculate angle with z-axis
                        z_unit = np.array([0, 0, 1])
                        dipole_magnitudes = np.linalg.norm(dipole_vectors, axis=1)
                        
                        valid_dipoles = dipole_magnitudes > 0
                        if np.any(valid_dipoles):
                            dipole_unit_vectors = dipole_vectors[valid_dipoles] / dipole_magnitudes[valid_dipoles][:, np.newaxis]
                            cos_angles = np.dot(dipole_unit_vectors, z_unit)
                            cos_angles = np.clip(cos_angles, -1, 1)  # Ensure valid range
                            # FIXED: Remove np.abs() to get full 0-180° range
                            angles = np.degrees(np.arccos(cos_angles))
                            
                            # Store positions and angles
                            oxygen_z = oxygen_pos[valid_dipoles, 2]
                            if self.center_box:
                                oxygen_z = oxygen_z - box_z / 2
                            
                            dipole_positions.extend(oxygen_z)
                            dipole_angles.extend(angles)
                except Exception as e:
                    print(f"Warning: Could not calculate dipole orientation for frame {frame_idx}: {e}")
            
            # Store per-frame data for bootstrap analysis
            if collect_bootstrap_data:
                if frame_number not in self.results.per_frame_histograms:
                    self.results.per_frame_histograms[frame_number] = {}
                
                # Store water histogram
                self.results.per_frame_histograms[frame_number]['water'] = water_density_frame
                
                # Store ion histograms
                for ion_type, density in frame_ion_densities.items():
                    self.results.per_frame_histograms[frame_number][ion_type] = density
            
            frame_count += 1
        
        # Calculate averaged results
        if frame_count == 0:
            raise ValueError("No frames were processed. Check your trajectory and frame range.")
        
        print(f"Processed {frame_count} frames")
        
        # Store averaged results
        self.n_frames_analyzed = frame_count
        self.results.water_density = water_density_sum / frame_count
        
        # Calculate ion densities and identify present ion types
        self.results.ion_densities_by_type = {}
        self.results.ion_counts_by_type = {}
        
        for ion_type, density_sum in ion_density_sums.items():
            if np.sum(density_sum) > 0:
                self.results.ion_densities_by_type[ion_type] = density_sum / frame_count
                self.results.ion_counts_by_type[ion_type] = ion_count_sums[ion_type] / frame_count
        
        # CRITICAL FIX: Restore original AtomGroup objects to maintain compatibility
        # This ensures that calculate_ion_spatial_distribution_xy can still access .positions
        self.cation_types = original_cation_atomgroups.copy()
        self.anion_types = original_anion_atomgroups.copy()
        
        # Also add any ion types that were found by name but not in original groups
        for ion_type in self.results.ion_densities_by_type.keys():
            if ion_type not in self.cation_types and ion_type not in self.anion_types:
                # Try to create AtomGroup for this ion type
                try:
                    if ion_type.upper() in ['NA', 'K', 'MG', 'CA', 'LI', 'RB', 'CS']:
                        # Cation
                        ion_group = self.universe.select_atoms(f'name {ion_type}')
                        if len(ion_group) > 0:
                            self.cation_types[ion_type] = ion_group
                    elif ion_type.upper() in ['CL', 'BR', 'I', 'F', 'SO4', 'S']:
                        # Anion
                        ion_group = self.universe.select_atoms(f'name {ion_type}')
                        if len(ion_group) > 0:
                            self.anion_types[ion_type] = ion_group
                except:
                    pass  # Ignore if we can't create the group
        
        # Separate cations and anions for density calculation
        cation_list = ['NA', 'MG', 'CA', 'K', 'Li', 'Rb', 'Cs']
        anion_list = ['CL', 'Br', 'I', 'F', 'SO4', 'S']
        
        # Calculate combined cation and anion densities
        cation_densities = []
        for ion in cation_list:
            if ion in self.results.ion_densities_by_type:
                cation_densities.append(self.results.ion_densities_by_type[ion])
        
        anion_densities = []
        for ion in anion_list:
            if ion in self.results.ion_densities_by_type:
                anion_densities.append(self.results.ion_densities_by_type[ion])
        
        if cation_densities:
            self.results.cation_density = np.sum(cation_densities, axis=0)
        else:
            self.results.cation_density = np.zeros(len(self.z_centers))
        
        if anion_densities:
            self.results.anion_density = np.sum(anion_densities, axis=0)
        else:
            self.results.anion_density = np.zeros(len(self.z_centers))
        
        # Store dipole orientation results
        self.results.dipole_vs_z = {
            'z_positions': dipole_positions,
            'dipole_angles': dipole_angles
        }
        
        # Store z_centers and z_edges in results
        self.results.z_centers = self.z_centers
        self.results.z_edges = self.z_edges

        print(f"✓ Ion types identified: Cations={list(self.cation_types.keys())}, Anions={list(self.anion_types.keys())}")
        
        if collect_bootstrap_data:
            n_frames_collected = len(self.results.per_frame_histograms)
            print(f"✓ Collected per-frame data for {n_frames_collected} frames")
        
        # Save to cache after analysis
        if use_cache:
            cache_filename = self._get_cache_filename()
            self._save_cache(cache_filename)
        
        print("✓ Analysis complete!")


    def check_cache_status(self, cache_filename=None, step=None, start=None, stop=None):
        '''Check if cached results exist and display information.'''
        
        if cache_filename is None:
            # Generate same filename as run() method
            step_str = f"_step{step}" if step and step > 1 else ""
            start_str = f"_start{start}" if start else ""
            stop_str = f"_stop{stop}" if stop else ""
            center_str = "_centered" if self.center_box else ""
            
            cache_filename = f'z_analysis_cache_{self.n_bins}bins{step_str}{start_str}{stop_str}{center_str}.pkl'
        
        if os.path.exists(cache_filename):
            try:
                with open(cache_filename, 'rb') as f:
                    cached_data = pickle.load(f)
                
                file_size_mb = os.path.getsize(cache_filename) / 1024 / 1024
                
                print(f"Cache Status: FOUND")
                print(f"  File: {cache_filename}")
                print(f"  Size: {file_size_mb:.2f} MB")
                print(f"  Frames analyzed: {cached_data.get('n_frames_analyzed', 'unknown')}")
                
                cache_params = cached_data.get('analysis_parameters', {})
                print(f"  Parameters:")
                for key, value in cache_params.items():
                    print(f"    {key}: {value}")
                
                return True
                
            except Exception as e:
                print(f"Cache Status: CORRUPTED - {e}")
                return False
        else:
            print(f"Cache Status: NOT FOUND")
            print(f"  Expected file: {cache_filename}")
            return False

    def clear_cache(self, cache_filename=None, step=None, start=None, stop=None, confirm=True):
        '''Clear/delete cached results.'''
        
        if cache_filename is None:
            step_str = f"_step{step}" if step and step > 1 else ""
            start_str = f"_start{start}" if start else ""
            stop_str = f"_stop{stop}" if stop else ""
            center_str = "_centered" if self.center_box else ""
            
            cache_filename = f'z_analysis_cache_{self.n_bins}bins{step_str}{start_str}{stop_str}{center_str}.pkl'
        
        if os.path.exists(cache_filename):
            if confirm:
                response = input(f"Delete cache file '{cache_filename}'? (y/N): ")
                if response.lower() not in ['y', 'yes']:
                    print("Cache deletion cancelled.")
                    return False
            
            try:
                os.remove(cache_filename)
                print(f"✓ Cache deleted: {cache_filename}")
                return True
            except Exception as e:
                print(f"Failed to delete cache: {e}")
                return False
        else:
            print(f"Cache file not found: {cache_filename}")
            return False


    def symmetrize_profiles(self, method='average'):
        '''
        Symmetrize density profiles using mirror symmetry around z=0.
        
        Parameters
        ----------
        method : str
            Symmetrization method:
            - 'average': Average left and right sides (recommended)
            - 'fold': Fold right side onto left
            - 'mirror_positive': Mirror positive side to negative
            - 'mirror_negative': Mirror negative side to positive
        
        Returns
        -------
        dict
            Symmetrized profiles and metadata
        '''
        
        if not self.center_box:
            print("Warning: Box is not centered. Symmetrization may not be meaningful.")
        
        # Find zero crossing index
        zero_idx = np.argmin(np.abs(self.z_centers))
        
        # Determine symmetric range (use the smaller side)
        left_points = zero_idx
        right_points = len(self.z_centers) - zero_idx - 1
        n_symmetric = min(left_points, right_points)
        
        # Create symmetric z-centers (only positive side, will be mirrored)
        z_symmetric = self.z_centers[zero_idx:zero_idx + n_symmetric + 1]
        
        # Initialize results dictionary
        symmetric_results = {
            'z_centers': z_symmetric,
            'method': method,
            'symmetrization_info': {
                'zero_z': self.z_centers[zero_idx],
                'n_symmetric_bins': n_symmetric,
                'symmetric_range': z_symmetric[-1]
            }
        }
        
        # Symmetrize general profiles (water, cation, anion)
        profiles_to_symmetrize = {
            'water_density': self.results.water_density,
            'cation_density': self.results.cation_density,
            'anion_density': self.results.anion_density,
            'water_counts': self.results.water_counts,
            'cation_counts': self.results.cation_counts,
            'anion_counts': self.results.anion_counts
        }
        
        for profile_name, profile_data in profiles_to_symmetrize.items():
            symmetric_results[profile_name] = self._symmetrize_single_profile(
                profile_data, zero_idx, n_symmetric, method
            )
        
        # **NEW: Symmetrize ion-specific densities**
        symmetric_results['ion_densities'] = {}
        for ion_type, density in self.results.ion_densities_by_type.items():
            symmetric_results['ion_densities'][ion_type] = self._symmetrize_single_profile(
                density, zero_idx, n_symmetric, method
            )
        
        # **NEW: Symmetrize ion-specific counts**
        symmetric_results['ion_counts'] = {}
        for ion_type, counts in self.results.ion_counts_by_type.items():
            symmetric_results['ion_counts'][ion_type] = self._symmetrize_single_profile(
                counts, zero_idx, n_symmetric, method
            )
        
        # Store in results
        self.results.symmetric_profiles = symmetric_results
        
        print(f"Profiles symmetrized using '{method}' method")
        print(f"Symmetric range: ±{z_symmetric[-1]:.2f} Å ({n_symmetric} bins on each side)")
        
        return symmetric_results


    def _symmetrize_single_profile(self, profile, zero_idx, n_symmetric, method):
        '''
        Helper method to symmetrize a single profile.
        
        Parameters
        ----------
        profile : np.ndarray
            Profile to symmetrize
        zero_idx : int
            Index of z=0
        n_symmetric : int
            Number of symmetric bins
        method : str
            Symmetrization method
        
        Returns
        -------
        np.ndarray
            Symmetrized profile (positive side only)
        '''
        
        # Extract left and right sides
        left_side = profile[zero_idx - n_symmetric:zero_idx + 1]
        right_side = profile[zero_idx:zero_idx + n_symmetric + 1]
        
        # Flip left side for comparison
        left_flipped = np.flip(left_side)
        
        # Apply symmetrization method
        if method == 'average':
            # Average both sides
            symmetric_profile = (left_flipped + right_side) / 2
        
        elif method == 'fold':
            # Fold right onto left (same as average for symmetric systems)
            symmetric_profile = (left_flipped + right_side) / 2
        
        elif method == 'mirror_positive':
            # Use positive side only
            symmetric_profile = right_side.copy()
        
        elif method == 'mirror_negative':
            # Use negative side (flipped)
            symmetric_profile = left_flipped.copy()
        
        else:
            raise ValueError(f"Unknown symmetrization method: {method}")
        
        return symmetric_profile


    def _apply_symmetrization(self, profile, symmetric_mask, zero_bin, method):
        '''Apply specific symmetrization method to a profile'''
        
        # Extract symmetric region
        symmetric_profile = profile[symmetric_mask].copy()
        z_centers_sym = self.z_centers[symmetric_mask]
        
        if method == 'average':
            # Average positive and negative sides
            n_bins = len(symmetric_profile)
            center_idx = np.argmin(np.abs(z_centers_sym))
            
            for i in range(n_bins):
                z_pos = z_centers_sym[i]
                # Find corresponding position on opposite side
                opposite_z = -z_pos
                opposite_idx = np.argmin(np.abs(z_centers_sym - opposite_z))
                
                if opposite_idx != i:  # Don't average center bin with itself
                    avg_value = (symmetric_profile[i] + symmetric_profile[opposite_idx]) / 2
                    symmetric_profile[i] = avg_value
                    symmetric_profile[opposite_idx] = avg_value
        
        elif method == 'fold':
            # Fold negative side onto positive side
            center_idx = np.argmin(np.abs(z_centers_sym))
            
            for i in range(len(symmetric_profile)):
                if z_centers_sym[i] < 0:  # Negative side
                    z_pos = z_centers_sym[i]
                    opposite_z = -z_pos
                    opposite_idx = np.argmin(np.abs(z_centers_sym - opposite_z))
                    symmetric_profile[i] = symmetric_profile[opposite_idx]
        
        elif method == 'mirror_positive':
            # Use positive side, mirror to negative
            center_idx = np.argmin(np.abs(z_centers_sym))
            
            for i in range(len(symmetric_profile)):
                if z_centers_sym[i] < 0:  # Negative side
                    z_pos = z_centers_sym[i]
                    opposite_z = -z_pos
                    opposite_idx = np.argmin(np.abs(z_centers_sym - opposite_z))
                    symmetric_profile[i] = symmetric_profile[opposite_idx]
        
        elif method == 'mirror_negative':
            # Use negative side, mirror to positive
            center_idx = np.argmin(np.abs(z_centers_sym))
            
            for i in range(len(symmetric_profile)):
                if z_centers_sym[i] > 0:  # Positive side
                    z_pos = z_centers_sym[i]
                    opposite_z = -z_pos
                    opposite_idx = np.argmin(np.abs(z_centers_sym - opposite_z))
                    symmetric_profile[i] = symmetric_profile[opposite_idx]
        
        return symmetric_profile


    def compare_symmetrization_methods(self, methods=['average', 'fold', 'mirror_positive'], 
                                     profile_type='water_density', save_plots=True, figsize=(15, 10)):
        '''Compare different symmetrization methods'''
        
        print(f"Comparing symmetrization methods: {methods}")
        
        # Store current symmetric profiles if any
        original_symmetric = getattr(self.results, 'symmetric_profiles', None)
        
        # Calculate symmetrized profiles for each method
        method_results = {}
        
        for method in methods:
            print(f"Calculating symmetrization using method: {method}")
            self.symmetrize_profiles(method=method)
            method_results[method] = self.results.symmetric_profiles.copy()
        
        # Create comparison plots
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        
        # Plot 1: Direct comparison of methods
        ax1 = axes[0, 0]
        colors = ['blue', 'red', 'green', 'orange', 'purple']
        
        for i, (method, sym_data) in enumerate(method_results.items()):
            color = colors[i % len(colors)]
            z_centers = sym_data['z_centers']
            profile_data = sym_data[profile_type]
            
            ax1.plot(z_centers, profile_data, color=color, linewidth=2, 
                    label=f'{method}', linestyle='-')
        
        # Also plot original for reference
        symmetric_mask = np.abs(self.z_centers) <= np.max(np.abs(z_centers))
        z_orig = self.z_centers[symmetric_mask]
        original_profile = getattr(self.results, profile_type.split('_')[0] + '_' + profile_type.split('_')[1])
        ax1.plot(z_orig, original_profile[symmetric_mask], 'k--', alpha=0.7, 
                label='Original', linewidth=1)
        
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel(f'{profile_type.replace("_", " ").title()}')
        ax1.set_title(f'Symmetrization Methods Comparison: {profile_type}', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='-', alpha=0.7)
        
        # Plot 2: Difference from average method
        ax2 = axes[0, 1]
        
        if 'average' in method_results:
            reference_data = method_results['average'][profile_type]
            reference_z = method_results['average']['z_centers']
            
            for i, (method, sym_data) in enumerate(method_results.items()):
                if method != 'average':
                    color = colors[i % len(colors)]
                    z_centers = sym_data['z_centers']
                    profile_data = sym_data[profile_type]
                    
                    # Interpolate to common grid
                    if len(z_centers) == len(reference_z) and np.allclose(z_centers, reference_z):
                        difference = profile_data - reference_data
                    else:
                        interp_func = interp1d(z_centers, profile_data, kind='linear', 
                                             bounds_error=False, fill_value=0)
                        interpolated_data = interp_func(reference_z)
                        difference = interpolated_data - reference_data
                    
                    ax2.plot(reference_z, difference, color=color, linewidth=2, 
                            label=f'{method} - average')
            
            ax2.set_xlabel('z (Å)')
            ax2.set_ylabel(f'Difference in {profile_type.replace("_", " ").title()}')
            ax2.set_title('Difference from Average Method', fontweight='bold')
            ax2.legend()
            ax2.grid(True, alpha=0.3)
            ax2.axvline(0, color='k', linestyle='-', alpha=0.7)
            ax2.axhline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 3: Asymmetry measure for each method
        ax3 = axes[1, 0]
        
        for i, (method, sym_data) in enumerate(method_results.items()):
            color = colors[i % len(colors)]
            z_centers = sym_data['z_centers']
            profile_data = sym_data[profile_type]
            
            # Calculate asymmetry
            asymmetry = []
            asym_z = []
            
            for j, z in enumerate(z_centers):
                if z > 0:  # Only positive side
                    opposite_z = -z
                    opposite_idx = np.argmin(np.abs(z_centers - opposite_z))
                    
                    if opposite_idx < len(profile_data):
                        asym = abs(profile_data[j] - profile_data[opposite_idx])
                        asymmetry.append(asym)
                        asym_z.append(z)
            
            ax3.plot(asym_z, asymmetry, color=color, linewidth=2, 
                    marker='o', markersize=3, label=method)
        
        ax3.set_xlabel('|z| (Å)')
        ax3.set_ylabel('Asymmetry |ρ(z) - ρ(-z)|')
        ax3.set_title('Asymmetry Comparison', fontweight='bold')
        ax3.legend()
        ax3.grid(True, alpha=0.3)
        ax3.set_yscale('log')
        
        # Plot 4: Statistics summary
        ax4 = axes[1, 1]
        
        method_names = []
        total_asymmetries = []
        
        for method, sym_data in method_results.items():
            z_centers = sym_data['z_centers']
            profile_data = sym_data[profile_type]
            
            # Calculate total asymmetry
            total_asym = 0
            n_points = 0
            
            for j, z in enumerate(z_centers):
                if z > 0:
                    opposite_z = -z
                    opposite_idx = np.argmin(np.abs(z_centers - opposite_z))
                    
                    if opposite_idx < len(profile_data):
                        total_asym += abs(profile_data[j] - profile_data[opposite_idx])
                        n_points += 1
            
            if n_points > 0:
                avg_asymmetry = total_asym / n_points
                method_names.append(method)
                total_asymmetries.append(avg_asymmetry)
        
        bars = ax4.bar(method_names, total_asymmetries, 
                      color=colors[:len(method_names)], alpha=0.7)
        ax4.set_ylabel('Average Asymmetry')
        ax4.set_title('Method Comparison: Average Asymmetry', fontweight='bold')
        ax4.grid(True, alpha=0.3, axis='y')
        
        # Add value labels on bars
        for bar, value in zip(bars, total_asymmetries):
            height = bar.get_height()
            ax4.text(bar.get_x() + bar.get_width()/2., height,
                    f'{value:.4f}', ha='center', va='bottom')
        
        plt.tight_layout()
        
        if save_plots:
            filename = f'symmetrization_comparison_{profile_type}.png'
            plt.savefig(filename, dpi=300, bbox_inches='tight')
            print(f"Symmetrization comparison plot saved as: {filename}")
        
        plt.show()
        
        # Restore original symmetric profiles if they existed
        if original_symmetric is not None:
            self.results.symmetric_profiles = original_symmetric
        
        # Print summary
        print(f"\nSymmetrization Methods Comparison Summary:")
        for method, avg_asym in zip(method_names, total_asymmetries):
            print(f"  {method:15s}: Average asymmetry = {avg_asym:.6f}")
        
        return method_results   


