    def _convert_clay_grids_to_objects(self, clay_data):
        """
        Convert 2D grid-based clay data to individual positioned objects for plotting.
        
        This method extracts peaks from clay density grids and converts them into
        individual objects (circles, lines, markers) that plotting methods expect.
        """
        
        print(f"\n🔄 Converting clay grids to individual objects for plotting...")
        print(f"📋 DEBUG: Clay data structure:")
        
        if not clay_data:
            print("❌ No clay_data provided")
            return None
        
        if 'z_slices' not in clay_data:
            print("❌ No 'z_slices' key in clay_data")
            print(f"   Available keys: {list(clay_data.keys())}")
            return None
        
        print(f"   ✓ Found {len(clay_data['z_slices'])} z-slices")
        
        # Debug first slice to understand structure
        if len(clay_data['z_slices']) > 0:
            first_slice = clay_data['z_slices'][0]
            print(f"   📊 First slice keys: {list(first_slice.keys())}")
            
            # Check for coordinate arrays
            for coord_key in ['x_centers', 'y_centers', 'x_edges', 'y_edges']:
                if coord_key in first_slice:
                    coord_array = first_slice[coord_key]
                    print(f"   ✓ {coord_key}: shape {np.array(coord_array).shape}, type {type(coord_array)}")
                else:
                    print(f"   ❌ Missing {coord_key}")
            
            # Check for grid data
            for grid_key in ['mg_grid', 'si_grid', 'combined_grid']:
                if grid_key in first_slice:
                    grid_array = first_slice[grid_key]
                    if hasattr(grid_array, 'shape'):
                        print(f"   ✓ {grid_key}: shape {grid_array.shape}, max {np.max(grid_array):.3f}")
                    else:
                        print(f"   ⚠ {grid_key}: not an array, type {type(grid_array)}")
                else:
                    print(f"   ❌ Missing {grid_key}")
        
        # Initialize converted results - preserve all original data
        converted_results = clay_data.copy()
        
        # Get parameters for object creation
        mg_vdw_scaling = clay_data.get('mg_vdw_scaling', 2.0)
        si_vdw_scaling = clay_data.get('si_vdw_scaling', 1.5)
        mg_vdw_radius = clay_data.get('mg_vdw_radius', 0.72)
        si_vdw_radius = clay_data.get('si_vdw_radius', 1.11)
        
        print(f"\n🎨 Object creation parameters:")
        print(f"   Mg VdW: {mg_vdw_radius:.2f} Å × {mg_vdw_scaling} = {mg_vdw_radius * mg_vdw_scaling:.2f} Å")
        print(f"   Si VdW: {si_vdw_radius:.2f} Å × {si_vdw_scaling} = {si_vdw_radius * si_vdw_scaling:.2f} Å")
        
        # Convert each z-slice
        for slice_idx, slice_data in enumerate(clay_data['z_slices']):
            print(f"\n  🔍 Processing z-slice {slice_idx + 1}/{len(clay_data['z_slices'])}...")
            
            # Initialize object lists
            slice_data['mg_footprints'] = []
            slice_data['si_connections'] = []
            slice_data['si_centers'] = []
            
            # CRITICAL: Validate coordinate arrays exist and are accessible
            coordinate_arrays = {}
            coordinate_valid = True
            
            for coord_name in ['x_centers', 'y_centers']:
                if coord_name in slice_data:
                    coord_array = slice_data[coord_name]
                    
                    # Convert to numpy array if needed
                    if not isinstance(coord_array, np.ndarray):
                        try:
                            coord_array = np.array(coord_array)
                            slice_data[coord_name] = coord_array  # Update in place
                        except:
                            print(f"    ❌ Failed to convert {coord_name} to array")
                            coordinate_valid = False
                            break
                    
                    coordinate_arrays[coord_name] = coord_array
                    print(f"    ✓ {coord_name}: {len(coord_array)} points")
                else:
                    print(f"    ❌ Missing required coordinate array: {coord_name}")
                    coordinate_valid = False
                    break
            
            if not coordinate_valid:
                print(f"    ⚠ Skipping slice {slice_idx + 1} due to invalid coordinates")
                continue
            
            x_centers = coordinate_arrays['x_centers']
            y_centers = coordinate_arrays['y_centers']
            
            # Create meshgrid for distance calculations
            try:
                X_grid, Y_grid = np.meshgrid(x_centers, y_centers)
                print(f"    ✓ Created meshgrid: {X_grid.shape}")
            except Exception as e:
                print(f"    ❌ Failed to create meshgrid: {e}")
                continue
            
            # Process Mg grid
            if 'mg_grid' in slice_data and slice_data['mg_grid'] is not None:
                mg_grid = slice_data['mg_grid']
                
                if not isinstance(mg_grid, np.ndarray):
                    try:
                        mg_grid = np.array(mg_grid)
                    except:
                        print(f"    ❌ Invalid mg_grid data")
                        mg_grid = None
                
                if mg_grid is not None and mg_grid.size > 0:
                    print(f"    🟢 Processing Mg grid: shape {mg_grid.shape}, max {np.max(mg_grid):.3f}")
                    
                    # Find peaks using simple thresholding
                    mg_max = np.max(mg_grid)
                    threshold = mg_max * 0.15  # 15% of maximum
                    
                    # Find positions above threshold
                    peak_positions = np.where(mg_grid > threshold)
                    
                    if len(peak_positions[0]) > 0:
                        print(f"      ✓ Found {len(peak_positions[0])} Mg peaks above threshold {threshold:.3f}")
                        
                        # Create Mg footprints
                        for peak_y_idx, peak_x_idx in zip(peak_positions[0], peak_positions[1]):
                            # Validate indices
                            if peak_y_idx >= len(y_centers) or peak_x_idx >= len(x_centers):
                                continue
                            
                            # Get real-world coordinates
                            x_pos = x_centers[peak_x_idx]
                            y_pos = y_centers[peak_y_idx]
                            intensity = mg_grid[peak_y_idx, peak_x_idx]
                            
                            # Create simple footprint
                            footprint = {
                                'center': (x_pos, y_pos),
                                'radius': mg_vdw_radius * mg_vdw_scaling,
                                'intensity': intensity,
                                'circles': [{
                                    'x': x_pos,
                                    'y': y_pos,
                                    'radius': mg_vdw_radius * mg_vdw_scaling,
                                    'color': clay_data.get('mgo_color', 'green'),
                                    'alpha': 0.8,
                                    'zorder': 10
                                }]
                            }
                            
                            slice_data['mg_footprints'].append(footprint)
                    else:
                        print(f"      ⚠ No Mg peaks found above threshold {threshold:.3f}")
            
            # Process Si grid
            if 'si_grid' in slice_data and slice_data['si_grid'] is not None:
                si_grid = slice_data['si_grid']
                
                if not isinstance(si_grid, np.ndarray):
                    try:
                        si_grid = np.array(si_grid)
                    except:
                        print(f"    ❌ Invalid si_grid data")
                        si_grid = None
                
                if si_grid is not None and si_grid.size > 0:
                    print(f"    🟠 Processing Si grid: shape {si_grid.shape}, max {np.max(si_grid):.3f}")
                    
                    # Find Si peaks
                    si_max = np.max(si_grid)
                    threshold = si_max * 0.10  # 10% of maximum for Si
                    
                    peak_positions = np.where(si_grid > threshold)
                    
                    if len(peak_positions[0]) > 0:
                        print(f"      ✓ Found {len(peak_positions[0])} Si peaks above threshold {threshold:.3f}")
                        
                        # Extract Si positions
                        si_positions = []
                        for peak_y_idx, peak_x_idx in zip(peak_positions[0], peak_positions[1]):
                            if peak_y_idx >= len(y_centers) or peak_x_idx >= len(x_centers):
                                continue
                            
                            x_pos = x_centers[peak_x_idx]
                            y_pos = y_centers[peak_y_idx]
                            intensity = si_grid[peak_y_idx, peak_x_idx]
                            
                            si_positions.append({
                                'x': x_pos,
                                'y': y_pos,
                                'intensity': intensity
                            })
                            
                            # Create Si center marker
                            si_center = {
                                'x': x_pos,
                                'y': y_pos,
                                'size': 50,
                                'color': clay_data.get('si_color', 'orange'),
                                'alpha': 0.8,
                                'marker': 'h',  # hexagon
                                'edgecolor': 'black',
                                'linewidth': 1.0,
                                'zorder': 10
                            }
                            slice_data['si_centers'].append(si_center)
                        
                        # Create Si connections
                        si_connection_threshold = clay_data.get('si_connection_threshold', 5.0)
                        
                        for i in range(len(si_positions)):
                            for j in range(i + 1, len(si_positions)):
                                pos1 = si_positions[i]
                                pos2 = si_positions[j]
                                
                                # Calculate distance
                                dx = pos1['x'] - pos2['x']
                                dy = pos1['y'] - pos2['y']
                                distance = np.sqrt(dx*dx + dy*dy)
                                
                                # Create connection if within threshold
                                if distance <= si_connection_threshold:
                                    connection = {
                                        'start': [pos1['x'], pos1['y']],
                                        'end': [pos2['x'], pos2['y']],
                                        'distance': distance,
                                        'color': clay_data.get('si_color', 'orange'),
                                        'alpha': 0.6,
                                        'linewidth': 1.2,
                                        'zorder': 2
                                    }
                                    slice_data['si_connections'].append(connection)
                    else:
                        print(f"      ⚠ No Si peaks found above threshold {threshold:.3f}")
            
            # Print conversion results
            print(f"    ✅ Conversion complete:")
            print(f"      Mg footprints: {len(slice_data['mg_footprints'])}")
            print(f"      Si connections: {len(slice_data['si_connections'])}")
            print(f"      Si centers: {len(slice_data['si_centers'])}")
        
        print(f"\n✅ Clay grid-to-objects conversion complete!")
        
        total_mg = sum(len(s.get('mg_footprints', [])) for s in converted_results['z_slices'])
        total_si_centers = sum(len(s.get('si_centers', [])) for s in converted_results['z_slices'])
        total_si_connections = sum(len(s.get('si_connections', [])) for s in converted_results['z_slices'])
        
        print(f"📊 Final object counts:")
        print(f"   Total Mg footprints: {total_mg}")
        print(f"   Total Si centers: {total_si_centers}")
        print(f"   Total Si connections: {total_si_connections}")
        
        if total_mg == 0 and total_si_centers == 0:
            print("\n⚠️ WARNING: No clay objects were created!")
            print("   This could mean:")
            print("   1. Clay grids are empty or very low intensity")
            print("   2. Coordinate arrays are missing or invalid")
            print("   3. Peak detection thresholds are too high")
            print("   4. Clay atoms were not found in the original calculation")
        
        return converted_results


