    #         print(f"❌ Unknown return_format: {return_format}")
    #         return results


    def calculate_clay_spatial_distribution_xy(self, 
                                            z_slice_centers=None,
                                            z_slice_width=2.0,
                                            xy_grid_size=0.5,
                                            mg_vdw_radius=0.72,
                                            si_vdw_radius=1.11,
                                            mg_vdw_scaling=2.0,
                                            si_vdw_scaling=1.5,
                                            mgo_radial_fade=True,
                                            fade_method='gaussian',
                                            fade_sigma=0.3,
                                            fade_steps=5,
                                            fade_alpha_min=0.1,
                                            fade_alpha_max=0.8,
                                            mgo_color='green',
                                            si_color='orange',
                                            mgo_fade_colormap=None,
                                            si_connection_threshold=5.0,
                                            si_connection_style='lines',
                                            si_connection_alpha=0.6,
                                            si_connection_linewidth=1.2,
                                            show_hexagonal_pattern=True,
                                            mg_texture_intensity=0.7,
                                            mg_glow_effect=True,
                                            si_network_thickness=1.2,
                                            step=1,
                                            use_cache=True,
                                            cache_filename='clay_spatial_xy_cache.npz',
                                            max_frames=None,
                                            return_format='objects',
                                            combine_mg_layers=True):
        """
        Calculate clay spatial distribution with FAST grid-based approach + optional object conversion.
        
        This method uses a two-stage approach:
        1. FAST: Calculate 2D grids using vectorized numpy operations (O(N))
        2. CONVERT: Transform grids to individual objects only when needed for plotting
        
        Parameters
        ----------
        z_slice_centers : array-like, optional
            Z-positions for slice centers. If None, uses default range.
        z_slice_width : float, default=2.0
            Width of each z-slice (Å)
        xy_grid_size : float, default=0.5
            Grid spacing for XY plane (Å)
        mg_vdw_radius : float, default=0.72
            Base Van der Waals radius for Mg atoms (Å)
        si_vdw_radius : float, default=1.11
            Base Van der Waals radius for Si atoms (Å)
        mg_vdw_scaling : float, default=2.0
            Scaling factor for Mg VdW radius
        si_vdw_scaling : float, default=1.5
            Scaling factor for Si VdW radius
        mgo_radial_fade : bool, default=True
            Enable Gaussian grainy radial fade for Mg atoms
        fade_method : str, default='gaussian'
            Fade function: 'gaussian', 'linear', 'exponential'
        fade_sigma : float, default=0.3
            Gaussian fade parameter
        fade_steps : int, default=5
            Number of concentric fade circles
        fade_alpha_min : float, default=0.1
            Minimum alpha in fade
        fade_alpha_max : float, default=0.8
            Maximum alpha in fade
        mgo_color : str, default='green'
            Color for Mg atoms
        si_color : str, default='orange'
            Color for Si atoms
        mgo_fade_colormap : str, optional
            Custom colormap for Mg fade effect
        si_connection_threshold : float, default=5.0
            Distance cutoff for Si-Si connections (Å)
        si_connection_style : str, default='lines'
            Si connection style: 'lines', 'dashed', 'dotted'
        si_connection_alpha : float, default=0.6
            Transparency of Si connections
        si_connection_linewidth : float, default=1.2
            Line width of Si connections
        show_hexagonal_pattern : bool, default=True
            Show Si center markers for enhanced structure visualization
        mg_texture_intensity : float, default=0.7
            Intensity of grainy texture (0-1)
        mg_glow_effect : bool, default=True
            Enable outer halo effect for Mg atoms
        si_network_thickness : float, default=1.2
            Thickness of Si network connections
        step : int, default=1
            Frame sampling interval
        use_cache : bool, default=True
            Whether to use cached data if available
        cache_filename : str
            Name of cache file
        max_frames : int, optional
            Maximum number of frames to analyze
        return_format : str, default='objects'
            Return format:
            - 'grids': Fast 2D numpy arrays (for analysis)
            - 'objects': Individual positioned objects (for plotting)
            - 'both': Both formats included
        combine_mg_layers : bool, default=True
            If True, combines Mg atoms from both upper and lower clay layers in all z-slices.
            If False, separates Mg atoms by layer (original behavior).
        
        Returns
        -------
        dict
            Clay spatial distribution results in requested format
        """
        
        print(f"\n🧱 FAST Clay Spatial Distribution Analysis")
        print(f"{'='*50}")
        print(f"  Return format: {return_format.upper()}")
        print(f"  Grid approach: FAST O(N) vectorized operations")
        print(f"  Mg VdW scaling: {mg_vdw_scaling}x")
        print(f"  Si VdW scaling: {si_vdw_scaling}x")
        
        if combine_mg_layers:
            print(f"  🔗 Mg layer combination: ENABLED (showing Mg from both clay layers)")
        else:
            print(f"  🔗 Mg layer combination: DISABLED (separating Mg by layer)")
        
        # Cache handling using the working water dipole pattern
        import os
        cache_exists = os.path.exists(cache_filename)
        
        if use_cache and cache_exists:
            print(f"📦 Loading clay data from cache: {cache_filename}")
            try:
                cache_data = np.load(cache_filename, allow_pickle=True)
                
                # Verify cache parameters match current request
                cached_params = cache_data['parameters'].item()
                params_match = (
                    np.array_equal(cached_params.get('z_slice_centers', []), z_slice_centers or []) and
                    cached_params.get('z_slice_width') == z_slice_width and
                    cached_params.get('xy_grid_size') == xy_grid_size and
                    cached_params.get('mg_vdw_scaling') == mg_vdw_scaling and
                    cached_params.get('si_vdw_scaling') == si_vdw_scaling and
                    cached_params.get('combine_mg_layers') == combine_mg_layers and
                    cached_params.get('return_format') == return_format
                )
                
                if params_match:
                    print("✓ Cache parameters match - loading cached data")
                    results = cache_data['results'].item()
                    
                    # Check if cache has the format we need
                    if return_format == 'grids':
                        print(f"✓ Loaded grid-based clay data from cache")
                        return results
                    elif return_format == 'objects':
                        # Check if cache already has objects, otherwise convert
                        if 'mg_footprints' in results.get('z_slices', [{}])[0]:
                            print(f"✓ Loaded object-based clay data from cache")
                            return results
                        else:
                            print(f"⚠ Cache has grids, converting to objects...")
                            return self._convert_clay_grids_to_objects(results)
                    elif return_format == 'both':
                        # Always convert to ensure both formats are available
                        converted = self._convert_clay_grids_to_objects(results)
                        print(f"✓ Loaded clay data from cache (both formats)")
                        return converted
                else:
                    print("⚠ Cache parameters don't match - recalculating")
                    
            except Exception as e:
                print(f"⚠ Error loading cache: {e}")
                print("  Computing from scratch...")
        
        # Get clay atoms
        try:
            # Mg atoms
            mg_atoms = self.universe.select_atoms("resname MMT and (name Mgo or name MGO or name Mg or name MG)")
            print(f"Found {len(mg_atoms)} Mg atoms")
            
            # Si atoms  
            si_atoms = self.universe.select_atoms("resname MMT and (name Si or name SI or name Sio or name SIO)")
            print(f"Found {len(si_atoms)} Si atoms")
            
            if len(mg_atoms) == 0 and len(si_atoms) == 0:
                print("❌ No clay atoms found!")
                return None
                
        except Exception as e:
            print(f"❌ Error selecting clay atoms: {e}")
            return None
        
        # Set up z-slices
        if z_slice_centers is None:
            z_slice_centers = np.arange(-30, 31, z_slice_width)
        
        print(f"Processing {len(z_slice_centers)} z-slices...")
        
        # Mg and Si parameters
        scaled_mg_radius = mg_vdw_radius * mg_vdw_scaling
        scaled_si_radius = si_vdw_radius * si_vdw_scaling
        
        # Determine frame range
        total_frames = len(self.universe.trajectory)
        if max_frames is not None:
            frames_to_process = min(max_frames, total_frames)
        else:
            frames_to_process = total_frames
        
        frame_indices = range(0, frames_to_process, step)
        print(f"Processing {len(frame_indices)} frames (step={step})")
        
        # Get box dimensions from first frame
        self.universe.trajectory[0]
        box_dims = self.universe.dimensions
        box_x, box_y = box_dims[0], box_dims[1]
        box_center_z = box_dims[2] / 2 if self.center_box else 0
        
        # Create XY grid
        x_edges = np.arange(0, box_x + xy_grid_size, xy_grid_size)
        y_edges = np.arange(0, box_y + xy_grid_size, xy_grid_size)
        x_centers = (x_edges[:-1] + x_edges[1:]) / 2
        y_centers = (y_edges[:-1] + y_edges[1:]) / 2
        
        print(f"XY grid: {len(x_centers)} × {len(y_centers)} points")
        
        # Initialize results with all parameters for object conversion
        results = {
            'z_slices': [],
            'z_slice_width': z_slice_width,
            'xy_grid_size': xy_grid_size,
            'mg_vdw_scaling': mg_vdw_scaling,
            'si_vdw_scaling': si_vdw_scaling,
            'mg_vdw_radius': mg_vdw_radius,
            'si_vdw_radius': si_vdw_radius,
            'mgo_radial_fade': mgo_radial_fade,
            'fade_method': fade_method,
            'fade_sigma': fade_sigma,
            'fade_steps': fade_steps,
            'fade_alpha_min': fade_alpha_min,
            'fade_alpha_max': fade_alpha_max,
            'mgo_color': mgo_color,
            'si_color': si_color,
            'mgo_fade_colormap': mgo_fade_colormap,
            'si_connection_threshold': si_connection_threshold,
            'si_connection_style': si_connection_style,
            'si_connection_alpha': si_connection_alpha,
            'si_connection_linewidth': si_connection_linewidth,
            'show_hexagonal_pattern': show_hexagonal_pattern,
            'mg_texture_intensity': mg_texture_intensity,
            'mg_glow_effect': mg_glow_effect,
            'si_network_thickness': si_network_thickness,
            'combine_mg_layers': combine_mg_layers
        }
        
        # FAST grid-based calculation
        for z_idx, z_center in enumerate(z_slice_centers):
            print(f"  Processing z-slice {z_idx+1}/{len(z_slice_centers)}: z = {z_center:.1f} Å")
            
            z_slice_data = {
                'z_center': z_center,
                'x_centers': x_centers,
                'y_centers': y_centers,
                'x_edges': x_edges,
                'y_edges': y_edges,
                'mg_grid': np.zeros((len(y_centers), len(x_centers))),
                'si_grid': np.zeros((len(y_centers), len(x_centers))),
                'combined_grid': np.zeros((len(y_centers), len(x_centers)))
            }
            
            # Process frames for this z-slice
            mg_positions_all = []
            si_positions_all = []
            
            for frame_idx in frame_indices:
                self.universe.trajectory[frame_idx]
                
                # Get Mg positions in this z-slice
                if len(mg_atoms) > 0:
                    mg_positions = mg_atoms.positions.copy()
                    if self.center_box:
                        mg_positions[:, 2] -= box_center_z
                    
                    if combine_mg_layers:
                        # ✅ NEW: Include ALL Mg atoms regardless of z-position
                        mg_in_slice = mg_positions
                    else:
                        # ✅ ORIGINAL: Filter by z-slice (layer separation)
                        z_mask = np.abs(mg_positions[:, 2] - z_center) <= (z_slice_width / 2)
                        mg_in_slice = mg_positions[z_mask]
                    
                    if len(mg_in_slice) > 0:
                        # Apply PBC
                        mg_in_slice[:, 0] = mg_in_slice[:, 0] % box_x
                        mg_in_slice[:, 1] = mg_in_slice[:, 1] % box_y
                        mg_positions_all.extend(mg_in_slice[:, :2])  # Only XY
                
                # Get Si positions in this z-slice (UNCHANGED - Si stays layer-separated)
                if len(si_atoms) > 0:
                    si_positions = si_atoms.positions.copy()
                    if self.center_box:
                        si_positions[:, 2] -= box_center_z
                    
                    # Filter by z-slice (Si atoms remain layer-separated)
                    z_mask = np.abs(si_positions[:, 2] - z_center) <= (z_slice_width / 2)
                    si_in_slice = si_positions[z_mask]
                    
                    if len(si_in_slice) > 0:
                        # Apply PBC
                        si_in_slice[:, 0] = si_in_slice[:, 0] % box_x
                        si_in_slice[:, 1] = si_in_slice[:, 1] % box_y
                        si_positions_all.extend(si_in_slice[:, :2])  # Only XY
            
            # Create FAST 2D histograms
            if mg_positions_all:
                mg_array = np.array(mg_positions_all)
                mg_hist, _, _ = np.histogram2d(mg_array[:, 1], mg_array[:, 0], 
                                            bins=[y_edges, x_edges])
                z_slice_data['mg_grid'] = mg_hist
                
                # Apply Gaussian smoothing based on VdW radius
                if scaled_mg_radius > 0:
                    from scipy.ndimage import gaussian_filter
                    sigma = scaled_mg_radius / xy_grid_size  # Convert to grid units
                    z_slice_data['mg_grid'] = gaussian_filter(z_slice_data['mg_grid'], sigma=sigma)
            
            if si_positions_all:
                si_array = np.array(si_positions_all)
                si_hist, _, _ = np.histogram2d(si_array[:, 1], si_array[:, 0],
                                            bins=[y_edges, x_edges])
                z_slice_data['si_grid'] = si_hist
                
                # Apply Gaussian smoothing based on VdW radius
                if scaled_si_radius > 0:
                    from scipy.ndimage import gaussian_filter
                    sigma = scaled_si_radius / xy_grid_size  # Convert to grid units
                    z_slice_data['si_grid'] = gaussian_filter(z_slice_data['si_grid'], sigma=sigma)
            
            # Create combined grid
            z_slice_data['combined_grid'] = z_slice_data['mg_grid'] * 2.0 + z_slice_data['si_grid']
            
            results['z_slices'].append(z_slice_data)
            
            print(f"    ✓ Mg grid max: {np.max(z_slice_data['mg_grid']):.2f}")
            print(f"    ✓ Si grid max: {np.max(z_slice_data['si_grid']):.2f}")
        
        # Save cache using the working water dipole pattern
        if use_cache:
            print(f"💾 Saving clay data to cache: {cache_filename}")
            try:
                np.savez(cache_filename,
                        parameters={'z_slice_centers': z_slice_centers,
                                'z_slice_width': z_slice_width,
                                'xy_grid_size': xy_grid_size,
                                'mg_vdw_scaling': mg_vdw_scaling,
                                'si_vdw_scaling': si_vdw_scaling,
                                'mg_vdw_radius': mg_vdw_radius,
                                'si_vdw_radius': si_vdw_radius,
                                'combine_mg_layers': combine_mg_layers,
                                'return_format': return_format,
                                'fade_method': fade_method,
                                'mg_texture_intensity': mg_texture_intensity,
                                'step': step,
                                'max_frames': max_frames},
                        results=results)
                print("✓ Cache saved successfully")
            except Exception as e:
                print(f"⚠ Warning: Could not save cache: {e}")
        
        # Apply return format
        if return_format == 'grids':
            print(f"✅ Fast clay spatial distribution complete (GRID format)")
            return results
        
        elif return_format == 'objects':
            print(f"🔄 Converting grids to objects for plotting...")
            converted_results = self._convert_clay_grids_to_objects(results)
            print(f"✅ Fast clay spatial distribution complete (OBJECT format)")
            return converted_results
        
        elif return_format == 'both':
            print(f"🔄 Converting grids to objects (both formats)...")
            converted_results = self._convert_clay_grids_to_objects(results)
            print(f"✅ Fast clay spatial distribution complete (BOTH formats)")
            return converted_results
        
        else:
            print(f"❌ Unknown return_format: {return_format}")
            return results




    def analyze_ion_peaks_detailed(self, save_plots=True, figsize=(15, 10),
                                filename='ion_peak_analysis.png',
                                peak_height_threshold=0.1,
                                peak_distance=5.0,
                                show_clay_boundaries=True,
                                save_table=False,
                                table_filename='ion_peaks_table.csv',
                                print_table=True):
        """
        Detailed analysis of ion density peaks with clay interface context
        Returns both plots AND tabular peak data
        
        Parameters
        ----------
        save_plots : bool
            Save plots to file
        save_table : bool
            Save peak table to CSV file
        table_filename : str
            Name of CSV file for peak table
        print_table : bool
            Print formatted table to console
        
        Returns
        -------
        dict
            Dictionary containing peak data for each ion type
        """
        
        # Fix: Access ion densities directly from self.results
        if not hasattr(self.results, 'ion_densities_by_type'):
            print("No ion density data available.")
            return None
        
        from scipy.signal import find_peaks
        import matplotlib.pyplot as plt
        import pandas as pd
        
        z_centers = self.z_centers
        ion_types = list(self.results.ion_densities_by_type.keys())
        
        # Create subplots for each ion
        n_ions = len(ion_types)
        ncols = min(2, n_ions)
        nrows = (n_ions + ncols - 1) // ncols
        
        fig, axes = plt.subplots(nrows, ncols, figsize=figsize)
        if n_ions == 1:
            axes = [axes]
        elif nrows == 1:
            axes = list(axes)
        else:
            axes = axes.flatten()
        
        # Initialize peak data storage
        peak_summary = {}
        all_peaks_data = []  # For CSV table
        
        for idx, ion_type in enumerate(ion_types):
            ax = axes[idx]
            density = self.results.ion_densities_by_type[ion_type]
            
            # Plot density profile
            ax.plot(z_centers, density, 'b-', linewidth=2, label=f'{ion_type} density')
            
            # Find peaks
            peaks, properties = find_peaks(density, 
                                        height=peak_height_threshold,
                                        distance=int(peak_distance / np.mean(np.diff(z_centers))))
            
            if len(peaks) > 0:
                peak_positions = z_centers[peaks]
                peak_densities = density[peaks]
                peak_heights = properties['peak_heights']
                
                # Highlight peaks
                ax.plot(peak_positions, peak_densities, 'ro', markersize=8, 
                    markeredgecolor='black', markeredgewidth=1, label='Peaks')
                
                # Annotate peaks
                for i, (pos, dens) in enumerate(zip(peak_positions, peak_densities)):
                    ax.annotate(f'P{i+1}\n{pos:.1f}Å\n{dens:.3f}', 
                            xy=(pos, dens), 
                            xytext=(10, 10), 
                            textcoords='offset points',
                            fontsize=9,
                            bbox=dict(boxstyle='round,pad=0.3', 
                                    facecolor='yellow', 
                                    alpha=0.7),
                            arrowprops=dict(arrowstyle='->', 
                                            connectionstyle='arc3,rad=0'))
                
                # Store peak analysis for this ion
                peak_summary[ion_type] = {
                    'n_peaks': len(peaks),
                    'positions': peak_positions.tolist(),
                    'densities': peak_densities.tolist(),
                    'heights': peak_heights.tolist(),
                    'interface_peaks': [],
                    'bulk_peaks': []
                }
                
                # Classify peaks by region and add to table data
                for i, (pos, dens, height) in enumerate(zip(peak_positions, peak_densities, peak_heights)):
                    # Determine region
                    if abs(pos) < 15:  # Interface region
                        region = 'interface'
                        peak_summary[ion_type]['interface_peaks'].append({
                            'position': pos, 'density': dens, 'height': height, 'region': region
                        })
                    else:  # Bulk region
                        region = 'bulk'
                        peak_summary[ion_type]['bulk_peaks'].append({
                            'position': pos, 'density': dens, 'height': height, 'region': region
                        })
                    
                    # Add to combined table data
                    all_peaks_data.append({
                        'Ion_Type': ion_type,
                        'Peak_Number': i + 1,
                        'Z_Position_Angstrom': round(pos, 2),
                        'Density': round(dens, 4),
                        'Peak_Height': round(height, 4),
                        'Region': region,
                        'Distance_from_Center': round(abs(pos), 2)
                    })
            else:
                # No peaks found
                peak_summary[ion_type] = {
                    'n_peaks': 0,
                    'positions': [],
                    'densities': [],
                    'heights': [],
                    'interface_peaks': [],
                    'bulk_peaks': []
                }
            
            # Add clay boundaries if available
            if show_clay_boundaries and hasattr(self.results, 'clay_interface_boundaries'):
                clay_data = self.results.clay_interface_boundaries
                
                # Add boundary lines
                for boundary_name, z_pos in clay_data.items():
                    if z_pos is not None and 'z_' in boundary_name:
                        ax.axvline(z_pos, color='gray', linestyle='--', alpha=0.7,
                                label=boundary_name.replace('_', ' ').title() if idx == 0 else "")
            
            # Formatting
            ax.set_xlabel('z (Å)')
            ax.set_ylabel(f'{ion_type} Density')
            ax.set_title(f'{ion_type}: Peak Analysis')
            ax.legend()
            ax.grid(True, alpha=0.3)
            ax.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Hide unused subplots
        for i in range(n_ions, len(axes)):
            axes[i].axis('off')
        
        plt.tight_layout()
        
        if save_plots:
            plt.savefig(filename, dpi=300, bbox_inches='tight')
            print(f"Peak analysis plot saved as: {filename}")
        
        plt.show()
        
        # CREATE AND DISPLAY PEAK TABLE
        if all_peaks_data:
            # Create DataFrame
            peaks_df = pd.DataFrame(all_peaks_data)
            
            # Sort by ion type and position
            peaks_df = peaks_df.sort_values(['Ion_Type', 'Z_Position_Angstrom']).reset_index(drop=True)
            
            # Print formatted table to console
            if print_table:
                print(f"\n{'='*80}")
                print(f"ION DENSITY PEAKS SUMMARY TABLE")
                print(f"{'='*80}")
                print(f"Peak detection parameters:")
                print(f"  Height threshold: {peak_height_threshold}")
                print(f"  Minimum distance: {peak_distance} Å")
                print(f"  Interface region: |z| < 15 Å")
                print(f"{'='*80}")
                
                # Display table with nice formatting
                pd.set_option('display.max_columns', None)
                pd.set_option('display.width', None)
                pd.set_option('display.max_colwidth', 20)
                
                print(peaks_df.to_string(index=False))
                
                # Summary statistics
                print(f"\n{'='*80}")
                print(f"PEAK STATISTICS BY ION TYPE")
                print(f"{'='*80}")
                
                for ion_type in ion_types:
                    ion_peaks = peaks_df[peaks_df['Ion_Type'] == ion_type]
                    if len(ion_peaks) > 0:
                        interface_peaks = ion_peaks[ion_peaks['Region'] == 'interface']
                        bulk_peaks = ion_peaks[ion_peaks['Region'] == 'bulk']
                        
                        print(f"\n{ion_type}:")
                        print(f"  Total peaks: {len(ion_peaks)}")
                        print(f"  Interface peaks: {len(interface_peaks)}")
                        print(f"  Bulk peaks: {len(bulk_peaks)}")
                        
                        if len(ion_peaks) > 0:
                            print(f"  Z-position range: {ion_peaks['Z_Position_Angstrom'].min():.2f} to {ion_peaks['Z_Position_Angstrom'].max():.2f} Å")
                            print(f"  Average density: {ion_peaks['Density'].mean():.4f}")
                            print(f"  Highest peak: {ion_peaks['Density'].max():.4f} at z = {ion_peaks.loc[ion_peaks['Density'].idxmax(), 'Z_Position_Angstrom']:.2f} Å")
            
            # Save table to CSV
            if save_table:
                peaks_df.to_csv(table_filename, index=False)
                print(f"\n✓ Peak data table saved as: {table_filename}")
                print(f"  Contains {len(peaks_df)} peaks from {len(ion_types)} ion types")
            
            # Store results
            if not hasattr(self.results, 'peak_analysis'):
                self.results.peak_analysis = {}
            self.results.peak_analysis['detailed_ion_peaks'] = peak_summary
            self.results.peak_analysis['peaks_table'] = peaks_df
            
            return {
                'peak_summary': peak_summary,
                'peaks_table': peaks_df,
                'total_peaks': len(all_peaks_data),
                'ion_types': ion_types
            }
        
        else:
            print("\n⚠ No peaks found with current detection parameters")
            print(f"  Try reducing peak_height_threshold (current: {peak_height_threshold})")
            print(f"  or peak_distance (current: {peak_distance} Å)")
            return None


    def calculate_clay_spatial_distribution_xy_oldx4(self, 
                                            z_slice_centers=None,
                                            z_slice_width=2.0,
                                            xy_grid_size=0.5,
                                            mg_vdw_radius=0.72,
                                            si_vdw_radius=1.11,
                                            mg_vdw_scaling=2.0,
                                            si_vdw_scaling=1.5,
                                            mgo_radial_fade=True,
                                            fade_method='gaussian',
                                            fade_sigma=0.3,
                                            fade_steps=5,
                                            fade_alpha_min=0.1,
                                            fade_alpha_max=0.8,
                                            mgo_color='green',
                                            si_color='orange',
                                            mgo_fade_colormap=None,
                                            si_connection_threshold=5.0,
                                            si_connection_style='lines',
                                            si_connection_alpha=0.6,
                                            si_connection_linewidth=1.2,
                                            show_hexagonal_pattern=True,
                                            mg_texture_intensity=0.7,
                                            mg_glow_effect=True,
                                            si_network_thickness=1.2,
                                            step=1,
                                            use_cache=True,
                                            cache_filename='clay_spatial_xy_cache.npz',
                                            max_frames=None):
        """
        CENTRALIZED clay spatial distribution calculation with VdW-based visualization
        
        This method handles ALL clay visualization logic:
        1. Mg atoms: VdW-scaled with Gaussian grainy texture and radial fade
        2. Si atoms: Network connectivity showing hexagonal clay structure
        3. Returns plotting-ready data for use in any plotting method
        
        Parameters
        ----------
        z_slice_centers : array-like, optional
            Z-positions for slice centers. If None, uses standard range.
        z_slice_width : float, default=2.0
            Width of each z-slice (Å)
        xy_grid_size : float, default=0.5
            Grid spacing in XY plane (Å)
        mg_vdw_radius : float, default=0.72
            Base Van der Waals radius for Mg atoms (Å)
        si_vdw_radius : float, default=1.11
            Base Van der Waals radius for Si atoms (Å)
        mg_vdw_scaling : float, default=2.0
            Scaling factor for Mg VdW radius
        si_vdw_scaling : float, default=1.5
            Scaling factor for Si VdW radius
        mgo_radial_fade : bool, default=True
            Enable Gaussian grainy radial fade for Mg atoms
        fade_method : str, default='gaussian'
            Fade function: 'gaussian', 'linear', 'exponential'
        fade_sigma : float, default=0.3
            Gaussian fade parameter
        fade_steps : int, default=5
            Number of concentric fade circles
        fade_alpha_min : float, default=0.1
            Minimum alpha in fade
        fade_alpha_max : float, default=0.8
            Maximum alpha in fade
        mgo_color : str, default='green'
            Color for Mg atoms
        si_color : str, default='orange'
            Color for Si atoms
        mgo_fade_colormap : str, optional
            Custom colormap for Mg fade effect
        si_connection_threshold : float, default=5.0
            Distance cutoff for Si-Si connections (Å)
        si_connection_style : str, default='lines'
            Si connection style: 'lines', 'dashed', 'dotted'
        si_connection_alpha : float, default=0.6
            Transparency of Si connections
        si_connection_linewidth : float, default=1.2
            Line width of Si connections
        show_hexagonal_pattern : bool, default=True
            Show Si center markers for enhanced structure visualization
        mg_texture_intensity : float, default=0.7
            Intensity of grainy texture (0-1)
        mg_glow_effect : bool, default=True
            Enable outer halo effect for Mg atoms
        si_network_thickness : float, default=1.2
            Thickness of Si network connections
        step : int, default=1
            Frame sampling interval
        use_cache : bool, default=True
            Whether to use cached data if available
        cache_filename : str, default='clay_spatial_xy_cache.npz'
            Cache filename
        max_frames : int, optional
            Maximum number of frames to analyze
        
        Returns
        -------
        dict
            Complete clay spatial distribution results with plotting-ready data
        """
        
        print(f"\n{'='*70}")
        print(f"🧱 CENTRALIZED CLAY SPATIAL DISTRIBUTION CALCULATION")
        print(f"{'='*70}")
        
        # ✅ CACHE IMPLEMENTATION
        import os
        from datetime import datetime
        
        cache_exists = os.path.exists(cache_filename)
        
        if use_cache and cache_exists:
            print(f"📦 Loading clay data from cache: {cache_filename}")
            try:
                cache_data = np.load(cache_filename, allow_pickle=True)
                clay_results = cache_data['clay_results'].item()
                
                # Verify cache parameters match current request
                cached_params = clay_results.get('parameters', {})
                current_key_params = {
                    'mg_vdw_scaling': mg_vdw_scaling,
                    'si_vdw_scaling': si_vdw_scaling,
                    'xy_grid_size': xy_grid_size,
                    'z_slice_width': z_slice_width,
                    'fade_method': fade_method,
                    'mg_texture_intensity': mg_texture_intensity
                }
                
                params_match = all(
                    cached_params.get(k) == v for k, v in current_key_params.items()
                )
                
                if params_match:
                    print(f"✓ Cache parameters match - using cached data")
                    print(f"  Loaded {len(clay_results['z_slices'])} z-slices")
                    self.results.clay_spatial_xy = clay_results
                    return clay_results
                else:
                    print(f"⚠ Cache parameters don't match - recalculating")
                    use_cache = False
            except Exception as e:
                print(f"⚠ Error loading cache: {e}")
                use_cache = False
        
        # ✅ CALCULATE VdW SCALING
        mg_scaled_radius = mg_vdw_radius * mg_vdw_scaling
        si_scaled_radius = si_vdw_radius * si_vdw_scaling
        
        print(f"🔹 Mg VdW radius: {mg_vdw_radius:.2f} Å → {mg_scaled_radius:.2f} Å ({mg_vdw_scaling}x)")
        print(f"🔸 Si VdW radius: {si_vdw_radius:.2f} Å → {si_scaled_radius:.2f} Å ({si_vdw_scaling}x)")
        print(f"🎨 Visualization settings:")
        print(f"   Mg color: {mgo_color}, fade: {mgo_radial_fade} ({fade_method})")
        print(f"   Si color: {si_color}, connections: {si_connection_style}")
        print(f"   Si network threshold: {si_connection_threshold:.1f} Å")
        
        # ✅ GET CLAY ATOMS
        try:
            # Select clay atoms with comprehensive name matching
            si_atoms = self.universe.select_atoms("resname MMT and (name Si* or name SI* or name Sio* or name SIO*)")
            mg_atoms = self.universe.select_atoms("resname MMT and (name Mg* or name MG* or name Mgo* or name MGO*)")
            
            print(f"🔍 Found clay atoms:")
            print(f"   Si atoms: {len(si_atoms)}")
            print(f"   Mg atoms: {len(mg_atoms)}")
            
            if len(si_atoms) == 0 and len(mg_atoms) == 0:
                print("❌ No clay atoms found! Check atom selection.")
                return None
                
        except Exception as e:
            print(f"❌ Error selecting clay atoms: {e}")
            return None
        
        # ✅ DETERMINE Z-SLICES
        if z_slice_centers is None:
            if hasattr(self, 'z_min') and hasattr(self, 'z_max'):
                z_min = self.z_min
                z_max = self.z_max
            else:
                z_min = -30.0
                z_max = 30.0
            z_slice_centers = np.arange(z_min, z_max + z_slice_width, z_slice_width)
        
        # Handle single value input
        if isinstance(z_slice_centers, (int, float)):
            z_slice_centers = [z_slice_centers]
        
        z_slice_centers = np.array(z_slice_centers)
        n_slices = len(z_slice_centers)
        
        print(f"📏 Z-slice configuration:")
        print(f"   Centers: {z_slice_centers[0]:.1f} to {z_slice_centers[-1]:.1f} Å")
        print(f"   Width: {z_slice_width:.1f} Å")
        print(f"   Count: {n_slices}")
        
        # ✅ BOX DIMENSIONS
        box_dims = self.universe.dimensions[:3] if self.universe.dimensions is not None else [100, 100, 100]
        print(f"📦 Box dimensions: {box_dims[0]:.1f} × {box_dims[1]:.1f} × {box_dims[2]:.1f} Å")
        
        # ✅ XY GRID SETUP
        if self.center_box:
            x_edges = np.arange(-box_dims[0]/2, box_dims[0]/2 + xy_grid_size, xy_grid_size)
            y_edges = np.arange(-box_dims[1]/2, box_dims[1]/2 + xy_grid_size, xy_grid_size)
        else:
            x_edges = np.arange(0, box_dims[0] + xy_grid_size, xy_grid_size)
            y_edges = np.arange(0, box_dims[1] + xy_grid_size, xy_grid_size)
        
        x_centers = (x_edges[:-1] + x_edges[1:]) / 2
        y_centers = (y_edges[:-1] + y_edges[1:]) / 2
        
        print(f"🗂️ XY grid: {len(x_centers)} × {len(y_centers)} points (spacing: {xy_grid_size:.2f} Å)")
        
        # ✅ FRAME SAMPLING
        n_frames = len(self.universe.trajectory)
        if max_frames is not None and max_frames < n_frames:
            n_frames = max_frames
        
        frame_indices = np.arange(0, n_frames, step)
        print(f"🎬 Frame sampling: {len(frame_indices)} frames (every {step}, max: {max_frames or 'all'})")
        
        # ✅ HELPER FUNCTIONS FOR CLAY VISUALIZATION
        def create_mg_vdw_footprint(x_pos, y_pos, radius, color, texture_intensity=0.7):
            """Create VdW-scaled Mg atom footprint with Gaussian grainy texture"""
            
            footprint_data = {
                'center': (x_pos, y_pos),
                'radius': radius,
                'color': color,
                'circles': []  # List of circle data for visualization
            }
            
            if mgo_radial_fade:
                # Create concentric circles with noise for grainy texture
                alphas = np.linspace(fade_alpha_max, fade_alpha_min, fade_steps)
                radii = np.linspace(0.3 * radius, radius, fade_steps)
                
                for i, (r, alpha) in enumerate(zip(radii, alphas)):
                    # Add Gaussian noise for grainy texture
                    noise_factor = texture_intensity * 0.1 * radius * (1 - i/fade_steps)
                    actual_radius = r + np.random.normal(0, noise_factor)
                    actual_alpha = alpha + np.random.normal(0, 0.05 * texture_intensity)
                    actual_alpha = np.clip(actual_alpha, 0.05, 1.0)
                    
                    # Color variation for texture
                    if fade_method == 'gaussian':
                        color_factor = np.exp(-(i/fade_steps)**2 / (2 * fade_sigma**2))
                    elif fade_method == 'linear':
                        color_factor = 1 - i/fade_steps
                    elif fade_method == 'exponential':
                        color_factor = np.exp(-i/fade_steps * 3)
                    else:
                        color_factor = 1.0
                    
                    footprint_data['circles'].append({
                        'x': x_pos, 'y': y_pos, 'radius': max(0.1, actual_radius),
                        'alpha': actual_alpha, 'color': color,
                        'color_factor': color_factor, 'zorder': 5 + i
                    })
            else:
                # Simple solid circle
                footprint_data['circles'].append({
                    'x': x_pos, 'y': y_pos, 'radius': radius,
                    'alpha': fade_alpha_max, 'color': color,
                    'color_factor': 1.0, 'zorder': 10
                })
            
            return footprint_data
        
        def create_si_network_connections(si_positions, threshold=5.0):
            """Create Si-Si connection network"""
            
            connections = []
            si_centers = []
            
            if len(si_positions) == 0:
                return connections, si_centers
            
            si_array = np.array(si_positions)
            
            # Calculate all pairwise distances and connections
            for i in range(len(si_array)):
                for j in range(i+1, len(si_array)):
                    distance = np.linalg.norm(si_array[i] - si_array[j])
                    
                    if distance < threshold:
                        connection = {
                            'start': (si_array[i][0], si_array[i][1]),
                            'end': (si_array[j][0], si_array[j][1]),
                            'distance': distance,
                            'color': si_color,
                            'alpha': si_connection_alpha,
                            'linewidth': si_connection_linewidth,
                            'style': si_connection_style,
                            'zorder': 3
                        }
                        connections.append(connection)
            
            # Si center markers for hexagonal pattern visualization
            if show_hexagonal_pattern:
                for pos in si_array:
                    center = {
                        'x': pos[0], 'y': pos[1],
                        'size': 20, 'color': si_color,
                        'alpha': 0.8, 'marker': 'o',
                        'edgecolor': 'black', 'linewidth': 0.5,
                        'zorder': 4
                    }
                    si_centers.append(center)
            
            return connections, si_centers
        
        # ✅ MAIN CALCULATION LOOP
        print(f"\n🔄 Processing {n_slices} z-slices across {len(frame_indices)} frames...")
        
        z_slice_results = []
        
        for slice_idx, z_center in enumerate(z_slice_centers):
            print(f"\n📍 Processing z-slice {slice_idx+1}/{n_slices}: z = {z_center:.1f} Å")
            
            # Initialize slice data
            slice_mg_positions = []
            slice_si_positions = []
            slice_mg_footprints = []
            
            # Z-bounds for this slice
            z_min_slice = z_center - z_slice_width / 2
            z_max_slice = z_center + z_slice_width / 2
            
            frame_count = 0
            
            # Process frames
            for frame_idx in frame_indices:
                try:
                    self.universe.trajectory[frame_idx]
                except IndexError:
                    continue
                
                # Apply centering if needed
                z_offset = 0
                if self.center_box:
                    z_offset = box_dims[2] / 2
                
                # ✅ PROCESS MG ATOMS
                if len(mg_atoms) > 0:
                    mg_positions = mg_atoms.positions.copy()
                    mg_z = mg_positions[:, 2] - z_offset
                    
                    # Filter by z-slice
                    mg_in_slice = (mg_z >= z_min_slice) & (mg_z <= z_max_slice)
                    mg_slice_pos = mg_positions[mg_in_slice]
                    
                    # Apply XY centering if needed
                    if self.center_box:
                        mg_slice_pos[:, 0] -= box_dims[0] / 2
                        mg_slice_pos[:, 1] -= box_dims[1] / 2
                    
                    # Store Mg positions
                    for mg_pos in mg_slice_pos:
                        x, y = mg_pos[0], mg_pos[1]
                        slice_mg_positions.append((x, y))
                
                # ✅ PROCESS SI ATOMS
                if len(si_atoms) > 0:
                    si_positions = si_atoms.positions.copy()
                    si_z = si_positions[:, 2] - z_offset
                    
                    # Filter by z-slice
                    si_in_slice = (si_z >= z_min_slice) & (si_z <= z_max_slice)
                    si_slice_pos = si_positions[si_in_slice]
                    
                    # Apply XY centering if needed
                    if self.center_box:
                        si_slice_pos[:, 0] -= box_dims[0] / 2
                        si_slice_pos[:, 1] -= box_dims[1] / 2
                    
                    # Store Si positions
                    for si_pos in si_slice_pos:
                        x, y = si_pos[0], si_pos[1]
                        slice_si_positions.append((x, y))
                
                frame_count += 1
            
            # Average positions over frames (remove duplicates)
            if slice_mg_positions:
                # Get unique positions (average nearby positions)
                unique_mg_positions = []
                mg_array = np.array(slice_mg_positions)
                
                # Simple clustering to get average positions
                processed = set()
                for i, pos in enumerate(mg_array):
                    if i in processed:
                        continue
                    
                    # Find nearby positions
                    distances = np.linalg.norm(mg_array - pos, axis=1)
                    nearby = distances < 1.0  # Within 1 Å
                    
                    # Average nearby positions
                    avg_pos = np.mean(mg_array[nearby], axis=0)
                    unique_mg_positions.append(tuple(avg_pos))
                    
                    # Mark as processed
                    for j in np.where(nearby)[0]:
                        processed.add(j)
                
                slice_mg_positions = unique_mg_positions
            
            # Do the same for Si positions
            if slice_si_positions:
                unique_si_positions = []
                si_array = np.array(slice_si_positions)
                
                processed = set()
                for i, pos in enumerate(si_array):
                    if i in processed:
                        continue
                    
                    distances = np.linalg.norm(si_array - pos, axis=1)
                    nearby = distances < 1.0
                    
                    avg_pos = np.mean(si_array[nearby], axis=0)
                    unique_si_positions.append(tuple(avg_pos))
                    
                    for j in np.where(nearby)[0]:
                        processed.add(j)
                
                slice_si_positions = unique_si_positions
            
            # ✅ CREATE MG VdW FOOTPRINTS
            for mg_pos in slice_mg_positions:
                x, y = mg_pos
                footprint = create_mg_vdw_footprint(
                    x, y, mg_scaled_radius, mgo_color, mg_texture_intensity
                )
                slice_mg_footprints.append(footprint)
            
            # ✅ CREATE SI NETWORK CONNECTIONS
            si_connections, si_centers = create_si_network_connections(
                slice_si_positions, si_connection_threshold
            )
            
            # ✅ CREATE OPTIONAL COMBINED SPATIAL GRID (for backward compatibility)
            combined_grid = np.zeros((len(y_centers), len(x_centers)))
            
            # Add Mg contributions to grid
            for footprint in slice_mg_footprints:
                x_pos, y_pos = footprint['center']
                radius = footprint['radius']
                
                # Find grid points within radius and add contribution
                for i, x_center in enumerate(x_centers):
                    for j, y_center in enumerate(y_centers):
                        dx = x_center - x_pos
                        dy = y_center - y_pos
                        distance = np.sqrt(dx*dx + dy*dy)
                        
                        if distance <= radius:
                            # Gaussian contribution
                            contrib = np.exp(-(distance/(radius/2))**2)
                            combined_grid[j, i] += contrib
            
            # ✅ STORE SLICE RESULTS WITH PLOTTING-READY DATA
            slice_result = {
                'z_center': z_center,
                'z_bounds': (z_min_slice, z_max_slice),
                
                # ✅ PLOTTING-READY DATA FOR MG ATOMS
                'mg_positions': slice_mg_positions,
                'mg_footprints': slice_mg_footprints,
                'mg_scaled_radius': mg_scaled_radius,
                'mg_color': mgo_color,
                
                # ✅ PLOTTING-READY DATA FOR SI ATOMS  
                'si_positions': slice_si_positions,
                'si_connections': si_connections,
                'si_centers': si_centers,
                'si_color': si_color,
                
                # ✅ GRID DATA (for backward compatibility)
                'combined_grid': combined_grid,
                'x_centers': x_centers.copy(),
                'y_centers': y_centers.copy(),
                'x_edges': x_edges.copy(),
                'y_edges': y_edges.copy(),
                
                # ✅ METADATA
                'frame_count': frame_count,
                'mg_count': len(slice_mg_positions),
                'si_count': len(slice_si_positions),
                'connection_count': len(si_connections)
            }
            
            z_slice_results.append(slice_result)
            
            print(f"   ✓ Mg atoms: {len(slice_mg_positions)}, Si atoms: {len(slice_si_positions)}")
            print(f"   ✓ Si connections: {len(si_connections)}, Frames: {frame_count}")
        
        # ✅ COMPILE FINAL RESULTS
        clay_results = {
            'z_slices': z_slice_results,
            'parameters': {
                'z_slice_centers': z_slice_centers.tolist(),
                'z_slice_width': z_slice_width,
                'xy_grid_size': xy_grid_size,
                'mg_vdw_radius': mg_vdw_radius,
                'si_vdw_radius': si_vdw_radius,
                'mg_vdw_scaling': mg_vdw_scaling,
                'si_vdw_scaling': si_vdw_scaling,
                'mgo_radial_fade': mgo_radial_fade,
                'fade_method': fade_method,
                'fade_sigma': fade_sigma,
                'fade_steps': fade_steps,
                'fade_alpha_min': fade_alpha_min,
                'fade_alpha_max': fade_alpha_max,
                'mgo_color': mgo_color,
                'si_color': si_color,
                'si_connection_threshold': si_connection_threshold,
                'si_connection_style': si_connection_style,
                'si_connection_alpha': si_connection_alpha,
                'si_connection_linewidth': si_connection_linewidth,
                'show_hexagonal_pattern': show_hexagonal_pattern,
                'mg_texture_intensity': mg_texture_intensity,
                'mg_glow_effect': mg_glow_effect,
                'si_network_thickness': si_network_thickness,
                'step': step,
                'max_frames': max_frames
            },
            'box_dimensions': box_dims,
            'mg_vdw_scaled_radius': mg_scaled_radius,
            'si_vdw_scaled_radius': si_scaled_radius,
            'total_frames_processed': len(frame_indices),
            'calculation_timestamp': datetime.now().isoformat()
        }
        
        # ✅ SAVE TO CACHE
        if use_cache:
            print(f"\n💾 Saving clay data to cache: {cache_filename}")
            try:
                np.savez(cache_filename, clay_results=clay_results)
                print(f"✓ Cache saved successfully")
            except Exception as e:
                print(f"⚠ Warning: Could not save cache: {e}")
        
        # ✅ STORE IN RESULTS
        self.results.clay_spatial_xy = clay_results
        
        # ✅ PRINT COMPREHENSIVE SUMMARY
        print(f"\n{'='*70}")
        print(f"🎯 CLAY SPATIAL DISTRIBUTION CALCULATION COMPLETE")
        print(f"{'='*70}")
        
        total_mg = sum(len(s['mg_positions']) for s in z_slice_results)
        total_si = sum(len(s['si_positions']) for s in z_slice_results)
        total_connections = sum(len(s['si_connections']) for s in z_slice_results)
        
        print(f"📊 Summary Statistics:")
        print(f"   Z-slices processed: {n_slices}")
        print(f"   Frames analyzed: {len(frame_indices)}")
        print(f"   Total Mg atoms: {total_mg}")
        print(f"   Total Si atoms: {total_si}")
        print(f"   Total Si connections: {total_connections}")
        
        print(f"\n🎨 Visualization Data Generated:")
        print(f"   ✓ Mg VdW footprints with {fade_method} fade")
        print(f"   ✓ Si network connections ({si_connection_style})")
        print(f"   ✓ Combined spatial grids")
        print(f"   ✓ All plotting-ready coordinates")
        
        print(f"\n🔧 Parameters Used:")
        print(f"   Mg VdW: {mg_vdw_radius:.2f} → {mg_scaled_radius:.2f} Å")
        print(f"   Si VdW: {si_vdw_radius:.2f} → {si_scaled_radius:.2f} Å")
        print(f"   Grid spacing: {xy_grid_size:.2f} Å")
        print(f"   Si network threshold: {si_connection_threshold:.1f} Å")
        
        print(f"{'='*70}\n")
        
        return clay_results



