    def calculate_pmf_vs_z(self, ion_types=None, temperature=298.15, units='kT',
                        reference_method='center_zero', reference_region=(-5, 5),
                        bulk_region_z=0.0, symmetrize=False, symmetrize_method='average',
                        smoothing=False, smoothing_method='gaussian', gaussian_sigma=1.0,
                        shift_pmf=True, noise_region=(-10, 10), flag_noise=True,
                        confidence_intervals=False,
                        limit_pmf_range=True, max_pmf_value=None, 
                        density_cutoff_method='percentile', density_cutoff_value=1.0,
                        replace_high_pmf_method='interpolate'):
        """
        Calculate Potential of Mean Force from ion density profiles with enhanced features and PMF range limiting.
        
        Parameters
        ----------
        ion_types : list or None
            Ion types to analyze. If None, analyzes all available ion types
        temperature : float, default=298.15
            Temperature in Kelvin for kT calculation
        units : str, default='kT'
            Output units for PMF:
            - 'kT': Thermal energy units (kT)
            - 'kJ_mol': kJ/mol
            - 'kcal_mol': kcal/mol
            - 'eV': electron volts
        reference_method : str, default='center_zero'
            Method to define reference (zero) point:
            - 'center_zero': Set Z=0 region as reference (bulk in symmetric systems)
            - 'bulk_average': Average density in |z| > bulk_region_z
            - 'global_minimum': Set global PMF minimum as zero
            - 'custom_region': User-defined reference region
        reference_region : tuple, default=(-5, 5)
            Z-range for reference calculation (Å) when using 'center_zero' or 'custom_region'
        bulk_region_z : float, default=20.0
            Z-distance threshold for bulk region (|z| > bulk_region_z)
        symmetrize : bool, default=False
            Apply symmetrization to density profiles before PMF calculation
        symmetrize_method : str, default='average'
            Symmetrization method: 'average', 'fold', 'mirror_positive', 'mirror_negative'
        smoothing : bool, default=False
            Apply smoothing to density profiles before PMF calculation
        smoothing_method : str, default='gaussian'
            Smoothing method: 'gaussian', 'savgol', 'spline', 'moving_average'
        gaussian_sigma : float, default=1.0
            Standard deviation for Gaussian smoothing (in units of bin width)
        shift_pmf : bool, default=True
            Shift PMF to set reference region to zero
        noise_region : tuple, default=(-10, 10)
            Z-range where features might be noise (Å)
        flag_noise : bool, default=True
            Flag potential noise features in the noise region
        confidence_intervals : bool, default=False
            Calculate bootstrap confidence intervals (requires trajectory data)
        limit_pmf_range : bool, default=True
            If True, limit PMF to reasonable energy ranges by handling low-density regions
        max_pmf_value : float, optional
            Maximum allowed PMF value. If None, uses 10*kT as default cutoff
            Values above this will be handled according to replace_high_pmf_method
        density_cutoff_method : str, default='percentile'
            Method to identify problematic low-density regions:
            - 'percentile': Use percentile-based cutoff (recommended)
            - 'absolute': Use absolute density threshold
            - 'bulk_fraction': Use fraction of bulk density
        density_cutoff_value : float, default=1.0
            Cutoff parameter:
            - For 'percentile': percentile value (1.0 = 1st percentile)
            - For 'absolute': minimum density threshold
            - For 'bulk_fraction': fraction of bulk density (0.01 = 1% of bulk)
        replace_high_pmf_method : str, default='interpolate'
            How to handle regions above max_pmf_value:
            - 'interpolate': Linear interpolation from neighboring valid points
            - 'cap': Cap at max_pmf_value
            - 'nan': Set to NaN (excluded from analysis)
            - 'extrapolate': Extrapolate from last valid gradient
        
        Returns
        -------
        dict : PMF results for each ion type with enhanced analysis and range limiting
        """
        
        self._validate_analysis()
        
        print(f"\n{'='*70}")
        print(f"ENHANCED PMF CALCULATION WITH RANGE LIMITING")
        print(f"{'='*70}")
        
        # Physical constants
        k_B = 1.380649e-23  # J/K (Boltzmann constant)
        N_A = 6.02214076e23  # mol^-1 (Avogadro's number)
        eV_to_J = 1.602176634e-19  # J/eV
        
        # Calculate kT in different units
        kT_J = k_B * temperature  # J
        kT_kJ_mol = kT_J * N_A / 1000  # kJ/mol
        kT_kcal_mol = kT_kJ_mol / 4.184  # kcal/mol
        kT_eV = kT_J / eV_to_J  # eV
        
        # Select kT value based on output units
        if units == 'kT':
            kT = 1.0
            unit_label = 'kT'
        elif units == 'kJ_mol':
            kT = kT_kJ_mol
            unit_label = 'kJ/mol'
        elif units == 'kcal_mol':
            kT = kT_kcal_mol
            unit_label = 'kcal/mol'
        elif units == 'eV':
            kT = kT_eV
            unit_label = 'eV'
        else:
            raise ValueError(f"Unknown units: {units}. Use 'kT', 'kJ_mol', 'kcal_mol', or 'eV'")
        
        # Set up PMF range limiting parameters
        if limit_pmf_range:
            if max_pmf_value is None:
                max_pmf_value = 10.0 * kT  # 10 kT is a reasonable physical limit
            print(f"PMF range limiting: ENABLED")
            print(f"  Maximum PMF value: {max_pmf_value:.3f} {unit_label}")
            print(f"  Density cutoff method: {density_cutoff_method}")
            print(f"  Density cutoff value: {density_cutoff_value}")
            print(f"  Replace method: {replace_high_pmf_method}")
        else:
            print(f"PMF range limiting: DISABLED")
        
        print(f"Temperature: {temperature:.1f} K (kT = {kT:.6f} {unit_label})")
        print(f"Reference method: {reference_method}")
        print(f"Symmetrization: {'ON' if symmetrize else 'OFF'}")
        print(f"Smoothing: {'ON' if smoothing else 'OFF'} ({smoothing_method})")
        print(f"PMF shifting: {'ON' if shift_pmf else 'OFF'}")
        
        # Get ion types to analyze
        if ion_types is None:
            ion_types = list(self.results.ion_densities_by_type.keys())
        
        pmf_results = {}
        
        # Import smoothing functions
        if smoothing:
            from scipy.ndimage import gaussian_filter1d
            from scipy.signal import savgol_filter
            from scipy.interpolate import UnivariateSpline
        
        for ion_type in ion_types:
            if ion_type not in self.results.ion_densities_by_type:
                print(f"  Warning: Ion type '{ion_type}' not found in results")
                continue
            
            print(f"\n🔍 Processing {ion_type}:")
            
            # Get density profile
            density = self.results.ion_densities_by_type[ion_type].copy()
            z_centers = self.z_centers.copy()
            
            # Apply symmetrization if requested
            if symmetrize:
                print(f"  → Applying symmetrization ({symmetrize_method})")
                density_sym = self._symmetrize_density_profile(density, z_centers, symmetrize_method)
                density = density_sym
                print(f"    ✓ Symmetrization applied successfully")
            
            # Apply smoothing if requested
            if smoothing:
                print(f"  → Applying smoothing ({smoothing_method})")
                
                if smoothing_method == 'gaussian':
                    density = gaussian_filter1d(density, sigma=gaussian_sigma)
                elif smoothing_method == 'savgol':
                    window_length = max(5, int(2 * gaussian_sigma + 1))
                    if window_length % 2 == 0:
                        window_length += 1
                    if window_length < len(density):
                        density = savgol_filter(density, window_length, polyorder=3)
                elif smoothing_method == 'spline':
                    spline = UnivariateSpline(z_centers, density, s=gaussian_sigma)
                    density = spline(z_centers)
                elif smoothing_method == 'moving_average':
                    window_size = max(1, int(gaussian_sigma))
                    density = np.convolve(density, np.ones(window_size)/window_size, mode='same')
                
                print(f"    ✓ Smoothing applied (σ={gaussian_sigma})")
            
            # Apply density cutoff to identify problematic regions
            if limit_pmf_range:
                print(f"  → Applying density-based PMF range limiting...")
                
                # Identify density cutoff threshold
                if density_cutoff_method == 'percentile':
                    # Use percentile-based cutoff (recommended)
                    density_threshold = np.percentile(density[density > 0], density_cutoff_value)
                    print(f"    Density threshold ({density_cutoff_value}th percentile): {density_threshold:.6f}")
                
                elif density_cutoff_method == 'absolute':
                    density_threshold = density_cutoff_value
                    print(f"    Absolute density threshold: {density_threshold:.6f}")
                
                elif density_cutoff_method == 'bulk_fraction':
                    # Calculate bulk density for reference
                    if reference_method == 'center_zero':
                        ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                        bulk_density_ref = np.mean(density[ref_mask]) if np.any(ref_mask) else np.mean(density)
                    elif reference_method == 'bulk_average':
                        bulk_mask = np.abs(z_centers) > bulk_region_z
                        bulk_density_ref = np.mean(density[bulk_mask]) if np.any(bulk_mask) else np.mean(density)
                    else:
                        bulk_density_ref = np.mean(density)
                    
                    density_threshold = bulk_density_ref * density_cutoff_value
                    print(f"    Bulk density reference: {bulk_density_ref:.6f}")
                    print(f"    Density threshold ({density_cutoff_value*100:.1f}% of bulk): {density_threshold:.6f}")
                
                # Create mask for valid density regions
                valid_density_mask = density >= density_threshold
                n_valid = np.sum(valid_density_mask)
                n_total = len(density)
                print(f"    Valid density points: {n_valid}/{n_total} ({100*n_valid/n_total:.1f}%)")
                
                # Apply minimum density floor to avoid log(0)
                min_density = max(1e-10, density_threshold * 0.1)  # 10% of threshold as floor
                density_safe = np.maximum(density, min_density)
            
            else:
                # Original behavior: handle zero/near-zero densities
                min_density = 1e-10
                density_safe = np.maximum(density, min_density)
                valid_density_mask = np.ones(len(density), dtype=bool)
            
            # Calculate reference density based on method
            if reference_method == 'center_zero':
                # Use density around z=0 (bulk in symmetric systems)
                ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                if np.any(ref_mask):
                    bulk_density = np.mean(density_safe[ref_mask])
                    n_ref_points = np.sum(ref_mask)
                    print(f"    Reference (z=0 region): {bulk_density:.6f} ions/Å³ ({n_ref_points} points)")
                else:
                    bulk_density = np.mean(density_safe)
                    print(f"    Warning: No reference region found, using global average")
                    
            elif reference_method == 'bulk_average':
                # Original bulk method
                bulk_mask = np.abs(z_centers) > bulk_region_z
                if np.any(bulk_mask):
                    bulk_density = np.mean(density_safe[bulk_mask])
                    n_bulk_points = np.sum(bulk_mask)
                    print(f"    Bulk density: {bulk_density:.6f} ions/Å³ ({n_bulk_points} points)")
                else:
                    bulk_density = np.mean(density_safe)
                    print(f"    Warning: No bulk region found, using global average")
                    
            elif reference_method == 'global_minimum':
                # Set global minimum to zero (most bound state)
                bulk_density = np.max(density_safe)  # Will make PMF minimum = 0
                print(f"    Reference (global max density): {bulk_density:.6f} ions/Å³")
                
            elif reference_method == 'custom_region':
                # User-defined reference region
                ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                if np.any(ref_mask):
                    bulk_density = np.mean(density_safe[ref_mask])
                    n_ref_points = np.sum(ref_mask)
                    print(f"    Custom reference: {bulk_density:.6f} ions/Å³ ({n_ref_points} points)")
                else:
                    raise ValueError(f"No data points in custom reference region {reference_region}")
            else:
                raise ValueError(f"Unknown reference_method: {reference_method}")
            
            # Calculate PMF using Boltzmann relation: W(z) = -kT ln[ρ(z)/ρ₀]
            pmf = -kT * np.log(density_safe / bulk_density)
            
            # Handle infinities and NaNs
            pmf = np.where(np.isfinite(pmf), pmf, np.nan)
            
            # Apply PMF range limiting
            if limit_pmf_range:
                print(f"  → Applying PMF range limiting (max: {max_pmf_value:.3f} {unit_label})...")
                
                # Identify points exceeding maximum PMF
                high_pmf_mask = pmf > max_pmf_value
                n_high = np.sum(high_pmf_mask & np.isfinite(pmf))
                
                if n_high > 0:
                    print(f"    Found {n_high} points above maximum PMF")
                    print(f"    Original PMF range: {np.nanmin(pmf):.3f} to {np.nanmax(pmf):.3f} {unit_label}")
                    
                    # Apply replacement method
                    if replace_high_pmf_method == 'cap':
                        # Simple capping at maximum value
                        pmf[high_pmf_mask] = max_pmf_value
                        print(f"    Applied capping at {max_pmf_value:.3f} {unit_label}")
                    
                    elif replace_high_pmf_method == 'nan':
                        # Set high values to NaN
                        pmf[high_pmf_mask] = np.nan
                        print(f"    Set {n_high} high-PMF points to NaN")
                    
                    elif replace_high_pmf_method == 'interpolate':
                        # Linear interpolation from neighboring valid points
                        print(f"    Applying linear interpolation for high-PMF regions...")
                        
                        # Create mask for valid PMF values
                        valid_pmf_mask = (pmf <= max_pmf_value) & np.isfinite(pmf)
                        
                        if np.sum(valid_pmf_mask) >= 2:  # Need at least 2 points for interpolation
                            from scipy.interpolate import interp1d
                            
                            # Get valid points
                            z_valid = z_centers[valid_pmf_mask]
                            pmf_valid = pmf[valid_pmf_mask]
                            
                            # Create interpolator (with extrapolation for edge cases)
                            interpolator = interp1d(z_valid, pmf_valid, kind='linear', 
                                                bounds_error=False, fill_value='extrapolate')
                            
                            # Interpolate high-PMF regions
                            pmf[high_pmf_mask] = interpolator(z_centers[high_pmf_mask])
                            
                            # Cap interpolated values that might still be too high
                            pmf[high_pmf_mask & (pmf > max_pmf_value)] = max_pmf_value
                            
                            print(f"    Interpolation complete")
                        
                        else:
                            print(f"    ⚠ Insufficient valid points for interpolation, using capping instead")
                            pmf[high_pmf_mask] = max_pmf_value
                    
                    elif replace_high_pmf_method == 'extrapolate':
                        # Extrapolate from last valid gradient
                        print(f"    Applying gradient-based extrapolation...")
                        
                        for i in range(len(pmf)):
                            if high_pmf_mask[i]:
                                # Find nearest valid neighbors
                                left_valid = None
                                right_valid = None
                                
                                # Search left
                                for j in range(i-1, -1, -1):
                                    if pmf[j] <= max_pmf_value and np.isfinite(pmf[j]):
                                        left_valid = j
                                        break
                                
                                # Search right
                                for j in range(i+1, len(pmf)):
                                    if pmf[j] <= max_pmf_value and np.isfinite(pmf[j]):
                                        right_valid = j
                                        break
                                
                                # Extrapolate based on available neighbors
                                if left_valid is not None and right_valid is not None:
                                    # Linear interpolation
                                    weight = (z_centers[i] - z_centers[left_valid]) / (z_centers[right_valid] - z_centers[left_valid])
                                    pmf[i] = pmf[left_valid] + weight * (pmf[right_valid] - pmf[left_valid])
                                elif left_valid is not None:
                                    # Extrapolate from left with zero gradient
                                    pmf[i] = min(pmf[left_valid], max_pmf_value)
                                elif right_valid is not None:
                                    # Extrapolate from right with zero gradient
                                    pmf[i] = min(pmf[right_valid], max_pmf_value)
                                else:
                                    # No valid neighbors, cap at maximum
                                    pmf[i] = max_pmf_value
                        
                        print(f"    Extrapolation complete")
                    
                    print(f"    Final PMF range: {np.nanmin(pmf):.3f} to {np.nanmax(pmf):.3f} {unit_label}")
                
                else:
                    print(f"    No points exceed maximum PMF - no limiting applied")
            
            # Apply PMF shifting if requested
            if shift_pmf:
                if reference_method == 'center_zero':
                    # Shift so reference region averages to zero
                    ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                    if np.any(ref_mask) and not np.all(np.isnan(pmf[ref_mask])):
                        shift_value = np.nanmean(pmf[ref_mask])
                        pmf -= shift_value
                        print(f"    ✓ PMF shifted by {shift_value:.3f} {unit_label} (reference region → 0)")
                elif reference_method == 'global_minimum':
                    # Shift so global minimum is zero
                    if not np.all(np.isnan(pmf)):
                        shift_value = np.nanmin(pmf)
                        pmf -= shift_value
                        print(f"    ✓ PMF shifted by {shift_value:.3f} {unit_label} (global min → 0)")
            
            # Analyze features and flag potential noise
            valid_mask = np.isfinite(pmf)
            noise_flags = np.zeros(len(pmf), dtype=bool)
            
            if flag_noise and np.any(valid_mask):
                # Flag features in noise region
                noise_mask = (z_centers >= noise_region[0]) & (z_centers <= noise_region[1])
                
                if np.any(noise_mask):
                    # Find local maxima and minima in noise region
                    from scipy.signal import find_peaks
                    
                    pmf_noise_region = pmf[noise_mask & valid_mask]
                    z_noise_region = z_centers[noise_mask & valid_mask]
                    
                    if len(pmf_noise_region) > 3:
                        # Find peaks (barriers) and valleys (binding sites)
                        peaks, _ = find_peaks(pmf_noise_region, prominence=0.5*kT)
                        valleys, _ = find_peaks(-pmf_noise_region, prominence=0.5*kT)
                        
                        n_features = len(peaks) + len(valleys)
                        
                        if n_features > 0:
                            print(f"    ⚠ Potential noise detected in {noise_region} Å region:")
                            print(f"      Found {n_features} features (peaks: {len(peaks)}, valleys: {len(valleys)})")
                            print(f"      Consider smoothing or increasing statistics")
                            
                            # Flag the noise region
                            noise_flags[noise_mask] = True
            
            # Calculate statistics
            if np.any(valid_mask):
                pmf_min = np.nanmin(pmf)
                pmf_max = np.nanmax(pmf)
                pmf_range = pmf_max - pmf_min
                
                # Find binding sites (minima) and barriers (maxima)
                from scipy.signal import find_peaks
                
                pmf_valid = pmf[valid_mask]
                z_valid = z_centers[valid_mask]
                
                if len(pmf_valid) > 3:
                    # Find minima (binding sites) - look for valleys in PMF
                    minima_indices, minima_props = find_peaks(-pmf_valid, prominence=0.5*kT)
                    minima_z = z_valid[minima_indices] if len(minima_indices) > 0 else np.array([])
                    minima_values = pmf_valid[minima_indices] if len(minima_indices) > 0 else np.array([])
                    
                    # Find maxima (barriers) - look for peaks in PMF
                    maxima_indices, maxima_props = find_peaks(pmf_valid, prominence=0.5*kT)
                    maxima_z = z_valid[maxima_indices] if len(maxima_indices) > 0 else np.array([])
                    maxima_values = pmf_valid[maxima_indices] if len(maxima_indices) > 0 else np.array([])
                else:
                    minima_z, minima_values = np.array([]), np.array([])
                    maxima_z, maxima_values = np.array([]), np.array([])
                
                print(f"    📊 PMF Statistics:")
                print(f"      Range: {pmf_min:.3f} to {pmf_max:.3f} {unit_label} (Δ = {pmf_range:.3f})")
                print(f"      Binding sites: {len(minima_indices)} found")
                print(f"      Energy barriers: {len(maxima_indices)} found")
                
                if len(minima_indices) > 0:
                    strongest_idx = np.argmin(minima_values)
                    print(f"      Strongest binding: {minima_values[strongest_idx]:.3f} {unit_label} at z = {minima_z[strongest_idx]:.2f} Å")
                
                if len(maxima_indices) > 0:
                    highest_idx = np.argmax(maxima_values)
                    print(f"      Highest barrier: {maxima_values[highest_idx]:.3f} {unit_label} at z = {maxima_z[highest_idx]:.2f} Å")
            
            else:
                print(f"    ⚠ Warning: No finite PMF values found for {ion_type}")
                minima_z, minima_values = np.array([]), np.array([])
                maxima_z, maxima_values = np.array([]), np.array([])
                pmf_min = pmf_max = pmf_range = np.nan
            
            # Store enhanced results with PMF limiting information
            pmf_results[ion_type] = {
                'pmf': pmf,
                'density': density,
                'bulk_density': bulk_density,
                'z_centers': z_centers.copy(),
                'units': unit_label,
                'temperature': temperature,
                'kT_value': kT,
                
                # Method parameters
                'reference_method': reference_method,
                'reference_region': reference_region,
                'bulk_region_z': bulk_region_z,
                'symmetrized': symmetrize,
                'symmetrize_method': symmetrize_method if symmetrize else None,
                'smoothed': smoothing,
                'smoothing_method': smoothing_method if smoothing else None,
                'gaussian_sigma': gaussian_sigma if smoothing else None,
                'shifted': shift_pmf,
                
                # PMF limiting parameters and results
                'pmf_range_limited': limit_pmf_range,
                'max_pmf_value': max_pmf_value if limit_pmf_range else None,
                'density_cutoff_method': density_cutoff_method if limit_pmf_range else None,
                'density_cutoff_value': density_cutoff_value if limit_pmf_range else None,
                'replace_high_pmf_method': replace_high_pmf_method if limit_pmf_range else None,
                'n_points_limited': np.sum(high_pmf_mask & np.isfinite(pmf)) if limit_pmf_range else 0,
                'density_threshold_used': density_threshold if limit_pmf_range else None,
                
                # Noise analysis
                'noise_region': noise_region,
                'noise_flags': noise_flags,
                'potential_noise_detected': np.any(noise_flags),
                
                # Statistics
                'statistics': {
                    'min_pmf': pmf_min,
                    'max_pmf': pmf_max,
                    'pmf_range': pmf_range,
                    'mean_pmf': np.nanmean(pmf) if np.any(valid_mask) else np.nan,
                    'std_pmf': np.nanstd(pmf) if np.any(valid_mask) else np.nan
                },
                
                # Features
                'binding_sites': {
                    'positions': minima_z.tolist(),
                    'energies': minima_values.tolist(),
                    'count': len(minima_z)
                },
                'energy_barriers': {
                    'positions': maxima_z.tolist(),
                    'energies': maxima_values.tolist(),
                    'count': len(maxima_z)
                },
                
                # Quality indicators
                'valid_data_fraction': np.sum(valid_mask) / len(pmf),
                'convergence_indicators': {
                    'has_binding_sites': len(minima_z) > 0,
                    'has_barriers': len(maxima_z) > 0,
                    'reasonable_range': pmf_range < 10.0 * kT if np.isfinite(pmf_range) else False
                }
            }
            
            # Add confidence intervals if requested (placeholder - would need bootstrap)
            if confidence_intervals:
                print(f"    📈 Confidence intervals: Not yet implemented (requires trajectory data)")
                pmf_results[ion_type]['confidence_intervals'] = {
                    'method': 'bootstrap',
                    'implemented': False,
                    'lower_bound': None,
                    'upper_bound': None
                }
        
        # Store in results
        self.results.pmf_vs_z = pmf_results
        
        print(f"\n{'='*70}")
        print(f"✅ ENHANCED PMF CALCULATION WITH RANGE LIMITING COMPLETE")
        print(f"{'='*70}")
        print(f"Ion types analyzed: {len(pmf_results)}")
        print(f"Units: {unit_label}")
        print(f"Temperature: {temperature:.1f} K")
        print(f"PMF range limiting: {'ENABLED' if limit_pmf_range else 'DISABLED'}")
        if limit_pmf_range:
            print(f"  Maximum PMF value: {max_pmf_value:.1f} {unit_label}")
            print(f"  Density cutoff method: {density_cutoff_method}")
            print(f"  Replace method: {replace_high_pmf_method}")
        print(f"Enhancements applied:")
        print(f"  → Reference method: {reference_method}")
        if symmetrize:
            print(f"  → Symmetrization: {symmetrize_method}")
        if smoothing:
            print(f"  → Smoothing: {smoothing_method}")
        if shift_pmf:
            print(f"  → PMF shifting: Applied")
        if flag_noise:
            noise_detected = any(result['potential_noise_detected'] for result in pmf_results.values())
            print(f"  → Noise detection: {'Potential noise found' if noise_detected else 'No obvious noise'}")
        
        # Print range limiting summary
        if limit_pmf_range:
            total_limited_points = sum(result['n_points_limited'] for result in pmf_results.values())
            if total_limited_points > 0:
                print(f"  → PMF range limiting applied to {total_limited_points} total points")
                print(f"  → Method: {replace_high_pmf_method}")
            else:
                print(f"  → PMF range limiting: No points exceeded maximum")
        
        return pmf_results


    def _symmetrize_density_profile(self, density, z_centers, method='average'):
        """
        CORRECTED symmetrization method that properly handles both sides.
        
        Parameters
        ----------
        density : np.ndarray
            Original density profile
        z_centers : np.ndarray
            Z-coordinate centers
        method : str
            Symmetrization method
        
        Returns
        -------
        np.ndarray
            Symmetrized density profile with same length as input
        """
        
        # Find center index (closest to z=0)
        center_idx = np.argmin(np.abs(z_centers))
        n_total = len(z_centers)
        
        # Create a copy to modify
        density_sym = density.copy()
        
        if method == 'average':
            # Average corresponding points on both sides
            for i in range(n_total):
                z_val = z_centers[i]
                
                # Find corresponding point on opposite side
                opposite_z = -z_val
                
                # Find closest index to opposite z
                opposite_idx = np.argmin(np.abs(z_centers - opposite_z))
                
                # Only symmetrize if we have a reasonable match (within half bin width)
                if abs(z_centers[opposite_idx] - opposite_z) < abs(z_centers[1] - z_centers[0]):
                    # Average the two sides
                    avg_density = (density[i] + density[opposite_idx]) / 2.0
                    density_sym[i] = avg_density
                    density_sym[opposite_idx] = avg_density
        
        elif method == 'fold':
            # Fold right side onto left (for positive z, use negative z values)
            for i in range(n_total):
                z_val = z_centers[i]
                
                if z_val > 0:  # Positive side
                    opposite_z = -z_val
                    opposite_idx = np.argmin(np.abs(z_centers - opposite_z))
                    
                    if abs(z_centers[opposite_idx] - opposite_z) < abs(z_centers[1] - z_centers[0]):
                        # Use positive side value for negative side
                        density_sym[opposite_idx] = density[i]
        
        elif method == 'mirror_positive':
            # Use positive side, mirror to negative
            for i in range(n_total):
                z_val = z_centers[i]
                
                if z_val < 0:  # Negative side
                    opposite_z = -z_val
                    opposite_idx = np.argmin(np.abs(z_centers - opposite_z))
                    
                    if abs(z_centers[opposite_idx] - opposite_z) < abs(z_centers[1] - z_centers[0]):
                        # Use positive side value for negative side
                        density_sym[i] = density[opposite_idx]
        
        elif method == 'mirror_negative':
            # Use negative side, mirror to positive
            for i in range(n_total):
                z_val = z_centers[i]
                
                if z_val > 0:  # Positive side
                    opposite_z = -z_val
                    opposite_idx = np.argmin(np.abs(z_centers - opposite_z))
                    
                    if abs(z_centers[opposite_idx] - opposite_z) < abs(z_centers[1] - z_centers[0]):
                        # Use negative side value for positive side
                        density_sym[i] = density[opposite_idx]
        
        return density_sym

      
    def calculate_bootstrap_pmf_uncertainty(self, ion_types=None, n_bootstrap=100, confidence_level=0.95,
                                temperature=298.15, units='kT',
                                reference_method='center_zero', reference_region=(-5, 5),
                                bulk_region_z=0.0, smoothing=False, smoothing_method='gaussian', 
                                gaussian_sigma=1.0, shift_pmf=True,
                                noise_region=(-10, 10), flag_noise=True,
                                symmetrize=True, symmetrize_method='average',
                                block_resampling=True, block_size=50,
                                parallel_processing=False, n_jobs=None,
                                save_bootstrap_data=False, bootstrap_filename=None,
                                limit_pmf_range=False, max_pmf_value=None, 
                                density_cutoff_method='percentile', density_cutoff_value=1.0,
                                replace_high_pmf_method='interpolate',
                                confidence_levels=None):
        """
        Bootstrap uncertainty estimation for PMF calculations using existing calculate_pmf_vs_z parameters.
        
        This method performs bootstrap resampling of trajectory frames to estimate uncertainty
        in PMF calculations. All parameters match calculate_pmf_vs_z() for consistency.
        
        Parameters
        ----------
        ion_types : list of str, optional
            Ion types to analyze (e.g., ['NA', 'CL']). If None, analyzes all available ion types
        n_bootstrap : int, default=100
            Number of bootstrap resampling iterations
        confidence_level : float, default=0.95
            Confidence level for uncertainty intervals (0.95 = 95% CI)
            Used only if confidence_levels is None
        temperature : float, default=298.15
            Temperature in Kelvin for kT calculation (matches calculate_pmf_vs_z)
        units : str, default='kT'
            PMF units: 'kT', 'kJ_mol', 'kcal_mol', 'eV' (matches calculate_pmf_vs_z)
        reference_method : str, default='center_zero'
            Reference method: 'center_zero', 'bulk_average', 'global_minimum', 'custom_region'
            (matches calculate_pmf_vs_z)
        reference_region : tuple, default=(-5, 5)
            Z-range for reference calculation (matches calculate_pmf_vs_z)
        bulk_region_z : float, default=0.0
            Z-distance threshold for bulk region (matches calculate_pmf_vs_z)
        smoothing : bool, default=False
            Apply smoothing to density profiles (matches calculate_pmf_vs_z)
        smoothing_method : str, default='gaussian'
            Smoothing method: 'gaussian', 'savgol', 'spline', 'moving_average'
            (matches calculate_pmf_vs_z)
        gaussian_sigma : float, default=1.0
            Standard deviation for smoothing (matches calculate_pmf_vs_z)
        shift_pmf : bool, default=True
            Shift PMF to set reference region to zero (matches calculate_pmf_vs_z)
        noise_region : tuple, default=(-10, 10)
            Z-range where features might be noise (Å) (matches calculate_pmf_vs_z)
        flag_noise : bool, default=True
            Flag potential noise features in the noise region (matches calculate_pmf_vs_z)
        symmetrize : bool, default=True
            Apply symmetrization to density profiles before PMF calculation (matches calculate_pmf_vs_z)
        symmetrize_method : str, default='average'
            Symmetrization method: 'average', 'fold', 'mirror_positive', 'mirror_negative'
            (matches calculate_pmf_vs_z)
        block_resampling : bool, default=True
            Use block resampling to preserve temporal correlation
            If False, uses simple random resampling
        block_size : int, default=50
            Size of blocks for block resampling (frames)
        parallel_processing : bool, default=False
            Use parallel processing for bootstrap iterations (experimental)
        n_jobs : int, optional
            Number of parallel jobs. If None, uses all available cores
        save_bootstrap_data : bool, default=False
            Save individual bootstrap PMF curves for detailed analysis
        bootstrap_filename : str, optional
            Filename for saving bootstrap data. If None, auto-generates
        limit_pmf_range : bool, default=False
            Whether to limit PMF range to prevent divergence (matches calculate_pmf_vs_z)
        max_pmf_value : float, optional
            Maximum allowed PMF value (matches calculate_pmf_vs_z)
        density_cutoff_method : str, default='percentile'
            Method for determining density cutoff (matches calculate_pmf_vs_z)
        density_cutoff_value : float, default=1.0
            Cutoff value for low-density regions (matches calculate_pmf_vs_z)
        replace_high_pmf_method : str, default='interpolate'
            Method for replacing high PMF values (matches calculate_pmf_vs_z)
        confidence_levels : list of float, optional
            Multiple confidence levels to calculate (e.g., [0.68, 0.95])
            If provided, takes precedence over confidence_level parameter
        
        Returns
        -------
        dict
            Bootstrap results containing:
            - For single ion type: Direct bootstrap results dict
            - For multiple ion types: Dict with ion_type keys containing bootstrap results
            
            Each result dict contains:
            - 'mean_pmf': Average PMF across bootstrap samples
            - 'pmf_std': Standard deviation at each z-position  
            - 'confidence_intervals': Dict with confidence level keys or single level
            - 'bootstrap_pmfs': All individual bootstrap PMF curves (if save_bootstrap_data=True)
            - 'z_centers': Z-position centers (matches calculate_pmf_vs_z output)
            - 'units': PMF units used (matches calculate_pmf_vs_z output)
            - 'statistics': Summary statistics
            - 'parameters': All parameters used
            - 'convergence_check': Bootstrap convergence analysis
        """
        
        print(f"\n{'='*70}")
        print(f"BOOTSTRAP PMF UNCERTAINTY ESTIMATION")
        print(f"{'='*70}")
        
        # Handle confidence levels parameter
        if confidence_levels is not None:
            # Multiple confidence levels provided
            if isinstance(confidence_levels, (int, float)):
                confidence_levels = [float(confidence_levels)]
            else:
                confidence_levels = list(confidence_levels)
            
            print(f"Multiple confidence levels: {[f'{cl*100:.0f}%' for cl in confidence_levels]}")
            using_multiple_ci = True
        else:
            # Single confidence level (backward compatibility)
            confidence_levels = [confidence_level]
            using_multiple_ci = False
            print(f"Confidence level: {confidence_level*100}%")
        
        # Handle ion_types parameter
        if ion_types is None:
            # Get all available ion types
            if not hasattr(self.results, 'ion_densities_by_type'):
                raise ValueError("No ion density data found. Run the main analysis first with run()")
            ion_types = list(self.results.ion_densities_by_type.keys())
        elif isinstance(ion_types, str):
            # Convert single string to list
            ion_types = [ion_types]
        
        print(f"Ion types: {ion_types}")
        print(f"Bootstrap iterations: {n_bootstrap}")
        print(f"Temperature: {temperature:.1f} K")
        print(f"Units: {units}")
        print(f"Reference method: {reference_method}")
        
        # Display additional parameters
        print(f"Symmetrization: {'ON' if symmetrize else 'OFF'} ({symmetrize_method})")
        print(f"Noise detection: {'ON' if flag_noise else 'OFF'} (region: {noise_region} Å)")
        
        # Validate that we have the required data
        if not hasattr(self.results, 'ion_densities_by_type'):
            raise ValueError("No ion density data found. Run the main analysis first with run()")
        
        # Check that all requested ion types exist
        available_types = list(self.results.ion_densities_by_type.keys())
        for ion_type in ion_types:
            if ion_type not in available_types:
                raise ValueError(f"Ion type '{ion_type}' not found. Available types: {available_types}")
        
        # Check that we have frame data for resampling
        if not hasattr(self, 'n_frames_analyzed') or self.n_frames_analyzed == 0:
            raise ValueError("No frame information available. Bootstrap requires trajectory frame data.")
        
        # Physical constants (same as calculate_pmf_vs_z)
        k_B = 1.380649e-23  # J/K (Boltzmann constant)
        N_A = 6.02214076e23  # mol^-1 (Avogadro's number)
        eV_to_J = 1.602176634e-19  # J/eV
        
        # Calculate kT in different units (same as calculate_pmf_vs_z)
        kT_J = k_B * temperature  # J
        kT_kJ_mol = kT_J * N_A / 1000  # kJ/mol
        kT_kcal_mol = kT_kJ_mol / 4.184  # kcal/mol
        kT_eV = kT_J / eV_to_J  # eV
        
        # Select kT value based on output units (same as calculate_pmf_vs_z)
        if units == 'kT':
            kT = 1.0
            unit_label = 'kT'
        elif units == 'kJ_mol':
            kT = kT_kJ_mol
            unit_label = 'kJ/mol'
        elif units == 'kcal_mol':
            kT = kT_kcal_mol
            unit_label = 'kcal/mol'
        elif units == 'eV':
            kT = kT_eV
            unit_label = 'eV'
        else:
            raise ValueError(f"Unknown units: {units}. Use 'kT', 'kJ_mol', 'kcal_mol', or 'eV'")
        
        print(f"Block resampling: {'ON' if block_resampling else 'OFF'}")
        if block_resampling:
            print(f"Block size: {block_size} frames")
        
        # Prepare bootstrap resampling strategy
        total_frames = self.n_frames_analyzed
        print(f"Total frames available: {total_frames}")
        
        if block_resampling:
            # Block resampling to preserve temporal correlation
            n_blocks = total_frames // block_size
            if n_blocks < 2:
                print(f"⚠ Warning: Only {n_blocks} blocks with block_size={block_size}")
                print(f"  Switching to simple resampling")
                block_resampling = False
            else:
                print(f"Block resampling: {n_blocks} blocks of {block_size} frames")
        
        # Import smoothing functions if needed (same as calculate_pmf_vs_z)
        if smoothing:
            from scipy.ndimage import gaussian_filter1d
            from scipy.signal import savgol_filter
            from scipy.interpolate import UnivariateSpline
            print(f"Smoothing enabled: {smoothing_method} (σ={gaussian_sigma})")
        
        # Helper function: Generate bootstrap sample indices
        def generate_bootstrap_indices():
            """Generate bootstrap sample of frame indices"""
            
            if block_resampling:
                # Block resampling: randomly sample blocks with replacement
                selected_blocks = np.random.choice(n_blocks, size=n_blocks, replace=True)
                bootstrap_frames = []
                
                for block_idx in selected_blocks:
                    start_frame = block_idx * block_size
                    end_frame = min((block_idx + 1) * block_size, total_frames)
                    bootstrap_frames.extend(range(start_frame, end_frame))
                
                return np.array(bootstrap_frames[:total_frames])  # Ensure same length
            
            else:
                # Simple random resampling
                return np.random.choice(total_frames, size=total_frames, replace=True)

        # Helper function: Calculate PMF for a density profile using REAL BOOTSTRAP RESAMPLING
        def calculate_single_pmf_bootstrap(ion_type, bootstrap_frame_indices):
            """Calculate PMF from resampled frames using stored per-frame histograms"""
            
            # Check if we have per-frame data
            if not hasattr(self.results, 'per_frame_histograms'):
                raise ValueError("No per-frame histogram data available. Enable bootstrap data collection first.")
            
            per_frame_data = self.results.per_frame_histograms
            
            # FIXED: Check if per_frame_data is a dictionary with frame keys
            if not isinstance(per_frame_data, dict):
                raise ValueError("Per-frame histograms not in expected format. Run analysis with bootstrap data collection enabled.")
            
            # Get available frame keys (they are integers like 0, 10, 20, etc.)
            available_frames = list(per_frame_data.keys())
            if len(available_frames) == 0:
                raise ValueError("No per-frame data available. Run analysis with bootstrap data collection enabled.")
            
            # FIXED: Get first frame to check structure
            first_frame_key = available_frames[0]
            first_frame_data = per_frame_data[first_frame_key]
            
            # Check if this ion type exists in the per-frame data
            if ion_type not in first_frame_data:
                raise ValueError(f"No per-frame data for ion type {ion_type}")
            
            print(f"  Found per-frame data for {len(available_frames)} frames")
            
            # FIXED: Collect densities for this ion type across all available frames
            stored_densities = []
            for frame_key in available_frames:
                frame_data = per_frame_data[frame_key]
                if ion_type in frame_data:
                    density_array = frame_data[ion_type]
                    stored_densities.append(density_array)
            
            if len(stored_densities) == 0:
                raise ValueError(f"No per-frame densities found for {ion_type}")
            
            # REAL BOOTSTRAP: Resample from stored per-frame densities
            n_stored_frames = len(stored_densities)
            
            # Map bootstrap indices to stored frame indices
            bootstrap_stored_indices = np.random.choice(n_stored_frames, size=n_stored_frames, replace=True)
            
            # Calculate new density by averaging resampled frames
            resampled_densities = [stored_densities[idx] for idx in bootstrap_stored_indices]
            density_profile = np.mean(resampled_densities, axis=0)
            
            # Get z_centers from current analysis
            z_centers = self.z_centers.copy()
            
            # Apply symmetrization if requested
            if symmetrize:
                density_profile = self._symmetrize_density_profile(density_profile, z_centers, symmetrize_method)
            
            # Apply smoothing if requested (same logic as calculate_pmf_vs_z)
            if smoothing:
                if smoothing_method == 'gaussian':
                    density_profile = gaussian_filter1d(density_profile, sigma=gaussian_sigma)
                elif smoothing_method == 'savgol':
                    window_length = max(5, int(2 * gaussian_sigma + 1))
                    if window_length % 2 == 0:
                        window_length += 1
                    if window_length < len(density_profile):
                        density_profile = savgol_filter(density_profile, window_length, polyorder=3)
                elif smoothing_method == 'spline':
                    spline = UnivariateSpline(z_centers, density_profile, s=gaussian_sigma)
                    density_profile = spline(z_centers)
                elif smoothing_method == 'moving_average':
                    window_size = max(1, int(gaussian_sigma))
                    density_profile = np.convolve(density_profile, np.ones(window_size)/window_size, mode='same')
            
            # Handle zero/near-zero densities
            min_density = 1e-10
            density_profile = np.maximum(density_profile, min_density)
            
            # Apply density cutoff to identify problematic regions
            if limit_pmf_range:
                if density_cutoff_method == 'percentile':
                    density_threshold = np.percentile(density_profile[density_profile > 0], density_cutoff_value)
                elif density_cutoff_method == 'absolute':
                    density_threshold = density_cutoff_value
                elif density_cutoff_method == 'bulk_fraction':
                    bulk_mask = np.abs(z_centers) > bulk_region_z
                    if np.any(bulk_mask):
                        bulk_density = np.mean(density_profile[bulk_mask])
                        density_threshold = bulk_density * density_cutoff_value
                    else:
                        density_threshold = np.mean(density_profile) * density_cutoff_value
                
                min_density = max(1e-10, density_threshold * 0.1)
                density_profile = np.maximum(density_profile, min_density)
            
            # Calculate reference density based on method
            if reference_method == 'center_zero':
                ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                if np.any(ref_mask):
                    bulk_density = np.mean(density_profile[ref_mask])
                else:
                    bulk_density = np.mean(density_profile)
            
            elif reference_method == 'bulk_average':
                bulk_mask = np.abs(z_centers) > bulk_region_z
                if np.any(bulk_mask):
                    bulk_density = np.mean(density_profile[bulk_mask])
                else:
                    bulk_density = np.mean(density_profile)
            
            elif reference_method == 'global_minimum':
                bulk_density = np.max(density_profile)
            
            elif reference_method == 'custom_region':
                ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                if np.any(ref_mask):
                    bulk_density = np.mean(density_profile[ref_mask])
                else:
                    raise ValueError(f"No data points in custom reference region {reference_region}")
            else:
                raise ValueError(f"Unknown reference_method: {reference_method}")
            
            # Calculate PMF using Boltzmann relation
            pmf = -kT * np.log(density_profile / bulk_density)
            
            # Handle infinities and NaNs
            pmf = np.where(np.isfinite(pmf), pmf, np.nan)
            
            # Apply PMF range limiting
            if limit_pmf_range:
                max_pmf_value_calc = max_pmf_value if max_pmf_value is not None else 10.0 * kT
                
                high_pmf_mask = pmf > max_pmf_value_calc
                
                if np.any(high_pmf_mask):
                    if replace_high_pmf_method == 'interpolate':
                        valid_mask = np.isfinite(pmf) & ~high_pmf_mask
                        if np.sum(valid_mask) > 2:
                            from scipy.interpolate import interp1d
                            interp_func = interp1d(z_centers[valid_mask], pmf[valid_mask], 
                                                kind='linear', fill_value='extrapolate')
                            pmf[high_pmf_mask] = interp_func(z_centers[high_pmf_mask])
                    elif replace_high_pmf_method == 'cap':
                        pmf[high_pmf_mask] = max_pmf_value_calc
                    elif replace_high_pmf_method == 'nan':
                        pmf[high_pmf_mask] = np.nan
            
            # Apply PMF shifting if requested
            if shift_pmf:
                if reference_method == 'center_zero':
                    ref_mask = (z_centers >= reference_region[0]) & (z_centers <= reference_region[1])
                    if np.any(ref_mask) and not np.all(np.isnan(pmf[ref_mask])):
                        shift_value = np.nanmean(pmf[ref_mask])
                        pmf -= shift_value
                elif reference_method == 'global_minimum':
                    if not np.all(np.isnan(pmf)):
                        shift_value = np.nanmin(pmf)
                        pmf -= shift_value
            
            return pmf
        
        # Process each ion type
        all_results = {}
        
        for ion_type in ion_types:
            print(f"\n🔍 Processing {ion_type}:")
            
            # Check if we have per-frame data for this ion type
            if not hasattr(self.results, 'per_frame_histograms'):
                raise ValueError("No per-frame data available. You must run the analysis with bootstrap data collection enabled first.")
            
            per_frame_data = self.results.per_frame_histograms
            
            # FIXED: Check the actual data structure
            if not isinstance(per_frame_data, dict) or len(per_frame_data) == 0:
                print(f"  Warning: No per-frame data available for {ion_type}, skipping...")
                continue
            
            # Check if this ion type exists in any frame
            available_frames = list(per_frame_data.keys())
            ion_found = False
            for frame_key in available_frames:
                if ion_type in per_frame_data[frame_key]:
                    ion_found = True
                    break
            
            if not ion_found:
                print(f"  Warning: No per-frame data for {ion_type}, skipping...")
                continue
            
            print(f"  Found per-frame data for {ion_type} across {len(available_frames)} frames")
            
            # Get z_centers from current analysis
            z_centers = self.z_centers.copy()
            
            # Storage for bootstrap results
            bootstrap_pmfs = []
            convergence_data = {
                'n_iterations': [],
                'mean_pmf_evolution': [],
                'std_evolution': []
            }
            
            # Main bootstrap loop with REAL resampling
            print(f"\n🔄 Running {n_bootstrap} bootstrap iterations for {ion_type}...")
            
            for i in range(n_bootstrap):
                if (i + 1) % max(1, n_bootstrap // 10) == 0:
                    print(f"  Bootstrap iteration {i+1}/{n_bootstrap}")
                
                try:
                    # Generate bootstrap sample indices
                    bootstrap_indices = generate_bootstrap_indices()
                    
                    # Calculate PMF using REAL bootstrap resampling of stored per-frame data
                    pmf_bootstrap = calculate_single_pmf_bootstrap(ion_type, bootstrap_indices)
                    
                    if pmf_bootstrap is not None and not np.all(np.isnan(pmf_bootstrap)):
                        bootstrap_pmfs.append(pmf_bootstrap)
                        
                        # Convergence monitoring
                        if len(bootstrap_pmfs) > 1:
                            current_mean = np.nanmean(bootstrap_pmfs, axis=0)
                            current_std = np.nanstd(bootstrap_pmfs, axis=0)
                            
                            convergence_data['n_iterations'].append(len(bootstrap_pmfs))
                            convergence_data['mean_pmf_evolution'].append(np.nanmean(current_mean))
                            convergence_data['std_evolution'].append(np.nanmean(current_std))
                
                except Exception as e:
                    print(f"    ⚠ Bootstrap iteration {i+1} failed: {e}")
                    continue
            
            if len(bootstrap_pmfs) == 0:
                print(f"  ❌ No successful bootstrap iterations for {ion_type}")
                continue
            
            print(f"\n✓ Bootstrap iterations complete for {ion_type}")
            print(f"  Successful iterations: {len(bootstrap_pmfs)}/{n_bootstrap}")
            
            # Convert to numpy array for analysis
            bootstrap_pmfs = np.array(bootstrap_pmfs)
            
            # Calculate statistics
            mean_pmf = np.nanmean(bootstrap_pmfs, axis=0)
            pmf_std = np.nanstd(bootstrap_pmfs, axis=0)
            
            # Calculate confidence intervals - Multiple CI support
            if using_multiple_ci:
                # Multiple confidence intervals
                ci_results = {}
                for cl in confidence_levels:
                    alpha = 1 - cl
                    lower_percentile = (alpha / 2) * 100
                    upper_percentile = (1 - alpha / 2) * 100
                    
                    ci_lower = np.nanpercentile(bootstrap_pmfs, lower_percentile, axis=0)
                    ci_upper = np.nanpercentile(bootstrap_pmfs, upper_percentile, axis=0)
                    
                    ci_results[cl] = {
                        'lower': ci_lower,
                        'upper': ci_upper
                    }
                
                confidence_intervals = ci_results
            else:
                # Single confidence interval (backward compatibility)
                cl = confidence_levels[0]
                alpha = 1 - cl
                lower_percentile = (alpha / 2) * 100
                upper_percentile = (1 - alpha / 2) * 100
                
                ci_lower = np.nanpercentile(bootstrap_pmfs, lower_percentile, axis=0)
                ci_upper = np.nanpercentile(bootstrap_pmfs, upper_percentile, axis=0)
                
                confidence_intervals = {
                    'lower': ci_lower,
                    'upper': ci_upper,
                    'confidence_level': cl
                }
            
            # Calculate original PMF for comparison
            original_density = self.results.ion_densities_by_type[ion_type].copy()
            original_pmf = calculate_single_pmf_bootstrap(ion_type, np.arange(len(available_frames)))
            
            # Analyze features and flag potential noise
            valid_mask = np.isfinite(mean_pmf)
            noise_flags = np.zeros(len(mean_pmf), dtype=bool)
            
            if flag_noise and np.any(valid_mask):
                # Flag features in noise region
                noise_mask = (z_centers >= noise_region[0]) & (z_centers <= noise_region[1])
                
                if np.any(noise_mask):
                    # Find local maxima and minima in noise region
                    from scipy.signal import find_peaks
                    
                    pmf_noise_region = mean_pmf[noise_mask & valid_mask]
                    z_noise_region = z_centers[noise_mask & valid_mask]
                    
                    if len(pmf_noise_region) > 3:
                        # Find peaks (barriers) and valleys (binding sites)
                        peaks, _ = find_peaks(pmf_noise_region, prominence=0.5*kT)
                        valleys, _ = find_peaks(-pmf_noise_region, prominence=0.5*kT)
                        
                        n_features = len(peaks) + len(valleys)
                        
                        if n_features > 0:
                            print(f"    ⚠ Potential noise detected in {noise_region} Å region:")
                            print(f"      Found {n_features} features (peaks: {len(peaks)}, valleys: {len(valleys)})")
                            print(f"      Consider smoothing or increasing statistics")
                            
                            # Flag the noise region
                            noise_flags[noise_mask] = True
            
            # Bootstrap convergence check
            if len(convergence_data['n_iterations']) > 1:
                # Check if standard deviation has stabilized
                std_evolution = np.array(convergence_data['std_evolution'])
                if len(std_evolution) >= 3:
                    recent_std_change = np.abs(std_evolution[-1] - std_evolution[-3])
                    avg_std = np.mean(std_evolution[-3:], axis=0)
                    relative_change = np.nanmean(recent_std_change / (avg_std + 1e-10))
                    converged = relative_change < 0.05  # 5% convergence criterion
                else:
                    converged = False
            else:
                converged = False
            
            # Compile results (using CORRECT KEY NAMES expected by plotting method)
            ion_results = {
                # Core PMF data (CORRECT KEYS - matches what plotting method expects)
                'mean_pmf': mean_pmf,  # ✅ CORRECT - plotting method expects this key
                'pmf_std': pmf_std,    # ✅ CORRECT - plotting method expects this key
                'confidence_intervals': confidence_intervals,  # Multiple or single CI support
                'z_centers': z_centers.copy(),  # Matches calculate_pmf_vs_z
                'units': unit_label,  # Matches calculate_pmf_vs_z
                'temperature': temperature,  # Matches calculate_pmf_vs_z
                'kT_value': kT,  # Matches calculate_pmf_vs_z
                
                # Bootstrap-specific data
                'original_pmf': original_pmf,
                'bootstrap_pmfs': bootstrap_pmfs if save_bootstrap_data else None,
                'n_bootstrap': n_bootstrap,
                'bootstrap_method': 'block' if block_resampling else 'simple',
                'block_size': block_size if block_resampling else None,
                
                # Method parameters (matches calculate_pmf_vs_z structure)
                'reference_method': reference_method,
                'reference_region': reference_region,
                'bulk_region_z': bulk_region_z,
                'smoothed': smoothing,
                'smoothing_method': smoothing_method if smoothing else None,
                'gaussian_sigma': gaussian_sigma if smoothing else None,
                'shifted': shift_pmf,
                
                # Additional parameters from calculate_pmf_vs_z
                'symmetrized': symmetrize,
                'symmetrize_method': symmetrize_method if symmetrize else None,
                'noise_region': noise_region,
                'noise_flags': noise_flags,
                'potential_noise_detected': np.any(noise_flags),
                
                # PMF range limiting parameters
                'limit_pmf_range': limit_pmf_range,
                'max_pmf_value': max_pmf_value,
                'density_cutoff_method': density_cutoff_method if limit_pmf_range else None,
                'density_cutoff_value': density_cutoff_value if limit_pmf_range else None,
                'replace_high_pmf_method': replace_high_pmf_method if limit_pmf_range else None,
                
                # Multiple confidence levels metadata
                'using_multiple_ci': using_multiple_ci,
                'confidence_levels_used': confidence_levels,
                
                # Statistics (matches calculate_pmf_vs_z structure)
                'statistics': {
                    'min_pmf': np.nanmin(mean_pmf),
                    'max_pmf': np.nanmax(mean_pmf),
                    'pmf_range': np.nanmax(mean_pmf) - np.nanmin(mean_pmf),
                    'mean_uncertainty': np.nanmean(pmf_std),
                    'max_uncertainty': np.nanmax(pmf_std),
                    'mean_ci_width': np.nanmean(list(confidence_intervals.values())[0]['upper'] - list(confidence_intervals.values())[0]['lower']) if using_multiple_ci else np.nanmean(confidence_intervals['upper'] - confidence_intervals['lower'])
                },
                
                # Convergence analysis
                'convergence_check': {
                    'converged': converged,
                    'convergence_data': convergence_data,
                    'n_iterations_for_convergence': convergence_data['n_iterations'][-1] if convergence_data['n_iterations'] else n_bootstrap
                },
                
                # Quality indicators
                'valid_data_fraction': np.sum(np.isfinite(mean_pmf)) / len(mean_pmf),
                'uncertainty_flags': {
                    'high_uncertainty_regions': pmf_std > np.nanmean(pmf_std) + 2*np.nanstd(pmf_std),
                    'low_sampling_regions': pmf_std > kT,  # Uncertainty > kT indicates poor sampling
                }
            }
            
            # Save bootstrap data if requested
            if save_bootstrap_data:
                if bootstrap_filename is None:
                    bootstrap_filename = f'bootstrap_pmf_{ion_type}_{n_bootstrap}iter_{units}.npz'
                else:
                    # Add ion type to filename if multiple ions
                    if len(ion_types) > 1:
                        name, ext = os.path.splitext(bootstrap_filename)
                        bootstrap_filename = f'{name}_{ion_type}{ext}'
                
                print(f"💾 Saving bootstrap data for {ion_type}: {bootstrap_filename}")
                try:
                    np.savez(bootstrap_filename,
                            bootstrap_pmfs=bootstrap_pmfs,
                            mean_pmf=mean_pmf,
                            pmf_std=pmf_std,
                            confidence_intervals=confidence_intervals,
                            z_centers=z_centers,
                            parameters=ion_results)
                    print(f"✓ Bootstrap data saved successfully")
                except Exception as e:
                    print(f"⚠ Warning: Could not save bootstrap data: {e}")
            
            # Store results for this ion type
            all_results[ion_type] = ion_results
            
            # Print uncertainty statistics for this ion
            valid_mask = np.isfinite(mean_pmf) & np.isfinite(pmf_std)
            if np.any(valid_mask):
                print(f"\nUncertainty Statistics for {ion_type}:")
                print(f"  Mean PMF range: {np.nanmin(mean_pmf):.3f} to {np.nanmax(mean_pmf):.3f} {unit_label}")
                print(f"  Average uncertainty: {np.nanmean(pmf_std[valid_mask]):.3f} {unit_label}")
                print(f"  Maximum uncertainty: {np.nanmax(pmf_std):.3f} {unit_label}")
                
                # Print CI information
                if using_multiple_ci:
                    for cl in confidence_levels:
                        ci_lower = confidence_intervals[cl]['lower']
                        ci_upper = confidence_intervals[cl]['upper']
                        mean_ci_width = np.nanmean((ci_upper - ci_lower)[valid_mask])
                        print(f"  Mean CI width ({cl*100:.0f}%): {mean_ci_width:.3f} {unit_label}")
                else:
                    ci_lower = confidence_intervals['lower']
                    ci_upper = confidence_intervals['upper']
                    mean_ci_width = np.nanmean((ci_upper - ci_lower)[valid_mask])
                    print(f"  Mean CI width: {mean_ci_width:.3f} {unit_label}")
                
                # Reliability assessment
                reliable_points = np.sum(pmf_std[valid_mask] < kT)
                total_points = np.sum(valid_mask)
                reliability = reliable_points / total_points * 100
                print(f"  Reliability: {reliability:.1f}% of points have uncertainty < 1 kT")
            
            if not converged:
                print(f"\n⚠ Bootstrap for {ion_type} may not have converged. Consider increasing n_bootstrap.")
        
        print(f"\n{'='*70}")
        print(f"✅ BOOTSTRAP PMF UNCERTAINTY COMPLETE")
        print(f"{'='*70}")
        print(f"Ion types analyzed: {len(ion_types)}")
        print(f"Units: {unit_label}")
        print(f"Temperature: {temperature:.1f} K")
        print(f"Bootstrap method: {'Block resampling' if block_resampling else 'Simple resampling'}")
        print(f"Iterations: {n_bootstrap}")
        
        # Print CI information
        if using_multiple_ci:
            print(f"Confidence intervals: {[f'{cl*100:.0f}%' for cl in confidence_levels]}")
        else:
            print(f"Confidence interval: {confidence_levels[0]*100:.0f}%")
        
        # Print additional features
        if symmetrize:
            print(f"Symmetrization: {symmetrize_method}")
        if flag_noise:
            noise_detected = any(result['potential_noise_detected'] for result in all_results.values())
            print(f"Noise detection: {'Potential noise found' if noise_detected else 'No obvious noise'}")
        
        # Return results - single dict if one ion, multi-dict if multiple ions
        if len(ion_types) == 1:
            return all_results[ion_types[0]]
        else:
            return all_results

        
