    def calculate_electrostatic_potential_spatial_distribution_xy(self,
                                                            z_slice_centers=None,
                                                            z_slice_width=2.0,
                                                            xy_grid_size=0.5,
                                                            step=1,
                                                            charge_dict=None,
                                                            potential_calculation_method='point_charges',
                                                            use_ion_radii=False,
                                                            ion_vdw_radii=None,
                                                            gaussian_smoothing=True,
                                                            smoothing_sigma=None,
                                                            dielectric_screening=True,
                                                            relative_permittivity=78.0,
                                                            vacuum_permittivity=8.854e-12,
                                                            potential_units='relative',
                                                            cutoff_distance=15.0,
                                                            use_cache=True,
                                                            cache_filename=None,
                                                            max_frames=None,
                                                            return_negative_potential=True,
                                                            histogram_heights=True,
                                                            return_surface_peaks=False,
                                                            surface_peak_method='global_max'):
        """
        Calculate electrostatic potential spatial distribution in XY plane at different Z-slices
        with support for 3D histogram visualization showing negative potential intensity.
        
        This method follows the same design pattern as calculate_ion_spatial_distribution_xy(),
        calculate_clay_spatial_distribution_xy(), and calculate_water_dipole_orientation_xy().
        
        Parameters
        ----------
        z_slice_centers : array-like, optional
            Z-positions for slice centers. If None, uses default range.
        z_slice_width : float, default=2.0
            Width of each z-slice (Å)
        xy_grid_size : float, default=0.5
            Grid spacing in XY plane (Å)
        step : int, default=1
            Frame sampling interval
        charge_dict : dict, optional
            Ion charges. If None, uses default values:
            {'NA': 1.0, 'CL': -1.0, 'MG': 2.0, 'CA': 2.0, 'K': 1.0, 'BR': -1.0, 'F': -1.0, 'I': -1.0}
        potential_calculation_method : str, default='point_charges'
            Method for potential calculation:
            - 'point_charges': Simple Coulomb potential from point charges
            - 'gaussian_charges': Charges distributed with Gaussian shape
            - 'vdw_distributed': Charges distributed over VdW radius
        use_ion_radii : bool, default=False
            If True, distribute charge over ionic VdW radius instead of point charges
        ion_vdw_radii : dict, optional
            VdW radii for ions (Å). If None, uses default values
        gaussian_smoothing : bool, default=True
            Apply Gaussian smoothing to final potential grids
        smoothing_sigma : float, optional
            Gaussian smoothing parameter. If None, uses xy_grid_size
        dielectric_screening : bool, default=True
            Include dielectric screening effects from water
        relative_permittivity : float, default=78.0
            Relative permittivity of water for screening
        vacuum_permittivity : float, default=8.854e-12
            Vacuum permittivity (F/m)
        potential_units : str, default='relative'
            Units for potential:
            - 'relative': Relative units (arbitrary)
            - 'volts': Actual voltage units
            - 'kj_mol': kJ/mol units
        cutoff_distance : float, default=15.0
            Cutoff distance for potential calculation (Å)
        use_cache : bool, default=True
            Whether to use cached data if available
        cache_filename : str
            Name of cache file
        max_frames : int, optional
            Maximum number of frames to analyze
        return_negative_potential : bool, default=True
            If True, returns negative potential for histogram visualization
            (higher bars = more negative potential = stronger negative charge)
        histogram_heights : bool, default=True
            If True, prepare data for 3D histogram bars where height = potential intensity
        return_surface_peaks : bool, default=False
            If True, extract peak heights from grids to create surface data
        surface_peak_method : str, default='global_max'
            Method for extracting surface peaks:
            - 'global_max': Maximum value across all z-slices per XY position
        
        Returns
        -------
        dict
            Results containing potential grids for each z-slice with consistent coordinates
            Format similar to other XY spatial distribution methods:
            {
                'z_slice_centers': array of z positions
                'x_centers': x-coordinate centers for grids
                'y_centers': y-coordinate centers for grids  
                'x_edges': x-coordinate edges
                'y_edges': y-coordinate edges
                'box_dimensions': (box_x, box_y)
                'grid_dimensions': (n_x, n_y)
                'z_slices': [
                    {
                        'potential_grid': 2D array of electrostatic potential
                        'negative_potential_grid': 2D array of negative potential (for histograms)
                        'charge_density_grid': 2D array of charge density
                        'z_center': z position of slice
                        'n_frames': number of frames processed
                        # ... other metadata
                    }
                ]
                'surface_peaks': dict (if return_surface_peaks=True)
                    {
                        'peak_surface': 2D array of peak heights
                        'z_peak_positions': 2D array of z-positions where peaks occur
                        'X_grid': meshgrid X coordinates
                        'Y_grid': meshgrid Y coordinates
                        'method': surface extraction method used
                    }
            }
        """
        
        print(f"\n{'='*70}")
        print(f"ELECTROSTATIC POTENTIAL XY SPATIAL DISTRIBUTION")
        print(f"{'='*70}")
        print(f"Method: {potential_calculation_method}")
        print(f"Z-slice width: {z_slice_width:.2f} Å")
        print(f"XY grid size: {xy_grid_size:.2f} Å")
        print(f"Frame sampling: every {step} frame(s)")
        
        if return_negative_potential:
            print(f"Output: Negative potential for 3D histogram visualization")
            print(f"  → Higher bars = more negative potential = stronger negative charge")
        
        if return_surface_peaks:
            print(f"Surface peaks: ENABLED ({surface_peak_method})")
            print(f"  → Memory-efficient surface extraction from peak heights")
        
        # Set up default charge dictionary
        if charge_dict is None:
            charge_dict = {
                'NA': 1.0, 'CL': -1.0, 'MG': 2.0, 'CA': 2.0, 
                'K': 1.0, 'BR': -1.0, 'F': -1.0, 'I': -1.0
            }
        
        # Set up default VdW radii if needed
        if use_ion_radii and ion_vdw_radii is None:
            ion_vdw_radii = {
                'NA': 1.02, 'K': 1.38, 'MG': 0.72, 'CA': 1.00,
                'CL': 1.81, 'BR': 1.96, 'I': 2.20, 'F': 1.47
            }
        
        print(f"Ion charges: {charge_dict}")
        if use_ion_radii:
            print(f"Using ionic VdW radii: {ion_vdw_radii}")
        if dielectric_screening:
            print(f"Dielectric screening: ε_r = {relative_permittivity}")
        
        # Auto-derive cache filename from key parameters to prevent collisions
        if cache_filename is None:
            import hashlib, json as _json
            _zc = [float(z) for z in z_slice_centers] if z_slice_centers is not None else None
            _cache_key = _json.dumps({
                'z_slice_centers': _zc,
                'z_slice_width': z_slice_width,
                'xy_grid_size': xy_grid_size,
                'potential_calculation_method': potential_calculation_method,
                'use_ion_radii': use_ion_radii,
                'dielectric_screening': dielectric_screening,
                'relative_permittivity': relative_permittivity,
                'cutoff_distance': cutoff_distance,
            }, sort_keys=True)
            _hash = hashlib.md5(_cache_key.encode()).hexdigest()[:8]
            cache_filename = f'electrostatic_potential_xy_cache_{_hash}.npz'

        # Check cache
        cache_exists = os.path.exists(cache_filename)
        
        if use_cache and cache_exists:
            print(f"\n📦 Loading from cache: {cache_filename}")
            try:
                cache_data = np.load(cache_filename, allow_pickle=True)
                
                # Verify cache parameters match
                cached_params = cache_data['parameters'].item()
                params_match = (
                    np.array_equal(cached_params.get('z_slice_centers', []), z_slice_centers or []) and
                    cached_params.get('z_slice_width') == z_slice_width and
                    cached_params.get('xy_grid_size') == xy_grid_size and
                    cached_params.get('potential_calculation_method') == potential_calculation_method and
                    cached_params.get('use_ion_radii') == use_ion_radii
                )
                
                if params_match:
                    print("✓ Cache parameters match - loading cached data")
                    results = cache_data['results'].item()
                    
                    # Add surface peaks if requested and not in cache
                    if return_surface_peaks and 'surface_peaks' not in results:
                        print("  → Extracting surface peaks from cached data...")
                        results = self._add_surface_peaks_to_results(results, surface_peak_method)
                    
                    self.results.electrostatic_potential_xy = results
                    return results
                else:
                    print("⚠ Cache parameters don't match - recalculating")
            except Exception as e:
                print(f"⚠ Error loading cache: {e} - recalculating")
        
        # Determine z-slice centers (same logic as other methods)
        if z_slice_centers is None:
            print("\n🔍 Auto-detecting z-slice positions...")
            
            if hasattr(self.results, 'clay_interface_boundaries') and self.results.clay_interface_boundaries:
                boundaries = self.results.clay_interface_boundaries
                z_slice_centers = []
                
                print("  Using clay boundaries for slice positioning")
                
                for boundary_type in ['si_average_z_positive', 'si_average_z_negative',
                                    'mgo_average_z_positive', 'mgo_average_z_negative']:
                    if boundary_type in boundaries and boundaries[boundary_type] is not None:
                        z_val = boundaries[boundary_type]
                        for offset in [2, 5]:
                            if 'positive' in boundary_type:
                                z_slice_centers.append(z_val - offset)
                            else:
                                z_slice_centers.append(z_val + offset)
                
                z_slice_centers.append(0.0)
                z_slice_centers = sorted(list(set(z_slice_centers)))
            else:
                print("  No clay boundaries available - using z-range from system")
                z_min = self.z_min if hasattr(self, 'z_min') else -30
                z_max = self.z_max if hasattr(self, 'z_max') else 30
                n_slices = 7
                z_slice_centers = np.linspace(z_min + 5, z_max - 5, n_slices).tolist()
        
        z_slice_centers = np.array(z_slice_centers) if isinstance(z_slice_centers, list) else z_slice_centers
        print(f"\n🎯 Z-slice centers ({len(z_slice_centers)}): {[f'{z:.1f}' for z in z_slice_centers]}")
        
        # Get box dimensions and create CONSISTENT XY grids (same as other methods)
        box_x, box_y = self.universe.dimensions[0], self.universe.dimensions[1]
        
        # CRITICAL: Ensure grid covers EXACT box dimensions
        n_x = int(np.ceil(box_x / xy_grid_size))
        n_y = int(np.ceil(box_y / xy_grid_size))
        
        # Create coordinate arrays that EXACTLY match the grid dimensions
        x_edges = np.linspace(0, box_x, n_x + 1)
        y_edges = np.linspace(0, box_y, n_y + 1)
        
        # Grid centers for plotting - these MUST match the grid array indices
        x_centers = (x_edges[:-1] + x_edges[1:]) / 2
        y_centers = (y_edges[:-1] + y_edges[1:]) / 2
        
        # Create meshgrids for distance calculations
        X_grid, Y_grid = np.meshgrid(x_centers, y_centers)
        
        print(f"\n📐 Grid setup:")
        print(f"  XY box: {box_x:.2f} × {box_y:.2f} Å")
        print(f"  Grid dimensions: {n_x} × {n_y} bins")
        print(f"  X edges: {x_edges[0]:.2f} to {x_edges[-1]:.2f} Å")
        print(f"  Y edges: {y_edges[0]:.2f} to {y_edges[-1]:.2f} Å")
        
        # Initialize results storage with CONSISTENT coordinates (same pattern as other methods)
        results = {
            'z_slice_centers': z_slice_centers,
            'z_slice_width': z_slice_width,
            'x_centers': x_centers,
            'y_centers': y_centers,
            'x_edges': x_edges,
            'y_edges': y_edges,
            'box_dimensions': (box_x, box_y),
            'grid_dimensions': (n_x, n_y),
            'potential_calculation_method': potential_calculation_method,
            'xy_grid_size': xy_grid_size,
            'charge_dict': charge_dict,
            'use_ion_radii': use_ion_radii,
            'ion_vdw_radii': ion_vdw_radii if use_ion_radii else None,
            'dielectric_screening': dielectric_screening,
            'relative_permittivity': relative_permittivity,
            'potential_units': potential_units,
            'return_negative_potential': return_negative_potential,
            'histogram_heights': histogram_heights,
            'return_surface_peaks': return_surface_peaks,
            'surface_peak_method': surface_peak_method,
            'z_slices': []
        }
        
        # Set up smoothing parameters
        if smoothing_sigma is None:
            smoothing_sigma = xy_grid_size
        
        # Physical constants for potential calculation
        if potential_units == 'volts':
            # Coulomb constant in SI units
            k_coulomb = 1.0 / (4.0 * np.pi * vacuum_permittivity)
            if dielectric_screening:
                k_coulomb /= relative_permittivity
            unit_conversion = 1.602e-19  # Convert elementary charge to Coulombs
        else:
            # Use relative units
            k_coulomb = 1.0
            unit_conversion = 1.0
        
        # Get z-offset for centering
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Helper function: Calculate potential contribution from ion
        def calculate_ion_potential_contribution(ion_pos, ion_charge, grid_x, grid_y):
            """Calculate potential contribution from a single ion"""
            x, y = ion_pos[0], ion_pos[1]
            
            # Apply periodic boundary conditions
            x = x % box_x
            y = y % box_y
            
            if use_ion_radii:
                # Distribute charge over VdW radius
                ion_type = None
                for itype in charge_dict.keys():
                    if abs(ion_charge - charge_dict[itype]) < 0.1:
                        ion_type = itype
                        break
                
                if ion_type and ion_type in ion_vdw_radii:
                    radius = ion_vdw_radii[ion_type]
                    
                    # Calculate distances to all grid points
                    dx = grid_x - x
                    dy = grid_y - y
                    
                    # Apply periodic boundary conditions
                    dx = np.where(dx > box_x/2, dx - box_x, dx)
                    dx = np.where(dx < -box_x/2, dx + box_x, dx)
                    dy = np.where(dy > box_y/2, dy - box_y, dy)
                    dy = np.where(dy < -box_y/2, dy + box_y, dy)
                    
                    distances = np.sqrt(dx**2 + dy**2)
                    
                    if potential_calculation_method == 'gaussian_charges':
                        # Gaussian charge distribution
                        sigma = radius / 2.0
                        charge_density = np.exp(-0.5 * (distances / sigma)**2)
                        charge_density /= np.sum(charge_density)  # Normalize
                        
                        # Calculate potential (simplified)
                        potential_contrib = k_coulomb * ion_charge * unit_conversion * charge_density / (distances + 0.1)
                    
                    elif potential_calculation_method == 'vdw_distributed':
                        # Uniform charge distribution within VdW radius
                        mask = distances <= radius
                        potential_contrib = np.zeros_like(distances)
                        
                        if np.any(mask):
                            # Uniform distribution within VdW sphere
                            n_points = np.sum(mask)
                            charge_per_point = ion_charge / n_points
                            potential_contrib[mask] = k_coulomb * charge_per_point * unit_conversion / (distances[mask] + 0.1)
                    
                    else:  # point_charges with radius effects
                        potential_contrib = k_coulomb * ion_charge * unit_conversion / (distances + 0.1)
                
                else:
                    # Fallback to point charge
                    dx = grid_x - x
                    dy = grid_y - y
                    dx = dx - box_x * np.round(dx / box_x)
                    dy = dy - box_y * np.round(dy / box_y)
                    distances = np.sqrt(dx**2 + dy**2)
                    potential_contrib = k_coulomb * ion_charge * unit_conversion / (distances + 0.1)
            
            else:
                # Point charge calculation
                dx = grid_x - x
                dy = grid_y - y
                
                # Apply periodic boundary conditions
                dx = dx - box_x * np.round(dx / box_x)
                dy = dy - box_y * np.round(dy / box_y)
                
                distances = np.sqrt(dx**2 + dy**2)
                
                # Avoid division by zero and apply cutoff
                distances = np.maximum(distances, 0.1)  # Minimum distance
                cutoff_mask = distances <= cutoff_distance
                
                potential_contrib = np.zeros_like(distances)
                potential_contrib[cutoff_mask] = k_coulomb * ion_charge * unit_conversion / distances[cutoff_mask]
            
            return potential_contrib
        
        # Process each z-slice
        for z_idx, z_center in enumerate(z_slice_centers):
            print(f"\n🔍 Processing z-slice {z_idx + 1}/{len(z_slice_centers)}: z = {z_center:.2f} Å...")
            
            z_min_slice = z_center - z_slice_width / 2
            z_max_slice = z_center + z_slice_width / 2
            
            # Initialize grids with EXACT dimensions matching coordinates
            potential_grid = np.zeros((n_y, n_x))  # Note: (y, x) for image convention
            charge_density_grid = np.zeros((n_y, n_x))
            
            frame_count = 0
            
            # Loop through trajectory with frame limit
            for ts in self.universe.trajectory[::step]:
                if max_frames is not None and frame_count >= max_frames:
                    break
                
                # Process each ion type
                for ion_type, ion_group in {**self.cation_types, **self.anion_types}.items():
                    if len(ion_group) == 0:
                        continue
                    
                    # Get charge for this ion type
                    ion_charge = None
                    for charge_key, charge_val in charge_dict.items():
                        if charge_key.upper() in ion_type.upper() or ion_type.upper() in charge_key.upper():
                            ion_charge = charge_val
                            break
                    
                    if ion_charge is None:
                        continue
                    
                    # Get ion positions
                    ion_positions = ion_group.positions
                    z_positions = ion_positions[:, 2] - z_offset
                    
                    # Select ions in z-slice
                    in_slice = (z_positions >= z_min_slice) & (z_positions < z_max_slice)
                    
                    if not np.any(in_slice):
                        continue
                    
                    ions_in_slice = ion_positions[in_slice]
                    
                    # Calculate potential contribution from each ion in slice
                    for ion_pos in ions_in_slice:
                        potential_contrib = calculate_ion_potential_contribution(
                            ion_pos, ion_charge, X_grid, Y_grid
                        )
                        potential_grid += potential_contrib
                        
                        # Also calculate charge density
                        x, y = ion_pos[0] % box_x, ion_pos[1] % box_y
                        
                        if use_ion_radii and ion_type in ion_vdw_radii:
                            # Distribute charge over radius
                            radius = ion_vdw_radii[ion_type]
                            dx = X_grid - x
                            dy = Y_grid - y
                            dx = dx - box_x * np.round(dx / box_x)
                            dy = dy - box_y * np.round(dy / box_y)
                            distances = np.sqrt(dx**2 + dy**2)
                            
                            charge_contrib = np.zeros_like(distances)
                            mask = distances <= radius
                            if np.any(mask):
                                charge_contrib[mask] = ion_charge / np.sum(mask)
                            
                            charge_density_grid += charge_contrib
                        else:
                            # Point charge
                            x_idx = np.digitize(x, x_edges) - 1
                            y_idx = np.digitize(y, y_edges) - 1
                            
                            x_idx = np.clip(x_idx, 0, n_x - 1)
                            y_idx = np.clip(y_idx, 0, n_y - 1)
                            
                            charge_density_grid[y_idx, x_idx] += ion_charge
                
                frame_count += 1
            
            print(f"  ✓ Analyzed {frame_count} frames")
            
            # Average over frames
            if frame_count > 0:
                potential_grid /= frame_count
                charge_density_grid /= frame_count
            
            # Apply Gaussian smoothing if requested
            if gaussian_smoothing:
                from scipy.ndimage import gaussian_filter
                potential_grid = gaussian_filter(potential_grid, sigma=smoothing_sigma)
            
            # Normalize potential to have zero mean (remove arbitrary constant)
            potential_grid -= np.mean(potential_grid)
            
            # Create negative potential grid for histogram visualization
            if return_negative_potential:
                negative_potential_grid = -potential_grid
                # Ensure all values are positive for histogram heights
                negative_potential_grid -= np.min(negative_potential_grid)
            else:
                negative_potential_grid = potential_grid.copy()
            
            # Store slice data
            slice_data = {
                'potential_grid': potential_grid,
                'negative_potential_grid': negative_potential_grid,
                'charge_density_grid': charge_density_grid,
                'x_centers': x_centers,
                'y_centers': y_centers,
                'x_edges': x_edges,
                'y_edges': y_edges,
                'z_center': z_center,
                'z_slice_width': z_slice_width,
                'n_frames': frame_count,
                'box_dimensions': (box_x, box_y),
                'grid_dimensions': (n_x, n_y),
                'potential_calculation_method': potential_calculation_method,
                'potential_units': potential_units,
                'dielectric_screening': dielectric_screening,
                'cutoff_distance': cutoff_distance
            }
            
            print(f"  📊 Statistics:")
            print(f"    Potential range: {np.min(potential_grid):.3f} to {np.max(potential_grid):.3f}")
            if return_negative_potential:
                print(f"    Negative potential range: {np.min(negative_potential_grid):.3f} to {np.max(negative_potential_grid):.3f}")
            print(f"    Charge density range: {np.min(charge_density_grid):.3f} to {np.max(charge_density_grid):.3f}")
            
            results['z_slices'].append(slice_data)
        
        # Extract surface peaks if requested
        if return_surface_peaks:
            print(f"\n🏔️ Extracting surface peaks using {surface_peak_method} method...")
            results = self._add_surface_peaks_to_results(results, surface_peak_method)
        
        # Store results
        self.results.electrostatic_potential_xy = results
        
        # Save cache
        print(f"\n💾 Saving to cache: {cache_filename}")
        try:
            np.savez(cache_filename,
                    parameters={'z_slice_centers': z_slice_centers,
                            'z_slice_width': z_slice_width,
                            'xy_grid_size': xy_grid_size,
                            'potential_calculation_method': potential_calculation_method,
                            'use_ion_radii': use_ion_radii,
                            'charge_dict': charge_dict,
                            'dielectric_screening': dielectric_screening,
                            'relative_permittivity': relative_permittivity,
                            'return_surface_peaks': return_surface_peaks,
                            'surface_peak_method': surface_peak_method},
                    results=results)
            print("✓ Cache saved successfully")
        except Exception as e:
            print(f"⚠ Warning: Could not save cache: {e}")
        
        print(f"\n{'='*70}")
        print(f"ELECTROSTATIC POTENTIAL XY ANALYSIS COMPLETE")
        print(f"{'='*70}")
        print(f"✓ Electrostatic potential calculated for {len(z_slice_centers)} z-slices")
        print(f"✓ Grid dimensions: {n_x} × {n_y} bins")
        print(f"✓ Method: {potential_calculation_method}")
        if dielectric_screening:
            print(f"✓ Dielectric screening applied (ε_r = {relative_permittivity})")
        if return_negative_potential:
            print(f"✓ Negative potential prepared for 3D histogram visualization")
            print(f"  → Use 'negative_potential_grid' for bar heights")
            print(f"  → Higher bars = more negative potential = stronger negative charge accumulation")
        if return_surface_peaks:
            print(f"✓ Surface peaks extracted using {surface_peak_method} method")
            print(f"  → Memory-efficient surface data created from histogram peaks")
            print(f"  → Use results['surface_peaks'] for 3D surface plotting")
        
        return results

    def _add_surface_peaks_to_results(self, results, surface_peak_method='global_max'):
        """
        Helper method to extract surface peaks from existing results.
        
        Parameters
        ----------
        results : dict
            Existing electrostatic potential results
        surface_peak_method : str
            Method for extracting peaks ('global_max')
        
        Returns
        -------
        dict
            Results with added 'surface_peaks' key
        """
        
        if len(results['z_slices']) == 0:
            print("  ⚠ No z-slices available for surface extraction")
            return results
        
        # Get grid information from first slice
        first_slice = results['z_slices'][0]
        x_centers = first_slice['x_centers']
        y_centers = first_slice['y_centers']
        
        # Create meshgrid
        X_grid, Y_grid = np.meshgrid(x_centers, y_centers)
        
        # Initialize peak surface
        peak_surface = np.zeros_like(X_grid)
        z_peak_positions = np.zeros_like(X_grid)
        
        print(f"  Processing {len(results['z_slices'])} z-slices for surface extraction...")
        
        # Extract peaks using the specified method
        if surface_peak_method == 'global_max':
            # Find maximum across all z-slices for each XY position
            for i in range(X_grid.shape[0]):  # Y dimension
                for j in range(X_grid.shape[1]):  # X dimension
                    max_value = 0.0
                    max_z = 0.0
                    
                    # Check all z-slices for this XY position
                    for slice_data in results['z_slices']:
                        z_center = slice_data['z_center']
                        potential_grid = slice_data['negative_potential_grid']
                        
                        # Get value at this grid position
                        if i < potential_grid.shape[0] and j < potential_grid.shape[1]:
                            value = potential_grid[i, j]
                            
                            if value > max_value:
                                max_value = value
                                max_z = z_center
                    
                    peak_surface[i, j] = max_value
                    z_peak_positions[i, j] = max_z
        
        # Create surface results
        surface_peaks = {
            'peak_surface': peak_surface,
            'z_peak_positions': z_peak_positions,
            'X_grid': X_grid,
            'Y_grid': Y_grid,
            'x_centers': x_centers,
            'y_centers': y_centers,
            'method': surface_peak_method,
            'surface_shape': peak_surface.shape,
            'peak_range': (np.min(peak_surface), np.max(peak_surface)),
            'z_range': (np.min(z_peak_positions), np.max(z_peak_positions))
        }
        
        # Add to results
        results['surface_peaks'] = surface_peaks
        
        print(f"  ✅ Surface extraction complete!")
        print(f"    Peak surface range: {np.min(peak_surface):.3f} to {np.max(peak_surface):.3f}")
        print(f"    Z-position range: {np.min(z_peak_positions):.1f} to {np.max(z_peak_positions):.1f} Å")
        print(f"    Memory reduction: ~100x compared to full 3D histograms")
        
        return results



    def calculate_local_temperature_vs_z(self, mass_dict=None):
        '''Calculate local temperature profile from kinetic energy'''
        
        if mass_dict is None:
            # Default atomic masses (amu)
            mass_dict = {'O': 16.0, 'H': 1.0, 'NA': 23.0, 'CL': 35.5, 'MG': 24.3, 'CA': 40.1, 'K': 39.1}
        
        print("Calculating local temperature profile...")
        
        temperature_profile = np.zeros(self.n_bins)
        n_atoms_profile = np.zeros(self.n_bins)
        
        # Get z-offset for centering if needed
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Go to first frame to get structure
        self.universe.trajectory[0]
        
        # Calculate kinetic energy for each atom type
        for atom in self.universe.atoms:
            try:
                # Get atom mass
                atom_mass = mass_dict.get(atom.element, mass_dict.get(atom.name, 16.0))
                
                # Get z-position (with centering offset)
                atom_z = atom.position[2] - z_offset
                
                # Find which bin this atom belongs to
                bin_idx = np.digitize(atom_z, self.z_edges) - 1
                
                if 0 <= bin_idx < self.n_bins:
                    # Get velocity (if available) or use random thermal velocity
                    if hasattr(atom, 'velocity') and atom.velocity is not None:
                        v_squared = np.sum(atom.velocity**2)
                    else:
                        # Estimate from Maxwell-Boltzmann at 300K
                        kT = 2.479  # kT at 300K in kJ/mol
                        v_squared = 3 * kT / atom_mass  # <v²> = 3kT/m
                    
                    # Temperature from kinetic energy: T = mv²/(3k)
                    # Converting units appropriately
                    temp_contribution = (atom_mass * v_squared) / 3.0  # Simplified units
                    
                    temperature_profile[bin_idx] += temp_contribution
                    n_atoms_profile[bin_idx] += 1
                    
            except Exception as e:
                continue
        
        # Average temperature in each bin
        valid_bins = n_atoms_profile > 0
        temperature_profile[valid_bins] /= n_atoms_profile[valid_bins]
        
        # Normalize to reasonable temperature scale (assume bulk is ~300K)
        if np.any(valid_bins):
            bulk_temp = np.mean(temperature_profile[valid_bins])
            if bulk_temp > 0:
                temperature_profile = temperature_profile * (300.0 / bulk_temp)
        
        self.results.local_temperature = temperature_profile
        self.results.atom_count_profile = n_atoms_profile
        
        print(f"Local temperature calculated:")
        print(f"  Temperature range: {np.min(temperature_profile[valid_bins]):.1f} to {np.max(temperature_profile[valid_bins]):.1f} K")
        
        return temperature_profile


    def calculate_rdf_vs_z(self, 
                          ion_pairs=['Na-Ow', 'Mg-Ow', 'Na-Cl'],
                          r_max=12.0,
                          dr=0.1,
                          z_bin_width=5.0,
                          z_range=None,
                          auto_detect_z_range=False,
                          step=None,
                          n_frames_sample=None,
                          use_pbc=True,
                          density_mode='local',
                          save_cache=True,
                          cache_file=None,
                          force_rerun=False,
                          z_step=None,
                          debug=False):
        """
        Calculate radial distribution functions as a function of z-position.
        
        This method computes g(r,z) for ion-water and ion-ion pairs, where:
        - Reference ions are selected from each z-slice
        - Distances are calculated to ALL relevant target atoms (with PBC)
        - Proper density normalization is applied (global for water, local for ions)
        
        Parameters
        ----------
        ion_pairs : list of str
            Ion pairs to analyze. Format:
            - 'Na-Ow', 'Mg-Ow', 'Cl-Ow' for ion-water RDF
            - 'Na-Cl', 'Mg-Cl', 'Na-Na' for ion-ion RDF
        r_max : float, default=12.0
            Maximum radial distance (Å)
        dr : float, default=0.1
            Radial bin width (Å)
        z_bin_width : float, default=5.0
            Z-slice width (Å)
        z_range : tuple, optional
            (z_min, z_max) range for analysis. If None, uses self.z_min/z_max or auto-detection
        auto_detect_z_range : bool, default=False
            If True and z_range is None, automatically detect water region boundaries
            from trajectory. Useful for confined systems to avoid empty regions.
        step : int, optional
            Frame sampling interval (analyze every nth frame). If both step and n_frames_sample
            are None, defaults to step=10. Ignored if n_frames_sample is specified.
        n_frames_sample : int, optional
            Number of frames to sample evenly across trajectory (like OLD method).
            If specified, overrides step parameter.
        use_pbc : bool, default=True
            Use periodic boundary conditions for distance calculations
        density_mode : str, default='local'
            Density normalization mode for ion-water pairs:
            - 'local': Use density in each z-slice (physically correct for inhomogeneous systems)
            - 'global': Use bulk density (total waters / total volume)
            - 'water_region': Use bulk density of water-containing region only
            - 'mask_empty': Use global density but set g(r)=NaN in empty regions
            Note: Ion-ion pairs always use local density
        save_cache : bool, default=True
            Save results to cache file
        cache_file : str, optional
            Cache filename. If None, auto-generates based on parameters
        force_rerun : bool, default=False
            Force recalculation even if cache exists
        z_step : float, optional
            Option G — spacing between z-slice centres (\u00c5) for a sliding-window mode.
            When None (default), equals z_bin_width (non-overlapping, existing behaviour).
            When z_step < z_bin_width, centres are placed every z_step \u00c5 but each
            centre still collects reference ions within \u00b1z_bin_width/2, so slices
            overlap.  Statistics improve by ~z_bin_width/z_step.  The output matrix
            has more z-rows (finer z-axis) without any blurring of g(r).
            Requires force_rerun=True to take effect (changes cache filename).
        debug : bool, default=False
            Print detailed debug information
            
        Returns
        -------
        dict
            Results dictionary with structure:
            {
                'pair_name': {
                    'z_centers': array,           # Z-positions of slices
                    'r_centers': array,           # Radial bin centers
                    'rdf_matrix': array[n_z, n_r],  # g(r,z) values
                    'pair_counts': array[n_z, n_r], # Raw counts (debug)
                    'ref_ion_counts': array[n_z],   # Ions per z-slice
                    'density_used': float or array, # Normalization density
                    'pair_type': str,             # 'ion-water' or 'ion-ion'
                    'peak_info': dict,            # Peak position and value
                    'first_shell_integral': array # Coordination numbers
                },
                'metadata': {
                    'n_frames_analyzed': int,
                    'frame_indices': array,
                    'parameters': dict,
                    'box_dimensions': tuple,
                    'timestamp': str
                }
            }
            
        Notes
        -----
        **Density Normalization:**
        - Ion-water: Controlled by density_mode parameter (default: local)
        - Ion-ion: Always uses LOCAL z-slice density (nearby ions / slice volume)
        
        **Distance Calculation:**
        - Filters distances > r_max BEFORE binning to avoid out-of-bounds
        - Uses MDAnalysis distance_array() with PBC for accurate distances
        
        **Normalization Formula:**
        g(r) = (observed_pairs_per_ion) / (expected_pairs_per_ion)
             = (total_counts / total_ions) / (density * shell_volume)
        
        Examples
        --------
        >>> # Calculate ion-water RDFs
        >>> rdf_data = analysis.calculate_rdf_vs_z(
        ...     ion_pairs=['Na-Ow', 'Mg-Ow', 'Cl-Ow'],
        ...     r_max=12.0,
        ...     step=10
        ... )
        >>> 
        >>> # Access results
        >>> na_rdf = rdf_data['Na-Ow']['rdf_matrix']  # Shape: (n_z, n_r)
        >>> peak_pos = rdf_data['Na-Ow']['peak_info']['r_position']
        """
        
        # ====================================================================
        # PHASE 1: SETUP & VALIDATION
        # ====================================================================
        
        print(f"\n{'='*70}")
        print(f"RADIAL DISTRIBUTION FUNCTION vs Z-POSITION")
        print(f"{'='*70}")
        
        # Generate cache filename
        if cache_file is None:
            pairs_str = '_'.join([p.replace('-', '') for p in ion_pairs[:3]])
            _z_step_tag = float(z_step) if (z_step is not None and float(z_step) > 0) else z_bin_width
            if abs(_z_step_tag - z_bin_width) > 1e-6:
                cache_file = f'rdf_vs_z_{pairs_str}_r{r_max:.1f}_dr{dr:.2f}_z{z_bin_width:.1f}_zstep{_z_step_tag:.1f}_step{step}.pkl'
            else:
                cache_file = f'rdf_vs_z_{pairs_str}_r{r_max:.1f}_dr{dr:.2f}_z{z_bin_width:.1f}_step{step}.pkl'
        
        # Check cache
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"📦 Loading from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify parameters match
                cached_params = cached_data['metadata']['parameters']
                if (cached_params['r_max'] == r_max and
                    cached_params['dr'] == dr and
                    cached_params['z_bin_width'] == z_bin_width and
                    cached_params['step'] == step and
                    cached_params.get('z_step', None) == z_step):
                    
                    print("✓ Cache parameters match - using cached data")
                    self.results.rdf_vs_z = cached_data
                    return cached_data
                else:
                    print("⚠ Cache parameters don't match - recalculating")
            except Exception as e:
                print(f"⚠ Failed to load cache: {e} - recalculating")
        
        # Get box dimensions and z-offset early (needed for auto-detection)
        box_dims = self.universe.dimensions[:3]
        z_offset = box_dims[2] / 2 if self.center_box else 0.0
        
        # Setup z-range
        if z_range is None:
            # Auto-detect water region boundaries if requested
            if auto_detect_z_range:
                print("\n🔍 Auto-detecting water region boundaries...")
                
                # Get water oxygen atoms for detection
                water_oxygens_temp = self.universe.select_atoms('name O or name OW or name OH2')
                
                # Sample frames to find water z-range (use fewer frames for speed)
                n_total_frames = len(self.universe.trajectory)
                detection_frames = list(range(0, n_total_frames, max(step * 10, 100)))[:10]  # Max 10 frames
                
                water_z_all = []
                for frame_num in detection_frames:
                    self.universe.trajectory[frame_num]
                    water_pos = water_oxygens_temp.positions
                    # Apply z_offset immediately to get centered coordinates
                    water_z_all.extend(water_pos[:, 2] - z_offset)
                
                water_z_all = np.array(water_z_all)
                
                # Use percentiles to ignore outliers
                z_min = np.percentile(water_z_all, 1)
                z_max = np.percentile(water_z_all, 99)
                
                print(f"  ✓ Detected water region: {z_min:.1f} to {z_max:.1f} Å")
                print(f"    (Using 1st-99th percentile of centered water positions)")
            else:
                # Use default or stored z-range
                z_min = self.z_min if hasattr(self, 'z_min') else -30.0
                z_max = self.z_max if hasattr(self, 'z_max') else 30.0
        else:
            z_min, z_max = z_range
        
        # Setup bins - ensure we cover full range including upper boundary
        # Option G: z_step sets how far apart centres are; z_bin_width is the collection window
        _z_step = float(z_step) if (z_step is not None and float(z_step) > 0) else z_bin_width
        _use_sliding = (_z_step < z_bin_width - 1e-6)
        z_centers = np.arange(z_min + _z_step / 2, z_max, _z_step)
        r_bins = np.arange(0, r_max + dr, dr)
        r_centers = (r_bins[:-1] + r_bins[1:]) / 2
        n_z_bins = len(z_centers)
        n_r_bins = len(r_centers)
        
        print(f"\n📊 Configuration:")
        print(f"  Ion pairs: {', '.join(ion_pairs)}")
        print(f"  Z-range: {z_min:.1f} to {z_max:.1f} Å ({n_z_bins} bins)")
        print(f"  Z-centers: {z_centers[0]:.1f} to {z_centers[-1]:.1f} Å")
        if _use_sliding:
            print(f"  Z-bin: step {_z_step:.2f} Å, collection window {z_bin_width:.2f} Å (overlapping)")
        print(f"  R-range: 0 to {r_max:.1f} Å ({n_r_bins} bins)")
        if n_frames_sample is not None:
            print(f"  Frame sampling: {n_frames_sample} frames (linspace)")
        else:
            print(f"  Frame sampling: every {step if step else 10} frames")
        
        # Get water oxygen atoms
        try:
            water_oxygens = self.universe.select_atoms('name O or name OW or name OH2')
            print(f"  Water oxygens: {len(water_oxygens)} atoms")
        except:
            water_oxygens = None
            print(f"  ⚠ No water oxygen atoms found - ion-water RDFs will be skipped")
        
        # Validate ion selections and classify pair types
        validated_pairs = {}
        for pair in ion_pairs:
            parts = pair.split('-')
            if len(parts) != 2:
                print(f"  ⚠ Skipping invalid pair format: {pair}")
                continue
            
            ion1_type, ion2_type = parts
            
            # Check if ion-water RDF
            is_water = ion2_type.upper() in ['OW', 'O', 'WATER', 'WAT', 'H2O']
            
            if is_water:
                if water_oxygens is None:
                    print(f"  ⚠ Skipping {pair} - no water atoms")
                    continue
                pair_type = 'ion-water'
                
                # Find ion group
                ion_group = None
                for itype, igroup in {**self.cation_types, **self.anion_types}.items():
                    if ion1_type.upper() in itype.upper() or itype.upper() in ion1_type.upper():
                        ion_group = igroup
                        break
                
                if ion_group is None or len(ion_group) == 0:
                    print(f"  ⚠ Skipping {pair} - ion type not found")
                    continue
                
                validated_pairs[pair] = {
                    'type': pair_type,
                    'ion1': ion_group,
                    'ion2': water_oxygens,
                    'ion1_name': ion1_type,
                    'ion2_name': ion2_type
                }
                
            else:
                # Ion-ion RDF
                pair_type = 'ion-ion'
                
                ion1_group = None
                ion2_group = None
                for itype, igroup in {**self.cation_types, **self.anion_types}.items():
                    if ion1_type.upper() in itype.upper():
                        ion1_group = igroup
                    if ion2_type.upper() in itype.upper():
                        ion2_group = igroup
                
                if ion1_group is None or ion2_group is None:
                    print(f"  ⚠ Skipping {pair} - ion type not found")
                    continue
                if len(ion1_group) == 0 or len(ion2_group) == 0:
                    print(f"  ⚠ Skipping {pair} - no ions of this type")
                    continue
                
                validated_pairs[pair] = {
                    'type': pair_type,
                    'ion1': ion1_group,
                    'ion2': ion2_group,
                    'ion1_name': ion1_type,
                    'ion2_name': ion2_type
                }
        
        if not validated_pairs:
            raise ValueError("No valid ion pairs found!")
        
        print(f"\n✓ Validated {len(validated_pairs)} pairs:")
        for pair, info in validated_pairs.items():
            n1 = len(info['ion1'])
            n2 = len(info['ion2']) if info['type'] == 'ion-water' else len(info['ion2'])
            print(f"  {pair} ({info['type']}): {n1} × {n2} atoms")
        
        # Get box dimensions (already calculated earlier)
        box_volume = box_dims[0] * box_dims[1] * box_dims[2]
        box_xy_area = box_dims[0] * box_dims[1]
        
        print(f"\n📦 Box: {box_dims[0]:.2f} × {box_dims[1]:.2f} × {box_dims[2]:.2f} Å")
        print(f"  Volume: {box_volume:.2f} Å³")
        
        # ====================================================================
        # PHASE 2: INITIALIZE STORAGE
        # ====================================================================
        
        results = {}
        for pair in validated_pairs.keys():
            results[pair] = {
                'z_centers': z_centers.copy(),
                'r_centers': r_centers.copy(),
                'rdf_matrix': np.zeros((n_z_bins, n_r_bins)),
                'pair_counts': np.zeros((n_z_bins, n_r_bins)),
                'ref_ion_counts': np.zeros(n_z_bins),
                'density_used': None,
                'pair_type': validated_pairs[pair]['type'],
                'peak_info': {},
                'first_shell_integral': np.zeros(n_z_bins)
            }
        
        # ====================================================================
        # PHASE 3: ACCUMULATION LOOP
        # ====================================================================
        
        # Frame sampling: use linspace if n_frames_sample specified, else use step
        if n_frames_sample is not None:
            # Evenly sample n frames across trajectory (OLD method style)
            frame_indices = np.linspace(0, len(self.universe.trajectory) - 1,
                                      min(n_frames_sample, len(self.universe.trajectory)), dtype=int)
        else:
            # Use step-based sampling (default step=10 if not specified)
            if step is None:
                step = 10
            frame_indices = np.arange(0, len(self.universe.trajectory), step)
        
        n_frames = len(frame_indices)
        
        print(f"\n🔄 Processing {n_frames} frames...")
        
        for frame_idx, frame_num in enumerate(frame_indices):
            if frame_idx % max(1, n_frames // 10) == 0:
                progress = (frame_idx + 1) / n_frames * 100
                print(f"  Frame {frame_idx+1}/{n_frames} ({progress:.0f}%)", end='\r')
            
            self.universe.trajectory[frame_num]
            
            for pair, info in validated_pairs.items():
                pair_type = info['type']
                ion1_group = info['ion1']
                ion2_group = info['ion2']
                
                # Get positions
                ion1_pos = ion1_group.positions
                ion1_z = ion1_pos[:, 2] - z_offset
                
                ion2_pos = ion2_group.positions
                ion2_z = ion2_pos[:, 2] - z_offset
                
                # Bin reference ions by z
                if not _use_sliding:
                    # Fast path: non-overlapping bins, use vectorised digitize
                    ion1_z_bins = np.digitize(ion1_z, z_centers + z_bin_width / 2) - 1

                # Process each z-slice
                for z_idx in range(n_z_bins):
                    # Find reference ions in this z-slice
                    if _use_sliding:
                        # Sliding window: any ion within z_bin_width/2 of this centre
                        z_lo = z_centers[z_idx] - z_bin_width / 2
                        z_hi = z_centers[z_idx] + z_bin_width / 2
                        ions1_in_z_bin = np.where((ion1_z >= z_lo) & (ion1_z < z_hi))[0]
                    else:
                        ions1_in_z_bin = np.where(ion1_z_bins == z_idx)[0]

                    if len(ions1_in_z_bin) == 0:
                        continue
                    
                    results[pair]['ref_ion_counts'][z_idx] += len(ions1_in_z_bin)
                    
                    # Process each reference ion individually
                    for ion1_idx in ions1_in_z_bin:
                        atom1_pos = ion1_pos[ion1_idx]
                        atom1_z = ion1_z[ion1_idx]
                        
                        if pair_type == 'ion-water':
                            # For ion-water: use ALL waters
                            target_pos = ion2_pos
                            
                            # PBC only in XY direction (not Z)
                            delta = target_pos - atom1_pos
                            
                            # Apply minimum image convention in X and Y only
                            box_x, box_y = box_dims[0], box_dims[1]
                            delta[:, 0] = delta[:, 0] - box_x * np.round(delta[:, 0] / box_x)
                            delta[:, 1] = delta[:, 1] - box_y * np.round(delta[:, 1] / box_y)
                            # Z component is left as-is (no PBC)
                            
                            distances = np.linalg.norm(delta, axis=1)
                        else:
                            # For ion-ion: filter nearby ions in z
                            z_mask = np.abs(ion2_z - atom1_z) <= z_bin_width
                            
                            if not np.any(z_mask):
                                continue
                            
                            ion2_pos_nearby = ion2_pos[z_mask]
                            
                            # NO PBC for ion-ion
                            distances = np.linalg.norm(ion2_pos_nearby - atom1_pos, axis=1)
                            
                            # Exclude self-interactions
                            if info['ion1_name'] == info['ion2_name']:
                                distances = distances[distances > 0.1]
                        
                        # Bin distances
                        distance_bins = np.digitize(distances, r_bins) - 1
                        
                        # Accumulate counts
                        for r_idx in range(n_r_bins):
                            count = np.sum(distance_bins == r_idx)
                            results[pair]['pair_counts'][z_idx, r_idx] += count
        
        print(f"\n✓ Accumulation complete")
        
        # ====================================================================
        # PHASE 4: NORMALIZATION
        # ====================================================================
        
        print(f"\n🔢 Normalizing RDFs...")
        
        if debug:
            print(f"  n_z_bins = {n_z_bins}, n_frames = {n_frames}")
            print(f"  density_mode = {density_mode}")
        
        # Validate density_mode
        valid_modes = ['local', 'global', 'water_region', 'mask_empty']
        if density_mode not in valid_modes:
            raise ValueError(f"density_mode must be one of {valid_modes}, got '{density_mode}'")
        
        for pair, pair_data in results.items():
            pair_type = pair_data['pair_type']
            
            if debug:
                print(f"  Processing {pair} ({pair_type})")
            
            # Determine density
            if pair_type == 'ion-water':
                if density_mode == 'local':
                    # LOCAL: Use density in each z-slice (default, physically correct)
                    density_per_slice = np.zeros(n_z_bins)
                    
                    # Calculate average water density in each slice across all frames
                    for frame_num in frame_indices:
                        self.universe.trajectory[frame_num]
                        water_pos = water_oxygens.positions
                        water_z = water_pos[:, 2] - z_offset
                        
                        for z_idx in range(n_z_bins):
                            z_min_slice = z_centers[z_idx] - z_bin_width/2
                            z_max_slice = z_centers[z_idx] + z_bin_width/2
                            in_slice = (water_z >= z_min_slice) & (water_z < z_max_slice)
                            density_per_slice[z_idx] += np.sum(in_slice)
                    
                    # Average over frames
                    density_per_slice /= n_frames
                    slice_volume = box_xy_area * z_bin_width
                    density_per_slice /= slice_volume
                    pair_data['density_used'] = density_per_slice
                    
                    if debug:
                        print(f"    local density range = {density_per_slice.min():.6f} to {density_per_slice.max():.6f} atoms/Å³")
                
                elif density_mode == 'global':
                    # GLOBAL: Use bulk density everywhere BUT also track water presence
                    n_waters = len(water_oxygens)
                    density = n_waters / box_volume
                    pair_data['density_used'] = np.full(n_z_bins, density)
                    
                    # Calculate actual water count per slice to skip empty regions
                    water_count_per_slice = np.zeros(n_z_bins)
                    for frame_num in frame_indices:
                        self.universe.trajectory[frame_num]
                        water_pos = water_oxygens.positions
                        water_z = water_pos[:, 2] - z_offset
                        
                        for z_idx in range(n_z_bins):
                            z_min_slice = z_centers[z_idx] - z_bin_width/2
                            z_max_slice = z_centers[z_idx] + z_bin_width/2
                            in_slice = (water_z >= z_min_slice) & (water_z < z_max_slice)
                            water_count_per_slice[z_idx] += np.sum(in_slice)
                    
                    water_count_per_slice /= n_frames
                    pair_data['water_presence'] = water_count_per_slice
                    
                    if debug:
                        empty_slices = np.sum(water_count_per_slice == 0)
                        print(f"    global density = {density:.6f} atoms/Å³ ({empty_slices} slices with no water)")
                
                elif density_mode == 'water_region':
                    # WATER_REGION: Bulk density of water-containing region only
                    # Find z-range where water exists
                    water_z_all = []
                    for frame_num in frame_indices:
                        self.universe.trajectory[frame_num]
                        water_pos = water_oxygens.positions
                        water_z_all.extend(water_pos[:, 2] - z_offset)
                    
                    water_z_all = np.array(water_z_all)
                    z_min_water = water_z_all.min()
                    z_max_water = water_z_all.max()
                    water_region_volume = box_xy_area * (z_max_water - z_min_water)
                    
                    n_waters = len(water_oxygens)
                    density = n_waters / water_region_volume
                    pair_data['density_used'] = np.full(n_z_bins, density)
                    
                    # Also track water presence per slice
                    water_count_per_slice = np.zeros(n_z_bins)
                    for frame_num in frame_indices:
                        self.universe.trajectory[frame_num]
                        water_pos = water_oxygens.positions
                        water_z = water_pos[:, 2] - z_offset
                        
                        for z_idx in range(n_z_bins):
                            z_min_slice = z_centers[z_idx] - z_bin_width/2
                            z_max_slice = z_centers[z_idx] + z_bin_width/2
                            in_slice = (water_z >= z_min_slice) & (water_z < z_max_slice)
                            water_count_per_slice[z_idx] += np.sum(in_slice)
                    
                    water_count_per_slice /= n_frames
                    pair_data['water_presence'] = water_count_per_slice
                    
                    if debug:
                        empty_slices = np.sum(water_count_per_slice == 0)
                        print(f"    water region density = {density:.6f} atoms/Å³ (z: {z_min_water:.1f} to {z_max_water:.1f} Å, {empty_slices} empty slices)")
                
                elif density_mode == 'mask_empty':
                    # MASK_EMPTY: Use global density but will mask empty regions later
                    n_waters = len(water_oxygens)
                    density = n_waters / box_volume
                    pair_data['density_used'] = np.full(n_z_bins, density)
                    
                    # Also calculate which slices are empty for masking later
                    water_counts = np.zeros(n_z_bins)
                    for frame_num in frame_indices:
                        self.universe.trajectory[frame_num]
                        water_pos = water_oxygens.positions
                        water_z = water_pos[:, 2] - z_offset
                        
                        for z_idx in range(n_z_bins):
                            z_min_slice = z_centers[z_idx] - z_bin_width/2
                            z_max_slice = z_centers[z_idx] + z_bin_width/2
                            in_slice = (water_z >= z_min_slice) & (water_z < z_max_slice)
                            water_counts[z_idx] += np.sum(in_slice)
                    
                    pair_data['water_counts'] = water_counts / n_frames
                    
                    if debug:
                        empty_slices = np.sum(water_counts == 0)
                        print(f"    global density = {density:.6f} atoms/Å³ ({empty_slices} empty slices will be masked)")
            
            else:
                # Ion-ion: Use local z-slice densities from FIRST FRAME ONLY (matches OLD method)
                ion2_group = validated_pairs[pair]['ion2']
                density_per_slice = np.zeros(n_z_bins)
                
                # Calculate density in each slice from first frame only (OLD method behavior)
                self.universe.trajectory[frame_indices[0]]
                ion2_pos = ion2_group.positions
                ion2_z = ion2_pos[:, 2] - z_offset
                
                for z_idx in range(n_z_bins):
                    z_min_slice = z_centers[z_idx] - z_bin_width/2
                    z_max_slice = z_centers[z_idx] + z_bin_width/2
                    in_slice = (ion2_z >= z_min_slice) & (ion2_z < z_max_slice)
                    ion2_in_slice = np.sum(in_slice)
                    
                    if ion2_in_slice == 0:
                        density_per_slice[z_idx] = 0
                    else:
                        slice_volume = box_xy_area * z_bin_width
                        density_per_slice[z_idx] = ion2_in_slice / slice_volume
                
                pair_data['density_used'] = density_per_slice
                
                if debug:
                    print(f"  {pair}: local density range = {density_per_slice.min():.6f} to {density_per_slice.max():.6f} atoms/Å³")
            
            # Normalize each z-slice
            for z_idx in range(n_z_bins):
                total_ref_ions = pair_data['ref_ion_counts'][z_idx]
                
                if total_ref_ions == 0:
                    continue
                
                # Average ions per frame (like OLD method)
                n_ions_avg = total_ref_ions / n_frames
                
                # Get density for this slice
                current_density = pair_data['density_used'][z_idx] if isinstance(pair_data['density_used'], np.ndarray) else pair_data['density_used']
                
                # Skip normalization if no target particles in this slice
                if current_density == 0:
                    continue
                
                # For ion-water with global/water_region density: check if water actually exists
                if pair_type == 'ion-water' and density_mode in ['global', 'water_region']:
                    if 'water_presence' in pair_data and pair_data['water_presence'][z_idx] == 0:
                        # No water in this slice - skip normalization
                        continue
                
                # Normalize each r-bin
                for r_idx in range(n_r_bins):
                    total_counts = pair_data['pair_counts'][z_idx, r_idx]
                    
                    # Calculate shell volume
                    r_inner = r_bins[r_idx]
                    r_outer = r_bins[r_idx + 1]
                    shell_volume = (4/3) * np.pi * (r_outer**3 - r_inner**3)
                    
                    # Expected counts in ideal gas (OLD method formula)
                    n_ideal = current_density * shell_volume * n_ions_avg
                    
                    if n_ideal > 0:
                        # Actual counts per frame (OLD method formula)
                        n_actual = total_counts / n_frames
                        pair_data['rdf_matrix'][z_idx, r_idx] = n_actual / n_ideal
                    
                    # Debug output at specific location
                    if debug and z_idx == n_z_bins // 2 and r_idx == 20:
                        print(f"    {pair} z={z_idx}, r={r_centers[r_idx]:.2f}Å:")
                        print(f"      counts={total_counts:.0f}, ions_total={total_ref_ions:.0f}")
                        print(f"      n_actual={n_actual:.3f}, n_ideal={n_ideal:.3f}")
                        print(f"      g(r)={pair_data['rdf_matrix'][z_idx, r_idx]:.3f}")
        
        # Apply masking for mask_empty mode
        if density_mode == 'mask_empty':
            for pair, pair_data in results.items():
                if pair_data['pair_type'] == 'ion-water' and 'water_counts' in pair_data:
                    empty_mask = pair_data['water_counts'] == 0
                    pair_data['rdf_matrix'][empty_mask, :] = np.nan
                    if debug:
                        n_masked = np.sum(empty_mask)
                        print(f"  Masked {n_masked} empty z-slices for {pair}")
        
        # ====================================================================
        # PHASE 5: POST-PROCESSING & ANALYSIS
        # ====================================================================
        
        print(f"\n📈 Analyzing RDF features...")
        
        for pair, pair_data in results.items():
            rdf_matrix = pair_data['rdf_matrix']
            pair_type = pair_data['pair_type']
            
            # Find global peak (exclude small-r artifacts for ion-water)
            if pair_type == 'ion-water':
                r_min_search = 1.5  # Avoid small-r artifacts
                r_mask = r_centers >= r_min_search
                rdf_search = rdf_matrix[:, r_mask]
                r_centers_search = r_centers[r_mask]
            else:
                r_mask = np.ones(n_r_bins, dtype=bool)
                rdf_search = rdf_matrix
                r_centers_search = r_centers
            
            if np.any(rdf_search > 0):
                peak_idx_flat = np.argmax(rdf_search)
                peak_z_idx, peak_r_idx_rel = np.unravel_index(peak_idx_flat, rdf_search.shape)
                peak_r_idx = np.where(r_mask)[0][peak_r_idx_rel]
                
                pair_data['peak_info'] = {
                    'z_position': z_centers[peak_z_idx],
                    'r_position': r_centers[peak_r_idx],
                    'g_value': rdf_matrix[peak_z_idx, peak_r_idx],
                    'z_index': peak_z_idx,
                    'r_index': peak_r_idx
                }
            
            # Calculate first shell coordination numbers (integrate 0-3.5Å)
            first_shell_mask = (r_centers <= 3.5)
            for z_idx in range(n_z_bins):
                if np.any(first_shell_mask):
                    rdf_slice = rdf_matrix[z_idx, first_shell_mask]
                    r_slice = r_centers[first_shell_mask]
                    
                    # n(r) = 4πr²ρg(r)
                    # Get density for this specific z-slice
                    density = pair_data['density_used'][z_idx]
                    
                    integrand = 4 * np.pi * r_slice**2 * density * rdf_slice
                    pair_data['first_shell_integral'][z_idx] = np.trapz(integrand, r_slice)
            
            # Print summary
            avg_rdf = np.mean(rdf_matrix, axis=0)
            valid_mask = avg_rdf > 0
            
            print(f"\n  {pair} ({pair_type}):")
            if 'r_position' in pair_data['peak_info']:
                print(f"    Peak: r={pair_data['peak_info']['r_position']:.2f}Å, "
                      f"g(r)={pair_data['peak_info']['g_value']:.2f}")
            if np.any(valid_mask):
                print(f"    RDF range: {avg_rdf[valid_mask].min():.2f} to {avg_rdf[valid_mask].max():.2f}")
            
            avg_coord = np.mean(pair_data['first_shell_integral'][pair_data['first_shell_integral'] > 0])
            if not np.isnan(avg_coord):
                print(f"    Avg 1st shell coord: {avg_coord:.1f}")
        
        # ====================================================================
        # PHASE 6: SAVE & RETURN
        # ====================================================================
        
        # Add metadata
        from datetime import datetime
        results['metadata'] = {
            'n_frames_analyzed': n_frames,
            'frame_indices': frame_indices,
            'parameters': {
                'ion_pairs': ion_pairs,
                'r_max': r_max,
                'dr': dr,
                'z_bin_width': z_bin_width,
                'z_step': z_step,
                'z_range': (z_min, z_max),
                'step': step,
                'use_pbc': use_pbc
            },
            'box_dimensions': box_dims,
            'box_volume': box_volume,
            'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        
        # Save cache
        if save_cache:
            try:
                with open(cache_file, 'wb') as f:
                    pickle.dump(results, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size = os.path.getsize(cache_file) / 1024 / 1024
                print(f"\n💾 Saved to cache: {cache_file} ({file_size:.2f} MB)")
            except Exception as e:
                print(f"\n⚠ Failed to save cache: {e}")
        
        # Store in results
        self.results.rdf_vs_z = results
        
        print(f"\n{'='*70}")
        print(f"✅ RDF vs Z CALCULATION COMPLETE")
        print(f"{'='*70}")
        print(f"Pairs analyzed: {len(results) - 1}")  # -1 for metadata
        print(f"Frames: {n_frames}")
        print(f"Z-slices: {n_z_bins}")
        print(f"R-bins: {n_r_bins}")
        
        return results



