    def calculate_rdf_vs_z_detailed(self, ion_pairs=['Na-Cl', 'Na-Na', 'Cl-Cl'], 
                                r_max=15.0, dr=0.1, z_bin_width=5.0, 
                                n_frames_sample=10, force_rerun=False,
                                save_cache=True, cache_file=None):
        '''
        Calculate radial distribution functions as a function of z-position.
        Supports both ion-ion and ion-water RDFs with automatic caching.
        
        Parameters
        ----------
        ion_pairs : list
            List of ion pairs to analyze. Use format:
            - 'Na-Cl' for ion-ion RDF
            - 'Na-Ow' or 'Na-water' for ion-water RDF
        r_max : float
            Maximum distance for RDF (Å)
        dr : float
            Bin width for radial distance (Å)
        z_bin_width : float
            Bin width for z-direction (Å)
        n_frames_sample : int
            Number of frames to sample
        force_rerun : bool
            Force recalculation even if cache exists
        save_cache : bool
            If True, save results to cache file after calculation
        cache_file : str, optional
            Path to cache file. If None, auto-generates filename
        
        Returns
        -------
        dict
            Dictionary with RDF data for each ion pair vs z
        '''
        
        # Generate cache filename if not provided
        if cache_file is None:
            pairs_str = '_'.join([p.replace('-', '') for p in ion_pairs[:3]])  # First 3 pairs
            cache_file = f'rdf_vs_z_cache_{pairs_str}_rmax{r_max:.0f}_zbin{z_bin_width:.1f}.pkl'
        
        # Try to load from cache
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"Loading RDF vs z data from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify cache parameters match
                cache_params = cached_data.get('parameters', {})
                if (cache_params.get('r_max') == r_max and
                    cache_params.get('z_bin_width') == z_bin_width and
                    cache_params.get('dr') == dr):
                    
                    self.results.rdf_vs_z = cached_data['rdf_vs_z']
                    print(f"✓ Successfully loaded cached RDF vs z data")
                    print(f"  Cache created: {cached_data.get('timestamp', 'unknown')}")
                    print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                    print(f"  Ion pairs: {', '.join(cached_data.get('ion_pairs', []))}")
                    return self.results.rdf_vs_z
                else:
                    print("⚠ Cache parameters don't match, recalculating...")
            
            except Exception as e:
                print(f"⚠ Failed to load cache: {e}")
                print("Recalculating...")
        
        # If we get here, need to calculate
        print(f"\nCalculating RDF vs z for pairs: {ion_pairs}")
        
        # ... existing calculation code ...
        # (All the existing code from setup through calculation stays the same)
        
        # Setup bins
        z_layer_centers = np.arange(self.z_min + z_bin_width/2, 
                                self.z_max - z_bin_width/2, z_bin_width)
        r_bins = np.arange(0, r_max + dr, dr)
        r_centers = (r_bins[:-1] + r_bins[1:]) / 2
        n_z_bins = len(z_layer_centers)
        n_r_bins = len(r_centers)
        
        # Get water oxygen atoms
        try:
            water_oxygens = self.universe.select_atoms('name Ow or name OW')
            print(f"Found {len(water_oxygens)} water oxygen atoms")
        except:
            print("Warning: Could not find water oxygen atoms. Ion-water RDFs will be skipped.")
            water_oxygens = None
        
        # Initialize storage
        rdf_vs_z = {}
        
        for pair in ion_pairs:
            rdf_vs_z[pair] = {
                'z_centers': z_layer_centers,
                'r_centers': r_centers,
                'rdf_matrix': np.zeros((n_z_bins, n_r_bins)),
                'pair_counts': np.zeros((n_z_bins, n_r_bins)),
                'ion_counts_per_z': np.zeros(n_z_bins),
                'pair_type': 'unknown'
            }
        
        # Get z-offset for centering
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Sample frames
        frame_indices = np.linspace(0, len(self.universe.trajectory)-1, 
                                min(n_frames_sample, len(self.universe.trajectory)), dtype=int)
        
        print(f"Analyzing {len(frame_indices)} frames...")
        
        # Analyze each frame
        for frame_idx, frame_num in enumerate(frame_indices):
            if frame_idx % max(1, len(frame_indices) // 10) == 0:
                print(f"Processing frame {frame_idx+1}/{len(frame_indices)}...", end='\r')
            
            self.universe.trajectory[frame_num]
            
            # Get water positions if needed
            if water_oxygens is not None:
                water_pos = water_oxygens.positions
                water_z = water_pos[:, 2] - z_offset
            
            for pair in ion_pairs:
                ion1_type, ion2_type = pair.split('-')
                
                # Check if ion-water RDF
                is_water_rdf = ion2_type.upper() in ['OW', 'O', 'WATER', 'WAT', 'H2O']
                
                if is_water_rdf:
                    # ION-WATER RDF
                    if water_oxygens is None:
                        continue
                    
                    rdf_vs_z[pair]['pair_type'] = 'ion-water'
                    
                    # Get ion group
                    ion_atoms = None
                    for ion_type, ion_group in {**self.cation_types, **self.anion_types}.items():
                        if ion1_type.upper() in ion_type.upper() or ion_type.upper() in ion1_type.upper():
                            ion_atoms = ion_group
                            break
                    
                    if ion_atoms is None or len(ion_atoms) == 0:
                        continue
                    
                    ion_pos = ion_atoms.positions
                    ion_z = ion_pos[:, 2] - z_offset
                    ion_z_bins = np.digitize(ion_z, z_layer_centers + z_bin_width/2) - 1
                    
                    for z_idx in range(n_z_bins):
                        ions_in_z_bin = np.where(ion_z_bins == z_idx)[0]
                        
                        if len(ions_in_z_bin) == 0:
                            continue
                        
                        rdf_vs_z[pair]['ion_counts_per_z'][z_idx] += len(ions_in_z_bin)
                        
                        for ion_idx in ions_in_z_bin:
                            ion_position = ion_pos[ion_idx]
                            distances = np.linalg.norm(water_pos - ion_position, axis=1)
                            distance_bins = np.digitize(distances, r_bins) - 1
                            
                            for r_idx in range(n_r_bins):
                                count = np.sum(distance_bins == r_idx)
                                rdf_vs_z[pair]['pair_counts'][z_idx, r_idx] += count
                
                else:
                    # ION-ION RDF (existing code)
                    rdf_vs_z[pair]['pair_type'] = 'ion-ion'
                    
                    ion1_atoms = None
                    ion2_atoms = None
                    
                    for ion_type, ion_group in {**self.cation_types, **self.anion_types}.items():
                        if ion1_type.upper() in ion_type.upper():
                            ion1_atoms = ion_group
                        if ion2_type.upper() in ion_type.upper():
                            ion2_atoms = ion_group
                    
                    if ion1_atoms is None or ion2_atoms is None:
                        continue
                    if len(ion1_atoms) == 0 or len(ion2_atoms) == 0:
                        continue
                    
                    ion1_pos = ion1_atoms.positions
                    ion2_pos = ion2_atoms.positions
                    ion1_z = ion1_pos[:, 2] - z_offset
                    ion2_z = ion2_pos[:, 2] - z_offset
                    
                    ion1_z_bins = np.digitize(ion1_z, z_layer_centers + z_bin_width/2) - 1
                    
                    for z_idx in range(n_z_bins):
                        ions1_in_z_bin = np.where(ion1_z_bins == z_idx)[0]
                        
                        if len(ions1_in_z_bin) == 0:
                            continue
                        
                        rdf_vs_z[pair]['ion_counts_per_z'][z_idx] += len(ions1_in_z_bin)
                        
                        for ion1_idx in ions1_in_z_bin:
                            atom1_pos = ion1_pos[ion1_idx]
                            atom1_z = ion1_z[ion1_idx]
                            
                            z_mask = np.abs(ion2_z - atom1_z) <= z_bin_width
                            
                            if not np.any(z_mask):
                                continue
                            
                            ion2_pos_nearby = ion2_pos[z_mask]
                            distances = np.linalg.norm(ion2_pos_nearby - atom1_pos, axis=1)
                            
                            if ion1_type == ion2_type:
                                distances = distances[distances > 0.1]
                            
                            distance_bins = np.digitize(distances, r_bins) - 1
                            
                            for r_idx in range(n_r_bins):
                                count = np.sum(distance_bins == r_idx)
                                rdf_vs_z[pair]['pair_counts'][z_idx, r_idx] += count
        
        print(f"\nNormalizing RDFs...")
        
        # Normalize RDFs
        for pair in ion_pairs:
            pair_data = rdf_vs_z[pair]
            is_water_rdf = pair_data['pair_type'] == 'ion-water'
            
            for z_idx in range(n_z_bins):
                n_ions = pair_data['ion_counts_per_z'][z_idx]
                
                if n_ions == 0:
                    continue
                
                n_ions_avg = n_ions / n_frames_sample
                
                if is_water_rdf:
                    # ION-WATER NORMALIZATION
                    z_start = z_layer_centers[z_idx] - z_bin_width/2
                    z_end = z_layer_centers[z_idx] + z_bin_width/2
                    
                    if water_oxygens is not None:
                        self.universe.trajectory[frame_indices[0]]
                        water_pos = water_oxygens.positions
                        water_z = water_pos[:, 2] - z_offset
                        water_in_slice = np.sum((water_z >= z_start) & (water_z < z_end))
                    else:
                        water_in_slice = 0
                    
                    if water_in_slice == 0:
                        continue
                    
                    box_xy_area = self.universe.dimensions[0] * self.universe.dimensions[1]
                    slice_volume = box_xy_area * z_bin_width
                    water_density = water_in_slice / slice_volume
                    
                else:
                    # ION-ION NORMALIZATION
                    ion2_type = pair.split('-')[1]
                    ion2_atoms = None
                    
                    for ion_type, ion_group in {**self.cation_types, **self.anion_types}.items():
                        if ion2_type.upper() in ion_type.upper():
                            ion2_atoms = ion_group
                            break
                    
                    if ion2_atoms is None or len(ion2_atoms) == 0:
                        continue
                    
                    self.universe.trajectory[frame_indices[0]]
                    ion2_pos = ion2_atoms.positions
                    ion2_z = ion2_pos[:, 2] - z_offset
                    
                    z_start = z_layer_centers[z_idx] - z_bin_width/2
                    z_end = z_layer_centers[z_idx] + z_bin_width/2
                    
                    ion2_in_slice = np.sum((ion2_z >= z_start) & (ion2_z < z_end))
                    
                    if ion2_in_slice == 0:
                        continue
                    
                    box_xy_area = self.universe.dimensions[0] * self.universe.dimensions[1]
                    slice_volume = box_xy_area * z_bin_width
                    water_density = ion2_in_slice / slice_volume
                
                # Calculate g(r)
                for r_idx in range(n_r_bins):
                    r_inner = r_bins[r_idx]
                    r_outer = r_bins[r_idx + 1]
                    shell_volume = (4/3) * np.pi * (r_outer**3 - r_inner**3)
                    n_ideal = water_density * shell_volume * n_ions_avg
                    
                    if n_ideal > 0:
                        n_actual = pair_data['pair_counts'][z_idx, r_idx] / n_frames_sample
                        pair_data['rdf_matrix'][z_idx, r_idx] = n_actual / n_ideal
        
        # Store results
        self.results.rdf_vs_z = rdf_vs_z
        
        print(f"\n{'='*60}")
        print(f"RDF vs Z calculation complete!")
        print(f"{'='*60}")
        print(f"Analyzed pairs:")
        for pair in ion_pairs:
            pair_type = rdf_vs_z[pair]['pair_type']
            print(f"  {pair}: {pair_type}")
        print(f"Frames analyzed: {len(frame_indices)}")
        
        # Save to cache if requested
        if save_cache:
            try:
                from datetime import datetime
                
                cache_data = {
                    'rdf_vs_z': rdf_vs_z,
                    'parameters': {
                        'r_max': r_max,
                        'dr': dr,
                        'z_bin_width': z_bin_width,
                        'n_frames_sample': n_frames_sample
                    },
                    'ion_pairs': ion_pairs,
                    'n_frames': len(frame_indices),
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'bin_width': getattr(self, 'bin_width', None),
                    'n_bins': self.n_bins,
                    'z_min': self.z_min,
                    'z_max': self.z_max
                }
                
                with open(cache_file, 'wb') as f:
                    pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size_mb = os.path.getsize(cache_file) / 1024 / 1024
                print(f"\n✓ Saved RDF vs z data to cache: {cache_file}")
                print(f"  Cache size: {file_size_mb:.2f} MB")
            
            except Exception as e:
                print(f"⚠ Failed to save cache: {e}")
        else:
            print("\nCache saving skipped (save_cache=False)")
        
        return rdf_vs_z


    def calculate_water_structure_vs_z_detailed(self, force_rerun=False, step=None, n_frames_sample=None, 
                                            save_cache=True, cache_file=None):
        '''
        Analyze water structure properties vs z-position with caching.
        
        Parameters
        ----------
        force_rerun : bool, optional
            If True, recalculate even if cached data exists
        step : int, optional
            Analyze every nth frame. If None, uses n_frames_sample logic
        n_frames_sample : int, optional
            Number of frames to sample (alternative to step). Default is 5
            Ignored if step is provided
        save_cache : bool, optional
            If True, save results to cache file after calculation. Default is True
        cache_file : str, optional
            Path to cache file. If None, uses default naming based on trajectory
        
        Returns
        -------
        dict
            Water structure analysis results
        '''
        
        # Generate default cache filename if not provided
        if cache_file is None:
            traj_name = os.path.splitext(os.path.basename(self.trajectory_file))[0] if hasattr(self, 'trajectory_file') else 'trajectory'
            bin_width = getattr(self, 'bin_width', 1.0)
            cache_file = f'water_structure_cache_{traj_name}_bin{bin_width:.1f}A.pkl'
        
        # Try to load from cache
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"Loading water structure data from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify cache is compatible with current analysis
                if (cached_data.get('bin_width') == getattr(self, 'bin_width', 1.0) and
                    cached_data.get('n_bins') == self.n_bins):
                    
                    self.results.water_structure = cached_data['water_structure']
                    print(f"✓ Successfully loaded cached water structure data")
                    print(f"  Cache created: {cached_data.get('timestamp', 'unknown')}")
                    print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                    return self.results.water_structure
                else:
                    print("⚠ Cache parameters don't match current analysis, recalculating...")
            
            except Exception as e:
                print(f"⚠ Failed to load cache: {e}")
                print("Recalculating...")
        
        # If we get here, need to calculate
        print("Calculating water structure vs z...")
        
        z_bin_width = 3.0  # Å
        z_layer_centers = np.arange(self.z_min + z_bin_width/2, 
                                self.z_max - z_bin_width/2, z_bin_width)
        
        water_structure = {
            'z_centers': z_layer_centers,
            'tetrahedral_order': np.zeros(len(z_layer_centers)),
            'hydrogen_bonds_per_water': np.zeros(len(z_layer_centers)),
            'water_coordination_number': np.zeros(len(z_layer_centers)),
            'water_counts': np.zeros(len(z_layer_centers))
        }
        
        # Get z-offset for centering
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Determine which frames to analyze
        total_frames = len(self.universe.trajectory)
        
        if step is not None:
            # Use step parameter - analyze every nth frame
            frame_indices = np.arange(0, total_frames, step)
            print(f"Analyzing every {step} frames: {len(frame_indices)} frames total")
        else:
            # Use n_frames_sample parameter (original behavior)
            if n_frames_sample is None:
                n_frames_sample = 5
            frame_indices = np.linspace(0, total_frames - 1, 
                                    min(n_frames_sample, total_frames), dtype=int)
            print(f"Analyzing {len(frame_indices)} sampled frames")
        
        print(f"Processing frames: {len(frame_indices)} out of {total_frames} total frames...")
        
        for frame_idx in frame_indices:
            self.universe.trajectory[frame_idx]
            
            for z_idx, z_center in enumerate(z_layer_centers):
                # Find water molecules in this z-layer
                waters_in_layer = []
                water_positions = self.waters.positions  # Get all water positions at once
                
                for i, water_pos in enumerate(water_positions):
                    water_z = water_pos[2] - z_offset
                    if abs(water_z - z_center) <= z_bin_width / 2:
                        waters_in_layer.append(i)  # Store index
                
                if len(waters_in_layer) < 2:
                    continue
                
                water_structure['water_counts'][z_idx] += len(waters_in_layer)
                
                # Calculate tetrahedral order parameter (simplified)
                q_values = []
                hbond_counts = []
                coord_numbers = []
                
                for water_idx in waters_in_layer:
                    o_pos = water_positions[water_idx]
                    
                    # Find neighbors within 3.5 Å
                    neighbors = []
                    for other_water_idx in waters_in_layer:
                        if water_idx == other_water_idx:
                            continue
                        other_o_pos = water_positions[other_water_idx]
                        dist = np.linalg.norm(o_pos - other_o_pos)
                        if dist < 3.5:
                            neighbors.append(other_o_pos)
                    
                    coord_numbers.append(len(neighbors))
                    
                    # Simplified hydrogen bond count (waters within 3.5 Å)
                    hbond_counts.append(len(neighbors))
                    
                    # Simplified tetrahedral order (based on coordination)
                    if len(neighbors) >= 4:
                        q = 1.0 - (len(neighbors) - 4) * 0.1
                        q = max(0, q)
                        q_values.append(q)
                
                if q_values:
                    water_structure['tetrahedral_order'][z_idx] += np.mean(q_values)
                if hbond_counts:
                    water_structure['hydrogen_bonds_per_water'][z_idx] += np.mean(hbond_counts)
                if coord_numbers:
                    water_structure['water_coordination_number'][z_idx] += np.mean(coord_numbers)
        
        # Average over frames
        n_frames = len(frame_indices)
        water_structure['tetrahedral_order'] /= n_frames
        water_structure['hydrogen_bonds_per_water'] /= n_frames
        water_structure['water_coordination_number'] /= n_frames
        water_structure['water_counts'] /= n_frames
        
        # Store results
        self.results.water_structure = water_structure
        
        print("Water structure analysis complete")
        print(f"  Analyzed {n_frames} frames")
        print(f"  Mean tetrahedral order: {np.mean(water_structure['tetrahedral_order'][water_structure['tetrahedral_order'] > 0]):.3f}")
        print(f"  Mean H-bonds per water: {np.mean(water_structure['hydrogen_bonds_per_water'][water_structure['hydrogen_bonds_per_water'] > 0]):.2f}")
        
        # Save to cache if requested
        if save_cache:
            try:
                from datetime import datetime
                
                cache_data = {
                    'water_structure': water_structure,
                    'bin_width': getattr(self, 'bin_width', 1.0),
                    'n_bins': self.n_bins,
                    'n_frames': n_frames,
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'z_min': self.z_min,
                    'z_max': self.z_max,
                    'step': step,
                    'n_frames_sample': n_frames_sample
                }
                
                with open(cache_file, 'wb') as f:
                    pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size_kb = os.path.getsize(cache_file) / 1024
                print(f"✓ Saved water structure data to cache: {cache_file}")
                print(f"  Cache size: {file_size_kb:.1f} KB")
            
            except Exception as e:
                print(f"⚠ Failed to save cache: {e}")
        else:
            print("Cache saving skipped (save_cache=False)")
        
        return water_structure



    def calculate_mobility_vs_z_detailed(self, z_bin_width=5.0, time_window=50):
        '''Calculate ion mobility and diffusion coefficients vs z-position'''
        
        print("Calculating mobility vs z (simplified implementation)...")
        
        z_layer_centers = np.arange(self.z_min + z_bin_width/2, 
                                   self.z_max - z_bin_width/2, z_bin_width)
        
        mobility_results = {
            'z_centers': z_layer_centers,
            'diffusion_coefficients': {},
            'mean_square_displacement': {},
            'residence_times': {},
            'layer_transitions': {}
        }
        
        # Initialize for each ion type
        for ion_type in {**self.cation_types, **self.anion_types}.keys():
            mobility_results['diffusion_coefficients'][ion_type] = np.zeros(len(z_layer_centers))
            mobility_results['mean_square_displacement'][ion_type] = np.zeros(len(z_layer_centers))
            mobility_results['residence_times'][ion_type] = np.zeros(len(z_layer_centers))
            mobility_results['layer_transitions'][ion_type] = np.zeros(len(z_layer_centers))
        
        # Simplified mobility calculation
        # (Real implementation would track ion trajectories over time)
        for i, z_center in enumerate(z_layer_centers):
            for ion_type in {**self.cation_types, **self.anion_types}.keys():
                # Placeholder values - real calculation would analyze trajectories
                # Bulk-like mobility in center, reduced near interfaces
                distance_from_center = abs(z_center)
                mobility_factor = 1.0 / (1.0 + distance_from_center / 10.0)
                
                mobility_results['diffusion_coefficients'][ion_type][i] = 2.0e-5 * mobility_factor  # cm²/s
                mobility_results['mean_square_displacement'][ion_type][i] = 10.0 * mobility_factor  # Å²
                mobility_results['residence_times'][ion_type][i] = 50.0 / mobility_factor  # ps
                mobility_results['layer_transitions'][ion_type][i] = 0.1 * mobility_factor  # transitions/ps
        
        self.results.mobility_vs_z = mobility_results
        
        print("Mobility analysis complete (simplified)")
        return mobility_results




    def calculate_solvation_shells_vs_z_detailed(self, shell_radii=[3.5, 6.0, 9.0], 
                                                force_rerun=False, step=None, n_frames_sample=None,
                                                # NEW XY spatial analysis parameters
                                                ion_types=None,
                                                ion_specific_radii=None,
                                                target_z_values=None,
                                                z_slice_width=1.0, 
                                                xy_grid_size=1.0,
                                                enable_spatial_analysis=False,
                                                save_cache=True, 
                                                cache_filename=None):
        '''
        Calculate detailed solvation shell composition vs z-position with optional spatial XY analysis.
        
        Original functionality: Calculates solvation shells averaged across XY plane for each Z-layer.
        NEW functionality: When enable_spatial_analysis=True, calculates spatially-resolved 
        coordination data at specific XY coordinates within target Z-slices for height surface visualization.
        
        Parameters
        ----------
        shell_radii : list
            Radii defining shell boundaries (Å). Default: [3.5, 6.0, 9.0]
            Creates shells: 0-3.5, 3.5-6.0, 6.0-9.0 Å
        force_rerun : bool
            If True, recalculate even if cached data exists
        step : int, optional
            Analyze every nth frame
        n_frames_sample : int, optional
            Number of frames to sample (default: 10)
        
        NEW Spatial Analysis Parameters
        -------------------------------
        ion_types : list, default=['NA', 'MG', 'CL']
            Ion types for spatial analysis
        ion_specific_radii : dict, optional
            Ion-specific shell radii. Format: {'ION': [r1, r2, r3], ...}
            Example: {'NA': [3.0, 5.5, 8.5], 'MG': [2.8, 5.0, 8.0]}
            If not provided for an ion, uses default shell_radii
        target_z_values : list, default=[-21.6, 0.0, 22.8]
            Specific Z-positions for spatial analysis (e.g., clay interfaces, bulk)
        z_slice_width : float, default=1.0
            Z-slice thickness for spatial analysis (Å)
        xy_grid_size : float, default=1.0
            XY grid spacing for spatial analysis (Å)
        enable_spatial_analysis : bool, default=False
            If True, performs additional XY spatial analysis at target_z_values
        save_cache : bool, default=True
            Save results to cache file
        cache_filename : str, optional
            Custom cache filename. If None, auto-generates based on parameters
        '''
        
        # Generate cache filename if not provided
        if cache_filename is None:
            spatial_str = '_spatial' if enable_spatial_analysis else ''
            ion_str = '_'.join(ion_types[:3]) if enable_spatial_analysis else 'all'
            step_str = f'_step{step}' if step else f'_n{n_frames_sample or 10}'
            # Include shell_radii in filename to avoid cache mismatches
            radii_str = '_r' + '-'.join([f'{r:.1f}' for r in shell_radii])
            cache_filename = f'solvation_shells_vs_z{spatial_str}_{ion_str}{step_str}{radii_str}.pkl'
        
        # Check cache
        if not force_rerun:
            # First check for new spatial cache
            if enable_spatial_analysis and os.path.exists(cache_filename):
                try:
                    import pickle
                    with open(cache_filename, 'rb') as f:
                        cached_data = pickle.load(f)
                    print(f"✓ Loaded spatial solvation shell data from cache: {cache_filename}")
                    self.results.solvation_shells_vs_z = cached_data['z_analysis']
                    if 'spatial_analysis' in cached_data:
                        self.results.solvation_shells_xy_spatial = cached_data['spatial_analysis']
                    return cached_data['z_analysis']
                except Exception as e:
                    print(f"⚠ Error loading spatial cache: {e}")
            
            # Fallback to checking existing z-only data
            elif hasattr(self.results, 'solvation_shells_vs_z') and self.results.solvation_shells_vs_z is not None:
                if not enable_spatial_analysis:
                    print("Solvation shell data already calculated. Use force_rerun=True to recalculate.")
                    return self.results.solvation_shells_vs_z
                else:
                    print("Existing Z-data found. Adding spatial analysis...")
        
        analysis_type = "spatial solvation shell" if enable_spatial_analysis else "solvation shell"
        print(f"Calculating {analysis_type} analysis vs z...")
        
        if enable_spatial_analysis:
            # Set default target_z_values if not provided
            if target_z_values is None:
                target_z_values = [-21.6, 0.0, 22.8]
                print(f"🌐 Using default target Z-values: {target_z_values}")
            
            print(f"🌐 3D VOLUME MODE ENABLED:")
            print(f"   Ion types: {ion_types}")
            print(f"   Target Z-values: {target_z_values}")
            print(f"   Z-slice width: {z_slice_width:.1f} Å")
            print(f"   XY grid size: {xy_grid_size:.1f} Å")
        
        # Z-binning parameters - use target_z_values if spatial analysis enabled
        if enable_spatial_analysis and target_z_values is not None:
            z_layer_centers = np.array(target_z_values)
            z_bin_width = z_slice_width  # Use the same width as spatial analysis
        else:
            z_bin_width = 5.0  # Å
            z_layer_centers = np.arange(self.z_min + z_bin_width/2, 
                                    self.z_max - z_bin_width/2, z_bin_width)
        n_z_bins = len(z_layer_centers)
        
        # Use user-specified ion types, or all ion types if None
        if ion_types is None:
            all_ion_types = list({**self.cation_types, **self.anion_types}.keys())
        else:
            # Validate that requested ion types exist in the system
            available_ions = set({**self.cation_types, **self.anion_types}.keys())
            all_ion_types = [ion for ion in ion_types if ion in available_ions]
            if len(all_ion_types) != len(ion_types):
                missing = set(ion_types) - available_ions
                print(f"Warning: Ion types {missing} not found in system. Using: {all_ion_types}")
        
        # Setup ion-specific radii
        ion_radii_map = {}
        if ion_specific_radii is None:
            ion_specific_radii = {}
        
        for ion_type in all_ion_types:
            if ion_type in ion_specific_radii:
                ion_radii_map[ion_type] = ion_specific_radii[ion_type]
                print(f"Using specific radii for {ion_type}: {ion_specific_radii[ion_type]}")
            else:
                ion_radii_map[ion_type] = shell_radii
        
        # Initialize storage - determine max shells across all ions
        max_shells = max([len(radii) for radii in ion_radii_map.values()])
        shell_names = []
        for i in range(max_shells):
            if i == 0:
                shell_names.append('first_shell')
            elif i == 1:
                shell_names.append('second_shell')
            elif i == 2:
                shell_names.append('third_shell')
            else:
                shell_names.append(f'shell_{i+1}')
        
        solvation_data = {
            'z_centers': z_layer_centers,
            'shell_radii': shell_radii,  # Default radii for reference
            'ion_specific_radii': ion_radii_map,  # Store ion-specific radii used
            'shell_names': shell_names,
            'shell_water_counts': {},
            'coordination_numbers': {}
        }
        
        # Initialize arrays for each shell and ion type
        for shell_name in shell_names:
            solvation_data['shell_water_counts'][shell_name] = {}
            
            for ion_type in all_ion_types:
                solvation_data['shell_water_counts'][shell_name][ion_type] = np.zeros(n_z_bins)
        
        # Initialize coordination number arrays
        for ion_type in all_ion_types:
            solvation_data['coordination_numbers'][ion_type] = np.zeros(n_z_bins)
        
        # Get z-offset
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Determine frames to analyze
        total_frames = len(self.universe.trajectory)
        if step is not None:
            frame_indices = np.arange(0, total_frames, step)
            print(f"Analyzing every {step} frames: {len(frame_indices)} frames")
        else:
            if n_frames_sample is None:
                n_frames_sample = 10
            frame_indices = np.linspace(0, total_frames - 1, 
                                    min(n_frames_sample, total_frames), dtype=int)
            print(f"Analyzing {len(frame_indices)} sampled frames")
        
        # Analyze each frame
        from MDAnalysis.analysis import distances as mda_distances
        
        for frame_idx in frame_indices:
            self.universe.trajectory[frame_idx]
            
            # Analyze each z-layer
            for z_idx, z_center in enumerate(z_layer_centers):
                # Get ions in this z-layer for each type
                for ion_type in all_ion_types:
                    # Get ions of this type
                    if ion_type in self.cation_types:
                        ion_group = self.cations.select_atoms(f'name {ion_type}')
                    else:
                        ion_group = self.anions.select_atoms(f'name {ion_type}')
                    
                    if len(ion_group) == 0:
                        continue
                    
                    # Filter ions in this z-layer
                    ion_z_positions = ion_group.positions[:, 2] - z_offset
                    in_layer_mask = np.abs(ion_z_positions - z_center) <= z_bin_width / 2
                    
                    if not np.any(in_layer_mask):
                        continue
                    
                    ions_in_layer = ion_group[in_layer_mask]
                    
                    # Calculate distances to water oxygens only (not H atoms)
                    ion_positions = ions_in_layer.positions
                    water_oxygens = self.universe.select_atoms('name OW')  # TIP3P oxygen atoms
                    water_positions = water_oxygens.positions
                    
                    # Distance array: (n_ions_in_layer, n_water_oxygens)
                    dist_matrix = mda_distances.distance_array(ion_positions, water_positions, 
                                                            box=self.universe.dimensions)
                    
                    # Count waters in each shell for each ion using ion-specific radii
                    ion_radii = ion_radii_map[ion_type]  # Get radii for this specific ion
                    total_coord = 0
                    
                    for i_shell, shell_name in enumerate(shell_names):
                        if i_shell >= len(ion_radii):
                            continue  # Skip if not enough radii defined for this ion
                            
                        if i_shell == 0:
                            r_min = 0
                            r_max = ion_radii[0]
                        else:
                            r_min = ion_radii[i_shell - 1]
                            r_max = ion_radii[i_shell]
                        
                        # Waters in this shell for all ions in layer
                        in_shell = (dist_matrix >= r_min) & (dist_matrix < r_max)
                        waters_per_ion = in_shell.sum(axis=1)  # Sum over waters for each ion
                        
                        # Average over ions in layer
                        avg_waters = waters_per_ion.mean() if len(waters_per_ion) > 0 else 0
                        solvation_data['shell_water_counts'][shell_name][ion_type][z_idx] += avg_waters
                        
                        total_coord += avg_waters
                    
                    # Total coordination number (all shells combined)
                    solvation_data['coordination_numbers'][ion_type][z_idx] += total_coord
        
        # Average over frames
        n_frames = len(frame_indices)
        for shell_name in shell_names:
            for ion_type in all_ion_types:
                solvation_data['shell_water_counts'][shell_name][ion_type] /= n_frames
        
        for ion_type in all_ion_types:
            solvation_data['coordination_numbers'][ion_type] /= n_frames
        
        # CRITICAL: Store results in self.results
        self.results.solvation_shells_vs_z = solvation_data
        
        print("Solvation shell analysis complete")
        
        # Print Z-averaged summary (traditional analysis)
        print(f"\nZ-Averaged Solvation Shell Summary (Traditional Analysis):")
        for shell_name in shell_names:
            print(f"  {shell_name.replace('_', ' ').title()}:")
            for ion_type in all_ion_types:
                avg_waters = np.mean(solvation_data['shell_water_counts'][shell_name][ion_type])
                if avg_waters > 0.01:
                    print(f"    {ion_type}: {avg_waters:.2f} waters")
        
        # ===============================================
        # NEW: 3D VOLUME-BASED SPATIAL ANALYSIS
        # ===============================================
        spatial_data = None
        if enable_spatial_analysis:
            print(f"\n{'='*70}")
            print(f"🧊 3D VOLUME-BASED SOLVATION SHELL ANALYSIS")
            print(f"{'='*70}")
            print(f"Analyzing coordination in 3D volume regions...")
            
            # Get simulation box dimensions
            box_x, box_y = self.universe.dimensions[0], self.universe.dimensions[1]
            
            # Create 3D grid system (following calculate_pmf_vs_z_from_ion_density pattern)
            n_x = int(np.ceil(box_x / xy_grid_size))
            n_y = int(np.ceil(box_y / xy_grid_size))
            
            x_edges = np.linspace(0, box_x, n_x + 1)
            y_edges = np.linspace(0, box_y, n_y + 1)
            x_centers = (x_edges[:-1] + x_edges[1:]) / 2
            y_centers = (y_edges[:-1] + y_edges[1:]) / 2
            
            print(f"📐 3D Volume Grid Setup:")
            print(f"  XY box: {box_x:.1f} × {box_y:.1f} Å")
            print(f"  XY grid: {n_x} × {n_y} = {n_x * n_y} cells")
            print(f"  Volume element size: {xy_grid_size:.1f} × {xy_grid_size:.1f} × {z_slice_width:.1f} Å³")
            print(f"  Volume per element: {xy_grid_size**2 * z_slice_width:.3f} Å³")
            
            # Convert target_z_values to numpy array
            target_z_array = np.array(target_z_values)
            
            # Initialize spatial results structure (compatible with height surface plotting)
            spatial_data = {
                'z_slice_centers': target_z_array,
                'z_slice_width': z_slice_width,
                'x_centers': x_centers,
                'y_centers': y_centers,
                'x_edges': x_edges,
                'y_edges': y_edges,
                'box_dimensions': (box_x, box_y),
                'grid_dimensions': (n_x, n_y),
                'xy_grid_size': xy_grid_size,
                'ion_types': ion_types,
                'shell_radii': shell_radii,
                'shell_names': shell_names,
                'z_slices': []
            }
            
            # Process each target Z-layer for 3D volume analysis
            for z_idx, z_center in enumerate(target_z_array):
                print(f"\n🧊 Processing 3D volume layer {z_idx + 1}/{len(target_z_array)}: Z = {z_center:.1f} Å")
                print(f"   Volume layer: {z_center - z_slice_width/2:.1f} to {z_center + z_slice_width/2:.1f} Å")
                
                z_min_layer = z_center - z_slice_width / 2
                z_max_layer = z_center + z_slice_width / 2
                
                # Initialize coordination grids for this Z-layer
                layer_data = {
                    'z_center': z_center,
                    'z_slice_width': z_slice_width,
                    'z_min': z_min_layer,
                    'z_max': z_max_layer,
                    'coordination_grids': {},  # Height surface compatible
                    'shell_grids': {},
                    'volume_counts': {},  # Count of ions per volume element
                    'n_frames': len(frame_indices),
                    'x_centers': x_centers,
                    'y_centers': y_centers,
                    'volume_element_size': (xy_grid_size, xy_grid_size, z_slice_width),
                    'volume_element_volume': xy_grid_size**2 * z_slice_width
                }
                
                # Initialize grids for each shell and ion type
                for shell_name in shell_names:
                    layer_data['coordination_grids'][shell_name] = {}
                    layer_data['shell_grids'][shell_name] = {}
                    for ion_type in ion_types:
                        layer_data['coordination_grids'][shell_name][ion_type] = np.zeros((n_y, n_x))
                        layer_data['shell_grids'][shell_name][ion_type] = np.zeros((n_y, n_x))
                
                # Initialize total coordination and volume counting grids
                layer_data['coordination_grids']['total_coordination'] = {}
                layer_data['volume_counts'] = {}
                for ion_type in ion_types:
                    layer_data['coordination_grids']['total_coordination'][ion_type] = np.zeros((n_y, n_x))
                    layer_data['volume_counts'][ion_type] = np.zeros((n_y, n_x))
                
                # Process each frame for this Z-layer
                frame_count = 0
                total_ions_analyzed = 0
                
                for frame_idx in frame_indices:
                    self.universe.trajectory[frame_idx]
                    
                    # Process each ion type
                    for ion_type in ion_types:
                        # Get ions of this type
                        if ion_type in self.cation_types:
                            ion_group = self.cations.select_atoms(f'name {ion_type}')
                        elif ion_type in self.anion_types:
                            ion_group = self.anions.select_atoms(f'name {ion_type}')
                        else:
                            # Try to find in all atoms
                            try:
                                ion_group = self.universe.select_atoms(f'name {ion_type}')
                            except:
                                continue
                        
                        if len(ion_group) == 0:
                            continue
                        
                        # 🧊 3D VOLUME FILTERING: Get ions within this Z-layer
                        ion_z_positions = ion_group.positions[:, 2] - z_offset
                        in_layer_mask = (ion_z_positions >= z_min_layer) & (ion_z_positions < z_max_layer)
                        
                        if not np.any(in_layer_mask):
                            continue
                        
                        ions_in_layer = ion_group[in_layer_mask]
                        ion_positions = ions_in_layer.positions
                        
                        # 🧊 For each ion, determine its 3D volume element and calculate coordination
                        for ion_pos in ion_positions:
                            # Determine which 3D volume element this ion belongs to
                            x, y, z = ion_pos[0], ion_pos[1], ion_pos[2] - z_offset
                            
                            # Get XY grid indices for this volume element
                            x_idx = np.digitize(x % box_x, x_edges) - 1
                            y_idx = np.digitize(y % box_y, y_edges) - 1
                            
                            # Clip to valid indices
                            x_idx = np.clip(x_idx, 0, n_x - 1)
                            y_idx = np.clip(y_idx, 0, n_y - 1)
                            
                            # Count this ion in its volume element
                            layer_data['volume_counts'][ion_type][y_idx, x_idx] += 1
                            total_ions_analyzed += 1
                            
                            # 🧊 Calculate coordination for this ion within its volume element
                            # Use oxygen atoms only, not H atoms
                            water_oxygens = self.universe.select_atoms('name OW')
                            water_positions = water_oxygens.positions
                            distances = mda_distances.distance_array(
                                ion_pos.reshape(1, -1), water_positions, 
                                box=self.universe.dimensions
                            ).flatten()
                            
                            # Count waters in each shell for this ion using ion-specific radii
                            ion_radii = ion_radii_map[ion_type]  # Get radii for this specific ion
                            total_coord_this_ion = 0
                            
                            for i_shell, shell_name in enumerate(shell_names):
                                if i_shell >= len(ion_radii):
                                    continue  # Skip if not enough radii defined for this ion
                                    
                                if i_shell == 0:
                                    r_min = 0
                                    r_max = ion_radii[0]
                                else:
                                    r_min = ion_radii[i_shell - 1]
                                    r_max = ion_radii[i_shell]
                                
                                # Count waters in this shell around this ion
                                in_shell = (distances >= r_min) & (distances < r_max)
                                n_waters_in_shell = np.sum(in_shell)
                                
                                # Add coordination to the volume element grid
                                layer_data['coordination_grids'][shell_name][ion_type][y_idx, x_idx] += n_waters_in_shell
                                total_coord_this_ion += n_waters_in_shell
                            
                            # Add to total coordination for this volume element
                            layer_data['coordination_grids']['total_coordination'][ion_type][y_idx, x_idx] += total_coord_this_ion
                    
                    frame_count += 1
                
                # 🧊 Average coordination over ions in each volume element
                for shell_name in list(shell_names) + ['total_coordination']:
                    for ion_type in ion_types:
                        volume_counts = layer_data['volume_counts'][ion_type]
                        coord_grid = layer_data['coordination_grids'][shell_name][ion_type]
                        
                        # Average coordination where ions were found
                        nonzero_mask = volume_counts > 0
                        coord_grid[nonzero_mask] /= volume_counts[nonzero_mask]
                        
                        # Set zero coordination where no ions were found
                        coord_grid[~nonzero_mask] = 0.0
                
                print(f"  ✓ Processed {frame_count} frames, {total_ions_analyzed} ions total")
                
                # Calculate and report 3D volume statistics
                for ion_type in ion_types:
                    volume_counts = layer_data['volume_counts'][ion_type]
                    occupied_volumes = np.sum(volume_counts > 0)
                    total_volumes = n_x * n_y
                    occupancy = occupied_volumes / total_volumes * 100
                    
                    print(f"    {ion_type}: {occupied_volumes}/{total_volumes} volumes occupied ({occupancy:.1f}%)")
                    
                    if occupied_volumes > 0:
                        for shell_name in shell_names:
                            coord_grid = layer_data['coordination_grids'][shell_name][ion_type]
                            occupied_coords = coord_grid[coord_grid > 0]
                            if len(occupied_coords) > 0:
                                mean_coord = np.mean(occupied_coords)
                                std_coord = np.std(occupied_coords)
                                print(f"      {shell_name}: {mean_coord:.2f} ± {std_coord:.2f} waters per volume")
                
                spatial_data['z_slices'].append(layer_data)
            
            # Store spatial results
            self.results.solvation_shells_xy_spatial = spatial_data
            
            print(f"\n🎊 3D VOLUME-BASED ANALYSIS COMPLETE!")
            print(f"  Analyzed {len(target_z_array)} Z-layers")
            print(f"  Volume elements per layer: {n_x} × {n_y} = {n_x * n_y}")
            print(f"  Volume element size: {xy_grid_size:.1f} × {xy_grid_size:.1f} × {z_slice_width:.1f} Å³")
            print(f"  Volume per element: {xy_grid_size**2 * z_slice_width:.3f} Å³")
            print(f"  Ion types: {', '.join(ion_types)}")
            print(f"  🧊 Each volume element has its own coordination value!")
            print(f"  📊 Data ready for coordination height surface visualization!")
            
            # 🧊 SPATIAL ANALYSIS SUMMARY BY TARGET Z-REGION
            print(f"\n{'='*70}")
            print(f"🧊 SPATIAL SOLVATION SHELL SUMMARY BY Z-REGION")
            print(f"{'='*70}")
            
            for z_idx, layer_data in enumerate(spatial_data['z_slices']):
                z_center = layer_data['z_center']
                z_min = layer_data['z_min']
                z_max = layer_data['z_max']
                
                print(f"\n📍 Z-Region {z_idx + 1}: Z = {z_center:.1f} Å ({z_min:.1f} to {z_max:.1f} Å)")
                print(f"{'─' * 60}")
                
                # Calculate average coordination for occupied volume elements
                for shell_name in shell_names:
                    print(f"  {shell_name.replace('_', ' ').title()}:")
                    
                    for ion_type in ion_types:
                        coord_grid = layer_data['coordination_grids'][shell_name][ion_type]
                        volume_counts = layer_data['volume_counts'][ion_type]
                        
                        # Get coordination values from occupied volumes only
                        occupied_mask = volume_counts > 0
                        
                        if np.any(occupied_mask):
                            occupied_coords = coord_grid[occupied_mask]
                            
                            # Calculate statistics for occupied volumes
                            mean_coord = np.mean(occupied_coords)
                            std_coord = np.std(occupied_coords)
                            min_coord = np.min(occupied_coords)
                            max_coord = np.max(occupied_coords)
                            n_occupied = np.sum(occupied_mask)
                            total_volumes = coord_grid.size
                            occupancy = n_occupied / total_volumes * 100
                            
                            print(f"    {ion_type}: {mean_coord:.2f} ± {std_coord:.2f} waters")
                            print(f"         Range: {min_coord:.1f} - {max_coord:.1f} waters")
                            print(f"         Occupancy: {n_occupied}/{total_volumes} volumes ({occupancy:.1f}%)")
                        else:
                            print(f"    {ion_type}: No ions found in this region")
                
                # Report total coordination summary for this region
                print(f"  Total Coordination:")
                for ion_type in ion_types:
                    total_coord_grid = layer_data['coordination_grids']['total_coordination'][ion_type]
                    volume_counts = layer_data['volume_counts'][ion_type]
                    
                    occupied_mask = volume_counts > 0
                    if np.any(occupied_mask):
                        occupied_total_coords = total_coord_grid[occupied_mask]
                        mean_total = np.mean(occupied_total_coords)
                        std_total = np.std(occupied_total_coords)
                        print(f"    {ion_type}: {mean_total:.2f} ± {std_total:.2f} total waters")
                    else:
                        print(f"    {ion_type}: No coordination data")
            
            print(f"\n{'='*70}")
            print(f"🎯 SPATIAL ANALYSIS INTERPRETATION")
            print(f"{'='*70}")
            print(f"• Each Z-region shows coordination in {xy_grid_size:.1f}×{xy_grid_size:.1f}×{z_slice_width:.1f} Å³ volume elements")
            print(f"• Values are averaged over ions found in each volume element")
            print(f"• Occupancy shows what fraction of volume elements contain ions")
            print(f"• Range shows coordination heterogeneity within each region")
            print(f"• Lower occupancy + high variability = interface effects!")
        
        # Save to cache if requested
        if save_cache:
            try:
                import pickle
                cache_data = {
                    'z_analysis': solvation_data,
                    'parameters': {
                        'shell_radii': shell_radii,
                        'enable_spatial_analysis': enable_spatial_analysis,
                        'ion_types': ion_types if enable_spatial_analysis else None,
                        'target_z_values': target_z_values if enable_spatial_analysis else None,
                        'z_slice_width': z_slice_width if enable_spatial_analysis else None,
                        'xy_grid_size': xy_grid_size if enable_spatial_analysis else None,
                        'step': step,
                        'n_frames_sample': n_frames_sample
                    },
                    'timestamp': f"{__import__('datetime').datetime.now()}"
                }
                
                if enable_spatial_analysis and spatial_data:
                    cache_data['spatial_analysis'] = spatial_data
                
                with open(cache_filename, 'wb') as f:
                    pickle.dump(cache_data, f)
                print(f"\n💾 Results saved to cache: {cache_filename}")
            
            except Exception as e:
                print(f"⚠ Warning: Could not save cache: {e}")
        
        return solvation_data



    def calculate_surface_tension_profile(self):
        '''Calculate surface tension profile using pressure tensor components'''
        
        print("Calculating surface tension profile...")
        
        # Initialize surface tension results
        surface_tension_results = {
            'z_centers': self.z_centers,
            'pressure_normal': np.zeros(self.n_bins),  # P_zz
            'pressure_tangential': np.zeros(self.n_bins),  # (P_xx + P_yy)/2
            'pressure_tensor_profile': np.zeros(self.n_bins),
            'integrated_surface_tension': 0.0
        }
        
        # Simplified calculation (would need proper pressure tensor analysis)
        # Using density fluctuations as a proxy for pressure variations
        water_density = self.results.water_density
        bulk_density = np.mean([water_density[:10], water_density[-10:]])
        
        # Calculate pressure deviations based on density
        for i, z in enumerate(self.z_centers):
            density_deviation = water_density[i] - bulk_density
            
            # Simplified pressure components
            surface_tension_results['pressure_normal'][i] = -density_deviation * 100  # Arbitrary units
            surface_tension_results['pressure_tangential'][i] = density_deviation * 50
            
            # Surface tension contribution
            surface_tension_results['pressure_tensor_profile'][i] = (
                surface_tension_results['pressure_normal'][i] - 
                surface_tension_results['pressure_tangential'][i]
            )
        
        # Integrate to get total surface tension
        surface_tension_results['integrated_surface_tension'] = np.trapz(
            surface_tension_results['pressure_tensor_profile'], self.z_centers)
        
        self.results.surface_tension = surface_tension_results
        
        print(f"Surface tension calculation complete:")
        print(f"  Integrated surface tension: {surface_tension_results['integrated_surface_tension']:.3f}")
        
        return surface_tension_results

    def calculate_interfacial_thickness(self, interface_criterion='90_10'):
        '''Calculate interfacial thickness using different criteria'''
        
        if not hasattr(self.results, 'interfaces'):
            print("No interfaces detected. Run detect_interfaces() first.")
            return None
        
        print(f"Calculating interfacial thickness using {interface_criterion} criterion...")
        
        water_density = self.results.water_density
        bulk_density = np.mean([water_density[:10], water_density[-10:]])
        
        thickness_results = {
            'criterion': interface_criterion,
            'interface_thicknesses': [],
            'bulk_density': bulk_density
        }
        
        for i, (start, end) in enumerate(self.results.interfaces['all_interfaces']):
            interface_center = (start + end) / 2
            interface_mask = (self.z_centers >= start) & (self.z_centers <= end)
            
            if interface_criterion == '90_10':
                # 90%-10% criterion
                high_threshold = bulk_density * 0.9
                low_threshold = bulk_density * 0.1
            elif interface_criterion == '80_20':
                high_threshold = bulk_density * 0.8
                low_threshold = bulk_density * 0.2
            else:  # Default to 90-10
                high_threshold = bulk_density * 0.9
                low_threshold = bulk_density * 0.1
            
            # Find crossing points
            thickness = 0.0
            crossing_points = []
            
            for j in range(len(water_density) - 1):
                z_current = self.z_centers[j]
                z_next = self.z_centers[j + 1]
                density_current = water_density[j]
                density_next = water_density[j + 1]
                
                # Check for crossings of thresholds
                if ((density_current > high_threshold and density_next <= high_threshold) or
                    (density_current <= high_threshold and density_next > high_threshold) or
                    (density_current > low_threshold and density_next <= low_threshold) or
                    (density_current <= low_threshold and density_next > low_threshold)):
                    
                    # Interpolate crossing point
                    if abs(interface_center - z_current) < 10.0:  # Near interface
                        crossing_points.append((z_current + z_next) / 2)
            
            if len(crossing_points) >= 2:
                thickness = max(crossing_points) - min(crossing_points)
            else:
                thickness = end - start  # Fallback to interface width
            
            thickness_results['interface_thicknesses'].append(thickness)
            
            print(f"  Interface {i+1}: thickness = {thickness:.2f} Å")
        
        self.results.interfacial_thickness = thickness_results
        
        return thickness_results

    def calculate_local_pressure_vs_z(self):
        '''Calculate local pressure components vs z'''
        
        print("Calculating local pressure components vs z...")
        
        pressure_results = {
            'z_centers': self.z_centers,
            'kinetic': np.zeros(self.n_bins),
            'virial': np.zeros(self.n_bins),
            'total_pressure': np.zeros(self.n_bins)
        }
        
        # Simplified pressure calculation based on density and temperature
        water_density = self.results.water_density
        
        # Estimate kinetic contribution (P_kinetic = ρkT)
        if hasattr(self.results, 'local_temperature'):
            temperature = self.results.local_temperature
        else:
            temperature = np.full(self.n_bins, 300.0)  # Assume 300K
        
        # Simplified pressure calculation
        kB = 1.38e-23  # Boltzmann constant (J/K)
        pressure_results['kinetic'] = water_density * kB * temperature * 6.022e23  # Convert units
        
        # Estimate virial contribution (simplified)
        bulk_density = np.mean([water_density[:10], water_density[-10:]])
        for i in range(self.n_bins):
            density_deviation = water_density[i] - bulk_density
            pressure_results['virial'][i] = -density_deviation * 1000  # Arbitrary scaling
        
        # Total pressure
        pressure_results['total_pressure'] = (pressure_results['kinetic'] + 
                                             pressure_results['virial'])
        
        self.results.pressure_components = pressure_results
        
        print("Local pressure calculation complete")
        return pressure_results

    def calculate_chemical_potential_vs_z(self, ion_type='Na', method='density_based'):
        '''Calculate excess chemical potential vs z'''
        
        print(f"Calculating chemical potential for {ion_type} using {method} method...")
        
        # Find ion density profile
        ion_density = None
        for itype, density in self.results.ion_densities_by_type.items():
            if ion_type.upper() in itype.upper() or itype.upper() in ion_type.upper():
                ion_density = density
                break
        
        if ion_density is None:
            print(f"Ion type {ion_type} not found in analysis results.")
            return None
        
        chemical_potential_results = {
            'z_centers': self.z_centers,
            'ion_type': ion_type,
            'method': method,
            'mu_excess': np.zeros(self.n_bins),
            'mu_ideal': np.zeros(self.n_bins),
            'mu_total': np.zeros(self.n_bins)
        }
        
        # Bulk density reference
        bulk_density = np.mean([ion_density[:10], ion_density[-10:]])
        
        if method == 'density_based':
            # μ_excess = kT * ln(ρ(z)/ρ_bulk)
            kT = 2.479  # kT at 300K in kJ/mol
            
            for i in range(self.n_bins):
                if ion_density[i] > 0 and bulk_density > 0:
                    chemical_potential_results['mu_excess'][i] = kT * np.log(ion_density[i] / bulk_density)
                else:
                    chemical_potential_results['mu_excess'][i] = 0.0
        
        elif method == 'electrostatic':
            # Include electrostatic contribution
            if hasattr(self.results, 'electrostatic_potential'):
                potential = self.results.electrostatic_potential
                # μ_excess = q * φ(z) + kT * ln(ρ(z)/ρ_bulk)
                charge = 1.0  # Default charge
                kT = 2.479
                
                for i in range(self.n_bins):
                    electrostatic_term = charge * potential[i]
                    if ion_density[i] > 0 and bulk_density > 0:
                        density_term = kT * np.log(ion_density[i] / bulk_density)
                    else:
                        density_term = 0.0
                    
                    chemical_potential_results['mu_excess'][i] = electrostatic_term + density_term
            else:
                print("No electrostatic potential available. Run calculate_electrostatic_potential_vs_z() first.")
                return None
        
        # Ideal gas contribution (constant)
        chemical_potential_results['mu_ideal'] = np.full(self.n_bins, 0.0)  # Reference
        
        # Total chemical potential
        chemical_potential_results['mu_total'] = (chemical_potential_results['mu_excess'] + 
                                                 chemical_potential_results['mu_ideal'])
        
        self.results.chemical_potential = chemical_potential_results
        
        print(f"Chemical potential calculation complete for {ion_type}")
        return chemical_potential_results


    def _minimum_image_distance(self, pos1, pos2):
        '''
        Calculate minimum image distance accounting for periodic boundary conditions.
        
        Parameters
        ----------
        pos1, pos2 : np.ndarray
            Positions of two particles (3D coordinates)
        
        Returns
        -------
        float
            Minimum image distance between particles
        '''
        if self.universe.dimensions is None:
            # No PBC information, use simple distance
            return np.linalg.norm(pos1 - pos2)
        
        # Get box dimensions
        box = self.universe.dimensions[:3]  # [Lx, Ly, Lz]
        
        # Calculate distance vector
        delta = pos1 - pos2
        
        # Apply minimum image convention for each dimension
        delta = delta - box * np.round(delta / box)
        
        # Return magnitude
        return np.linalg.norm(delta)
    

