    def calculate_ion_clustering_vs_z(self, cluster_cutoff=4.0, ion_types=None, 
                                    step=None, n_frames_sample=None, 
                                    z_slice_width=4.0, force_rerun=False,
                                    save_cache=True, cache_file=None):
        '''
        Analyze ion clustering vs z-position using periodic boundary conditions.
        
        Parameters
        ----------
        cluster_cutoff : float
            Distance threshold for clustering (Å), default=4.0
            Uses minimum image convention for periodic boundaries
        ion_types : list, optional
            List of ion types to analyze (e.g., ['NA', 'CL'])
            If None, analyzes all available ion types
        step : int, optional
            Analyze every nth frame. Takes precedence over n_frames_sample
        n_frames_sample : int, optional
            Number of frames to evenly sample from trajectory
            Default is 3. Ignored if step is provided
        z_slice_width : float, optional
            Width of z-slices for analysis (Å), default=4.0
        force_rerun : bool, optional
            If True, recalculate even if cached data exists. Default is False
        save_cache : bool, optional
            If True, save results to cache file after calculation. Default is True
        cache_file : str, optional
            Path to cache file. If None, uses default naming based on parameters
        
        Returns
        -------
        dict
            Clustering analysis results for each ion type containing:
            - average_cluster_size: Mean cluster size (includes monomers)
            - fraction_clustered: Fraction of ions in clusters of size > 1
        
        Notes
        -----
        The method uses BFS clustering with PBC-aware distances. Monomers (isolated ions)
        are included in average_cluster_size but excluded from fraction_clustered.
        Results are cached for faster subsequent analysis. Use force_rerun=True to recalculate.
        '''
        
        # Generate default cache filename if not provided
        if cache_file is None:
            traj_name = os.path.splitext(os.path.basename(self.trajectory_file))[0] if hasattr(self, 'trajectory_file') else 'trajectory'
            ion_str = '_'.join(ion_types[:3]) if ion_types else 'all'
            cache_file = f'ion_clustering_cache_{traj_name}_cutoff{cluster_cutoff:.1f}_zslice{z_slice_width:.1f}.pkl'
        
        # Try to load from cache
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"Loading ion clustering data from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify cache parameters match
                cache_params = cached_data.get('parameters', {})
                if (cache_params.get('cluster_cutoff') == cluster_cutoff and
                    cache_params.get('z_slice_width') == z_slice_width and
                    cache_params.get('z_min') == self.z_min and
                    cache_params.get('z_max') == self.z_max):
                    
                    self.results.ion_clustering = cached_data['clustering_results']
                    print(f"✓ Successfully loaded cached ion clustering data")
                    print(f"  Cache created: {cached_data.get('timestamp', 'unknown')}")
                    print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                    print(f"  Ion types: {', '.join(cached_data.get('ion_types', []))}")
                    return self.results.ion_clustering
                else:
                    print("⚠ Cache parameters don't match, recalculating...")
            
            except Exception as e:
                print(f"⚠ Failed to load cache: {e}")
                print("Recalculating...")
        
        # If we get here, need to calculate
        print(f"Calculating ion clustering vs z...")
        print(f"Cluster cutoff: {cluster_cutoff} Å")
        print(f"Z-slice width: {z_slice_width} Å")
        
        if ion_types is None:
            # Analyze all available ion types
            ion_types = list(self.cation_types.keys()) + list(self.anion_types.keys())
        
        # Include full z-range: start from z_min, end at z_max
        # Bin centers will be at z_min + z_slice_width/2, ..., up to z_max
        z_layer_centers = np.arange(self.z_min + z_slice_width/2, 
                                    self.z_max + z_slice_width/2, z_slice_width)
        # Clip to ensure we don't exceed z_max
        z_layer_centers = z_layer_centers[z_layer_centers <= self.z_max]
        
        n_z_bins = len(z_layer_centers)
        z_range = self.z_max - self.z_min
        
        print(f"Z-range: {self.z_min:.2f} to {self.z_max:.2f} Å (total: {z_range:.2f} Å)")
        print(f"Number of z-bins: {n_z_bins}")
        print(f"Bin centers: {z_layer_centers[0]:.2f} to {z_layer_centers[-1]:.2f} Å")
        
        clustering_results = {
            'z_centers': z_layer_centers,
            'z_slice_width': z_slice_width,
            'n_z_bins': n_z_bins,
            'cluster_cutoff': cluster_cutoff,
            'average_cluster_size': {},
            'fraction_clustered': {},
            'cluster_size_distribution': {}
        }
        
        # Initialize for each ion type
        for ion_type in ion_types:
            clustering_results['average_cluster_size'][ion_type] = np.zeros(len(z_layer_centers))
            clustering_results['fraction_clustered'][ion_type] = np.zeros(len(z_layer_centers))
            clustering_results['cluster_size_distribution'][ion_type] = {}
        
        # Get z-offset for centering
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Determine which frames to analyze
        total_frames = len(self.universe.trajectory)
        
        if step is not None:
            # Use step parameter - analyze every nth frame
            frame_indices = np.arange(0, total_frames, step)
            print(f"Analyzing every {step} frames: {len(frame_indices)} frames total")
        else:
            # Use n_frames_sample parameter (default behavior)
            if n_frames_sample is None:
                n_frames_sample = 3  # Default value
            frame_indices = np.linspace(0, total_frames - 1, 
                                        min(n_frames_sample, total_frames), dtype=int)
            print(f"Analyzing {len(frame_indices)} evenly sampled frames")
        
        print(f"Processing {len(frame_indices)} out of {total_frames} total frames...")
        
        for frame_idx in frame_indices:
            self.universe.trajectory[frame_idx]
            
            for ion_type in ion_types:
                # Get ion group for this type
                if ion_type in self.cation_types:
                    ion_group = self.cation_types[ion_type]
                elif ion_type in self.anion_types:
                    ion_group = self.anion_types[ion_type]
                else:
                    continue
                
                if len(ion_group) == 0:
                    continue
                
                # Analyze clustering in each z-layer
                for z_idx, z_center in enumerate(z_layer_centers):
                    # Find ions in this layer
                    ions_in_layer = []
                    for ion in ion_group:
                        ion_z = ion.position[2] - z_offset
                        if abs(ion_z - z_center) <= z_slice_width / 2:
                            ions_in_layer.append(ion)
                    
                    if len(ions_in_layer) < 2:
                        continue
                    
                    # Build clusters using distance-based algorithm
                    clustered = [False] * len(ions_in_layer)
                    clusters = []
                    
                    for i, ion1 in enumerate(ions_in_layer):
                        if clustered[i]:
                            continue
                        
                        # Start new cluster
                        cluster = [i]
                        clustered[i] = True
                        to_check = [i]
                        
                        while to_check:
                            current = to_check.pop(0)
                            current_ion = ions_in_layer[current]
                            
                            # Find neighbors using PBC-aware distance
                            for j, ion2 in enumerate(ions_in_layer):
                                if clustered[j]:
                                    continue
                                
                                # Use minimum image convention for periodic boundaries
                                distance = self._minimum_image_distance(
                                    current_ion.position, ion2.position)
                                
                                if distance <= cluster_cutoff:
                                    cluster.append(j)
                                    clustered[j] = True
                                    to_check.append(j)
                        
                        clusters.append(cluster)
                    
                    # Calculate statistics
                    if clusters:
                        cluster_sizes = [len(c) for c in clusters]
                        avg_size = np.mean(cluster_sizes)
                        
                        # Fraction in clusters (size > 1)
                        n_clustered = sum(len(c) for c in clusters if len(c) > 1)
                        frac_clustered = n_clustered / len(ions_in_layer) if len(ions_in_layer) > 0 else 0
                        
                        clustering_results['average_cluster_size'][ion_type][z_idx] += avg_size
                        clustering_results['fraction_clustered'][ion_type][z_idx] += frac_clustered
        
        # Average over frames
        n_frames = len(frame_indices)
        for ion_type in ion_types:
            clustering_results['average_cluster_size'][ion_type] /= n_frames
            clustering_results['fraction_clustered'][ion_type] /= n_frames
        
        self.results.ion_clustering = clustering_results
        
        print(f"\n{'='*60}")
        print(f"Ion clustering analysis complete!")
        print(f"{'='*60}")
        print(f"Analysis parameters:")
        print(f"  Z-slice width: {z_slice_width} Å")
        print(f"  Number of z-bins: {n_z_bins}")
        print(f"  Cluster cutoff: {cluster_cutoff} Å")
        print(f"  Frames analyzed: {n_frames}")
        print(f"\nResults:")
        print(f"  Ion types analyzed: {', '.join(ion_types)}")
        for ion_type in ion_types:
            avg_cluster_size = np.mean(clustering_results['average_cluster_size'][ion_type])
            avg_fraction = np.mean(clustering_results['fraction_clustered'][ion_type])
            print(f"  {ion_type}:")
            print(f"    Average cluster size: {avg_cluster_size:.2f}")
            print(f"    Average fraction clustered: {avg_fraction*100:.1f}%")
        
        # Save to cache if requested
        if save_cache:
            try:
                from datetime import datetime
                
                cache_data = {
                    'clustering_results': clustering_results,
                    'parameters': {
                        'cluster_cutoff': cluster_cutoff,
                        'z_slice_width': z_slice_width,
                        'z_min': self.z_min,
                        'z_max': self.z_max,
                        'step': step,
                        'n_frames_sample': n_frames_sample
                    },
                    'ion_types': ion_types,
                    'n_frames': n_frames,
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'n_bins': self.n_bins
                }
                
                with open(cache_file, 'wb') as f:
                    pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size_kb = os.path.getsize(cache_file) / 1024
                print(f"\n✓ Saved ion clustering data to cache: {cache_file}")
                print(f"  Cache size: {file_size_kb:.1f} KB")
            
            except Exception as e:
                print(f"\n⚠ Failed to save cache: {e}")
        else:
            print("\nCache saving skipped (save_cache=False)")
        
        return clustering_results


    def calculate_dielectric_profile(self):
        '''Calculate dielectric constant profile'''
        
        print("Calculating dielectric profile...")
        
        dielectric_results = {
            'z_centers': self.z_centers,
            'dielectric_constant': np.zeros(self.n_bins),
            'polarization': np.zeros(self.n_bins)
        }
        
        # Simplified dielectric calculation based on water density
        water_density = self.results.water_density
        bulk_water_density = np.mean([water_density[:10], water_density[-10:]])
        bulk_dielectric = 78.0  # Water dielectric constant
        
        # Linear relationship (simplified)
        for i in range(self.n_bins):
            if bulk_water_density > 0:
                density_ratio = water_density[i] / bulk_water_density
                dielectric_results['dielectric_constant'][i] = 1.0 + (bulk_dielectric - 1.0) * density_ratio
            else:
                dielectric_results['dielectric_constant'][i] = 1.0
        
        # Polarization (simplified)
        dielectric_results['polarization'] = (dielectric_results['dielectric_constant'] - 1.0) / (4 * np.pi)
        
        self.results.dielectric_profile = dielectric_results
        
        print("Dielectric profile calculation complete")
        return dielectric_results


    def calculate_ion_clustering_xy_plane(self, cluster_cutoff=4.0, ion_types=None, 
                                        z_slice_width=5.0, z_slice_centers=None,
                                        distance_mode='3D', xy_grid_size=None,
                                        n_frames_sample=None, step=None,
                                        force_rerun=False, save_cache=True, cache_file=None):
        '''
        Analyze ion clustering in XY planes at different z-positions with optional spatial gridding.
        
        Parameters
        ----------
        cluster_cutoff : float
            Distance threshold for clustering (Å), default=4.0
        ion_types : list, optional
            List of ion types to analyze (e.g., ['NA', 'CL'])
            If None, analyzes all available ion types
        z_slice_width : float, optional
            Thickness of each z-slice (Å), default=5.0
        z_slice_centers : array-like, optional
            Specific z-positions to analyze. If None, auto-generates based on z-range
        distance_mode : str, optional
            Distance calculation mode: '3D' (default) or '2D-XY'
            - '3D': Full 3D distance with PBC (physically correct)
            - '2D-XY': Only XY distance, ignoring Z component
        xy_grid_size : float, optional
            If provided, bins clustering data onto XY spatial grid with this spacing (Å).
            Returns 3D arrays (z, x, y) for spatial hotspot analysis.
            If None (default), returns 1D z-dependent profiles averaged over XY plane.
        n_frames_sample : int, optional
            Number of frames to evenly sample from trajectory
            Default is 3. Ignored if step is provided
        step : int, optional
            Analyze every nth frame. Takes precedence over n_frames_sample
        force_rerun : bool, optional
            If True, recalculate even if cached data exists. Default is False
        save_cache : bool, optional
            If True, save results to cache file after calculation. Default is True
        cache_file : str, optional
            Path to cache file. If None, uses default naming based on parameters
        
        Returns
        -------
        dict
            Clustering analysis results. Structure depends on xy_grid_size:
            
            If xy_grid_size is None (default):
                - Returns 1D arrays vs z for each metric
                - Keys: 'average_cluster_size', 'fraction_clustered', etc.
                - Values: dict[ion_type] = array(n_slices)
            
            If xy_grid_size is provided:
                - Returns 3D arrays (z, x, y) for spatial analysis
                - Additional keys: 'x_edges', 'y_edges', 'xy_grid_spacing'
                - Values: dict[ion_type] = array(n_slices, nx, ny)
        
        Notes
        -----
        Distance Mode:
            - '3D' (recommended): Uses full 3D distance for physically correct clustering.
              Two ions cluster if sqrt(dx² + dy² + dz²) <= cluster_cutoff
            - '2D-XY': Uses only XY distance, ignoring Z separation.
              Two ions cluster if sqrt(dx² + dy²) <= cluster_cutoff
              Useful for strictly 2D systems or surface phenomena.
        
        Spatial Gridding:
            When xy_grid_size is provided, clusters are mapped to XY grid cells based on
            their center-of-mass positions. This enables identification of clustering hotspots.
        
        Results are cached for faster subsequent analysis.
        '''
        
        # Generate default cache filename if not provided
        if cache_file is None:
            traj_name = os.path.splitext(os.path.basename(self.trajectory_file))[0] if hasattr(self, 'trajectory_file') else 'trajectory'
            ion_str = '_'.join(ion_types[:3]) if ion_types else 'all'
            cache_file = f'ion_clustering_xy_cache_{traj_name}_cutoff{cluster_cutoff:.1f}_zslice{z_slice_width:.1f}.pkl'
        
        # Try to load from cache
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"Loading XY-plane clustering data from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify cache parameters match
                cache_params = cached_data.get('parameters', {})
                if (cache_params.get('cluster_cutoff') == cluster_cutoff and
                    cache_params.get('z_slice_width') == z_slice_width and
                    cache_params.get('distance_mode') == distance_mode and
                    cache_params.get('xy_grid_size') == xy_grid_size and
                    cache_params.get('z_min') == self.z_min and
                    cache_params.get('z_max') == self.z_max):
                    
                    self.results.ion_clustering_xy = cached_data['clustering_results']
                    print(f"✓ Successfully loaded cached XY-plane clustering data")
                    print(f"  Cache created: {cached_data.get('timestamp', 'unknown')}")
                    print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                    print(f"  Ion types: {', '.join(cached_data.get('ion_types', []))}")
                    return self.results.ion_clustering_xy
                else:
                    print("⚠ Cache parameters don't match, recalculating...")
            
            except Exception as e:
                print(f"⚠ Failed to load cache: {e}")
                print("Recalculating...")
        
        # If we get here, need to calculate
        print(f"Calculating ion clustering in XY planes...")
        print(f"Cluster cutoff: {cluster_cutoff} Å")
        print(f"Distance mode: {distance_mode}")
        print(f"Z-slice width: {z_slice_width} Å")
        if xy_grid_size is not None:
            print(f"XY grid size: {xy_grid_size} Å (spatial gridding enabled)")
        
        if ion_types is None:
            ion_types = list(self.cation_types.keys()) + list(self.anion_types.keys())
        
        # Define z-slices
        if z_slice_centers is None:
            # Auto-generate z-slices
            z_slice_centers = np.arange(self.z_min + z_slice_width/2, 
                                        self.z_max - z_slice_width/2, 
                                        z_slice_width)
        else:
            z_slice_centers = np.array(z_slice_centers)
        
        n_slices = len(z_slice_centers)
        
        print(f"Z-range: {self.z_min:.2f} to {self.z_max:.2f} Å")
        print(f"Number of z-slices: {n_slices}")
        print(f"Slice centers: {z_slice_centers[0]:.2f} to {z_slice_centers[-1]:.2f} Å")
        
        # Initialize results storage
        clustering_results = {
            'z_slice_centers': z_slice_centers,
            'z_slice_width': z_slice_width,
            'n_slices': n_slices,
            'cluster_cutoff': cluster_cutoff,
            'average_cluster_size': {},
            'fraction_clustered': {},
            'cluster_size_distribution': {},
            'cluster_density': {},  # clusters per area
            'largest_cluster_size': {}
        }
        
        # Initialize for each ion type
        for ion_type in ion_types:
            clustering_results['average_cluster_size'][ion_type] = np.zeros(n_slices)
            clustering_results['fraction_clustered'][ion_type] = np.zeros(n_slices)
            clustering_results['cluster_density'][ion_type] = np.zeros(n_slices)
            clustering_results['largest_cluster_size'][ion_type] = np.zeros(n_slices)
            clustering_results['cluster_size_distribution'][ion_type] = {}
        
        # Get z-offset for centering
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2
        
        # Get XY box dimensions for area calculation
        if self.universe.dimensions is not None:
            box_x = self.universe.dimensions[0]
            box_y = self.universe.dimensions[1]
            xy_area = box_x * box_y
        else:
            xy_area = 1.0  # Default if dimensions not available
        
        # Setup spatial grid if requested
        use_spatial_grid = xy_grid_size is not None
        if use_spatial_grid:
            nx = int(np.ceil(box_x / xy_grid_size))
            ny = int(np.ceil(box_y / xy_grid_size))
            x_edges = np.linspace(0, box_x, nx + 1)
            y_edges = np.linspace(0, box_y, ny + 1)
            x_centers = (x_edges[:-1] + x_edges[1:]) / 2
            y_centers = (y_edges[:-1] + y_edges[1:]) / 2
            print(f"Spatial grid: {nx} x {ny} cells")
            
            # Initialize 3D arrays for gridded data
            for ion_type in ion_types:
                clustering_results['average_cluster_size'][ion_type] = np.zeros((n_slices, nx, ny))
                clustering_results['fraction_clustered'][ion_type] = np.zeros((n_slices, nx, ny))
                clustering_results['cluster_density'][ion_type] = np.zeros((n_slices, nx, ny))
                clustering_results['largest_cluster_size'][ion_type] = np.zeros((n_slices, nx, ny))
                # Track counts for averaging
                clustering_results['_ion_counts'] = {ion_type: np.zeros((n_slices, nx, ny)) for ion_type in ion_types}
                clustering_results['_cluster_counts'] = {ion_type: np.zeros((n_slices, nx, ny)) for ion_type in ion_types}
            
            # Store grid info in results
            clustering_results['xy_grid_spacing'] = xy_grid_size
            clustering_results['x_edges'] = x_edges
            clustering_results['y_edges'] = y_edges
            clustering_results['x_centers'] = x_centers
            clustering_results['y_centers'] = y_centers
        else:
            # Initialize 1D arrays for z-profile data (original behavior)
            for ion_type in ion_types:
                clustering_results['average_cluster_size'][ion_type] = np.zeros(n_slices)
                clustering_results['fraction_clustered'][ion_type] = np.zeros(n_slices)
                clustering_results['cluster_density'][ion_type] = np.zeros(n_slices)
                clustering_results['largest_cluster_size'][ion_type] = np.zeros(n_slices)
        
        # Determine which frames to analyze
        total_frames = len(self.universe.trajectory)
        
        if step is not None:
            frame_indices = np.arange(0, total_frames, step)
            print(f"Analyzing every {step} frames: {len(frame_indices)} frames total")
        else:
            if n_frames_sample is None:
                n_frames_sample = 3
            frame_indices = np.linspace(0, total_frames - 1, 
                                        min(n_frames_sample, total_frames), dtype=int)
            print(f"Analyzing {len(frame_indices)} evenly sampled frames")
        
        print(f"Processing {len(frame_indices)} out of {total_frames} total frames...")
        
        for frame_idx in frame_indices:
            self.universe.trajectory[frame_idx]
            
            for ion_type in ion_types:
                # Get ion group
                if ion_type in self.cation_types:
                    ion_group = self.cation_types[ion_type]
                elif ion_type in self.anion_types:
                    ion_group = self.anion_types[ion_type]
                else:
                    continue
                
                if len(ion_group) == 0:
                    continue
                
                # Analyze clustering in each z-slice
                for z_idx, z_center in enumerate(z_slice_centers):
                    # Find ions in this z-slice
                    ions_in_slice = []
                    for ion in ion_group:
                        ion_z = ion.position[2] - z_offset
                        if abs(ion_z - z_center) <= z_slice_width / 2:
                            ions_in_slice.append(ion)
                    
                    if len(ions_in_slice) < 2:
                        continue
                    
                    # Build clusters using XY-distance only
                    clustered = [False] * len(ions_in_slice)
                    clusters = []
                    
                    for i, ion1 in enumerate(ions_in_slice):
                        if clustered[i]:
                            continue
                        
                        # Start new cluster
                        cluster = [i]
                        clustered[i] = True
                        to_check = [i]
                        
                        while to_check:
                            current = to_check.pop(0)
                            current_ion = ions_in_slice[current]
                            
                            # Find neighbors based on distance mode
                            for j, ion2 in enumerate(ions_in_slice):
                                if clustered[j]:
                                    continue
                                
                                # Calculate distance based on mode
                                if distance_mode == '3D':
                                    # Use full 3D distance with PBC (recommended)
                                    distance = self._minimum_image_distance(
                                        current_ion.position, ion2.position)
                                elif distance_mode == '2D-XY':
                                    # Use XY-only distance, ignoring Z
                                    dx = current_ion.position[0] - ion2.position[0]
                                    dy = current_ion.position[1] - ion2.position[1]
                                    
                                    # Apply periodic boundary conditions in XY
                                    if self.universe.dimensions is not None:
                                        dx = dx - box_x * np.round(dx / box_x)
                                        dy = dy - box_y * np.round(dy / box_y)
                                    
                                    distance = np.sqrt(dx**2 + dy**2)
                                else:
                                    raise ValueError(f"Unknown distance_mode: {distance_mode}. Use '3D' or '2D-XY'")
                                
                                if distance <= cluster_cutoff:
                                    cluster.append(j)
                                    clustered[j] = True
                                    to_check.append(j)
                        
                        clusters.append(cluster)
                    
                    # Calculate statistics
                    if clusters:
                        cluster_sizes = [len(c) for c in clusters]
                        
                        if use_spatial_grid:
                            # Map clusters to spatial grid
                            for cluster_indices in clusters:
                                cluster_ions = [ions_in_slice[idx] for idx in cluster_indices]
                                cluster_size = len(cluster_ions)
                                
                                # Calculate cluster center-of-mass in XY
                                com_x = np.mean([ion.position[0] for ion in cluster_ions])
                                com_y = np.mean([ion.position[1] for ion in cluster_ions])
                                
                                # Apply PBC to COM
                                com_x = com_x % box_x
                                com_y = com_y % box_y
                                
                                # Find grid cell
                                grid_i = int(com_x / xy_grid_size)
                                grid_j = int(com_y / xy_grid_size)
                                
                                # Ensure within bounds
                                grid_i = np.clip(grid_i, 0, nx - 1)
                                grid_j = np.clip(grid_j, 0, ny - 1)
                                
                                # Accumulate cluster metrics in grid cell
                                clustering_results['average_cluster_size'][ion_type][z_idx, grid_i, grid_j] += cluster_size
                                clustering_results['_cluster_counts'][ion_type][z_idx, grid_i, grid_j] += 1
                                
                                # Track if cluster size > 1
                                if cluster_size > 1:
                                    clustering_results['fraction_clustered'][ion_type][z_idx, grid_i, grid_j] += cluster_size
                                    clustering_results['cluster_density'][ion_type][z_idx, grid_i, grid_j] += 1
                                
                                # Track largest cluster
                                clustering_results['largest_cluster_size'][ion_type][z_idx, grid_i, grid_j] = max(
                                    clustering_results['largest_cluster_size'][ion_type][z_idx, grid_i, grid_j],
                                    cluster_size
                                )
                                
                                # Count all ions in this grid cell
                                for ion in cluster_ions:
                                    ion_x = ion.position[0] % box_x
                                    ion_y = ion.position[1] % box_y
                                    ion_grid_i = int(ion_x / xy_grid_size)
                                    ion_grid_j = int(ion_y / xy_grid_size)
                                    ion_grid_i = np.clip(ion_grid_i, 0, nx - 1)
                                    ion_grid_j = np.clip(ion_grid_j, 0, ny - 1)
                                    clustering_results['_ion_counts'][ion_type][z_idx, ion_grid_i, ion_grid_j] += 1
                        
                        else:
                            # Original behavior: z-profile averaging
                            avg_size = np.mean(cluster_sizes)
                            max_size = np.max(cluster_sizes)
                            
                            # Fraction in clusters (size > 1)
                            n_clustered = sum(len(c) for c in clusters if len(c) > 1)
                            frac_clustered = n_clustered / len(ions_in_slice)
                            
                            # Cluster density (clusters per nm²)
                            n_clusters = len([c for c in clusters if len(c) > 1])
                            cluster_dens = n_clusters / (xy_area / 100.0)  # Convert Ų to nm²
                            
                            clustering_results['average_cluster_size'][ion_type][z_idx] += avg_size
                            clustering_results['fraction_clustered'][ion_type][z_idx] += frac_clustered
                            clustering_results['cluster_density'][ion_type][z_idx] += cluster_dens
                            clustering_results['largest_cluster_size'][ion_type][z_idx] = max(
                                clustering_results['largest_cluster_size'][ion_type][z_idx],
                                max_size
                            )
        
        # Average over frames and normalize
        n_frames = len(frame_indices)
        
        if use_spatial_grid:
            # Normalize gridded data
            cell_area_nm2 = (xy_grid_size / 10.0) ** 2  # Convert Ų to nm²
            
            for ion_type in ion_types:
                # Average cluster size: total size / n_clusters
                cluster_counts = clustering_results['_cluster_counts'][ion_type]
                mask = cluster_counts > 0
                clustering_results['average_cluster_size'][ion_type][mask] /= cluster_counts[mask]
                
                # Fraction clustered: clustered ions / total ions
                ion_counts = clustering_results['_ion_counts'][ion_type]
                mask = ion_counts > 0
                clustering_results['fraction_clustered'][ion_type][mask] /= ion_counts[mask]
                
                # Cluster density: clusters per frame per area
                clustering_results['cluster_density'][ion_type] /= (n_frames * cell_area_nm2)
                
                # Largest cluster size already tracked correctly (max, not sum)
            
            # Remove temporary count arrays
            del clustering_results['_ion_counts']
            del clustering_results['_cluster_counts']
        
        else:
            # Original z-profile averaging
            for ion_type in ion_types:
                clustering_results['average_cluster_size'][ion_type] /= n_frames
                clustering_results['fraction_clustered'][ion_type] /= n_frames
                clustering_results['cluster_density'][ion_type] /= n_frames
        
        self.results.ion_clustering_xy = clustering_results
        
        print(f"\n{'='*60}")
        print(f"XY-plane ion clustering analysis complete!")
        print(f"{'='*60}")
        print(f"Analysis parameters:")
        print(f"  Z-slice width: {z_slice_width} Å")
        print(f"  Number of z-slices: {n_slices}")
        print(f"  Cluster cutoff: {cluster_cutoff} Å")
        print(f"  Distance mode: {distance_mode}")
        if use_spatial_grid:
            print(f"  XY grid: {nx} x {ny} cells ({xy_grid_size} Å spacing)")
        print(f"  Frames analyzed: {n_frames}")
        print(f"\nResults:")
        print(f"  Ion types analyzed: {', '.join(ion_types)}")
        
        if use_spatial_grid:
            print(f"  Spatial gridding enabled - results are 3D arrays (z, x, y)")
            for ion_type in ion_types:
                # Report spatial statistics
                avg_cluster_size = np.mean(clustering_results['average_cluster_size'][ion_type])
                avg_fraction = np.mean(clustering_results['fraction_clustered'][ion_type])
                avg_density = np.mean(clustering_results['cluster_density'][ion_type])
                max_cluster = np.max(clustering_results['largest_cluster_size'][ion_type])
                print(f"  {ion_type}:")
                print(f"    Average cluster size: {avg_cluster_size:.2f}")
                print(f"    Average fraction clustered: {avg_fraction*100:.1f}%")
                print(f"    Average cluster density: {avg_density:.3f} clusters/nm²")
                print(f"    Largest cluster observed: {max_cluster:.0f} ions")
        else:
            for ion_type in ion_types:
                avg_cluster_size = np.mean(clustering_results['average_cluster_size'][ion_type])
                avg_fraction = np.mean(clustering_results['fraction_clustered'][ion_type])
                avg_density = np.mean(clustering_results['cluster_density'][ion_type])
                print(f"  {ion_type}:")
                print(f"    Average cluster size: {avg_cluster_size:.2f}")
                print(f"    Average fraction clustered: {avg_fraction*100:.1f}%")
                print(f"    Average cluster density: {avg_density:.3f} clusters/nm²")
        
        # Save to cache if requested
        if save_cache:
            try:
                from datetime import datetime
                
                cache_data = {
                    'clustering_results': clustering_results,
                    'parameters': {
                        'cluster_cutoff': cluster_cutoff,
                        'z_slice_width': z_slice_width,
                        'distance_mode': distance_mode,
                        'xy_grid_size': xy_grid_size,
                        'z_min': self.z_min,
                        'z_max': self.z_max,
                        'step': step,
                        'n_frames_sample': n_frames_sample
                    },
                    'ion_types': ion_types,
                    'n_frames': n_frames,
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'n_slices': n_slices
                }
                
                with open(cache_file, 'wb') as f:
                    pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size_kb = os.path.getsize(cache_file) / 1024
                print(f"\n✓ Saved XY-plane clustering data to cache: {cache_file}")
                print(f"  Cache size: {file_size_kb:.1f} KB")
            
            except Exception as e:
                print(f"\n⚠ Failed to save cache: {e}")
        else:
            print("\nCache saving skipped (save_cache=False)")
        
        return clustering_results



    def calculate_water_dipole_orientation_xy(self, 
                                            z_slice_centers=None,
                                            z_slice_width=2.0,
                                            xy_grid_size=0.5,
                                            step=1,
                                            orientation_metric='angle_to_z',
                                            gaussian_sigma=None,
                                            smoothing_method='none',
                                            water_vdw_radius=1.52,
                                            ellipse_aspect_ratio=2.0,
                                            molecular_vdw_radius=None,
                                            hydrogen_vdw_radius=1.2,
                                            xy_projection=False,  # 
                                            projection_method='elliptical',  
                                            projection_radius=2.8,  
                                            use_cache=True,
                                            cache_filename='water_dipole_xy_cache.npz',
                                            max_frames=None):
        """
        Calculate water dipole orientation in XY plane at different Z-slices
        with consistent grid data and coordinate arrays to fix heat map alignment issues.
        
        Parameters
        ----------
        z_slice_centers : list or None
            Z-positions for analysis slices (default: auto-detect from clay boundaries)
        z_slice_width : float
            Width of each z-slice (Å)
        xy_grid_size : float
            Grid spacing in XY plane (Å)
        step : int
            Frame sampling interval
        orientation_metric : str
            Type of orientation analysis:
            - 'angle_to_z': Average dipole angle relative to z-axis (0°-180°)
            - 'order_parameter': Orientational order parameter S = ⟨3cos²θ - 1⟩/2
            - 'vector_field': Average dipole vector components (x, y, z)
        gaussian_sigma : float, optional
            Gaussian smoothing parameter for final grids (applied after accumulation)
        smoothing_method : str
            Spatial smoothing method for dipole contributions:
            - 'none': No smoothing, point-based (default)
            - 'vdw': Van der Waals radius circular smoothing (oxygen only)
            - 'molecular_vdw': Effective molecular radius smoothing (all 3 atoms)
            - 'three_point': Three-point smoothing at O and 2H positions
            - 'elliptical': Dipole-oriented elliptical smoothing
        water_vdw_radius : float
            Van der Waals radius for oxygen (Å), default=1.52
        ellipse_aspect_ratio : float
            Ratio of major to minor axis for elliptical smoothing, default=2.0
        molecular_vdw_radius : float, optional
            Effective molecular radius for water molecule (Å). If None, auto-calculates
            based on O-H geometry. Default calculation gives ~2.4-2.5 Å
        hydrogen_vdw_radius : float
            Van der Waals radius for hydrogen (Å), default=1.2
        xy_projection : bool
            Whether to project molecular footprint onto XY plane, default=False
        projection_method : str
            Method for XY projection (when xy_projection=True):
            - 'circular': Simple circular footprint with projection_radius
            - 'elliptical': Dipole-oriented elliptical footprint (most physical)
            - 'three_atom': Project all three atoms individually (most accurate)
        projection_radius : float
            Effective radius for circular projection (Å), default=2.8
            For elliptical: minor axis radius; major axis = projection_radius * ellipse_aspect_ratio
        use_cache : bool
            Whether to use cached data if available
        cache_filename : str
            Name of cache file
        max_frames : int, optional
            Maximum number of frames to analyze
        
        Returns
        -------
        dict : Results containing orientation grids for each z-slice with consistent coordinates
        """
        
        print(f"\n{'='*60}")
        print(f"WATER DIPOLE ORIENTATION XY ANALYSIS")
        print(f"{'='*60}")
        
        # Validate parameters
        valid_metrics = ['angle_to_z', 'order_parameter', 'vector_field']
        if orientation_metric not in valid_metrics:
            raise ValueError(f"orientation_metric must be one of {valid_metrics}")
        
        valid_smoothing = ['none', 'vdw', 'molecular_vdw', 'three_point', 'elliptical']
        if smoothing_method not in valid_smoothing:
            raise ValueError(f"smoothing_method must be one of {valid_smoothing}")
        
        valid_projection = ['circular', 'elliptical', 'three_atom']
        if xy_projection and projection_method not in valid_projection:
            raise ValueError(f"projection_method must be one of {valid_projection}")
        
        # Calculate effective molecular radius if not provided
        if molecular_vdw_radius is None:
            oh_bond_length = 0.96  # Å
            molecular_vdw_radius = water_vdw_radius + oh_bond_length + hydrogen_vdw_radius
            
            print(f"🧮 Auto-calculated molecular VdW radius: {molecular_vdw_radius:.2f} Å")
            print(f"   Components: O_vdw({water_vdw_radius}) + O-H({oh_bond_length}) + H_vdw({hydrogen_vdw_radius})")
        else:
            print(f"🧮 Using provided molecular VdW radius: {molecular_vdw_radius:.2f} Å")
        
        print(f"\n📊 Configuration:")
        print(f"  Orientation metric: {orientation_metric}")
        
        # Display method information
        if xy_projection:
            print(f"  XY Projection: ENABLED ({projection_method.upper()})")
            if projection_method == 'circular':
                print(f"    Projection radius: {projection_radius:.2f} Å")
                print(f"    Projected area: {np.pi * projection_radius**2:.1f} Å²")
            elif projection_method == 'elliptical':
                major_axis = projection_radius * ellipse_aspect_ratio
                print(f"    Minor axis: {projection_radius:.2f} Å")
                print(f"    Major axis: {major_axis:.2f} Å (aspect ratio: {ellipse_aspect_ratio})")
                print(f"    Projected area: {np.pi * projection_radius * major_axis:.1f} Å²")
            elif projection_method == 'three_atom':
                print(f"    O projection: {water_vdw_radius:.2f} Å radius")
                print(f"    H projection: {hydrogen_vdw_radius:.2f} Å radius each")
                print(f"    Most physically accurate method")
        else:
            print(f"  Smoothing method: {smoothing_method.upper()}")
            if smoothing_method == 'molecular_vdw':
                print(f"    Molecular VdW radius: {molecular_vdw_radius:.2f} Å")
            elif smoothing_method == 'three_point':
                print(f"    Three-point smoothing: O({water_vdw_radius:.2f}Å) + 2H({hydrogen_vdw_radius:.2f}Å)")
            elif smoothing_method == 'vdw':
                print(f"    Oxygen VdW radius: {water_vdw_radius:.2f} Å")
        
        print(f"  Z-slice width: {z_slice_width:.2f} Å")
        print(f"  XY grid size: {xy_grid_size:.2f} Å")
        print(f"  Frame sampling: every {step} frame(s)")
        
        # Check cache
        cache_exists = os.path.exists(cache_filename)
        _cache_base_results = None  # Will hold previously computed slices to merge with new ones

        if use_cache and cache_exists:
            print(f"\n📦 Loading from cache: {cache_filename}")
            try:
                cache_data = np.load(cache_filename, allow_pickle=True)
                cached_params = cache_data['parameters'].item()

                # Compare only non-spatial parameters (z_slice_centers excluded intentionally)
                non_spatial_match = (
                    cached_params.get('z_slice_width') == z_slice_width and
                    cached_params.get('xy_grid_size') == xy_grid_size and
                    cached_params.get('orientation_metric') == orientation_metric and
                    cached_params.get('smoothing_method') == smoothing_method and
                    cached_params.get('xy_projection', False) == xy_projection and
                    cached_params.get('projection_method', 'elliptical') == projection_method and
                    abs(cached_params.get('projection_radius', 2.8) - projection_radius) < 0.01
                )

                if non_spatial_match:
                    print("✓ Non-spatial parameters match - checking z-slice coverage...")
                    _cache_base_results = cache_data['results'].item()
                else:
                    print("⚠ Cache parameters don't match - recalculating all z-slices")
            except Exception as e:
                print(f"⚠ Error loading cache: {e} - recalculating")
        
        # Determine z-slice centers
        if z_slice_centers is None:
            print("\n🔍 Auto-detecting z-slice positions...")
            
            if hasattr(self.results, 'clay_interface_boundaries') and self.results.clay_interface_boundaries:
                boundaries = self.results.clay_interface_boundaries
                z_slice_centers = []
                
                print("  Using clay boundaries for slice positioning")
                
                for boundary_type in ['si_average_z_positive', 'si_average_z_negative',
                                    'mgo_average_z_positive', 'mgo_average_z_negative']:
                    if boundary_type in boundaries and boundaries[boundary_type] is not None:
                        z_val = boundaries[boundary_type]
                        for offset in [2, 5]:
                            if 'positive' in boundary_type:
                                z_slice_centers.append(z_val - offset)
                            else:
                                z_slice_centers.append(z_val + offset)
                
                z_slice_centers.append(0.0)
                z_slice_centers = sorted(list(set(z_slice_centers)))
            else:
                print("  No clay boundaries available - using z-range from system")
                z_min = self.z_min if hasattr(self, 'z_min') else -30
                z_max = self.z_max if hasattr(self, 'z_max') else 30
                n_slices = 7
                z_slice_centers = np.linspace(z_min + 5, z_max - 5, n_slices).tolist()
        
        z_slice_centers = np.array(z_slice_centers) if isinstance(z_slice_centers, list) else z_slice_centers
        print(f"\n🎯 Z-slice centers ({len(z_slice_centers)}): {[f'{z:.1f}' for z in z_slice_centers]}")

        # Smart incremental cache: determine which z-centers still need computing
        precomputed_slices = []
        z_centers_to_compute = list(z_slice_centers)

        if _cache_base_results is not None:
            _z_tol = 0.01  # Å tolerance for matching z-centers
            cached_z_list = [s['z_center'] for s in _cache_base_results.get('z_slices', [])]
            missing_z = [z for z in z_centers_to_compute
                         if not any(abs(z - cz) < _z_tol for cz in cached_z_list)]
            found_z   = [z for z in z_centers_to_compute
                         if     any(abs(z - cz) < _z_tol for cz in cached_z_list)]

            if not missing_z:
                print(f"✓ All {len(z_centers_to_compute)} requested z-center(s) found in cache - returning cached data")
                requested_slices = sorted(
                    [s for s in _cache_base_results['z_slices']
                     if any(abs(s['z_center'] - z) < _z_tol for z in z_slice_centers)],
                    key=lambda s: s['z_center']
                )
                _cache_base_results['z_slices'] = requested_slices
                self.results.water_dipole_xy = _cache_base_results
                return _cache_base_results
            else:
                print(f"✓ {len(found_z)} z-center(s) reused from cache, "
                      f"{len(missing_z)} new z-center(s) to compute: {[f'{z:.2f}' for z in missing_z]}")
                precomputed_slices = [s for s in _cache_base_results['z_slices']
                                      if any(abs(s['z_center'] - z) < _z_tol for z in found_z)]
                z_centers_to_compute = missing_z

        # Get box dimensions and create CONSISTENT XY grids
        box_x, box_y = self.universe.dimensions[0], self.universe.dimensions[1]
        
        # CRITICAL: Ensure grid covers EXACT box dimensions
        n_x = int(np.ceil(box_x / xy_grid_size))
        n_y = int(np.ceil(box_y / xy_grid_size))
        
        # Create coordinate arrays that EXACTLY match the grid dimensions
        x_edges = np.linspace(0, box_x, n_x + 1)
        y_edges = np.linspace(0, box_y, n_y + 1)
        
        # Grid centers for plotting - these MUST match the grid array indices
        x_centers = (x_edges[:-1] + x_edges[1:]) / 2
        y_centers = (y_edges[:-1] + y_edges[1:]) / 2
        
        # Create meshgrids for distance calculations
        X_grid, Y_grid = np.meshgrid(x_centers, y_centers)
        
        print(f"\n📐 Grid setup:")
        print(f"  XY box: {box_x:.2f} × {box_y:.2f} Å")
        print(f"  Grid dimensions: {n_x} × {n_y} bins")
        print(f"  X edges: {x_edges[0]:.2f} to {x_edges[-1]:.2f} Å")
        print(f"  Y edges: {y_edges[0]:.2f} to {y_edges[-1]:.2f} Å")
        
        # Initialize results storage with CONSISTENT coordinates
        results = {
            'z_slice_centers': z_slice_centers,
            'z_slice_width': z_slice_width,
            'x_centers': x_centers,
            'y_centers': y_centers,
            'x_edges': x_edges,
            'y_edges': y_edges,
            'box_dimensions': (box_x, box_y),
            'grid_dimensions': (n_x, n_y),
            'orientation_metric': orientation_metric,
            'smoothing_method': smoothing_method if not xy_projection else 'xy_projection',
            'xy_grid_size': xy_grid_size,
            'molecular_vdw_radius': molecular_vdw_radius,
            'hydrogen_vdw_radius': hydrogen_vdw_radius,
            'xy_projection': xy_projection,
            'projection_method': projection_method,
            'projection_radius': projection_radius,
            'z_slices': []
        }
        
        # Helper function: Calculate dipole vector
        def get_dipole_vector(water_atoms):
            """Calculate normalized dipole vector for water molecule (O→H direction: from H to O)"""
            try:
                O_atoms = water_atoms.select_atoms('name OW or name Ow')
                H_atoms = water_atoms.select_atoms('name HW* or name Hw*')
                
                if len(O_atoms) == 0 or len(H_atoms) < 2:
                    return None
                
                O_pos = O_atoms.positions[0]
                H_pos = H_atoms.positions[:2]  # First 2 hydrogens
                
                H_midpoint = np.mean(H_pos, axis=0)
                dipole = O_pos - H_midpoint
                
                norm = np.linalg.norm(dipole)
                if norm > 0:
                    return dipole / norm
                else:
                    return None
            except:
                return None
        
        # Helper function: Get all three atomic positions
        def get_water_atom_positions(water_atoms):
            """Get positions of oxygen and two hydrogens"""
            try:
                O_atoms = water_atoms.select_atoms('name OW or name Ow')
                H_atoms = water_atoms.select_atoms('name HW* or name Hw*')
                
                if len(O_atoms) == 0 or len(H_atoms) < 2:
                    return None
                
                O_pos = O_atoms.positions[0]
                H_pos = H_atoms.positions[:2]  # First 2 hydrogens
                
                return {
                    'O': O_pos,
                    'H1': H_pos[0],
                    'H2': H_pos[1]
                }
            except:
                return None
        
        # NEW: Helper function for XY projection
        def apply_xy_projection(dipole, water_molecule, O_pos, value):
            """Apply XY projection of molecular footprint"""
            x, y = O_pos[0] % box_x, O_pos[1] % box_y
            
            if projection_method == 'circular':
                # Simple circular projection
                dx = X_grid - x
                dy = Y_grid - y
                
                # Apply periodic boundary conditions
                dx = np.where(dx > box_x/2, dx - box_x, dx)
                dx = np.where(dx < -box_x/2, dx + box_x, dx)
                dy = np.where(dy > box_y/2, dy - box_y, dy)
                dy = np.where(dy < -box_y/2, dy + box_y, dy)
                
                distances = np.sqrt(dx**2 + dy**2)
                
                # Uniform distribution within projection radius
                weights = np.where(distances <= projection_radius, 1.0, 0.0)
                
                # Normalize by area
                total_weight = np.sum(weights)
                if total_weight > 0:
                    weights = weights / total_weight
                
            elif projection_method == 'elliptical':
                # Dipole-oriented elliptical projection
                dipole_xy = dipole[:2]
                dipole_xy_norm = np.linalg.norm(dipole_xy)
                
                if dipole_xy_norm < 0.01:
                    # Nearly vertical dipole - fallback to circular
                    dx = X_grid - x
                    dy = Y_grid - y
                    dx = dx - box_x * np.round(dx / box_x)
                    dy = dy - box_y * np.round(dy / box_y)
                    distances = np.sqrt(dx**2 + dy**2)
                    
                    weights = np.where(distances <= projection_radius, 1.0, 0.0)
                else:
                    # Dipole-oriented ellipse
                    dipole_xy_unit = dipole_xy / dipole_xy_norm
                    theta = np.arctan2(dipole_xy_unit[1], dipole_xy_unit[0])
                    
                    # Grid points relative to water
                    dx = X_grid - x
                    dy = Y_grid - y
                    
                    # Periodic boundaries
                    dx = dx - box_x * np.round(dx / box_x)
                    dy = dy - box_y * np.round(dy / box_y)
                    
                    # Rotate to ellipse coordinate system
                    cos_theta = np.cos(-theta)
                    sin_theta = np.sin(-theta)
                    
                    dx_rot = dx * cos_theta - dy * sin_theta
                    dy_rot = dx * sin_theta + dy * cos_theta
                    
                    # Ellipse parameters
                    a = projection_radius * ellipse_aspect_ratio  # Major axis (along dipole)
                    b = projection_radius  # Minor axis (perpendicular to dipole)
                    
                    # Uniform elliptical distribution
                    ellipse_dist = (dx_rot / a)**2 + (dy_rot / b)**2
                    weights = np.where(ellipse_dist <= 1.0, 1.0, 0.0)
                
                # Normalize by area
                total_weight = np.sum(weights)
                if total_weight > 0:
                    weights = weights / total_weight
            
            elif projection_method == 'three_atom':
                # Project all three atoms individually (most accurate)
                atom_positions = get_water_atom_positions(water_molecule)
                if atom_positions is None:
                    return np.zeros((n_y, n_x))
                
                # Define atomic radii for projection
                atom_radii = {
                    'O': water_vdw_radius,      # 1.52 Å
                    'H1': hydrogen_vdw_radius,  # 1.2 Å
                    'H2': hydrogen_vdw_radius   # 1.2 Å
                }
                
                # Define atomic weights (based on electron density)
                atom_weights = {
                    'O': 8.0,   # 8 electrons
                    'H1': 1.0,  # 1 electron
                    'H2': 1.0   # 1 electron
                }
                
                total_weights = np.zeros((n_y, n_x))
                total_weight_sum = 0.0
                
                for atom_name, atom_pos in atom_positions.items():
                    atom_x, atom_y = atom_pos[0] % box_x, atom_pos[1] % box_y
                    atom_radius = atom_radii[atom_name]
                    atom_weight = atom_weights[atom_name]
                    
                    # Calculate distances from this atom to all grid points
                    dx = X_grid - atom_x
                    dy = Y_grid - atom_y
                    
                    # Apply periodic boundary conditions
                    dx = np.where(dx > box_x/2, dx - box_x, dx)
                    dx = np.where(dx < -box_x/2, dx + box_x, dx)
                    dy = np.where(dy > box_y/2, dy - box_y, dy)
                    dy = np.where(dy < -box_y/2, dy + box_y, dy)
                    
                    distances = np.sqrt(dx**2 + dy**2)
                    
                    # Uniform distribution within atomic radius
                    atom_contribution = np.where(distances <= atom_radius, atom_weight, 0.0)
                    
                    total_weights += atom_contribution
                    total_weight_sum += atom_weight
                
                # Normalize by total atomic weight
                weights = total_weights / total_weight_sum if total_weight_sum > 0 else total_weights
            
            return weights
        
        # Get z-offset for centering
        z_offset = 0
        if self.center_box and self.universe.dimensions is not None:
            z_offset = self.universe.dimensions[2] / 2

        # Process each z-slice (only missing ones when using incremental cache)
        for z_idx, z_center in enumerate(z_centers_to_compute):
            print(f"\n🔍 Processing z-slice {z_idx + 1}/{len(z_centers_to_compute)}: z = {z_center:.2f} Å...")

            z_min_slice = z_center - z_slice_width / 2
            z_max_slice = z_center + z_slice_width / 2

            # Initialize grids with EXACT dimensions matching coordinates
            if orientation_metric == 'angle_to_z':
                orientation_grid = np.zeros((n_y, n_x))  # Note: (y, x) for image convention
                count_grid = np.zeros((n_y, n_x))
            elif orientation_metric == 'order_parameter':
                orientation_grid = np.zeros((n_y, n_x))
                count_grid = np.zeros((n_y, n_x))
            elif orientation_metric == 'vector_field':
                vector_x_grid = np.zeros((n_y, n_x))
                vector_y_grid = np.zeros((n_y, n_x))
                vector_z_grid = np.zeros((n_y, n_x))
                count_grid = np.zeros((n_y, n_x))
            
            frame_count = 0
            
            # Loop through trajectory with frame limit
            for ts in tqdm(self.universe.trajectory[::step], 
                        desc=f"  Frames (z={z_center:.1f})"):
                
                if max_frames is not None and frame_count >= max_frames:
                    break
                
                # Get water oxygen atoms in this z-slice
                water_oxygens = self.waters.select_atoms('name OW or name Ow')
                if len(water_oxygens) == 0:
                    continue
                
                water_positions = water_oxygens.positions
                z_positions = water_positions[:, 2] - z_offset
                
                # Select waters in z-slice
                in_slice = (z_positions >= z_min_slice) & (z_positions < z_max_slice)
                
                if not np.any(in_slice):
                    continue
                
                water_indices_in_slice = np.where(in_slice)[0]
                
                # Process each water molecule in slice
                for water_idx in water_indices_in_slice:
                    oxygen = water_oxygens[water_idx]
                    water_resid = oxygen.resid
                    
                    # Get full water molecule
                    water_molecule = self.waters.select_atoms(f'resid {water_resid}')
                    if len(water_molecule) < 3:
                        continue
                    
                    # Calculate dipole vector
                    dipole = get_dipole_vector(water_molecule)
                    if dipole is None:
                        continue
                    
                    # Get oxygen XY position
                    O_pos = oxygen.position
                    x, y = O_pos[0], O_pos[1]
                    
                    # Apply periodic boundary conditions
                    x = x % box_x
                    y = y % box_y
                    
                    # Calculate orientation value based on metric
                    if orientation_metric == 'angle_to_z':
                        cos_theta = np.clip(dipole[2], -1, 1)
                        angle = np.degrees(np.arccos(cos_theta))
                        value = angle
                    elif orientation_metric == 'order_parameter':
                        cos_theta = dipole[2]
                        value = 1.5 * cos_theta**2 - 0.5
                    elif orientation_metric == 'vector_field':
                        # Will handle separately
                        pass
                    
                    # Apply spatial method or projection
                    if xy_projection:
                        # NEW: Apply XY projection
                        weights = apply_xy_projection(dipole, water_molecule, O_pos, value)
                        
                        if orientation_metric == 'vector_field':
                            vector_x_grid += dipole[0] * weights
                            vector_y_grid += dipole[1] * weights
                            vector_z_grid += dipole[2] * weights
                            count_grid += weights
                        else:
                            orientation_grid += value * weights
                            count_grid += weights
                    
                    else:
                        # Existing smoothing methods (unchanged)
                        if smoothing_method == 'none':
                            # Point-based assignment with CONSISTENT binning
                            x_idx = np.digitize(x, x_edges) - 1
                            y_idx = np.digitize(y, y_edges) - 1
                            
                            # Ensure indices are within bounds
                            x_idx = np.clip(x_idx, 0, n_x - 1)
                            y_idx = np.clip(y_idx, 0, n_y - 1)
                            
                            if orientation_metric == 'vector_field':
                                vector_x_grid[y_idx, x_idx] += dipole[0]
                                vector_y_grid[y_idx, x_idx] += dipole[1]
                                vector_z_grid[y_idx, x_idx] += dipole[2]
                                count_grid[y_idx, x_idx] += 1
                            else:
                                orientation_grid[y_idx, x_idx] += value
                                count_grid[y_idx, x_idx] += 1
                        
                        elif smoothing_method == 'vdw':
                            # Van der Waals radius smoothing (OXYGEN ONLY - original method)
                            dx = X_grid - x
                            dy = Y_grid - y
                            
                            # Apply periodic boundary conditions for distances
                            dx = np.where(dx > box_x/2, dx - box_x, dx)
                            dx = np.where(dx < -box_x/2, dx + box_x, dx)
                            dy = np.where(dy > box_y/2, dy - box_y, dy)
                            dy = np.where(dy < -box_y/2, dy + box_y, dy)
                            
                            distances = np.sqrt(dx**2 + dy**2)
                            
                            # Gaussian weight distribution using oxygen VdW radius
                            sigma = water_vdw_radius
                            weights = np.exp(-0.5 * (distances / sigma)**2)
                            
                            # Apply cutoff (3σ)
                            cutoff_mask = distances <= 3 * sigma
                            weights = weights * cutoff_mask
                            
                            if orientation_metric == 'vector_field':
                                vector_x_grid += dipole[0] * weights
                                vector_y_grid += dipole[1] * weights
                                vector_z_grid += dipole[2] * weights
                                count_grid += weights
                            else:
                                orientation_grid += value * weights
                                count_grid += weights
                        
                        elif smoothing_method == 'molecular_vdw':
                            # Molecular VdW radius smoothing (ALL 3 ATOMS CONSIDERED)
                            dx = X_grid - x
                            dy = Y_grid - y
                            
                            # Apply periodic boundary conditions for distances
                            dx = np.where(dx > box_x/2, dx - box_x, dx)
                            dx = np.where(dx < -box_x/2, dx + box_x, dx)
                            dy = np.where(dy > box_y/2, dy - box_y, dy)
                            dy = np.where(dy < -box_y/2, dy + box_y, dy)
                            
                            distances = np.sqrt(dx**2 + dy**2)
                            
                            # Gaussian weight distribution using MOLECULAR VdW radius
                            sigma = molecular_vdw_radius
                            weights = np.exp(-0.5 * (distances / sigma)**2)
                            
                            # Apply cutoff (3σ) - this will be a larger area than oxygen-only
                            cutoff_mask = distances <= 3 * sigma
                            weights = weights * cutoff_mask
                            
                            if orientation_metric == 'vector_field':
                                vector_x_grid += dipole[0] * weights
                                vector_y_grid += dipole[1] * weights
                                vector_z_grid += dipole[2] * weights
                                count_grid += weights
                            else:
                                orientation_grid += value * weights
                                count_grid += weights
                        
                        elif smoothing_method == 'three_point':
                            # Three-point smoothing at O and 2H positions
                            atom_positions = get_water_atom_positions(water_molecule)
                            if atom_positions is None:
                                continue
                            
                            # Define atomic weights (based on physical/chemical importance)
                            atom_weights = {
                                'O': 2.0,   # Higher weight for oxygen
                                'H1': 0.5,  # Lower weight for hydrogens
                                'H2': 0.5
                            }
                            
                            # Define VdW radii for each atom type
                            atom_radii = {
                                'O': water_vdw_radius,      # 1.52 Å
                                'H1': hydrogen_vdw_radius,  # 1.2 Å
                                'H2': hydrogen_vdw_radius   # 1.2 Å
                            }
                            
                            # Apply smoothing at each atomic position
                            total_contribution = np.zeros((n_y, n_x))
                            total_weight = 0.0
                            
                            for atom_name, atom_pos in atom_positions.items():
                                atom_x, atom_y = atom_pos[0] % box_x, atom_pos[1] % box_y
                                atom_weight = atom_weights[atom_name]
                                atom_radius = atom_radii[atom_name]
                                
                                # Calculate distances from this atom to all grid points
                                dx = X_grid - atom_x
                                dy = Y_grid - atom_y
                                
                                # Apply periodic boundary conditions
                                dx = np.where(dx > box_x/2, dx - box_x, dx)
                                dx = np.where(dx < -box_x/2, dx + box_x, dx)
                                dy = np.where(dy > box_y/2, dy - box_y, dy)
                                dy = np.where(dy < -box_y/2, dy + box_y, dy)
                                
                                distances = np.sqrt(dx**2 + dy**2)
                                
                                # Gaussian distribution with atom-specific radius
                                sigma = atom_radius
                                atom_contribution = np.exp(-0.5 * (distances / sigma)**2)
                                
                                # Apply cutoff (3σ)
                                cutoff_mask = distances <= 3 * sigma
                                atom_contribution = atom_contribution * cutoff_mask
                                
                                # Weight by atomic importance
                                total_contribution += atom_weight * atom_contribution
                                total_weight += atom_weight
                            
                            # Normalize by total weight
                            if total_weight > 0:
                                weights = total_contribution / total_weight
                                
                                if orientation_metric == 'vector_field':
                                    vector_x_grid += dipole[0] * weights
                                    vector_y_grid += dipole[1] * weights
                                    vector_z_grid += dipole[2] * weights
                                    count_grid += weights
                                else:
                                    orientation_grid += value * weights
                                    count_grid += weights
                        
                        elif smoothing_method == 'elliptical':
                            # Elliptical dipole-oriented smoothing
                            dipole_xy = dipole[:2]
                            dipole_xy_norm = np.linalg.norm(dipole_xy)
                            
                            if dipole_xy_norm < 0.01:
                                # Nearly vertical dipole - fallback to circular
                                dx = X_grid - x
                                dy = Y_grid - y
                                dx = dx - box_x * np.round(dx / box_x)
                                dy = dy - box_y * np.round(dy / box_y)
                                distances = np.sqrt(dx**2 + dy**2)
                                
                                sigma = water_vdw_radius
                                weights = np.exp(-0.5 * (distances / sigma)**2)
                                cutoff_mask = distances <= 3 * sigma
                                weights = weights * cutoff_mask
                            else:
                                # Dipole-oriented ellipse
                                dipole_xy_unit = dipole_xy / dipole_xy_norm
                                theta = np.arctan2(dipole_xy_unit[1], dipole_xy_unit[0])
                                
                                # Grid points relative to water
                                dx = X_grid - x
                                dy = Y_grid - y
                                
                                # Periodic boundaries
                                dx = dx - box_x * np.round(dx / box_x)
                                dy = dy - box_y * np.round(dy / box_y)
                                
                                # Rotate to ellipse coordinate system
                                cos_theta = np.cos(-theta)
                                sin_theta = np.sin(-theta)
                                
                                dx_rot = dx * cos_theta - dy * sin_theta
                                dy_rot = dx * sin_theta + dy * cos_theta
                                
                                # Ellipse parameters
                                a = water_vdw_radius * ellipse_aspect_ratio  # Major axis
                                b = water_vdw_radius  # Minor axis
                                
                                # Elliptical Gaussian
                                weights = np.exp(-0.5 * ((dx_rot / a)**2 + (dy_rot / b)**2))
                                
                                # Elliptical cutoff
                                ellipse_dist = np.sqrt((dx_rot / (3*a))**2 + (dy_rot / (3*b))**2)
                                cutoff_mask = ellipse_dist <= 1.0
                                weights = weights * cutoff_mask
                            
                            if orientation_metric == 'vector_field':
                                vector_x_grid += dipole[0] * weights
                                vector_y_grid += dipole[1] * weights
                                vector_z_grid += dipole[2] * weights
                                count_grid += weights
                            else:
                                orientation_grid += value * weights
                                count_grid += weights
                
                frame_count += 1
            
            print(f"  ✓ Analyzed {frame_count} frames")
            
            # Calculate final grids and apply post-smoothing if requested
            if orientation_metric in ['angle_to_z', 'order_parameter']:
                grid_final = np.zeros((n_y, n_x))
                valid_mask = count_grid > 0
                grid_final[valid_mask] = orientation_grid[valid_mask] / count_grid[valid_mask]
                
                # Apply Gaussian post-smoothing if requested
                if gaussian_sigma is not None:
                    from scipy.ndimage import gaussian_filter
                    grid_final = gaussian_filter(grid_final, sigma=gaussian_sigma)
                
                slice_data = {
                    'grid': grid_final,
                    'count_grid': count_grid,
                    'x_centers': x_centers,
                    'y_centers': y_centers,
                    'x_edges': x_edges,
                    'y_edges': y_edges,
                    'z_center': z_center,
                    'z_slice_width': z_slice_width,
                    'n_frames': frame_count,
                    'box_dimensions': (box_x, box_y),
                    'grid_dimensions': (n_x, n_y),
                    'orientation_metric': orientation_metric,
                    'smoothing_method': smoothing_method if not xy_projection else 'xy_projection',
                    'xy_projection': xy_projection,
                    'projection_method': projection_method,
                    'projection_radius': projection_radius,
                    'molecular_vdw_radius': molecular_vdw_radius,
                    'hydrogen_vdw_radius': hydrogen_vdw_radius
                }
                
                print(f"  📊 Statistics:")
                print(f"    Bins with data: {np.sum(valid_mask)} / {n_x*n_y}")
                if xy_projection:
                    print(f"    XY Projection: {projection_method}")
                    if projection_method == 'circular':
                        coverage = np.pi * projection_radius**2
                        print(f"    Coverage area: {coverage:.1f} Å² per water")
                    elif projection_method == 'elliptical':
                        coverage = np.pi * projection_radius * (projection_radius * ellipse_aspect_ratio)
                        print(f"    Coverage area: {coverage:.1f} Å² per water")
                    elif projection_method == 'three_atom':
                        print(f"    Three-atom projection with individual radii")
                
                if orientation_metric == 'angle_to_z' and np.sum(valid_mask) > 0:
                    print(f"    Mean angle: {np.mean(grid_final[valid_mask]):.1f}°")
                    print(f"    Angle range: {np.min(grid_final[valid_mask]):.1f}° - {np.max(grid_final[valid_mask]):.1f}°")
                elif orientation_metric == 'order_parameter' and np.sum(valid_mask) > 0:
                    print(f"    Mean S: {np.mean(grid_final[valid_mask]):.3f}")
            
            elif orientation_metric == 'vector_field':
                valid_mask = count_grid > 0
                
                grid_vx = np.zeros((n_y, n_x))
                grid_vy = np.zeros((n_y, n_x))
                grid_vz = np.zeros((n_y, n_x))
                
                grid_vx[valid_mask] = vector_x_grid[valid_mask] / count_grid[valid_mask]
                grid_vy[valid_mask] = vector_y_grid[valid_mask] / count_grid[valid_mask]
                grid_vz[valid_mask] = vector_z_grid[valid_mask] / count_grid[valid_mask]
                
                # Apply post-smoothing if requested
                if gaussian_sigma is not None:
                    from scipy.ndimage import gaussian_filter
                    grid_vx = gaussian_filter(grid_vx, sigma=gaussian_sigma)
                    grid_vy = gaussian_filter(grid_vy, sigma=gaussian_sigma)
                    grid_vz = gaussian_filter(grid_vz, sigma=gaussian_sigma)
                
                slice_data = {
                    'vector_x': grid_vx,
                    'vector_y': grid_vy,
                    'vector_z': grid_vz,
                    'count_grid': count_grid,
                    'x_centers': x_centers,
                    'y_centers': y_centers,
                    'x_edges': x_edges,
                    'y_edges': y_edges,
                    'z_center': z_center,
                    'z_slice_width': z_slice_width,
                    'n_frames': frame_count,
                    'box_dimensions': (box_x, box_y),
                    'grid_dimensions': (n_x, n_y),
                    'orientation_metric': orientation_metric,
                    'smoothing_method': smoothing_method if not xy_projection else 'xy_projection',
                    'xy_projection': xy_projection,
                    'projection_method': projection_method,
                    'projection_radius': projection_radius,
                    'molecular_vdw_radius': molecular_vdw_radius,
                    'hydrogen_vdw_radius': hydrogen_vdw_radius
                }
                
                print(f"  📊 Statistics:")
                print(f"    Bins with data: {np.sum(valid_mask)} / {n_x*n_y}")
                if xy_projection:
                    print(f"    XY Projection: {projection_method}")
                if np.sum(valid_mask) > 0:
                    magnitude = np.sqrt(grid_vx**2 + grid_vy**2 + grid_vz**2)
                    print(f"    Mean vector magnitude: {np.mean(magnitude[valid_mask]):.3f}")
            
            # Store slice data
            results['z_slices'].append(slice_data)

        # Merge newly computed slices with any precomputed ones from cache
        results['z_slices'] = sorted(
            precomputed_slices + results['z_slices'],
            key=lambda s: s['z_center']
        )
        results['z_slice_centers'] = np.array([s['z_center'] for s in results['z_slices']])

        # Store results
        self.results.water_dipole_xy = results

        # Save cache
        print(f"\n💾 Saving to cache: {cache_filename}")
        try:
            np.savez(cache_filename,
                    parameters={'z_slice_width': z_slice_width,
                            'xy_grid_size': xy_grid_size,
                            'orientation_metric': orientation_metric,
                            'smoothing_method': smoothing_method,
                            'water_vdw_radius': water_vdw_radius,
                            'ellipse_aspect_ratio': ellipse_aspect_ratio,
                            'molecular_vdw_radius': molecular_vdw_radius,
                            'hydrogen_vdw_radius': hydrogen_vdw_radius,
                            'xy_projection': xy_projection,
                            'projection_method': projection_method,
                            'projection_radius': projection_radius},
                    results=results)
            print("✓ Cache saved successfully")
        except Exception as e:
            print(f"⚠ Warning: Could not save cache: {e}")
        
        print(f"\n{'='*60}")
        print(f"ANALYSIS COMPLETE")
        print(f"{'='*60}")
        print(f"✓ Water dipole orientation available for {len(results['z_slices'])} z-slices "
              f"({len(z_centers_to_compute)} newly computed, {len(precomputed_slices)} from cache)")
        print(f"✓ Grid dimensions: {n_x} × {n_y} bins")
        
        if xy_projection:
            print(f"✓ XY Projection applied: {projection_method}")
            if projection_method == 'circular':
                print(f"  → Circular footprint: {projection_radius:.2f} Å radius")
            elif projection_method == 'elliptical':
                print(f"  → Elliptical footprint: {projection_radius:.2f} × {projection_radius * ellipse_aspect_ratio:.2f} Å")
                print(f"  → Orientation-dependent molecular shape")
            elif projection_method == 'three_atom':
                print(f"  → Three-atom projection: O({water_vdw_radius:.2f}Å) + 2H({hydrogen_vdw_radius:.2f}Å)")
                print(f"  → Most physically accurate representation")
            print(f"  → Realistic 2D molecular footprint projected onto XY plane")
        else:
            print(f"✓ Smoothing method: {smoothing_method}")
        
        print(f"✓ Orientation metric: {orientation_metric}")
        
        return results


