    def calculate_water_spatial_distribution_xy(self, z_slice_centers=None, 
                                            z_slice_width=5.0,
                                            xy_grid_size=0.5,
                                            step=None, 
                                            n_frames_sample=3,
                                            use_vdw_radius=True,
                                            water_vdw_radius=1.52,
                                            use_dipole_orientation=False,
                                            dipole_footprint='ellipse',
                                            ellipse_aspect_ratio=2.0,
                                            # NEW projection parameters (keep your original parameters unchanged)
                                            use_xy_projection=False,
                                            projection_method='three_atom',
                                            projection_radius=2.8,
                                            hydrogen_vdw_radius=1.2,
                                            force_rerun=False, 
                                            save_cache=True, 
                                            cache_file=None):
        '''
        Calculate 2D spatial distribution of water molecules in XY plane at different Z-positions.
        
        Supports multiple modes:
        1. VdW radius mode (default): Uses oxygen Van der Waals radius
        2. Dipole orientation mode (advanced): Orients elliptical footprint along dipole vector
        3. XY Projection mode (NEW): Projects molecular footprint onto XY plane
        
        Parameters
        ----------
        z_slice_centers : array-like, optional
            Z-positions to analyze
        z_slice_width : float
            Thickness of Z-slice (Å), default=5.0
        xy_grid_size : float
            Grid spacing for XY binning (Å), default=0.5
        step : int, optional
            Analyze every nth frame
        n_frames_sample : int
            Number of frames to sample, default=3
        use_vdw_radius : bool
            If True, use oxygen VdW radius for circular footprint. Default=True
        water_vdw_radius : float
            Van der Waals radius for oxygen (Å), default=1.52
        use_dipole_orientation : bool
            If True, use dipole-oriented elliptical footprint (advanced mode). Default=False
            This takes precedence over use_vdw_radius
        dipole_footprint : str
            Type of dipole footprint: 'ellipse' or 'circle'. Default='ellipse'
            Only used if use_dipole_orientation=True
        ellipse_aspect_ratio : float
            Ratio of major to minor axis for elliptical footprint. Default=2.0
            Only used if use_dipole_orientation=True and dipole_footprint='ellipse'
        use_xy_projection : bool, NEW
            If True, use XY projection mode (most physically accurate). Default=False
            This takes precedence over all other modes
        projection_method : str, NEW
            XY projection method: 'circular', 'elliptical', 'three_atom'. Default='three_atom'
        projection_radius : float, NEW
            Effective radius for projection (Å), default=2.8
        hydrogen_vdw_radius : float, NEW
            VdW radius for hydrogen atoms (Å), default=1.2
        force_rerun : bool
            Force recalculation even if cache exists. Default=False
        save_cache : bool
            If True, save results to cache file. Default=True
        cache_file : str, optional
            Path to cache file. If None, auto-generates filename
        
        Returns
        -------
        dict with:
            - 'xy_grids': {z_idx: 2D histogram array}
            - 'x_edges', 'y_edges': Grid edges
            - 'z_slice_centers': Z-positions analyzed
            - 'mode': 'vdw_radius', 'dipole_circle', 'dipole_ellipse', or projection modes
            - 'parameters': Dictionary of used parameters
        
        Examples
        --------
        # Basic mode: Oxygen VdW radius
        >>> results = z_analysis.calculate_water_spatial_distribution_xy(
        ...     z_slice_centers=[10, -10],
        ...     use_vdw_radius=True
        ... )
        
        # Advanced mode: Dipole-oriented ellipse
        >>> results = z_analysis.calculate_water_spatial_distribution_xy(
        ...     z_slice_centers=[10, -10],
        ...     use_dipole_orientation=True,
        ...     dipole_footprint='ellipse',
        ...     ellipse_aspect_ratio=2.5
        ... )
        
        # NEW: XY Projection mode (most accurate)
        >>> results = z_analysis.calculate_water_spatial_distribution_xy(
        ...     z_slice_centers=[10, -10],
        ...     use_xy_projection=True,
        ...     projection_method='three_atom'
        ... )
        '''
        
        # Determine mode (KEEP YOUR EXACT LOGIC, just add projection check)
        if use_xy_projection:
            if projection_method == 'circular':
                mode = 'projection_circular'
            elif projection_method == 'elliptical':
                mode = 'projection_elliptical'
            elif projection_method == 'three_atom':
                mode = 'projection_three_atom'
            else:
                mode = 'projection_three_atom'  # default
        elif use_dipole_orientation:
            if dipole_footprint == 'ellipse':
                mode = 'dipole_ellipse'
            else:
                mode = 'dipole_circle'
        else:
            mode = 'vdw_radius'
        
        # Generate cache filename (KEEP YOUR EXACT LOGIC)
        if cache_file is None:
            mode_str = mode.replace('_', '')
            aspect_str = f'_aspect{ellipse_aspect_ratio:.1f}' if mode == 'dipole_ellipse' else ''
            step_str = f'_step{step}' if step else f'_n{n_frames_sample}'
            cache_file = f'water_spatial_xy_cache_{mode_str}_grid{xy_grid_size:.2f}{aspect_str}{step_str}.pkl'
        
        # Try to load from cache (incremental z-center logic)
        _cache_base_results = None  # Will hold cached data for merging if partial hit
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"Loading water spatial XY distribution from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify non-spatial cache parameters
                cache_params = cached_data.get('parameters', {})
                current_params = {
                    'z_slice_width': z_slice_width,
                    'xy_grid_size': xy_grid_size,
                    'mode': mode,
                    'water_vdw_radius': water_vdw_radius,
                    'ellipse_aspect_ratio': ellipse_aspect_ratio if mode == 'dipole_ellipse' else None
                }
                
                params_match = True
                for key, value in current_params.items():
                    cached_value = cache_params.get(key)
                    if isinstance(value, (int, float)) and cached_value is not None:
                        if abs(cached_value - value) > 1e-6:
                            params_match = False
                            break
                    elif cached_value != value:
                        params_match = False
                        break
                
                if params_match:
                    cached_results = cached_data['results']
                    cached_z_arr = np.array(cached_results.get('z_slice_centers', []))
                    
                    if z_slice_centers is not None:
                        _z_tol = 0.01  # Å tolerance
                        missing_z = [z for z in z_slice_centers
                                     if not any(abs(z - cz) < _z_tol for cz in cached_z_arr)]
                        found_z   = [z for z in z_slice_centers
                                     if     any(abs(z - cz) < _z_tol for cz in cached_z_arr)]
                        
                        if not missing_z:
                            print(f"✓ All {len(z_slice_centers)} z-center(s) found in cache — skipping computation")
                            print(f"  Mode: {cached_data.get('mode', 'unknown')}")
                            print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                            self.results.water_spatial_xy = cached_results
                            return self.results.water_spatial_xy
                        else:
                            print(f"✓ Found {len(found_z)} z-center(s) in cache, computing {len(missing_z)} missing")
                            _cache_base_results = cached_data
                            z_slice_centers = missing_z  # Only compute missing z-centers
                    else:
                        # z_slice_centers=None (auto-detect): can't do incremental, return full cache
                        print(f"✓ Successfully loaded cached water spatial XY distribution")
                        print(f"  Mode: {cached_data.get('mode', 'unknown')}")
                        print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                        self.results.water_spatial_xy = cached_results
                        return self.results.water_spatial_xy
                else:
                    print("⚠ Cache parameters don't match, recalculating...")
            
            except Exception as e:
                print(f"⚠ Failed to load cache: {e}")
                print("Recalculating...")
        
        # CALCULATION STARTS HERE (KEEP YOUR EXACT LAYOUT)
        print(f"\n{'='*60}")
        print(f"WATER SPATIAL DISTRIBUTION XY ANALYSIS")
        print(f"{'='*60}")
        print(f"Mode: {mode.replace('_', ' ').title()}")
        
        if mode == 'vdw_radius':
            print(f"Using oxygen VdW radius: {water_vdw_radius} Å")
        elif mode == 'dipole_circle':
            print(f"Using dipole-oriented circular footprint")
            print(f"Circle radius: {water_vdw_radius} Å")
        elif mode == 'dipole_ellipse':
            print(f"Using dipole-oriented elliptical footprint")
            print(f"Ellipse aspect ratio: {ellipse_aspect_ratio}")
            print(f"Minor axis: {water_vdw_radius} Å")
            print(f"Major axis: {water_vdw_radius * ellipse_aspect_ratio} Å")
        # NEW projection mode descriptions
        elif mode == 'projection_circular':
            print(f"Using XY projection: Circular footprint")
            print(f"Projection radius: {projection_radius} Å")
        elif mode == 'projection_elliptical':
            print(f"Using XY projection: Elliptical footprint (dipole-oriented)")
            print(f"Minor axis: {projection_radius} Å")
            print(f"Major axis: {projection_radius * ellipse_aspect_ratio} Å")
        elif mode == 'projection_three_atom':
            print(f"Using XY projection: Three-atom method (most accurate)")
            print(f"Oxygen VdW: {water_vdw_radius} Å, Hydrogen VdW: {hydrogen_vdw_radius} Å")
        
        # Define z-slices (KEEP YOUR EXACT LOGIC)
        if z_slice_centers is None:
            # Auto-detect from clay boundaries if available
            if hasattr(self.results, 'clay_interface_boundaries') and self.results.clay_interface_boundaries:
                boundaries = self.results.clay_interface_boundaries
                z_slice_centers = []
                
                for boundary_type in ['si_average_z_positive', 'si_average_z_negative',
                                    'mgo_average_z_positive', 'mgo_average_z_negative']:
                    if boundary_type in boundaries and boundaries[boundary_type] is not None:
                        z_val = boundaries[boundary_type]
                        z_slice_centers.extend([z_val - 3, z_val + 3])
                
                z_slice_centers.append(0.0)  # Center
                z_slice_centers = sorted(list(set(z_slice_centers)))
            else:
                # Fallback: regular spacing
                z_slice_centers = np.arange(self.z_min + z_slice_width/2, 
                                            self.z_max - z_slice_width/2, 
                                            z_slice_width)
        
        z_slice_centers = np.array(z_slice_centers)
        n_slices = len(z_slice_centers)
        
        print(f"\nZ-slices: {n_slices} slices")
        print(f"  Centers: {z_slice_centers[0]:.1f} to {z_slice_centers[-1]:.1f} Å")
        print(f"  Width: {z_slice_width} Å")
        
        # Get box dimensions (KEEP YOUR EXACT LOGIC)
        box_x = self.universe.dimensions[0]
        box_y = self.universe.dimensions[1]
        
        # Create XY grid (KEEP YOUR EXACT LOGIC)
        x_bins = np.arange(0, box_x + xy_grid_size, xy_grid_size)
        y_bins = np.arange(0, box_y + xy_grid_size, xy_grid_size)
        
        x_centers = (x_bins[:-1] + x_bins[1:]) / 2
        y_centers = (y_bins[:-1] + y_bins[1:]) / 2
        X_grid, Y_grid = np.meshgrid(x_centers, y_centers)
        
        print(f"\nXY grid: {len(x_centers)} × {len(y_centers)} bins")
        print(f"  Box size: {box_x:.1f} × {box_y:.1f} Å")
        print(f"  Grid spacing: {xy_grid_size} Å")
        
        # Initialize results (KEEP YOUR EXACT STRUCTURE)
        results = {
            'z_slice_centers': z_slice_centers,
            'z_slice_width': z_slice_width,
            'x_edges': x_bins,
            'y_edges': y_bins,
            'xy_grids': {},
            'box_x': box_x,
            'box_y': box_y,
            'mode': mode,
            'parameters': {
                'water_vdw_radius': water_vdw_radius,
                'use_dipole_orientation': use_dipole_orientation,
                'dipole_footprint': dipole_footprint if use_dipole_orientation else None,
                'ellipse_aspect_ratio': ellipse_aspect_ratio if mode == 'dipole_ellipse' else None,
                # NEW projection parameters
                'use_xy_projection': use_xy_projection,
                'projection_method': projection_method if use_xy_projection else None,
                'projection_radius': projection_radius if use_xy_projection else None,
                'hydrogen_vdw_radius': hydrogen_vdw_radius if use_xy_projection else None
            }
        }
        
        # Initialize grids (KEEP YOUR EXACT LOGIC)
        for z_idx in range(n_slices):
            results['xy_grids'][z_idx] = np.zeros((len(y_bins)-1, len(x_bins)-1))
        
        # Get z-offset (KEEP YOUR EXACT LOGIC)
        z_offset = self.universe.dimensions[2] / 2 if self.center_box else 0
        
        # Determine frames (KEEP YOUR EXACT LOGIC)
        total_frames = len(self.universe.trajectory)
        if step is not None:
            frame_indices = np.arange(0, total_frames, step)
        else:
            frame_indices = np.linspace(0, total_frames-1, 
                                    min(n_frames_sample, total_frames), dtype=int)
        
        print(f"\nAnalyzing {len(frame_indices)} frames...")
        
        # Helper function to get dipole vector (KEEP YOUR EXACT FUNCTION)
        def get_water_dipole(water_resid):
            """Get dipole vector for a water molecule (O→H direction: from H to O)"""
            water_mol = self.waters.select_atoms(f'resid {water_resid}')
            
            if len(water_mol) < 3:
                return None
            
            O_atoms = water_mol.select_atoms('name OW or name Ow')
            H_atoms = water_mol.select_atoms('name HW* or name Hw*')
            
            if len(O_atoms) == 0 or len(H_atoms) < 2:
                return None
            
            O_pos = O_atoms.positions[0]
            H_pos = H_atoms.positions[:2]  # First 2 hydrogens
            
            H_midpoint = np.mean(H_pos, axis=0)
            dipole = O_pos - H_midpoint
            
            norm = np.linalg.norm(dipole)
            if norm > 0:
                return dipole / norm
            return None
        
        # NEW helper function for water atom positions
        def get_water_atom_positions(water_resid):
            """Get positions of oxygen and two hydrogens"""
            water_mol = self.waters.select_atoms(f'resid {water_resid}')
            
            if len(water_mol) < 3:
                return None
            
            O_atoms = water_mol.select_atoms('name OW or name Ow')
            H_atoms = water_mol.select_atoms('name HW* or name Hw*')
            
            if len(O_atoms) == 0 or len(H_atoms) < 2:
                return None
            
            O_pos = O_atoms.positions[0]
            H_pos = H_atoms.positions[:2]  # First 2 hydrogens
            
            return {
                'O': O_pos,
                'H1': H_pos[0],
                'H2': H_pos[1]
            }
        
        # Process frames (KEEP YOUR EXACT STRUCTURE)
        for frame_idx in tqdm(frame_indices, desc="Processing frames"):
            self.universe.trajectory[frame_idx]
            
            # Get all water oxygen positions (KEEP YOUR EXACT LOGIC)
            water_oxygens = self.waters.select_atoms('name OW or name Ow')
            if len(water_oxygens) == 0:
                continue
            
            water_positions = water_oxygens.positions
            water_z = water_positions[:, 2] - z_offset
            
            # Process each z-slice (KEEP YOUR EXACT LOGIC)
            for z_idx, z_center in enumerate(z_slice_centers):
                # Select waters in this z-slice
                in_slice = np.abs(water_z - z_center) <= z_slice_width / 2
                
                if not np.any(in_slice):
                    continue
                
                waters_in_slice = water_oxygens[in_slice]
                xy_positions = water_positions[in_slice, :2]
                
                # Mode 1: Simple VdW radius (circular) - KEEP YOUR EXACT CODE
                if mode == 'vdw_radius':
                    for water_pos in xy_positions:
                        dx = X_grid - water_pos[0]
                        dy = Y_grid - water_pos[1]
                        
                        # Periodic boundaries
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        
                        distances = np.sqrt(dx**2 + dy**2)
                        
                        # Gaussian distribution within VdW radius
                        contribution = np.exp(-0.5 * (distances / water_vdw_radius)**2)
                        mask = contribution > 0.01
                        
                        results['xy_grids'][z_idx] += contribution * mask
                
                # Mode 2: Dipole-oriented circular footprint - KEEP YOUR EXACT CODE
                elif mode == 'dipole_circle':
                    for water_oxy in waters_in_slice:
                        water_pos = water_oxy.position[:2]  # XY only
                        
                        # Get dipole (for potential future use, though circle is isotropic)
                        dipole = get_water_dipole(water_oxy.resid)
                        
                        dx = X_grid - water_pos[0]
                        dy = Y_grid - water_pos[1]
                        
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        
                        distances = np.sqrt(dx**2 + dy**2)
                        contribution = np.exp(-0.5 * (distances / water_vdw_radius)**2)
                        mask = contribution > 0.01
                        
                        results['xy_grids'][z_idx] += contribution * mask
                
                # Mode 3: Dipole-oriented elliptical footprint - KEEP YOUR EXACT CODE
                elif mode == 'dipole_ellipse':
                    for water_oxy in waters_in_slice:
                        water_pos = water_oxy.position[:2]  # XY position
                        
                        # Get dipole vector
                        dipole = get_water_dipole(water_oxy.resid)
                        
                        if dipole is None:
                            # Fallback to circular if dipole unavailable
                            dx = X_grid - water_pos[0]
                            dy = Y_grid - water_pos[1]
                            dx = dx - box_x * np.round(dx / box_x)
                            dy = dy - box_y * np.round(dy / box_y)
                            distances = np.sqrt(dx**2 + dy**2)
                            contribution = np.exp(-0.5 * (distances / water_vdw_radius)**2)
                            mask = contribution > 0.01
                            results['xy_grids'][z_idx] += contribution * mask
                            continue
                        
                        # Get dipole orientation in XY plane
                        dipole_xy = dipole[:2]  # XY components
                        dipole_xy_norm = np.linalg.norm(dipole_xy)
                        
                        if dipole_xy_norm < 0.01:
                            # Dipole is mostly vertical, use circular
                            dx = X_grid - water_pos[0]
                            dy = Y_grid - water_pos[1]
                            dx = dx - box_x * np.round(dx / box_x)
                            dy = dy - box_y * np.round(dy / box_y)
                            distances = np.sqrt(dx**2 + dy**2)
                            contribution = np.exp(-0.5 * (distances / water_vdw_radius)**2)
                            mask = contribution > 0.01
                            results['xy_grids'][z_idx] += contribution * mask
                            continue
                        
                        # Normalize dipole in XY
                        dipole_xy = dipole_xy / dipole_xy_norm
                        
                        # Calculate rotation angle
                        theta = np.arctan2(dipole_xy[1], dipole_xy[0])
                        
                        # Grid points relative to water
                        dx = X_grid - water_pos[0]
                        dy = Y_grid - water_pos[1]
                        
                        # Periodic boundaries
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        
                        # Rotate to align with dipole (ellipse major axis along dipole)
                        cos_theta = np.cos(-theta)
                        sin_theta = np.sin(-theta)
                        
                        dx_rot = dx * cos_theta - dy * sin_theta
                        dy_rot = dx * sin_theta + dy * cos_theta
                        
                        # Ellipse parameters
                        a = water_vdw_radius * ellipse_aspect_ratio  # Major axis (along dipole)
                        b = water_vdw_radius  # Minor axis (perpendicular)
                        
                        # Distance in ellipse coordinates
                        ellipse_dist = np.sqrt((dx_rot / a)**2 + (dy_rot / b)**2)
                        
                        # Gaussian distribution along ellipse
                        contribution = np.exp(-0.5 * ellipse_dist**2)
                        mask = contribution > 0.01
                        
                        results['xy_grids'][z_idx] += contribution * mask
                
                # NEW Mode 4: Projection circular
                elif mode == 'projection_circular':
                    for water_oxy in waters_in_slice:
                        water_pos = water_oxy.position[:2]  # XY position
                        
                        dx = X_grid - water_pos[0]
                        dy = Y_grid - water_pos[1]
                        
                        # Periodic boundaries
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        
                        distances = np.sqrt(dx**2 + dy**2)
                        
                        # Uniform distribution within projection radius
                        mask = distances <= projection_radius
                        area = np.pi * projection_radius**2
                        
                        results['xy_grids'][z_idx] += mask / area
                
                # NEW Mode 5: Projection elliptical (dipole-oriented)
                elif mode == 'projection_elliptical':
                    for water_oxy in waters_in_slice:
                        water_pos = water_oxy.position[:2]  # XY position
                        
                        # Get dipole vector
                        dipole = get_water_dipole(water_oxy.resid)
                        
                        if dipole is None:
                            # Fallback to circular
                            dx = X_grid - water_pos[0]
                            dy = Y_grid - water_pos[1]
                            dx = dx - box_x * np.round(dx / box_x)
                            dy = dy - box_y * np.round(dy / box_y)
                            distances = np.sqrt(dx**2 + dy**2)
                            mask = distances <= projection_radius
                            area = np.pi * projection_radius**2
                            results['xy_grids'][z_idx] += mask / area
                            continue
                        
                        # Get dipole orientation in XY plane
                        dipole_xy = dipole[:2]
                        dipole_xy_norm = np.linalg.norm(dipole_xy)
                        
                        if dipole_xy_norm < 0.01:
                            # Vertical dipole, use circular
                            dx = X_grid - water_pos[0]
                            dy = Y_grid - water_pos[1]
                            dx = dx - box_x * np.round(dx / box_x)
                            dy = dy - box_y * np.round(dy / box_y)
                            distances = np.sqrt(dx**2 + dy**2)
                            mask = distances <= projection_radius
                            area = np.pi * projection_radius**2
                            results['xy_grids'][z_idx] += mask / area
                            continue
                        
                        # Dipole-oriented ellipse
                        dipole_xy_unit = dipole_xy / dipole_xy_norm
                        theta = np.arctan2(dipole_xy_unit[1], dipole_xy_unit[0])
                        
                        # Grid points relative to water
                        dx = X_grid - water_pos[0]
                        dy = Y_grid - water_pos[1]
                        
                        # Periodic boundaries
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        
                        # Rotate to ellipse coordinate system
                        cos_theta = np.cos(-theta)
                        sin_theta = np.sin(-theta)
                        
                        dx_rot = dx * cos_theta - dy * sin_theta
                        dy_rot = dx * sin_theta + dy * cos_theta
                        
                        # Ellipse parameters
                        a = projection_radius * ellipse_aspect_ratio  # Major axis
                        b = projection_radius  # Minor axis
                        
                        # Uniform elliptical distribution
                        ellipse_dist = (dx_rot / a)**2 + (dy_rot / b)**2
                        mask = ellipse_dist <= 1.0
                        area = np.pi * a * b
                        
                        results['xy_grids'][z_idx] += mask / area
                
                # NEW Mode 6: Three-atom projection (most accurate)
                elif mode == 'projection_three_atom':
                    for water_oxy in waters_in_slice:
                        # Get all three atomic positions
                        atom_positions = get_water_atom_positions(water_oxy.resid)
                        if atom_positions is None:
                            continue
                        
                        # Project each atom with its own VdW radius
                        atom_contributions = np.zeros_like(X_grid)
                        
                        # Oxygen contribution (weight = 8 electrons)
                        o_pos = atom_positions['O'][:2]  # XY only
                        dx = X_grid - o_pos[0]
                        dy = Y_grid - o_pos[1]
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        o_distances = np.sqrt(dx**2 + dy**2)
                        o_mask = o_distances <= water_vdw_radius
                        o_area = np.pi * water_vdw_radius**2
                        atom_contributions += 8.0 * o_mask / o_area
                        
                        # Hydrogen 1 contribution (weight = 1 electron)
                        h1_pos = atom_positions['H1'][:2]  # XY only
                        dx = X_grid - h1_pos[0]
                        dy = Y_grid - h1_pos[1]
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        h1_distances = np.sqrt(dx**2 + dy**2)
                        h1_mask = h1_distances <= hydrogen_vdw_radius
                        h1_area = np.pi * hydrogen_vdw_radius**2
                        atom_contributions += 1.0 * h1_mask / h1_area
                        
                        # Hydrogen 2 contribution (weight = 1 electron)
                        h2_pos = atom_positions['H2'][:2]  # XY only
                        dx = X_grid - h2_pos[0]
                        dy = Y_grid - h2_pos[1]
                        dx = dx - box_x * np.round(dx / box_x)
                        dy = dy - box_y * np.round(dy / box_y)
                        h2_distances = np.sqrt(dx**2 + dy**2)
                        h2_mask = h2_distances <= hydrogen_vdw_radius
                        h2_area = np.pi * hydrogen_vdw_radius**2
                        atom_contributions += 1.0 * h2_mask / h2_area
                        
                        # Normalize by total electron count (10 electrons)
                        results['xy_grids'][z_idx] += atom_contributions / 10.0
        
        # Average over frames (KEEP YOUR EXACT LOGIC)
        n_frames = len(frame_indices)
        for z_idx in range(n_slices):
            results['xy_grids'][z_idx] /= n_frames
        
        # Merge newly computed slices with any precomputed slices from cache
        if _cache_base_results is not None:
            cached_results = _cache_base_results['results']
            cached_z_arr = np.array(cached_results.get('z_slice_centers', []))
            _z_tol = 0.01
            # Collect all (z_center, grid) pairs
            all_slices = []
            for ci, cz in enumerate(cached_z_arr):
                all_slices.append((cz, cached_results['xy_grids'][ci]))
            for z_idx in range(n_slices):
                all_slices.append((results['z_slice_centers'][z_idx], results['xy_grids'][z_idx]))
            # Sort by z_center
            all_slices.sort(key=lambda s: s[0])
            results['z_slice_centers'] = np.array([s[0] for s in all_slices])
            results['xy_grids'] = {i: s[1] for i, s in enumerate(all_slices)}
            n_slices = len(all_slices)
            print(f"✓ Merged {len(cached_z_arr)} cached + {len(results['z_slice_centers']) - len(cached_z_arr)} new z-slices")
        
        # Store results (KEEP YOUR EXACT LOGIC)
        self.results.water_spatial_xy = results
        
        # Print summary (KEEP YOUR EXACT LAYOUT)
        print(f"\n{'='*60}")
        print(f"ANALYSIS COMPLETE")
        print(f"{'='*60}")
        print(f"✓ Water spatial distribution calculated")
        print(f"  Mode: {mode.replace('_', ' ').title()}")
        print(f"  Grid size: {xy_grid_size} Å")
        print(f"  XY dimensions: {box_x:.1f} × {box_y:.1f} Å")
        print(f"  Frames analyzed: {n_frames}")
        print(f"  Z-slices: {n_slices}")
        
        # Save to cache (KEEP YOUR EXACT LOGIC)
        if save_cache:
            try:
                from datetime import datetime
                
                cache_data = {
                    'results': results,
                    'parameters': {
                        'z_slice_width': z_slice_width,
                        'xy_grid_size': xy_grid_size,
                        'mode': mode,
                        'water_vdw_radius': water_vdw_radius,
                        'ellipse_aspect_ratio': ellipse_aspect_ratio if mode == 'dipole_ellipse' else None,
                        'center_box': self.center_box,
                        # NEW parameters for cache validation
                        'use_xy_projection': use_xy_projection,
                        'projection_method': projection_method if use_xy_projection else None,
                        'projection_radius': projection_radius if use_xy_projection else None,
                        'hydrogen_vdw_radius': hydrogen_vdw_radius if use_xy_projection else None
                    },
                    'mode': mode,
                    'n_frames': n_frames,
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'n_z_slices': n_slices
                }
                
                with open(cache_file, 'wb') as f:
                    pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size_mb = os.path.getsize(cache_file) / 1024 / 1024
                print(f"\n✓ Saved to cache: {cache_file}")
                print(f"  Cache size: {file_size_mb:.2f} MB")
            
            except Exception as e:
                print(f"⚠ Failed to save cache: {e}")
        
        return results


    def calculate_ion_spatial_distribution_xy(self, ion_types=None, 
                                            z_slice_centers=None, z_slice_width=5.0,
                                            xy_grid_size=1.0, step=None, n_frames_sample=3,
                                            use_vdw_radius=False, vdw_radii=None,
                                            # NEW projection parameters (options 2 and 4)
                                            projection_mode='vdw_radius',
                                            solvation_radii=None,
                                            hydrated_radii=None,
                                            force_rerun=False, save_cache=True, cache_file=None):
        '''
        Calculate 2D spatial distribution of ions in XY plane at different Z-positions
        for heatmap visualization with automatic caching.
        
        Parameters
        ----------
        ion_types : list, optional
            Ion types to analyze (e.g., ['NA', 'CL'])
        z_slice_centers : array-like, optional
            Z-positions to analyze
        z_slice_width : float
            Thickness of Z-slice (Å)
        xy_grid_size : float
            Grid spacing for XY binning (Å)
        step : int, optional
            Analyze every nth frame
        n_frames_sample : int
            Number of frames to sample
        use_vdw_radius : bool, optional
            If True, spread ion density based on Van der Waals radius
            instead of single point. Default is False (point-based)
        vdw_radii : dict, optional
            Dictionary of Van der Waals radii for each ion type (Å)
            Example: {'NA': 1.02, 'CL': 1.81, 'MG': 0.72}
            If None and use_vdw_radius=True, uses default values
        projection_mode : str, optional
            Ion projection method onto XY plane:
            - 'point': Simple point-based (default, original method)
            - 'vdw_radius': Van der Waals radius projection (original method)
            - 'solvation_shell': First solvation shell projection (NEW)
            - 'hydrated_radius': Hydrated ionic radius projection (NEW)
        solvation_radii : dict, optional
            Dictionary of first solvation shell radii for each ion type (Å)
            Example: {'NA': 3.5, 'CL': 4.0, 'MG': 2.8}
            If None, uses default values when projection_mode='solvation_shell'
        hydrated_radii : dict, optional
            Dictionary of hydrated ionic radii for each ion type (Å)
            Example: {'NA': 2.4, 'CL': 3.3, 'MG': 2.1}
            If None, uses default values when projection_mode='hydrated_radius'
        force_rerun : bool, optional
            Force recalculation even if cache exists. Default is False
        save_cache : bool, optional
            If True, save results to cache file after calculation. Default is True
        cache_file : str, optional
            Path to cache file. If None, auto-generates filename
        
        Returns
        -------
        dict with:
            - 'xy_grids': {ion_type: {z_idx: 2D histogram array}}
            - 'x_edges', 'y_edges': Grid edges
            - 'z_slice_centers': Z-positions analyzed
            - 'use_vdw_radius': Boolean flag (for backward compatibility)
            - 'vdw_radii': Dictionary of used radii (if applicable)
            - 'projection_mode': Projection method used
            - 'solvation_radii': Dictionary of solvation radii (if applicable)
            - 'hydrated_radii': Dictionary of hydrated radii (if applicable)
        '''
        
        # Handle backward compatibility for use_vdw_radius parameter
        if use_vdw_radius and projection_mode == 'point':
            projection_mode = 'vdw_radius'
        
        # Generate cache filename if not provided
        if cache_file is None:
            ion_str = '_'.join(ion_types[:3]) if ion_types else 'all_ions'
            proj_str = f'_{projection_mode}' if projection_mode != 'point' else ''
            step_str = f'_step{step}' if step else f'_n{n_frames_sample}'
            cache_file = f'ion_spatial_xy_cache_{ion_str}_grid{xy_grid_size:.2f}{proj_str}{step_str}.pkl'
        
        _partial_hit = False  # set True when only some z-slices are missing from cache

        # Try to load from cache
        if not force_rerun and os.path.exists(cache_file):
            try:
                print(f"Loading ion spatial XY distribution from cache: {cache_file}")
                with open(cache_file, 'rb') as f:
                    cached_data = pickle.load(f)
                
                # Verify cache parameters match
                cache_params = cached_data.get('parameters', {})
                current_params = {
                    'z_slice_width': z_slice_width,
                    'xy_grid_size': xy_grid_size,
                    'projection_mode': projection_mode,
                    'center_box': self.center_box
                }
                
                # Check if parameters match
                params_match = True
                for key, value in current_params.items():
                    cached_value = cache_params.get(key)
                    if isinstance(value, (int, float)):
                        if abs(cached_value - value) > 1e-6:
                            params_match = False
                            print(f"Parameter mismatch: {key} = {value} (current) vs {cached_value} (cached)")
                            break
                    elif cached_value != value:
                        params_match = False
                        print(f"Parameter mismatch: {key} = {value} (current) vs {cached_value} (cached)")
                        break
                
                if params_match:
                    _cached_res = cached_data['results']
                    _cached_z   = np.asarray(_cached_res['z_slice_centers'])
                    _req_z      = np.asarray(z_slice_centers)
                    _tol        = 0.01  # Å tolerance for z-center matching

                    # Map each requested z-center to an index in the cache
                    _hit_map = {}  # req_idx -> cache_idx
                    for _ri, _rz in enumerate(_req_z):
                        _diffs = np.abs(_cached_z - _rz)
                        _best  = int(np.argmin(_diffs))
                        if _diffs[_best] <= _tol:
                            _hit_map[_ri] = _best

                    _missing_ri = [ri for ri in range(len(_req_z)) if ri not in _hit_map]

                    if not _missing_ri:
                        # ✓ Full cache hit — return data keyed to requested order
                        _merged = dict(_cached_res)
                        _merged['z_slice_centers'] = _req_z
                        _merged['xy_grids'] = {}
                        for _it in list(_cached_res['xy_grids'].keys()):
                            _merged['xy_grids'][_it] = {
                                _ri: _cached_res['xy_grids'][_it][_hit_map[_ri]]
                                for _ri in range(len(_req_z))
                            }
                        self.results.ion_spatial_xy = _merged
                        print(f"✓ All {len(_req_z)} requested z-slices found in cache")
                        print(f"  Cache created: {cached_data.get('timestamp', 'unknown')}")
                        print(f"  Frames analyzed: {cached_data.get('n_frames', 'unknown')}")
                        print(f"  Ion types: {', '.join(cached_data.get('ion_types', []))}")
                        return self.results.ion_spatial_xy
                    else:
                        # Partial hit — compute only the missing slices
                        _n_hit  = len(_hit_map)
                        _miss_z = [float(_req_z[ri]) for ri in _missing_ri]
                        print(f"  {_n_hit}/{len(_req_z)} z-slices found in cache")
                        print(f"  Cached (skipping): {[f'{_req_z[ri]:.2f}' for ri in sorted(_hit_map)]}")
                        print(f"  Computing {len(_missing_ri)} new slice(s): "
                              f"{[f'{z:.2f}' for z in _miss_z]}")
                        # Stash merge metadata; narrow z_slice_centers to missing only
                        _partial_hit      = True
                        _full_req_z       = _req_z
                        _partial_hit_map  = _hit_map
                        _partial_miss_ri  = _missing_ri
                        _partial_cached   = _cached_res
                        z_slice_centers   = np.array(_miss_z)
                else:
                    print("⚠ Cache parameters don't match, recalculating...")
            
            except Exception as e:
                print(f"⚠ Failed to load cache: {e}")
                print("Recalculating...")
        
        else:
            if force_rerun:
                print("force_rerun=True, running fresh calculation...")
            else:
                print(f"No cache found: {cache_file}")
                print("Running fresh calculation...")
        
        # CALCULATION STARTS HERE
        print("Calculating 2D XY spatial distributions at different Z...")
        
        if ion_types is None:
            ion_types = list(self.cation_types.keys()) + list(self.anion_types.keys())
        
        # Define default radii based on projection mode
        if projection_mode == 'vdw_radius' and vdw_radii is None:
            # Default Van der Waals radii (Å) from literature
            vdw_radii = {
                'NA': 1.02,   # Sodium
                'K': 1.38,    # Potassium
                'MG': 0.72,   # Magnesium
                'CA': 1.00,   # Calcium
                'CL': 1.81,   # Chloride
                'BR': 1.96,   # Bromide
                'I': 2.20,    # Iodide
                'F': 1.47     # Fluoride
            }
            print(f"Using default Van der Waals radii: {vdw_radii}")
        
        if projection_mode == 'solvation_shell' and solvation_radii is None:
            # Default first solvation shell radii (Å)
            solvation_radii = {
                'NA': 3.5,   # Na+ first shell
                'K': 4.0,    # K+ first shell
                'MG': 2.8,   # Mg2+ first shell (smaller due to higher charge)
                'CA': 3.2,   # Ca2+ first shell
                'CL': 4.0,   # Cl- first shell
                'BR': 4.2,   # Br- first shell
                'I': 4.5,    # I- first shell
                'F': 3.8     # F- first shell
            }
            print(f"Using default solvation shell radii: {solvation_radii}")
        
        if projection_mode == 'hydrated_radius' and hydrated_radii is None:
            # Default hydrated ionic radii (Å) - effective size in solution
            hydrated_radii = {
                'NA': 2.4,   # Na+ hydrated
                'K': 2.8,    # K+ hydrated
                'MG': 2.1,   # Mg2+ hydrated (smaller due to strong hydration)
                'CA': 2.4,   # Ca2+ hydrated
                'CL': 3.3,   # Cl- hydrated
                'BR': 3.5,   # Br- hydrated
                'I': 3.8,    # I- hydrated
                'F': 2.8     # F- hydrated
            }
            print(f"Using default hydrated ionic radii: {hydrated_radii}")
        
        # Print projection mode information
        if projection_mode == 'point':
            print(f"Point mode: Ions counted as single points in grid")
        elif projection_mode == 'vdw_radius':
            print(f"VdW radius mode: Ions will occupy circular areas based on their VdW radii")
        elif projection_mode == 'solvation_shell':
            print(f"Solvation shell mode: Ions projected with their first solvation shell areas")
        elif projection_mode == 'hydrated_radius':
            print(f"Hydrated radius mode: Ions projected with their effective hydrated sizes")
        
        # Define z-slices
        if z_slice_centers is None:
            z_slice_centers = np.arange(self.z_min + z_slice_width/2, 
                                        self.z_max - z_slice_width/2, 
                                        z_slice_width)
        
        # Get box dimensions
        box_x = self.universe.dimensions[0]
        box_y = self.universe.dimensions[1]
        
        # Create XY grid
        x_bins = np.arange(0, box_x + xy_grid_size, xy_grid_size)
        y_bins = np.arange(0, box_y + xy_grid_size, xy_grid_size)
        
        # Create grid centers for radius-based calculations
        x_centers = (x_bins[:-1] + x_bins[1:]) / 2
        y_centers = (y_bins[:-1] + y_bins[1:]) / 2
        X_grid, Y_grid = np.meshgrid(x_centers, y_centers)
        
        results = {
            'z_slice_centers': z_slice_centers,
            'z_slice_width': z_slice_width,
            'x_edges': x_bins,
            'y_edges': y_bins,
            'xy_grids': {},  # {ion_type: {z_idx: 2D array}}
            'box_x': box_x,
            'box_y': box_y,
            'projection_mode': projection_mode,
            # Keep backward compatibility
            'use_vdw_radius': (projection_mode == 'vdw_radius'),
            'vdw_radii': vdw_radii if projection_mode == 'vdw_radius' else None,
            # New projection parameters
            'solvation_radii': solvation_radii if projection_mode == 'solvation_shell' else None,
            'hydrated_radii': hydrated_radii if projection_mode == 'hydrated_radius' else None
        }
        
        # Initialize storage
        for ion_type in ion_types:
            results['xy_grids'][ion_type] = {}
            for z_idx in range(len(z_slice_centers)):
                results['xy_grids'][ion_type][z_idx] = np.zeros((len(y_bins)-1, len(x_bins)-1))
        
        # Get z-offset
        z_offset = self.universe.dimensions[2] / 2 if self.center_box else 0
        
        # Determine frames
        total_frames = len(self.universe.trajectory)
        if step is not None:
            frame_indices = np.arange(0, total_frames, step)
        else:
            frame_indices = np.linspace(0, total_frames-1, min(n_frames_sample, total_frames), dtype=int)
        
        print(f"Analyzing {len(frame_indices)} frames across {len(z_slice_centers)} Z-slices...")
        if projection_mode != 'point':
            print(f"XY grid resolution: {xy_grid_size} Å")
            print(f"Radii will be distributed over multiple grid cells")
        
        for frame_idx in tqdm(frame_indices, desc="Ion XY distribution", unit="frame"):
            self.universe.trajectory[frame_idx]
            
            for ion_type in ion_types:
                # Get ions
                if ion_type in self.cation_types:
                    ion_group = self.cation_types[ion_type]
                else:
                    ion_group = self.anion_types[ion_type]
                
                if len(ion_group) == 0:
                    continue
                
                # Get all ion positions
                ion_positions = ion_group.positions
                ion_z = ion_positions[:, 2] - z_offset
                
                # Get radius for this ion type based on projection mode
                ion_radius = None
                if projection_mode == 'vdw_radius':
                    for key in vdw_radii.keys():
                        if key.upper() in ion_type.upper() or ion_type.upper() in key.upper():
                            ion_radius = vdw_radii[key]
                            break
                    if ion_radius is None:
                        ion_radius = 1.5
                        print(f"Warning: No VdW radius found for {ion_type}, using default {ion_radius} Å")
                
                elif projection_mode == 'solvation_shell':
                    for key in solvation_radii.keys():
                        if key.upper() in ion_type.upper() or ion_type.upper() in key.upper():
                            ion_radius = solvation_radii[key]
                            break
                    if ion_radius is None:
                        ion_radius = 3.5
                        print(f"Warning: No solvation radius found for {ion_type}, using default {ion_radius} Å")
                
                elif projection_mode == 'hydrated_radius':
                    for key in hydrated_radii.keys():
                        if key.upper() in ion_type.upper() or ion_type.upper() in key.upper():
                            ion_radius = hydrated_radii[key]
                            break
                    if ion_radius is None:
                        ion_radius = 2.5
                        print(f"Warning: No hydrated radius found for {ion_type}, using default {ion_radius} Å")
                
                # For each z-slice
                for z_idx, z_center in enumerate(z_slice_centers):
                    # Select ions in this z-slice
                    in_slice = np.abs(ion_z - z_center) <= z_slice_width / 2
                    
                    if not np.any(in_slice):
                        continue
                    
                    # Get XY positions of ions in slice
                    xy_positions = ion_positions[in_slice, :2]  # Only X and Y
                    
                    if projection_mode == 'point':
                        # POINT MODE: Traditional histogram (original method)
                        H, _, _ = np.histogram2d(xy_positions[:, 1], xy_positions[:, 0],
                                                bins=[y_bins, x_bins])
                        
                        results['xy_grids'][ion_type][z_idx] += H
                    
                    else:
                        # RADIUS-BASED MODES: Distribute each ion as a circle
                        for ion_pos in xy_positions:
                            # Calculate distance from this ion to all grid points
                            dx = X_grid - ion_pos[0]
                            dy = Y_grid - ion_pos[1]
                            
                            # Apply periodic boundary conditions
                            dx = dx - box_x * np.round(dx / box_x)
                            dy = dy - box_y * np.round(dy / box_y)
                            
                            distances = np.sqrt(dx**2 + dy**2)
                            
                            # Add contribution to grid cells within radius
                            # Use Gaussian-like distribution for smooth edges
                            contribution = np.exp(-0.5 * (distances / ion_radius)**2)
                            
                            # Only add where contribution is significant (> 1% of peak)
                            mask = contribution > 0.01
                            results['xy_grids'][ion_type][z_idx] += contribution * mask
        
        # Average over frames
        n_frames = len(frame_indices)
        for ion_type in ion_types:
            for z_idx in range(len(z_slice_centers)):
                results['xy_grids'][ion_type][z_idx] /= n_frames
        
        # If partial cache hit: merge cached slices with freshly computed ones
        if _partial_hit:
            _final_grids = {}
            for _it in ion_types:
                _final_grids[_it] = {}
                for _ri in range(len(_full_req_z)):
                    if _ri in _partial_hit_map:
                        # Pull this slice from the original cache
                        _final_grids[_it][_ri] = _partial_cached['xy_grids'][_it][_partial_hit_map[_ri]]
                    else:
                        # Pull from freshly computed data (local index within missing list)
                        _local_idx = _partial_miss_ri.index(_ri)
                        _final_grids[_it][_ri] = results['xy_grids'][_it][_local_idx]
            results['z_slice_centers'] = _full_req_z
            results['xy_grids']        = _final_grids
            z_slice_centers            = _full_req_z  # keep in sync for cache save

        # Store in results
        self.results.ion_spatial_xy = results
        
        print(f"✓ XY spatial distribution calculated")
        print(f"  Mode: {projection_mode}")
        if projection_mode != 'point':
            print(f"  Ion radii used:")
            for ion_type in ion_types:
                if projection_mode == 'vdw_radius':
                    radii_dict = vdw_radii
                elif projection_mode == 'solvation_shell':
                    radii_dict = solvation_radii
                elif projection_mode == 'hydrated_radius':
                    radii_dict = hydrated_radii
                
                for key in radii_dict.keys():
                    if key.upper() in ion_type.upper() or ion_type.upper() in key.upper():
                        print(f"    {ion_type}: {radii_dict[key]:.2f} Å")
                        break
        print(f"  Grid size: {xy_grid_size} Å")
        print(f"  XY dimensions: {box_x:.1f} × {box_y:.1f} Å")
        print(f"  Frames analyzed: {n_frames}")
        
        # Save to cache if requested
        if save_cache:
            try:
                from datetime import datetime
                
                cache_data = {
                    'results': results,
                    'parameters': {
                        'z_slice_width': z_slice_width,
                        'xy_grid_size': xy_grid_size,
                        'projection_mode': projection_mode,
                        'center_box': self.center_box,
                        'vdw_radii': vdw_radii if projection_mode == 'vdw_radius' else None,
                        'solvation_radii': solvation_radii if projection_mode == 'solvation_shell' else None,
                        'hydrated_radii': hydrated_radii if projection_mode == 'hydrated_radius' else None
                    },
                    'ion_types': ion_types,
                    'n_frames': n_frames,
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'n_z_slices': len(results['z_slice_centers']),
                    'grid_dimensions': {
                        'x_bins': len(x_bins) - 1,
                        'y_bins': len(y_bins) - 1,
                        'z_slices': len(results['z_slice_centers'])
                    }
                }
                
                with open(cache_file, 'wb') as f:
                    pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
                
                file_size_mb = os.path.getsize(cache_file) / 1024 / 1024
                print(f"\n✓ Saved ion spatial XY distribution to cache: {cache_file}")
                print(f"  Cache size: {file_size_mb:.2f} MB")
            
            except Exception as e:
                print(f"⚠ Failed to save cache: {e}")
        else:
            print("\nCache saving skipped (save_cache=False)")
        
        return results



